INSERT INTO "code_blobs" VALUES('6162ad292fdf96b2e2acee65ae16c18da55f416d','php',5999,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * MemoryList — a TOP-LEVEL tag: the controller (Claude) tool-use log, reflecting
 * the state of the MCP. Every call routed through the gate is stamped
 * {ts, session, tool, intent} — often by Claude — and viewed here in REVERSE
 * CHRONOLOGICAL order.
 *
 * Source of truth is two-fold and merged so the view is always current:
 *   1. the durable `memories` table in the unified DB (where the gate persists), and
 *   2. the live gate log ~/.MCP/gate-memories.json (what the RUNNING gate is writing
 *      right now, before it has been restarted onto the DB path).
 * Rows are de-duped on (ts, tool) and sorted newest-first.
 */
if (!class_exists("MemoryList")) {
    class MemoryList implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        private function collect() {
            $rows = array();
            // 1) durable DB projection
            if (defined(''CONGRUENCY_SQLITE'')) {
                try {
                    $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                    $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                    foreach ($db->query("SELECT ts, session, tool, intent FROM memories") as $r) {
                        $rows[] = array(''ts'' => (string)$r[''ts''], ''session'' => $r[''session''],
                                        ''tool'' => (string)$r[''tool''], ''intent'' => (string)$r[''intent''], ''src'' => ''db'');
                    }
                } catch (\Throwable $e) { /* ignore, fall through to the live log */ }
            }
            // 2) the live MCP gate log (the running controller)
            $home = getenv(''HOME'');
            $log = $home ? rtrim($home, ''/'') . ''/.MCP/gate-memories.json'' : '''';
            if ($log && is_readable($log)) {
                $data = json_decode((string)@file_get_contents($log), true);
                if (is_array($data)) {
                    foreach ($data as $e) {
                        $rows[] = array(''ts'' => (string)($e[''timestamp''] ?? ''''), ''session'' => $e[''session''] ?? null,
                                        ''tool'' => (string)($e[''tool''] ?? ''''),
                                        ''intent'' => (string)($e[''intent''] ?? ($e[''note''] ?? '''')), ''src'' => ''mcp'');
                    }
                }
            }
            // de-dupe on (ts, tool); prefer the DB row (seen first)
            $seen = array(); $uniq = array();
            foreach ($rows as $r) {
                $k = $r[''ts''] . ''|'' . $r[''tool''];
                if (!isset($seen[$k])) { $seen[$k] = 1; $uniq[] = $r; }
            }
            // reverse chronological
            usort($uniq, function ($a, $b) { return strcmp($b[''ts''], $a[''ts'']); });
            return $uniq;
        }

        public function get_document() {
            try {
                $rows = $this->collect();
                $sessions = array();
                foreach ($rows as $r) { if ($r[''session''] !== null && $r[''session''] !== '''') { $sessions[$r[''session'']] = 1; } }

                // pagination (reverse chronological; page 1 = newest)
                $total = count($rows);
                $per   = 10;
                $pages = max(1, (int)ceil($total / $per));
                $pg    = isset($_GET[''p'']) ? (int)$_GET[''p''] : 1;
                if ($pg < 1) { $pg = 1; }
                if ($pg > $pages) { $pg = $pages; }
                $slice = array_slice($rows, ($pg - 1) * $per, $per);

                $out  = "<style>.mem{display:grid;gap:.55rem}"
                      . ".m{border:1px solid #d8d2c4;border-left:5px solid #8a5a1a;border-radius:6px;padding:.5rem .8rem;background:#fffdf8}"
                      . ".m .top{font:.7rem/1.4 monospace;color:#666}.m .tool{color:#8a5a1a;font-weight:600}"
                      . ".m .src{float:right;font:600 .58rem/1.6 sans-serif;text-transform:uppercase;color:#fff;background:#8a7a1a;padding:.05rem .4rem;border-radius:3px}"
                      . ".m .intent{margin:.25rem 0 0;font-size:.9rem;color:#333}"
                      . ".pager{margin:1rem 0;font-size:.85rem}.pager a{margin:0 .5rem}</style>\n";
                $out .= "<p style=''font-size:.85rem;color:#555''><strong>" . $total . "</strong> controller actions &middot; <strong>"
                      . count($sessions) . "</strong> session(s) &middot; reverse chronological, reflecting the MCP.</p>\n";

                $pager = "<div class=''pager''>";
                $pager .= ($pg > 1) ? "<a href=''?page=memories&p=" . ($pg - 1) . "''>&larr; newer</a>" : "<span style=''color:#aaa''>&larr; newer</span>";
                $pager .= " page <strong>$pg</strong> of $pages ";
                $pager .= ($pg < $pages) ? "<a href=''?page=memories&p=" . ($pg + 1) . "''>older &rarr;</a>" : "<span style=''color:#aaa''>older &rarr;</span>";
                $pager .= "</div>\n";

                $out .= $pager . "<div class=''mem''>\n";
                foreach ($slice as $r) {
                    $out .= "  <div class=''m''><div class=''top''><span class=''src''>" . self::esc($r[''src'']) . "</span>"
                          . self::esc($r[''ts'']) . " &middot; session " . self::esc($r[''session''] !== null ? $r[''session''] : ''-'')
                          . " &middot; <span class=''tool''>" . self::esc($r[''tool'']) . "</span></div>"
                          . "<div class=''intent''>" . self::esc($r[''intent'']) . "</div></div>\n";
                }
                $out .= "</div>\n" . $pager;
                return $out;
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>MemoryList error: " . self::esc(get_class($e) . '': '' . $e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('7245d47eeca6c42e771b0bdb35ce0d03b1324d27','php',4978,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * BugDemo — a congruency component that runs a bug LIVE inside the page.
 *
 * Usage in document content:  <<<BugDemo(sqli)>>>   or   <<<BugDemo(lifo)>>>
 * (tag arguments are alphanumeric only, per the FUNCTION_ARGUMENT regex, so
 * bug ids here are short slugs.)
 *
 * Only the non-fatal bugs are demonstrated live; the fatal ones (recursion,
 * null get_class, missing constants) are described by BugReport instead of
 * being triggered, since firing them would take the page down with it.
 */
if (!interface_exists("Command")) { /* loaded lazily below when needed */ }

if (!class_exists("BugDemo")) {

    class BugDemo implements Tag_Interface {

        private $which;

        public function __construct($arguments) {
            // TagArguments::pop() yields the single (slug) argument.
            $this->which = $arguments ? $arguments->pop() : '''';
        }

        public function get_document() {
            try {
                switch ($this->which) {
                    case ''sqli'': return $this->demo_sqli();
                    case ''lifo'': return $this->demo_lifo();
                    default:     return $this->box(''BugDemo'', "Unknown demo ''" . htmlspecialchars($this->which) . "''. Try sqli or lifo.");
                }
            } catch (\Throwable $e) {
                return $this->box(''BugDemo error'', htmlspecialchars(get_class($e) . '': '' . $e->getMessage()));
            }
        }

        /* ---- BUG-01 live: validated key discarded, raw input reaches SQL ---- */
        private function demo_sqli() {
            $dao    = new CatalogDAO();
            $legit  = $dao->select_products_by_category(''5'');          // category 5
            $inject = $dao->select_products_by_category(''0 OR 1=1'');   // "validated" — but ignored

            $leaked = array();
            foreach ($inject as $row) { $leaked[] = htmlspecialchars($row[''name'']); }

            $body  = "<code>select_products_by_category(''5'')</code> &rarr; <b>" . count($legit) . "</b> row(s)<br>";
            $body .= "<code>select_products_by_category(''0 OR 1=1'')</code> &rarr; <b>" . count($inject) . "</b> row(s)";
            if (count($inject) > count($legit)) {
                $body .= "<br><br><b style=''color:#b00020''>Injected.</b> The <code>WHERE</code> clause became "
                       . "<code>category=0 OR 1=1</code>, leaking every product: " . implode('', '', $leaked) . ".";
            } else {
                $body .= "<br><br><b style=''color:#1a7a3a''>Blocked &#10003;</b> The validated numeric key sanitised the input "
                       . "(<code>0 OR 1=1</code> &rarr; <code>NULL</code>), so no injectable query was built.";
            }
            return $this->box(''BUG-01 &mdash; PATCHED (was live SQL injection)'', $body);
        }

        /* ---- BUG-08 live: the command "queue" runs last-in-first-out ---- */
        private function demo_lifo() {
            // Ensure the Command interface + a tiny concrete command are available.
            getClassLoader()->loadClassByName(''Command'');
            if (!class_exists(''BugDemoOrderProbe'')) {
                eval(''class BugDemoOrderProbe implements Command {
                    public static $ran = array(); private $name;
                    public static function commandFactory($p){ $c=new self(); $c->name=$p; return $c; }
                    public function execute(){ self::$ran[] = $this->name; }
                    public function __toString(){ return "probe(".$this->name.")"; }
                }'');
            }
            BugDemoOrderProbe::$ran = array();
            $queue = new CommandInterfaceObject();
            $queue->enqueueCommand(BugDemoOrderProbe::commandFactory(''FIRST''));
            $queue->enqueueCommand(BugDemoOrderProbe::commandFactory(''SECOND''));
            $queue->execute();

            $body  = "enqueued: <code>FIRST</code> then <code>SECOND</code><br>";
            $body .= "executed: <code>" . implode(''</code> then <code>'', BugDemoOrderProbe::$ran) . "</code>";
            if (BugDemoOrderProbe::$ran === array(''SECOND'', ''FIRST'')) {
                $body .= "<br><br><b style=''color:#b5651d''>Reversed.</b> <code>execute()</code> drains with "
                       . "<code>array_pop()</code>, so the queue is really a stack.";
            }
            return $this->box(''BUG-08 &mdash; live command-queue ordering'', $body);
        }

        private function box($title, $body) {
            return "<div style=''border:1px solid #d8d2c4;border-radius:6px;background:#f3efe4;"
                 . "padding:.7rem .9rem;margin:.6rem 0;font-size:.85rem''>"
                 . "<div style=''font:600 .72rem/1 monospace;color:#7a5a2a;margin-bottom:.4rem''>&#9654; "
                 . $title . "</div>" . $body . "</div>";
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('c7e1fad0a14d13f10d8ed4d8a5990a2e47fbdeb0','php',6554,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * BugReport — a congruency component (tag/invocator).
 *
 * Implements Tag_Interface, so the tag engine instantiates it whenever a
 * document''s content contains <<<BugReport>>> and splices in get_document().
 * Renders the catalog of bugs found in congruency itself. Meta by design:
 * the CMS is publishing a page about its own defects, through its own pipeline.
 *
 * NOTE: any <<<Name>>> we emit would be re-parsed by execute_all_tags, so every
 * example of tag syntax below is HTML-escaped (&lt;&lt;&lt;) on purpose.
 */
if (!class_exists("BugReport")) {
    class BugReport implements Tag_Interface {

        private $arguments;

        public function __construct($arguments) {
            $this->arguments = $arguments;
        }

        private function catalog() {
            $gh = ''https://github.com/dudezilla/congruency/blob/main/'';
            return array(
                array(''BUG-01'', ''critical'', ''SQL injection in the product catalog'',
                    ''select_products_by_category() validates the key into $itemKey, then guards on isset($key) and interpolates the RAW $key into SQL. The validated value is dead code one variable name away.'',
                    ''lib/Modules/StoreModule/Catalog/DAO/CatalogDAO.php#L58'',
                    ''FIXED &mdash; CatalogDAO now interpolates the validated $itemKey and guards isset($itemKey); malicious keys sanitise to NULL.''),
                array(''BUG-02'', ''high'', ''ProductDAO never opens a connection'',
                    ''The constructor sets $this->table but omits the CreateConnection()->open() every sibling DAO has. First query dereferences null.'',
                    ''lib/Modules/StoreModule/Catalog/DAO/ProductDAO.php#L25'',
                    ''FIXED &mdash; the constructor now opens the STORE connection like sibling DAOs.''),
                array(''BUG-03'', ''high'', ''OrderDAO::updateRow calls a method that does not exist'',
                    ''Calls $this->insert() (no such method) and passes a bare key to delete() where a WHERE-clause is expected.'',
                    ''lib/Modules/StoreModule/Order/DAO/OrderDAO.php#L65'',
                    ''FIXED &mdash; updateRow now uses deleteRow() (a WHERE clause) and insertRow() (the real insert).''),
                array(''BUG-04'', ''medium'', ''Empty result set returns null, not []'',
                    ''returnAllBeans() inits to NULL and only fills in-loop; a zero-row query returns null and callers do current(null) -> TypeError.'',
                    ''lib/DatabaseDrivers/MySQL/AbstractDAO.php#L86'',
                    ''FIXED &mdash; returnAllBeans() now inits array(); a zero-row query returns [].''),
                array(''BUG-05'', ''medium'', ''A missing page crashes the front controller'',
                    ''Controller::display passes a possibly-null document to setData(), which does get_class(null). Silent false in PHP 5; fatal TypeError in PHP 8.'',
                    ''lib/PersistanceObjectManager/PersistentObjectManager.php#L75'',
                    ''RESOLVED &mdash; setData guards get_class with is_object(); DocumentManager falls back to the invalid document for missing pages.''),
                array(''BUG-06'', ''medium'', ''Unbounded tag recursion (stored-content DoS)'',
                    ''execute_all_tags recurses into a tag&rsquo;s rendered output with no depth/visited guard. A document whose Title is &lt;&lt;&lt;TitleTag&gt;&gt;&gt; loops forever.'',
                    ''lib/TagLoader/Tag/Tag_Wrapper.php#L81'',
                    ''FIXED &mdash; execute_all_tags now caps recursion depth at 64.''),
                array(''BUG-07'', ''high'', ''Config constants referenced but never defined'',
                    ''The store/order/auth modules use MYSQL_STORE_DATABASE, ETC, &hellip; that Constants.php never defines. Undefined constants are fatal on PHP 8 &mdash; why Install.txt says &ldquo;does not execute.&rdquo;'',
                    ''www/Constants.php'',
                    ''RESOLVED &mdash; config-as-data (constants.default.json + configure.php) now defines MYSQL_*, ETC, &hellip;.''),
                array(''BUG-08'', ''low'', ''Command queue runs in reverse'',
                    ''execute() drains the queue with array_pop(), so commands fire last-in-first-out.'',
                    ''lib/CommandQueues/InterfaceObject/CommandInterfaceObject.php#L38''),
            );
        }

        private static function colour($sev) {
            $map = array(''critical'' => ''#b00020'', ''high'' => ''#b5651d'', ''medium'' => ''#8a7a1a'', ''low'' => ''#5a6a5a'');
            return isset($map[$sev]) ? $map[$sev] : ''#666'';
        }

        public function get_document() {
            $gh = ''https://github.com/dudezilla/congruency/blob/main/'';
            $out  = "<style>";
            $out .= ".bugs{display:grid;gap:.8rem}";
            $out .= ".bug{border:1px solid #d8d2c4;border-left:5px solid #999;border-radius:6px;padding:.7rem .9rem;background:#fffdf8}";
            $out .= ".bug h3{margin:0 0 .2rem;font-size:1rem;font-weight:normal}";
            $out .= ".bug .id{font:600 .72rem/1 monospace;letter-spacing:.05em}";
            $out .= ".bug .sev{float:right;font:600 .62rem/1.6 sans-serif;text-transform:uppercase;color:#fff;padding:.1rem .45rem;border-radius:3px}";
            $out .= ".bug p{margin:.35rem 0 .3rem;font-size:.85rem;color:#444;line-height:1.45}";
            $out .= ".bug a{font:.72rem/1 monospace;color:#8a5a1a}";
            $out .= "</style>\n<div class=''bugs''>\n";
            foreach ($this->catalog() as $b) {
                list($id, $sev, $title, $desc, $loc, $fixed) = array_pad($b, 6, null);
                $c = $fixed ? ''#1a7a3a'' : self::colour($sev);
                $out .= "  <div class=''bug'' style=''border-left-color:$c" . ($fixed ? ";opacity:.72" : "") . "''>";
                $out .= "<span class=''sev'' style=''background:$c''>" . ($fixed ? ''resolved'' : $sev) . "</span>";
                $out .= "<span class=''id''>$id</span>";
                $out .= "<h3" . ($fixed ? " style=''text-decoration:line-through''" : "") . ">$title</h3>";
                $out .= "<p>$desc</p>";
                if ($fixed) { $out .= "<p style=''color:#1a7a3a;font-weight:600;margin:.2rem 0''>&#10003; $fixed</p>"; }
                $out .= "<a href=''$gh$loc''>$loc</a>";
                $out .= "</div>\n";
            }
            $out .= "</div>\n";
            return $out;
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('b28d69e85fb05c34a280464f78abf890e98e62a1','php',3432,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * CategoryPages — browse pages by category (the page-tagging layer).
 *
 * Invoked as <<<CategoryPages(specifications)>>>. Resolves the category name to
 * its Categories.key, then lists every Document linked to it via the
 * Page_Categories join table, as hyperlinks. With no argument it lists all
 * categories and how many pages each holds.
 */
if (!class_exists("CategoryPages")) {
    class CategoryPages implements Tag_Interface {

        private $category;
        public function __construct($arguments) {
            $this->category = (isset($arguments) && method_exists($arguments, ''top'')) ? $arguments->top() : '''';
        }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        private function db() {
            $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
            $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            return $db;
        }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<p>CategoryPages: no DB.</p>"; }
                $db = $this->db();
                // category comes from the tag argument, else the ?category= URL param (clickable index)
                $cat = trim((string)$this->category);
                if ($cat === '''' && isset($_GET[''category''])) { $cat = trim((string)$_GET[''category'']); }

                if ($cat === '''') {   // no arg -> index of all categories with page counts
                    $rows = $db->query("SELECT c.name, c.description, COUNT(pc.DocumentID) AS n
                        FROM Categories c LEFT JOIN Page_Categories pc ON pc.category_key=c.`key`
                        GROUP BY c.`key` ORDER BY c.name")->fetchAll(PDO::FETCH_ASSOC);
                    $out = "<ul>";
                    foreach ($rows as $r) {
                        $out .= "<li><a href=''?page=pages&category=" . self::esc($r[''name'']) . "''>" . self::esc($r[''name''])
                              . "</a> (" . (int)$r[''n''] . ")" . ($r[''description''] ? " &mdash; " . self::esc($r[''description'']) : "") . "</li>";
                    }
                    return $out . "</ul>";
                }

                $st = $db->prepare("SELECT d.DocumentID, d.Title FROM Page_Categories pc
                    JOIN Categories c ON c.`key`=pc.category_key
                    JOIN Documents d ON d.DocumentID=pc.DocumentID
                    WHERE c.name=? ORDER BY d.DocumentID");
                $st->execute(array($cat));
                $rows = $st->fetchAll(PDO::FETCH_ASSOC);
                if (!$rows) { return "<p>No pages tagged <code>" . self::esc($cat) . "</code> yet.</p>"; }
                $out = "<ul>";
                foreach ($rows as $r) {
                    $title = ($r[''Title''] !== null && $r[''Title''] !== '''') ? $r[''Title''] : $r[''DocumentID''];
                    $out .= "<li><a href=''?page=" . self::esc($r[''DocumentID'']) . "''>" . self::esc($title) . "</a></li>";
                }
                return $out . "</ul>";
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>CategoryPages error: " . self::esc(get_class($e) . '': '' . $e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('6e61698ea36cd59260cc06c2979a06d7b674f28f','php',1632,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * FormTag — render a stored form by id through the real form pipeline.
 *
 * Usage in document content:  <<<FormTag(contact)>>>
 * Looks up FORM_MANAGER in the POM and calls runForm(), which builds a
 * StandardForm from the `forms` table (FormElementDAO -> FormElementBean ->
 * produceElement) and renders it. The intent was sketched in
 * bin/Harness/FormSystemHarness.php ("FormTag(testForm)"); this implements it.
 *
 * Wrapped in try/catch because congruency''s tag engine has no error boundary
 * (see BUG-06) — a form problem should not take the whole page down.
 */
if (!class_exists("FormTag")) {
    class FormTag implements Tag_Interface {

        private $formId;

        public function __construct($arguments) {
            $this->formId = $arguments ? $arguments->pop() : '''';
        }

        public function get_document() {
            try {
                $formManager = PersistentObjectManager::getData("FORM_MANAGER");
                if (!isset($formManager)) {
                    return "<!-- FormTag: no FORM_MANAGER in the POM -->";
                }
                $html = $formManager->runForm($this->formId);
                return "<div class=''cy-form''>" . $html . "</div>";
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>FormTag error: "
                     . htmlspecialchars(get_class($e) . '': '' . $e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('bdeb6f2d5723fcd7f26e3d9160049a020027858b','php',2548,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * PageList — render every page as a hyperlink (the ?page=pages index).
 *
 * Implements Tag_Interface; invoked as <<<PageList>>>. Reads all Documents
 * from CONGRUENCY_SQLITE and lists them (title + id + description) as links.
 */
if (!class_exists("PageList")) {
    class PageList implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<p>PageList: no DB.</p>"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $rows = $db->query("SELECT DocumentID, Title, Description FROM Documents ORDER BY DocumentID")->fetchAll(PDO::FETCH_ASSOC);
                $out  = "<style>.pglist{display:grid;gap:.5rem;list-style:none;padding:0}"
                      . ".pglist li{border:1px solid #d8d2c4;border-left:5px solid #8a5a1a;border-radius:6px;padding:.5rem .8rem;background:#fffdf8}"
                      . ".pglist a{font-size:1.05rem}.pglist .id{font:.72rem/1 monospace;color:#777;margin-left:.4rem}"
                      . ".pglist p{margin:.2rem 0 0;font-size:.85rem;color:#555}</style>\n";
                $out .= "<p style=''font-size:.85rem;color:#555''><strong>" . count($rows) . "</strong> pages</p>\n";
                $out .= "<ul class=''pglist''>\n";
                foreach ($rows as $r) {
                    $id = $r[''DocumentID''];
                    $title = ($r[''Title''] !== null && $r[''Title''] !== '''') ? $r[''Title''] : $id;
                    $out .= "  <li><a href=''?page=" . self::esc($id) . "''>" . self::esc($title) . "</a>"
                          . "<span class=''id''>?page=" . self::esc($id) . "</span>";
                    if ($r[''Description'']) { $out .= "<p>" . self::esc($r[''Description'']) . "</p>"; }
                    $out .= "</li>\n";
                }
                $out .= "</ul>\n";
                return $out;
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>PageList error: " . self::esc(get_class($e) . '': '' . $e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('810e2006cf5680094c69fd72f8bbb1fbe767c8d1','php',2648,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * SiteMap — the "list all pages" tag, used as the site navigation.
 *
 * Implements Tag_Interface; invoked as <<<SiteMap>>>. Reads every Document
 * (page) from CONGRUENCY_SQLITE and renders an inline menu of links, so the
 * nav is generated from the pages that actually exist rather than hardcoded.
 * Terminal/internal pages (the order wizard''s tail, the 404) are blocklisted;
 * a small label map keeps the friendly names.
 */
if (!class_exists("SiteMap")) {
    class SiteMap implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<!-- SiteMap: no DB -->"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $have = array();
                foreach ($db->query("SELECT DocumentID FROM Documents")->fetchAll(PDO::FETCH_COLUMN) as $id) { $have[$id] = 1; }

                // home/about/order-wizard dropped from the nav (still reachable via Pages);
                // the nav now leads with Pages (all pages) and Tags (all tags).
                $block = array(''invalid'' => 1, ''thanks'' => 1, ''ticketDone'' => 1, ''order'' => 1,
                               ''catalog'' => 1, ''about'' => 1, ''config'' => 1);
                $label = array(''pages'' => ''Pages'', ''tags'' => ''Tags'', ''bugs'' => ''bug report'');
                $order = array(''pages'', ''tags'', ''bugs'', ''forms'', ''tickets'', ''memories'');

                $ids = array();
                foreach ($order as $id) { if (isset($have[$id]) && !isset($block[$id])) { $ids[] = $id; unset($have[$id]); } }
                foreach (array_keys($have) as $id) { if (!isset($block[$id])) { $ids[] = $id; } }  // any extras, after

                $links = array();
                foreach ($ids as $id) {
                    $text = isset($label[$id]) ? $label[$id] : $id;
                    $links[] = "<a href=''?page=" . self::esc($id) . "''>" . self::esc($text) . "</a>";
                }
                return implode(" &nbsp;&middot;&nbsp; ", $links);
            } catch (\Throwable $e) {
                return "<!-- SiteMap error: " . self::esc($e->getMessage()) . " -->";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('fe48db5b7fd472d0bda4513eedfaaf851201bee8','php',4643,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * TagList — the ?page=tags gallery. Lists every tag (invocator) under TAGS_DIR
 * as a hyperlink; clicking a tag (?page=tags&tag=NAME) renders that tag''s own
 * output below the list. Only files that implement Tag_Interface are listed,
 * and only a name already in that scanned set is ever instantiated (so the
 * ?tag= param can''t load an arbitrary class).
 */
if (!class_exists("TagList")) {
    class TagList implements Tag_Interface {

        private $arguments;
        private static $rendering = false;   // re-entrancy guard: selecting TagList would render itself forever
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        private static function scan() {
            $names = array();
            if (!defined(''TAGS_DIR'') || !is_dir(TAGS_DIR)) { return $names; }
            $it = new RecursiveIteratorIterator(new RecursiveDirectoryIterator(TAGS_DIR, FilesystemIterator::SKIP_DOTS));
            foreach ($it as $f) {
                if ($f->isFile() && strtolower($f->getExtension()) === ''php'') {
                    $src = @file_get_contents($f->getPathname());
                    if ($src !== false && strpos($src, ''Tag_Interface'') !== false) {
                        $names[substr($f->getFilename(), 0, -4)] = 1;   // basename minus .php
                    }
                }
            }
            $names = array_keys($names);
            sort($names);
            return $names;
        }

        public function get_document() {
            if (self::$rendering) {
                return "<em>(the tag gallery is rendered by TagList; it is not re-rendered inside itself)</em>";
            }
            self::$rendering = true;
            try {
                $names = self::scan();
                $sel = isset($_GET[''tag'']) ? (string)$_GET[''tag''] : '''';

                $out  = "<style>.taglist{display:flex;flex-wrap:wrap;gap:.4rem;list-style:none;padding:0}"
                      . ".taglist a{display:inline-block;border:1px solid #d8d2c4;border-radius:4px;padding:.15rem .5rem;background:#fffdf8;font:.85rem/1.4 monospace}"
                      . ".taglist a.sel{background:#8a5a1a;color:#fff;border-color:#8a5a1a}"
                      . ".tagout{margin-top:1.2rem;border:1px solid #d8d2c4;border-left:5px solid #8a5a1a;border-radius:6px;padding:.8rem 1rem;background:#fffdf8}"
                      . ".tagout h3{margin:0 0 .5rem;font-weight:normal}</style>\n";
                $out .= "<p style=''font-size:.85rem;color:#555''><strong>" . count($names) . "</strong> tags &mdash; click one to render it.</p>\n";
                $out .= "<ul class=''taglist''>\n";
                foreach ($names as $n) {
                    $cls = ($n === $sel) ? " class=''sel''" : "";
                    $out .= "  <li><a$cls href=''?page=tags&tag=" . self::esc($n) . "''>" . self::esc($n) . "</a></li>\n";
                }
                $out .= "</ul>\n";

                if ($sel !== '''' && in_array($sel, $names, true)) {
                    $out .= "<div class=''tagout''><h3>&lt;&lt;&lt;" . self::esc($sel) . "&gt;&gt;&gt;</h3>\n";
                    $loader = PersistentObjectManager::getData(''TAG_LOADER'');
                    if (isset($loader)) { $loader->loadClassByName($sel); }
                    if (class_exists($sel)) {
                        try {
                            $obj = new $sel(null);
                            $out .= (string)$obj->get_document();
                        } catch (\Throwable $e) {
                            $out .= "<p style=''color:#b00020''>This tag needs context to render standalone: "
                                  . self::esc(get_class($e) . '': '' . $e->getMessage()) . "</p>";
                        }
                    } else {
                        $out .= "<p style=''color:#b00020''>Tag class not loadable.</p>";
                    }
                    $out .= "</div>\n";
                } elseif ($sel !== '''') {
                    $out .= "<p style=''color:#b00020''>Unknown tag: " . self::esc($sel) . "</p>";
                }
                return $out;
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>TagList error: " . self::esc(get_class($e) . '': '' . $e->getMessage()) . "</div>";
            } finally {
                self::$rendering = false;
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('9879e050a015cbd9f0b14172f33cad3dd21b4aaa','php',3575,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * TagPageHandler — file a page->category tag (the handler for TagPageForm).
 *
 * Modeled on TicketLogger: on ?page=tagDone it reads the completed TagPageForm
 * results (pageId, category) via FORM_MANAGER, validates both against the DB,
 * and inserts a row into Page_Categories. Idempotent (INSERT OR IGNORE) and
 * self-consuming (resets the form) so a refresh can''t double-file.
 */
if (!class_exists("TagPageHandler")) {
    class TagPageHandler implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }
        private static function back() { return "<p><a href=''?page=pages''>&larr; back to tag a page</a></p>"; }

        public function get_document() {
            try {
                $fm = PersistentObjectManager::getData(''FORM_MANAGER'');
                $res = isset($fm) ? $fm->getResults(''TagPageForm'') : null;
                $pageId   = isset($res[''pageId''])   ? trim((string)$res[''pageId''])   : '''';
                $category = isset($res[''category'']) ? trim((string)$res[''category'']) : '''';

                if ($pageId === '''' && $category === '''') {
                    return "<p>No pending page tag. <a href=''?page=pages''>Tag a page &rarr;</a></p>";
                }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

                $st = $db->prepare("SELECT 1 FROM Documents WHERE DocumentID=?");
                $st->execute(array($pageId));
                if (!$st->fetch()) { return "<p style=''color:#b00020''>No such page: <code>" . self::esc($pageId) . "</code></p>" . self::back(); }

                $st = $db->prepare("SELECT `key` FROM Categories WHERE name=?");
                $st->execute(array($category));
                $row = $st->fetch(PDO::FETCH_ASSOC);
                if (!$row) { return "<p style=''color:#b00020''>No such category: <code>" . self::esc($category) . "</code></p>" . self::back(); }
                $key = (int)$row[''key''];

                $ins = $db->prepare("INSERT OR IGNORE INTO Page_Categories (DocumentID, category_key) VALUES (?,?)");
                $ins->execute(array($pageId, $key));
                $added = $ins->rowCount() > 0;

                if (isset($fm)) { $f = $fm->getCachedForm(''TagPageForm''); if (isset($f)) { $f->setResults(array()); $f->reset(); } }

                $msg = $added
                    ? "Tagged page <code>" . self::esc($pageId) . "</code> as <code>" . self::esc($category) . "</code>."
                    : "Page <code>" . self::esc($pageId) . "</code> was already tagged <code>" . self::esc($category) . "</code>.";
                return "<div style=''border:1px solid #1a7a3a;border-left:5px solid #1a7a3a;border-radius:6px;padding:.7rem .9rem;background:#f3fbf5''>"
                     . "<p style=''margin:.2rem 0''><strong>" . $msg . "</strong></p></div>\n"
                     . "<p><a href=''?page=pages&category=" . self::esc($category) . "''>&rarr; see pages in " . self::esc($category) . "</a></p>";
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>TagPageHandler error: " . self::esc(get_class($e) . '': '' . $e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('b5728cb12bee5d2842da9f9945d408de14ddeafd','php',4716,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * TicketList — a congruency component (tag/invocator).
 *
 * Implements Tag_Interface, so the tag engine instantiates it whenever a
 * document''s content contains <<<TicketList>>> and splices in get_document().
 * Renders the project ticket table from the unified congruency DB
 * (CONGRUENCY_SQLITE) — the same file the CMS, telemetry and gate all share.
 *
 * NB: ticket titles may themselves contain <<<Tag>>> syntax (e.g. this very
 * ticket, "render ... a <<<TicketList>>> ..."), so EVERY value is passed
 * through htmlspecialchars() — otherwise execute_all_tags would re-parse the
 * output and recurse. (This models BugReport.php, but reads live rows.)
 */
if (!class_exists("TicketList")) {
    class TicketList implements Tag_Interface {

        private $arguments;

        public function __construct($arguments) {
            $this->arguments = $arguments;
        }

        private function rows() {
            if (!defined(''CONGRUENCY_SQLITE'')) {
                return array(null, "CONGRUENCY_SQLITE is not defined");
            }
            try {
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                // OPEN first, then newest id first
                $sql = "SELECT id, component, severity, status, title, meta "
                     . "FROM tickets ORDER BY (status=''OPEN'') DESC, id DESC";
                return array($db->query($sql)->fetchAll(PDO::FETCH_ASSOC), null);
            } catch (Exception $e) {
                return array(null, $e->getMessage());
            }
        }

        private static function sev_colour($sev) {
            $map = array(''critical'' => ''#b00020'', ''high'' => ''#b5651d'',
                         ''medium'' => ''#8a7a1a'', ''low'' => ''#5a6a5a'');
            $sev = strtolower((string)$sev);
            return isset($map[$sev]) ? $map[$sev] : ''#666'';
        }

        private static function status_colour($st) {
            return strtoupper((string)$st) === ''OPEN'' ? ''#1a7a3a'' : ''#888'';
        }

        private static function esc($s) {
            return htmlspecialchars((string)$s, ENT_QUOTES);
        }

        public function get_document() {
            list($rows, $err) = $this->rows();
            if ($err !== null) {
                return "<p style=''color:#b00020''>TicketList: could not read tickets ("
                     . self::esc($err) . ")</p>";
            }
            $open = 0;
            foreach ($rows as $r) {
                if (strtoupper($r[''status'']) === ''OPEN'') { $open++; }
            }
            $total = count($rows);

            $out  = "<style>";
            $out .= ".tks{display:grid;gap:.7rem}";
            $out .= ".tk{border:1px solid #d8d2c4;border-left:5px solid #999;border-radius:6px;padding:.6rem .9rem;background:#fffdf8}";
            $out .= ".tk h3{margin:0 0 .2rem;font-size:1rem;font-weight:normal}";
            $out .= ".tk .id{font:600 .72rem/1 monospace;letter-spacing:.05em;color:#555}";
            $out .= ".tk .st{float:right;font:600 .62rem/1.6 sans-serif;text-transform:uppercase;color:#fff;padding:.1rem .45rem;border-radius:3px}";
            $out .= ".tk .cm{font:.72rem/1 monospace;color:#8a5a1a}";
            $out .= ".tks .sev{font:600 .6rem/1.6 sans-serif;text-transform:uppercase;color:#fff;padding:.05rem .4rem;border-radius:3px;margin-left:.4rem}";
            $out .= "</style>\n";
            $out .= "<p style=''font-size:.85rem;color:#555''><strong>" . $total
                  . "</strong> tickets &middot; <strong>" . $open . "</strong> open &middot; <strong>"
                  . ($total - $open) . "</strong> closed</p>\n";
            $out .= "<div class=''tks''>\n";
            foreach ($rows as $r) {
                $sc = self::sev_colour($r[''severity'']);
                $stc = self::status_colour($r[''status'']);
                $out .= "  <div class=''tk'' style=''border-left-color:$stc''>";
                $out .= "<span class=''st'' style=''background:$stc''>" . self::esc($r[''status'']) . "</span>";
                $out .= "<span class=''id''>#" . self::esc($r[''id'']) . "</span>";
                $out .= "<span class=''sev'' style=''background:$sc''>" . self::esc($r[''severity'']) . "</span>";
                $out .= "<h3>" . self::esc($r[''title'']) . "</h3>";
                $out .= "<span class=''cm''>" . self::esc($r[''component'']) . "</span>";
                $out .= "</div>\n";
            }
            $out .= "</div>\n";
            return $out;
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('9f04ca9e222c807ba59c0c907aab241d7a09e126','php',5539,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * TicketLogger — finalize a ticket submission (the handler half of #38).
 *
 * Modeled on the order-wizard handler pattern: invoked as <<<TicketLogger>>> on ?page=ticketDone,
 * it reads the POSTed ticket, validates `type` against the in_array allowlist
 * sourced from the forms table (TicketForm::spec), and inserts a row into the
 * unified `tickets` table (jazz schema) with a MECHANICAL id (SQLite
 * AUTOINCREMENT) — callers never supply the id, same discipline as jazz
 * open_ticket() and the gate stamping time. Renders the confirmation.
 * Wrapped in try/catch: the tag engine has no error boundary (BUG-06).
 */
if (!class_exists("TicketLogger")) {
    class TicketLogger implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }

        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        /* The type allowlist, read straight from the forms table (no cross-tag class ref — the tag
         * loader and the app autoloader are different ClassLoaders; a tag cannot autoload another tag). */
        private static function allowed_types() {
            $types = array();
            if (!defined(''CONGRUENCY_SQLITE'')) { return $types; }
            $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
            $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            $row = $db->query("SELECT elementString FROM forms WHERE formName=''TicketForm'' AND name=''type''")->fetch(PDO::FETCH_ASSOC);
            if ($row) { preg_match_all(''/<<([^>]+)>>/'', (string)$row[''elementString''], $m); $types = $m[1]; }
            return $types;
        }

        /* TicketDAO-style insert: the only writer of web-submitted tickets. */
        private static function insert_ticket($type, $description, $severity = ''medium'') {
            $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
            $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            $now = microtime(true);
            $meta = json_encode(array(''source'' => ''web-form'', ''type'' => $type));
            $st = $db->prepare("INSERT INTO tickets (ts,updated,component,title,severity,status,body,meta)
                                VALUES (:ts,:up,:cm,:ti,:sev,''OPEN'',:bo,:me)");
            $st->execute(array('':ts'' => $now, '':up'' => $now, '':cm'' => $type, '':sev'' => $severity,
                               '':ti'' => $description, '':bo'' => $description, '':me'' => $meta));
            return (int)$db->lastInsertId();
        }

        public function get_document() {
            try {
                // Native forms pipeline: the completed form''s results are carried here (the FCE
                // action=?page=ticketDone) via the POM-in-session, read through FORM_MANAGER.
                $fm = PersistentObjectManager::getData(''FORM_MANAGER'');
                $res = isset($fm) ? $fm->getResults(''TicketForm'') : null;
                $type = isset($res[''type'']) ? trim((string)$res[''type'']) : '''';
                $description = isset($res[''description'']) ? trim((string)$res[''description'']) : '''';

                if ($type === '''' && $description === '''') {
                    return "<p>No pending ticket submission. <a href=''?page=tickets''>File one &rarr;</a></p>";
                }

                $allow = self::allowed_types();               // allowlist FROM the forms table
                if (!in_array($type, $allow, true)) {
                    return "<p style=''color:#b00020''>Rejected: <code>" . self::esc($type)
                         . "</code> is not an allowed ticket type.</p>"
                         . "<p><a href=''?page=tickets''>&larr; back to the form</a></p>";
                }
                if ($description === '''') {
                    return "<p style=''color:#b00020''>Rejected: a description is required.</p>"
                         . "<p><a href=''?page=tickets''>&larr; back to the form</a></p>";
                }

                $urgent = isset($res[''urgent'']) && $res[''urgent''] !== '''' && $res[''urgent''] !== null;
                $id = self::insert_ticket($type, $description, $urgent ? ''high'' : ''medium'');
                // consume the submission so a refresh/return can''t file it twice
                if (isset($fm)) {
                    $form = $fm->getCachedForm(''TicketForm'');
                    if (isset($form)) { $form->setResults(array()); $form->reset(); }
                }
                return "<div style=''border:1px solid #1a7a3a;border-left:5px solid #1a7a3a;border-radius:6px;"
                     . "padding:.7rem .9rem;background:#f3fbf5''>"
                     . "<p style=''margin:.2rem 0''><strong>Ticket #" . self::esc($id) . " logged.</strong></p>"
                     . "<p style=''margin:.2rem 0;font-size:.9rem''>type <code>" . self::esc($type)
                     . "</code> &middot; status <code>OPEN</code></p>"
                     . "<p style=''margin:.4rem 0 .1rem;font-size:.9rem''>" . self::esc($description) . "</p>"
                     . "</div>\n<p><a href=''?page=tickets''>&larr; see it in the ticket list</a></p>";
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>TicketLogger error: "
                     . self::esc(get_class($e) . '': '' . $e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
