if (!class_exists("DateField")) {
    class DateField extends AbstractFormElement {

        private $min = null;
        private $max = null;

        public function __construct() {}

        public function setElementString($elementString) {
            $this->elementString = $elementString;
            $this->min = self::bound($elementString, ''min'');
            $this->max = self::bound($elementString, ''max'');
        }

        private static function bound($s, $key) {
            if (preg_match(''/'' . $key . ''\s*=\s*(\d{4}-\d{2}-\d{2})/i'', (string)$s, $m)) {
                return $m[1];
            }
            return null;
        }

        public function getMin() { return $this->min; }
        public function getMax() { return $this->max; }

        public function getHTML() {
            $cur  = $this->getInitial();
            $attr = "name=''" . $this->id . "'' " . $this->getTabIndex();
            if ($this->min !== null) { $attr .= " min=''" . $this->min . "''"; }
            if ($this->max !== null) { $attr .= " max=''" . $this->max . "''"; }
            $val  = ($cur !== null && $cur !== '''') ? " value=''" . htmlspecialchars((string)$cur, ENT_QUOTES) . "''" : "";
            return "<input type=''date'' " . $attr . $val . ">";
        }

        public function returnValue() {
            $d = $this->form->getFormData();
            return (isset($d[$this->id]) && $d[$this->id] !== '''') ? $d[$this->id] : null;
        }

        public function getInitial() { return $this->returnValue(); }

        public function failsExtendedValidation() {
            $v = $this->returnValue();
            if ($v === null) { return FALSE; }                                  // empty -> required check owns it
            if (!preg_match(''/^\d{4}-\d{2}-\d{2}$/'', (string)$v)) { return TRUE; } // not ISO date
            if ($this->min !== null && $v < $this->min) { return TRUE; }
            if ($this->max !== null && $v > $this->max) { return TRUE; }
            return FALSE;
        }

        /* #45: min/max are derived from elementString (re-derivable), so they are not serialized;
           from_array sets elementString on the base directly, so re-derive the bounds on rebuild. */
        protected function extraFromArray($extra) {
            if (isset($this->elementString)) {
                $this->setElementString($this->elementString);
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('2a772698b97a457ab7e7db8da56e6e4850109c0a','php',3860,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * DbSelect — a DB-backed <select> form element (a first step on ticket #44:
 * more form elements). Its elementString names a source (''pages'' | ''categories'')
 * and it renders a dropdown of live rows from CONGRUENCY_SQLITE. Extended
 * validation rejects any submitted value not in the current option set, so the
 * option list doubles as the allowlist.
 */
if (!class_exists("DbSelect")) {
    class DbSelect extends AbstractFormElement {

        private $options = array();   // array of array(value, label)

        public function __construct() {}

        public function setElementString($elementString) {
            $this->elementString = $elementString;
            $this->options = self::load(trim((string)$elementString));
        }

        private static function load($src) {
            $out = array();
            if (!defined(''CONGRUENCY_SQLITE'')) { return $out; }
            try {
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                if ($src === ''pages'') {
                    foreach ($db->query("SELECT DocumentID, Title FROM Documents ORDER BY DocumentID") as $r) {
                        $out[] = array($r[''DocumentID''], ($r[''Title''] !== null && $r[''Title''] !== '''') ? $r[''Title''] : $r[''DocumentID'']);
                    }
                } elseif ($src === ''categories'') {
                    foreach ($db->query("SELECT name FROM Categories ORDER BY name") as $r) {
                        $out[] = array($r[''name''], $r[''name'']);
                    }
                }
            } catch (\Throwable $e) { /* leave options empty; validation will reject */ }
            return $out;
        }

        public function getHTML() {
            $cur = $this->getInitial();
            $h = "<select name=''" . $this->id . "'' " . $this->getTabIndex() . ">";
            $h .= "<option value=''''>-- choose --</option>";
            foreach ($this->options as $o) {
                $v = $o[0]; $l = $o[1];
                $sel = ((string)$v === (string)$cur) ? " selected" : "";
                // labels may already hold HTML entities (e.g. Titles with &middot;) — decode then re-escape once
                $label = htmlspecialchars(html_entity_decode($l, ENT_QUOTES), ENT_QUOTES);
                $h .= "<option value=''" . htmlspecialchars($v, ENT_QUOTES) . "''$sel>" . $label . "</option>";
            }
            return $h . "</select>";
        }

        public function returnValue() {
            $d = $this->form->getFormData();
            return (isset($d[$this->id]) && $d[$this->id] !== '''') ? $d[$this->id] : null;
        }

        public function getInitial() { return $this->returnValue(); }

        public function failsExtendedValidation() {
            $v = $this->returnValue();
            if ($v === null) { return FALSE; }          // empty handled by the required check
            foreach ($this->options as $o) { if ((string)$o[0] === (string)$v) { return FALSE; } }
            return TRUE;                                 // value not among live options -> invalid
        }

        public function getOptions() { return $this->options; }   // #45: testability

        /* #45: $options are DB-derived from elementString (re-derivable), so they are NOT serialized.
           from_array sets elementString on the base directly (bypassing setElementString), so re-derive
           the option set here on rebuild. */
        protected function extraFromArray($extra) {
            if (isset($this->elementString)) {
                $this->setElementString($this->elementString);
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('2f957853c7d8cbc9f9c6de3e8e6e7ec96db31959','php',2167,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
if(!class_exists("FormConfigElement")){

	define("STYLE_REG","/<[sS]tyle\s?=\s?''.*?''\s?>/");
	define("ACTION_REG","/<[aA]ction\s?=\s?''.*?''\s?>/");
	define("ON_COMPLETE_REG","/<[oO]n\s?[cC]omplete\s?=\s?''.*?''\s?>/");
	define("INCOMPLETE_REG","/<[iI]ncomplete\s?=\s?''.*?''\s?>/");
	define("VALID_REG","/<[vV]alid\s?=\s?''.*?''\s?>/");
	define("INNER_EXPRESSION","/''.*(?=''\s?>)/");

	class FormConfigElement extends AbstractFormElement{

		public function __construct(){
		}
		
		public function getHTML(){
		}		

		public function returnValue(){
		}
		
		public function getInitial(){
		}
		
		public function failsExtendedValidation(){
			return FALSE;
		}
		
		public function setFormObject($form){
			$form->setStyle(self::parseStyleTag($this->getElementString()));
			$form->setAction(self::parseActionTag($this->getElementString()));
			$form->setOnComplete(self::parseOnCompleteTag($this->getElementString()));
			$form->setIncomplete(self::parseIncompleteTag($this->getElementString()));
			$form->setValid(self::parseValidTag($this->getElementString()));
			$form->formConfigElement($this);
		}
		
		
		public static function parseValidTag($validTag){
			return self::parseReg($validTag,VALID_REG);
		}
		
		public static function parseIncompleteTag($incompleteTag){
			return self::parseReg($incompleteTag,INCOMPLETE_REG);
		}
				
		public static function parseStyleTag($styleTag){
			return self::parseReg($styleTag,STYLE_REG);
		}
		
		public static function parseActionTag($styleTag){
			return self::parseReg($styleTag,ACTION_REG);
		}
		
		public static function parseOnCompleteTag($onComplete){
			return self::parseReg($onComplete,ON_COMPLETE_REG);
		}
		
		public static function parseReg($string,$expression){
			$matches = array();
			if(preg_match($expression,$string,$matches)){
				$match = $matches[0];
				$refinedMatch= array();
				preg_match(INNER_EXPRESSION,$match,$refinedMatch);
				return substr($refinedMatch[0],1);
			}else{
				return NULL;	
			}
		}		
	}
}');
INSERT INTO "code_blobs" VALUES('2217ed2022153f87efcf1391579eb6b61ecc2752','php',3263,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * MultiSelect — a multi-value checkbox group form element (ticket #44: more form elements).
 * Its elementString lists options in the same ''<<opt>><<opt>>'' format as RadioSelect (parsed with
 * FormElementUtils::parseRadioElementString). The field name is rendered as "ID[]" so PHP collects
 * the checked boxes into an array. returnValue() is the array of selected values (or null if none);
 * the option set doubles as the allowlist, so failsExtendedValidation rejects any submitted value
 * not among the options (same discipline as DbSelect). Produced from the forms table via
 * FormElementBean::produceElement (implements=''MultiSelect'').
 */
if (!class_exists("MultiSelect")) {
    class MultiSelect extends AbstractFormElement {

        private $options = array();

        public function __construct() {}

        public function setElementString($elementString) {
            $this->elementString = $elementString;
            $this->options = FormElementUtils::parseRadioElementString($elementString);
        }

        public function getOptions() { return $this->options; }

        public function getHTML() {
            $selected = (array) $this->getInitial();
            $h = "";
            $subElementCount = 1;
            $count = is_array($this->options) ? count($this->options) : 0;
            foreach ((array) $this->options as $option) {
                $checked = in_array((string) $option, array_map(''strval'', $selected), true) ? " checked=''checked''" : "";
                $tab = ($subElementCount === $count) ? " " . $this->getTabIndex() : "";
                $h .= "<input type=''checkbox'' name=''" . $this->id . "[]'' value=''"
                    . htmlspecialchars((string) $option, ENT_QUOTES) . "''" . $checked . $tab . ">"
                    . htmlspecialchars((string) $option, ENT_QUOTES) . "\n<br>\n";
                $subElementCount++;
            }
            return $h;
        }

        public function returnValue() {
            $d = $this->form->getFormData();
            $v = isset($d[$this->id]) ? $d[$this->id] : null;
            return (is_array($v) && count($v)) ? array_values($v) : null;
        }

        public function getInitial() { return $this->returnValue(); }

        public function failsExtendedValidation() {
            $sel = $this->returnValue();
            if ($sel === null) { return FALSE; }               // empty -> the required check owns it
            $allow = array_map(''strval'', (array) $this->options);
            foreach ($sel as $s) {
                if (!in_array((string) $s, $allow, true)) { return TRUE; }   // value not an option
            }
            return FALSE;
        }

        /* #45: $options are derived from elementString (re-derivable), so they are not serialized;
           from_array sets elementString on the base directly, so re-derive the option set on rebuild. */
        protected function extraFromArray($extra) {
            if (isset($this->elementString)) {
                $this->setElementString($this->elementString);
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('8b94a83a039e3492dae2ac0dd6f50b5b72cd6a53','php',3049,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * NumberField — a numeric <input type=number> form element (ticket #44: more form elements).
 * Optional min/max bounds are parsed from the elementString ("min=1;max=100" — either bound
 * optional, decimals allowed). failsExtendedValidation rejects non-numeric input and out-of-range
 * values; an empty value is left to the required check. Produced from the forms table via
 * FormElementBean::produceElement (implements=''NumberField'').
 */
if (!class_exists("NumberField")) {
    class NumberField extends AbstractFormElement {

        private $min = null;
        private $max = null;

        public function __construct() {}

        public function setElementString($elementString) {
            $this->elementString = $elementString;
            $this->min = self::bound($elementString, ''min'');
            $this->max = self::bound($elementString, ''max'');
        }

        private static function bound($s, $key) {
            if (preg_match(''/'' . $key . ''\s*=\s*(-?\d+(?:\.\d+)?)/i'', (string)$s, $m)) {
                return $m[1] + 0;
            }
            return null;
        }

        public function getMin() { return $this->min; }
        public function getMax() { return $this->max; }

        public function getHTML() {
            $cur  = $this->getInitial();
            $attr = "name=''" . $this->id . "'' " . $this->getTabIndex();
            if ($this->min !== null) { $attr .= " min=''" . $this->min . "''"; }
            if ($this->max !== null) { $attr .= " max=''" . $this->max . "''"; }
            $val  = ($cur !== null && $cur !== '''') ? " value=''" . htmlspecialchars((string)$cur, ENT_QUOTES) . "''" : "";
            return "<input type=''number'' " . $attr . $val . ">";
        }

        public function returnValue() {
            $d = $this->form->getFormData();
            return (isset($d[$this->id]) && $d[$this->id] !== '''') ? $d[$this->id] : null;
        }

        public function getInitial() { return $this->returnValue(); }

        public function failsExtendedValidation() {
            $v = $this->returnValue();
            if ($v === null) { return FALSE; }                 // empty -> the required check owns it
            if (!is_numeric($v)) { return TRUE; }              // non-numeric -> invalid
            $n = $v + 0;
            if ($this->min !== null && $n < $this->min) { return TRUE; }
            if ($this->max !== null && $n > $this->max) { return TRUE; }
            return FALSE;
        }

        /* #45: min/max are derived from elementString (re-derivable), so they are not serialized;
           from_array sets elementString on the base directly, so re-derive the bounds on rebuild. */
        protected function extraFromArray($extra) {
            if (isset($this->elementString)) {
                $this->setElementString($this->elementString);
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('e13e92c63c4d45aaeab3516ea837367985398ecd','php',1973,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
if(!class_exists("RadioSelect")){
	class RadioSelect extends AbstractFormElement{

		private $options;
		private $isChecked;

		public function __construct(){
		}
		
		public function getHTML(){
			$result = NULL;
			$subElementCount = 1;
			foreach($this->options as $option){
				$result .="<INPUT TYPE=''radio'' NAME=''".$this->id."'' VALUE=''". $option ."'' ". $this->testChecked($option,$subElementCount++).">";
				$result .= $option . "\n<br>\n";
			}
			return $result;
		}		
			
		public function returnValue(){
			$formElementResults = $this->form->getFormData();
			if(!empty($formElementResults[$this->id])){
				return $formElementResults[$this->id];
			}
		}
		
		public function failsExtendedValidation(){
			return FALSE;
		}
		
		public function getInitial(){
			return $this->returnValue();
		}
			
		public function getOptions(){
			return $this->options;
		}
		
		public function setOptions($elementString){
			$this->options = FormElementUtils::parseRadioElementString($elementString);
		}
		
		public function setElementString($elementString){
			$this->setOptions($elementString);	
		}
		
		private function testChecked($subElement,$subElCount){
			if($subElement == $this->getInitial()){
				$this->isChecked = TRUE;
				return "checked=''checked'' " . $this->getTabIndex();
			}else if(($subElCount == count($this->options))&& !$this->isChecked){
				return $this->getTabIndex();
			}
		}

		protected function extraToArray(){                       // #45
			return array(''options'' => $this->options, ''isChecked'' => $this->isChecked);
		}
		protected function extraFromArray($extra){               // #45
			$this->options   = isset($extra[''options''])   ? $extra[''options'']   : NULL;
			$this->isChecked = isset($extra[''isChecked'']) ? $extra[''isChecked''] : NULL;
		}
 	}

}
?>');
