INSERT INTO "code_blobs" VALUES('c22d8b152d87accf01d672fe0c6d791dfde9b65d','php',1800,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
if(!class_exists("FormElementUtils")){
	class FormElementUtils{	
	
		private function __construct(){}
		
		public static function parseRadioElementString($elementString){
			if(self::validateElementString($elementString)){
				$result = NULL;
				$working = explode(''>>'',$elementString);   // split() removed in PHP 7.0; ''>>'' is a literal, so explode() is equivalent
				$index = 0;
				$elements = count($working);
				unset($working[$elements - 1]); //For some reason an element is added to the end of the array I don''t know why.
				foreach($working as $field){
			 		$result[$index++] = substr($field,2);
				}
				return $result;
			}else{
				print ("<!--Error: Failed parsing form element string. Form element may not appear-->");
		
			}
		}
		
		//I removed some code that kept track of the number of fields identified here.
		public static function validateElementString($elementString){
			$result = TRUE;
			$working = explode(''>>'',$elementString);   // split() removed in PHP 7.0; ''>>'' is a literal, so explode() is equivalent
			$index = 0;
			$elements = count($working);
			$workingResult = NULL;
			unset($working[$elements - 1]);
			foreach($working as $field){
				if( $result && strlen($field) > 1){
			 		if (0 == substr_compare($field,"<<",0,2)){
			 			$workingResult[$index++] = substr($field,2);
			 		}else{	
						//(A) String Fails validation. More ''>>'' than ''<<''
						//		has form <<x>>*xxxx>>
						$result = FALSE;
			 		}
				}else{	
						//(B) String Fails validation. More ''>>'' than ''<<''
						//		has form <<x>>*>+
						$result = FALSE;
				}
			}	
	
			return $result;
		}	
	}
}
?>');
INSERT INTO "code_blobs" VALUES('ac4184f67dd270c0491e403064999fd301fa2a4c','php',3545,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/

/***************************
Goals:
	
FormManager.
The FormManager is a module level variable, which consolidates all Form objects.
	
	+To provide a layer of abstraction between the module and the Form system.
	Reduce coupling between the Form Module and any module that requires it.

	+Caches forms to reduce the number of database calls.
	
**********************/
if(!class_exists("FormManager")){
	define("FORM_LOAD_FAILURE","<!--FAILED TO LOAD FORM-->");
	class FormManager{
		private $formsArray;
		
		public function __construct(){
		}

		public function runForm($formId){
			$formString = NULL;
			$form = $this->loadForm($formId);
			if(isset($form)){
				$formString = $form->__toString();
			}else{
				$formString = FORM_LOAD_FAILURE;	
			}
			return $formString;
		}
					
		private function loadForm($formId){
			$form = $this->getCachedForm($formId);
			if(!isset($form)){
				$form = $this->lookupForm($formId);
			}
			return $form;
		}
		
		private function lookupForm($formId){
			$form = new StandardForm($formId);
			$this->produceForm($formId,$form);
			if(isset($form)){
				$this->formsArray[$formId] = $form;
				return $this->formsArray[$formId];
			}	
		}
		
		public function getCachedForm($formId){
			if(isset($this->formsArray[$formId])){
				$this->testRecalled($this->formsArray[$formId]);
				return $this->formsArray[$formId];
			}
		}
		
		public function getResults($formId){
			if(isset($this->formsArray[$formId])){
				return $this->formsArray[$formId]->getResults();	
			}else{
				return NULL;
			}			
		}
		
		public function setResults($formId,$formResults){
			if(!isset($this->formsArray[$formId])){
				$this->lookupForm($formId);
			}
			if(isset($this->formsArray[$formId])){
				$this->formsArray[$formId]->setResults($formResults);
			}
		}
		
		/*
			You can link away from an incomplete form...
			
			If you do, the partial results (often invalid) are stored in the 
			form. In effect anytime you return to the form you will encounter
			the incomplete data. 
			
			This is OK for forms that hold user data, maybe config forms, 
			but it''s not ok for the forms that are used for Admin.
			 
		*/
		private function testRecalled($form){
			$formData = $form->getFormData();
			if(!isset($formData[$form->getId()])){
				$form->reset();
			}	
		}
		

		/*
			There is no FormDAO Class...
		
			It''s not essential.
		
		*/
		private function produceForm($formName,&$form){
			if(isset($formName)){
				$formElementDAO = new FormElementDAO();
				$beansArray = $formElementDAO->obtainNRows($formName);
				if(!empty($beansArray)){
					foreach($beansArray as $element){
						$form->addElement($element->produceElement());
					}
				}else{
					$form = NULL;
				}
			}
		}

		/* #45: JSON (de)serialization for POM persistence — formsArray is an id-keyed map of StandardForm. */
		public function to_array(){
			$forms = array();
			if(!empty($this->formsArray)){
				foreach($this->formsArray as $id=>$form){
					$forms[$id] = $form->to_array();
				}
			}
			return array(''__class''=>''FormManager'', ''formsArray''=>$forms);
		}

		public static function from_array($a){
			$fm = new FormManager();
			$fm->formsArray = array();
			if(!empty($a[''formsArray''])){
				foreach($a[''formsArray''] as $id=>$fData){
					$fm->formsArray[$id] = StandardForm::from_array($fData);
				}
			}
			return $fm;
		}
	}		
}
?>');
INSERT INTO "code_blobs" VALUES('14d8f18534673ae6bcc071556fa73c67b9b68dfd','php',9329,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
if(!class_exists("StandardForm")){
	class StandardForm{
		private $id;			//id of Form. 
		private $methodType;	//HTML value GET or POST
		private $action;		//HTML value action=''...''
		private $classes;		//array: $classes[FormElementClass] == greater than zero if class is used.
		private $elementResults;	//recorded results for the form elements.
		private $formElements;	//array of form elements. An array of objects.
		private $onComplete;	//When the form is complete this message is displayed.
		private $incomplete;	//When the form is incomplete this message is displayed.
		private $valid;			//This message precedes any valid elements.
		private $isComplete;	//complete flag.
		private $isVerified;
		private $firstDisplay;
		private $sorter;

		private function validateForm(){
			if(!empty($this->formElements)){
				foreach($this->formElements as $element){
					if($element->failsValidation()){
						return FALSE;
					}	
				}
			}
			return TRUE;
		}
		
		private function pullResults(){
			if(!empty($this->formElements)){
				foreach($this->formElements as $element){
					$this->setElementResult($element->getId(),$element->returnValue());
				}
			}			
		}
		

		//Getters and setters.
		public function setValid($string){
			$this->valid = $string;	
		}
		
		public function getValid(){
			return $this->valid;	
		}
		
		public function setIncomplete($message){
			if(isset($message)){
			   $this->incomplete= $message;
			}
		}
		
		public function getIncomplete(){  
			return $this->incomplete;	
		}
		
		public function setOnComplete($onComplete){
			$this->onComplete=$onComplete;	
		}
				
		public function getOnComplete(){
			return $this->onComplete;	
		}
		
		public function formConfigElement($FCE){
			if(isset($this->formElements[$FCE->getId()])){
				unset($this->formElements[$FCE->getId()]);
			}
		}
						
		public function addElement($formElement){
			$this->formElements[$formElement->getId()] = $formElement;
			$formElement->setFormObject($this);
			$this->classes[get_class($formElement)] = NULL;
		}		
		
		public function getId(){
			return $this->id;
		}
		
		public function setID($ID){
			if(isset($ID)){
				$this->id = $ID;
			}else{
				$this->id = ''DEFAULT_FORM'';
			}			
		}
		
		public function obtainAction(){
			$this->isComplete = $this->validateForm();
			if(!$this->firstDisplay && $this->isComplete){
				return $this->action;
			}else{
				return NULL;	
			}
		}
		
		public function setAction($arg){
			$this->action = $arg;
		}

		public function setStyle($arg){
			$this->style=$arg;
		}
		
		public function getStyle(){
			return $this->style;
		}
		
		public function usePostMethod(){
			$this->methodType=''POST'';
		}
		
		public function getFormData(){
			if($this->methodType == "GET"){
				return $_GET;
			}else{
				return $_POST;
			}
		}
		
		public function getMethodType(){
			return $this->methodType;		
		}
		
		//get the results of a form. A value for each element.
		public function getResults(){
			return $this->elementResults;
		}

		public function setResults($resultsArray){
			$this->elementResults = $resultsArray;
		}
		
		//get the value for a particular element.
		public function getElementResult($id){
			if(isset($this->elementResults[$id])){
				return $this->elementResults[$id];
			}else{
				return NULL;
			}	
		}
		
		//set the value for a particular element.
		public function setElementResult($id,$value){
			$this->elementResults[$id] = $value;
		}
		
		/* #45: __wakeup removed — the POM no longer unserializes StandardForm (data is JSON via to_array/from_array);
		   the app autoloader loads element classes on demand. */
		
		public function __construct($ID){
			$this->usePostMethod();
			$this->setID($ID);
			$this->setResults(array());
			$this->firstDisplay = TRUE;
			$this->sorter = NULL;
			$this->incomplete= NULL;
		}
		
		private function getSorter(){
			if(!isset($this->sorter)){
				$this->sorter = new SortIterator();
				$this->sorter->setUnsorted($this->formElements);
			}
			$this->sorter->reset();
			return $this->sorter;	
		}
		
		private function finalElementStrings(){
			for($elementString=NULL,$sorter=$this->getSorter(),$element=$sorter->current();!$sorter->finished();$element=$sorter->next()){
				$elementString .= $element->finalString();	
			}
			return $elementString;
		}
			
		private function elementStrings(){
			$completeElements=$completeString=$incompleteString=NULL;
			$completeIndex=0;
			for($tabIndex=1,$sorter=$this->getSorter(),$element=$sorter->current();!$sorter->finished();$element=$sorter->next()){
				if($element->failsValidation()){
					$element->setTabIndex($tabIndex++);
					$incompleteString .= $element->__toString();
				}else{
					$completeElements[$completeIndex++] = $element;
				}	
			}
			$completeString = $this->stringComplete($completeElements,$tabIndex);			
			$completeString = $this->getValid().$completeString;
			return $incompleteString . $completeString;
		}
		
		private function stringComplete($completeElements,$tabIndex){
			$completeString = NULL;
			if(!empty($completeElements)){
				foreach($completeElements as $complete){
					$complete->setTabIndex($tabIndex++);
					$completeString .= $complete->__toString();
				}
			}
			return $completeString;
		}
				
		private function getElementStrings(){
			$elementStrings = NULL;
			if($this->firstDisplay){
				$elementStrings = $this->firstDisplay();
			}else{
				$this->pullResults();
				if($this->isComplete){
					$elementStrings = $this->getOnComplete();
					$elementStrings .= $this->finalElementStrings();
				}else{
					$elementStrings = $this->getIncomplete();
					$elementStrings .= $this->elementStrings();
				}
			}
			return $elementStrings;	
		}
		
		private function firstDisplay(){
			$elementString=NULL;
			for($tabIndex = 1,$sorter=$this->getSorter(),$element=$sorter->current();!$sorter->finished();$element=$sorter->next()){
				$element->setTabIndex($tabIndex++);
				$elementString .= $element->__toString();
			}
			$this->firstDisplay=FALSE;
			return $elementString;
		}
		
		public function __toString(){			
			$formString = "\n<form id=''".$this->getId()."'' action=''" . $this->obtainAction() . "'' method=''". $this->getMethodType() . "''>\n<br>\n";
			$formString .= $this->getElementStrings();
			$formString .= "\n<br>\n <input type=''hidden'' name=''". $this->getId() ."'' value=''1''>";
			$formString .= "\n<br>\n <input type=''submit'' value=''Continue''>";
			$formString .= "\n</form>";
			return $formString;
		}

		public function reset(){
			$this->isComplete=FALSE;
			$this->isVerified=FALSE;
			$this->firstDisplay=TRUE;
			$sorter = $this->getSorter();
			$sorter->reset();		
		}

		/* #45: plain-data (de)serialization for JSON-based POM persistence. formElements are stored as
		   an id-keyed map of each element''s to_array(); the transient $sorter is skipped (rebuilt lazily).
		   The FCE is already removed from formElements during build, so no config side effects on rebuild. */
		public function to_array(){
			$elements = array();
			if(!empty($this->formElements)){
				foreach($this->formElements as $key=>$el){
					$elements[$key] = $el->to_array();
				}
			}
			return array(
				''__class''        => ''StandardForm'',
				''id''             => $this->id,
				''methodType''     => $this->methodType,
				''action''         => $this->action,
				''onComplete''     => $this->onComplete,
				''incomplete''     => $this->incomplete,
				''valid''          => $this->valid,
				''style''          => isset($this->style) ? $this->style : NULL,
				''isComplete''     => $this->isComplete,
				''isVerified''     => $this->isVerified,
				''firstDisplay''   => $this->firstDisplay,
				''classes''        => $this->classes,
				''elementResults'' => $this->elementResults,
				''formElements''   => $elements,
			);
		}

		public static function from_array($a){
			$form = (new ReflectionClass(''StandardForm''))->newInstanceWithoutConstructor();
			$form->id             = isset($a[''id'']) ? $a[''id''] : NULL;
			$form->methodType     = isset($a[''methodType'']) ? $a[''methodType''] : ''POST'';
			$form->action         = isset($a[''action'']) ? $a[''action''] : NULL;
			$form->onComplete     = isset($a[''onComplete'']) ? $a[''onComplete''] : NULL;
			$form->incomplete     = isset($a[''incomplete'']) ? $a[''incomplete''] : NULL;
			$form->valid          = isset($a[''valid'']) ? $a[''valid''] : NULL;
			if(isset($a[''style''])){ $form->style = $a[''style'']; }
			$form->isComplete     = isset($a[''isComplete'']) ? $a[''isComplete''] : NULL;
			$form->isVerified     = isset($a[''isVerified'']) ? $a[''isVerified''] : NULL;
			$form->firstDisplay   = isset($a[''firstDisplay'']) ? $a[''firstDisplay''] : TRUE;
			$form->classes        = isset($a[''classes'']) ? $a[''classes''] : array();
			$form->elementResults = isset($a[''elementResults'']) ? $a[''elementResults''] : array();
			$form->sorter         = NULL;
			$form->formElements   = array();
			if(!empty($a[''formElements''])){
				foreach($a[''formElements''] as $key=>$elData){
					$el = AbstractFormElement::from_array($elData);
					if($el !== NULL){
						$form->formElements[$key] = $el;
						$el->setFormObject($form);
					}
				}
			}
			return $form;
		}
	}	
}
?>');
INSERT INTO "code_blobs" VALUES('030d6d024f625319577332eceb56920d148a9a26','php',916,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
if(!class_exists("FormElementList")){
	class FormElementList{

		private $elements;

		public function __construct(){
			$elDAO = new FormElementDAO();
			$this->elements = $elDAO->obtainAllRows();
			$this->organize();
		}

		public function __toString(){
			$listing = "";
			foreach($this->elements as $formName=>$formCollection){
				$listing .="<br><br>Form name: $formName<hr>\n";
				foreach($formCollection as $element){
					$listing .= $element->listing();
				}
			}
			return $listing;
		}
		
		private function organize(){
			if(!empty($this->elements)){
				foreach($this->elements as $element){
					$temp[$element->getFormName()][$element->getName()] = $element;	
				}
				$this->elements=$temp;				
			}	
		}		
	}
}
?>');
INSERT INTO "code_blobs" VALUES('9bdefb6ac76916bd3dba6891535756ced90665fa','php',1484,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
if ( !class_exists(''AbstractList'')){
   abstract class AbstractList{
	
 	   protected $database;
	   protected $fill;
	   protected $orderList;

	   protected abstract function obtainBean($arg);

	   protected function obtainList($table){
	      // #25 native PDO (was global mysql_query/num_rows/fetch_assoc)
	      $conn = DataConnection::CreateConnection(MYSQL_SERVER, MYSQL_CONT_DATABASE, CONTENT_LOGIN, CONTENT_PASSWORD);
	      $conn->open();
	      $result = $conn->query("SELECT * FROM $table ");
	      if ($result){
	         $this->fill = count($result->rows);
	         $count = 0;
	         foreach ($result->rows as $bean){
	            $this->orderList[ $count++ ] = $this->obtainBean( $bean );
	         }
	      }
	   }

	   protected function printList(){
	      if ($this->fill > 0){
	         $index = 0;
	         do{
	            $this->orderList[$index++]->table();
	   	     }while($index < $this->fill);
	      }else{
	         print("No Items.");
