INSERT INTO "code_blobs" VALUES('966f4f9bfb28357110c85779781d8308e4995a3d','php',2125,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
if(!class_exists("ProductDAO")){
	class ProductDAO extends AbstractDAO{
		
		public function __construct(){
			$this->table = "paw.product";
			$this->dataConnection = DataConnection::CreateConnection(MYSQL_SERVER,MYSQL_STORE_DATABASE,STORE_LOGIN,STORE_PASSWORD);   // BUG-02: open a connection like sibling DAOs
			$this->dataConnection->open();
		}

		public function obtainRow($key){
			$key = ValidateFields::validateNumericKey($key);
			if(isset($key)){
   	    		$selectString = "WHERE `key`=". $key;
				$rows = $this->select($selectString);
				$beansArray = $this->returnAllBeans($rows);
				return current($beansArray);
			}
		}
		
		public function obtainNRows($groupKey){
   	    	$groupKey = ValidateFields::validateNumericKey($groupKey);
   	    	$selectString = "WHERE `category`=".$groupKey;
			$rows = $this->select($selectString);
			return $this->returnAllBeans($rows);
		}
		
		public function obtainAllRows(){
			$rows = $this->select("");
			return $this->returnAllBeans($rows);
		}
		
		public function deleteRow($itemKey){
   	    	$itemKey = ValidateFields::validateNumericKey($itemKey);
			if(isset($itemKey)){
				$this->delete("WHERE `key`=$itemKey");
			}
		}
		
		public function insertRow($rowData){
			if(!empty($rowData)){
				foreach($rowData as &$value){
					$value = $this->quote($value);	
				}
				//$results[''index''] = "LAST_INSERT_ID()"; //MAGIC:: Seems as if mysql does this...
				$insertString = $this->buildInsertSQL($rowData);
				$this->query($insertString);
			}
		}
		
		public function updateRow($rowData){
			$this->deleteRow($rowData[''key'']);
			$this->insertRow($rowData);
		}


		public function getBean($row){
			$bean = new Product();
			$bean->setCategory($row[''category'']);
			$bean->setName($row[''name'']);
			$bean->setDescription($row[''description'']);
			$bean->setKey($row[''key'']);
			$bean->setPage($row[''page'']);
			$bean->setPicture($row[''picture'']);
			return $bean;
		} 

	}
}
?>');
INSERT INTO "code_blobs" VALUES('78c7b13e2ddee0598958d80572cf346a2f6924f2','php',1550,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
if(!class_exists("CategoryList")){
	class CategoryList{
		private $allCategories;

		public function __construct(){
			$this->getAllCategories();
		}

		public function __toString(){
			$listing = '''';
			for($index=0, $fill=count($this->allCategories); $index < $fill; $index++){
				$category = $this->allCategories[$index];
				$listing .= $category->catalog_string() . "<br /><br />";
			}
			return $listing;
		}

		private function getAllCategories(){
			$catDAO = new CatalogDAO();
			$this->instantiate_categories($catDAO->select_all_categories());
			
		}
		
		private function getSummary(){
			return "\n<br> <b>Available Categories: " . count($this->allCategories) . "</b><hr>";
		}
		
		private function getListing($bean){
			$categoryListing = "<br><br><A HREF=''?page=categoryMaker&categoryMaker=". $bean->getNumberKey() ."''>Edit</A>&nbsp;&nbsp;&nbsp;";			
			$categoryListing .= "Category: ". $bean->getName();
			return $categoryListing;
		}
		
		public function editorListing(){
			$listing = $this->getSummary();
			foreach($this->allCategories as $bean){
				$listing .= $this->getListing($bean);
			}
			return $listing;
		}
		
		private function instantiate_categories($assoc_arr){
			$this->allCategories = array();
			foreach ($assoc_arr as $cat_data){
				array_push($this->allCategories,Category::sql_assoc_array($cat_data));
			}			
		}		
	}
}
?>');
INSERT INTO "code_blobs" VALUES('d6a13ce35fed70b16d7bfaa7812ab76e9ece129b','php',2404,'<?php
