	}

	public function setComment($arg){
		$this->comment = $arg;
	}

	public function setClientEmail($arg){
		$this->clientEmail = $arg;
	}

	public function setDate($arg){
		$this->date = $arg;
	}

	public function setUnixKey($arg){
		$this->unixKey = $arg;
	}
	
	public function setRepComment($arg){
		$this->repComment = $arg;
	}


	public function toString(){
