			$this->getAllOrders();
		}

		public function __toString(){
			$listing = $this->getSummary();
			foreach($this->allOrders as $order){
				$listing .=  $this->orderMakerLink($order);	
			}
			return $listing;
		}

		private function getAllOrders(){
			$orderDAO = new OrderDAO();
