if(!class_exists("SortIterator")){
	define("MERGE_BASE_SIZE","1");
	class SortIterator{
		private $references;		
		private $unsorted;
		private $size;
		private $position;

		public function __construct(){
			$this->unsorted = NULL;
			$this->references = NULL;
			$this->size = 0;
			$this->position = 0;
		}
		
		public function setUnsorted($unsorted){
			$this->unsorted = $unsorted;
			$this->size = count($unsorted);
			if($this->size > 0){
				$this->position = 1;
				$this->mergeSort();
			}
		}

		public function getSorted(){
			return $this->references;
		}
		
		/**************************************************************\
		//These functions may not need to test if elements exist before 
		//pulling a value.
		/**************************************************************/
		public function current(){
			$currentValue = NULL;
			if( $this->size > 0){
				$currentValue = current($this->references);
			}
			return $currentValue;
		}

		public function reset(){
			$firstValue = NULL;
			if( $this->size > 0){
				$firstValue = reset($this->references);
				$this->position = 1;
			}
			return $firstValue;
		}

		public function next(){
			$nextValue = NULL;
			if( $this->size > 0){
				$nextValue = next($this->references);
				$this->position++;
			}
			return $nextValue;
		}
		
		public function finished(){
			return ($this->size < $this->position) || ($this->size < 1);	
		}

		private function compare($elOne,$elTwo){
			return $elOne->getCompareValue() < $elTwo->getCompareValue();
		}

		private function splitArray($arraySize){
			$mergeIndecies = (2 * $arraySize);
			$index = 0;
			while( $index < $this->size ){
				$this->merge($arraySize,$index);
				$index += $mergeIndecies;
			}
		}		
				
		private  function merge($numberOfEls,$lowerBound1){
			$lowerBound2 = $lowerBound1 + $numberOfEls;
			if($lowerBound2 < $this->size){
				$upperBound1 = $lowerBound1 + $numberOfEls -1;
				$upperBound2 = $upperBound1 + $numberOfEls;
				if($upperBound2 >= $this->size){
					$upperBound2 = $this->size -1;
				}
				$index1 = $lowerBound1;
				$index2 = $lowerBound2;
				$tempIndex = 0;
				while( ($index1 <= $upperBound1) && ($index2 <= $upperBound2) ){
					if($this->compare($this->references[$index1],$this->references[$index2])){
						$temp[$tempIndex++] = $this->references[$index1++];
					}else{
						$temp[$tempIndex++] = $this->references[$index2++];
					}
				}
				if(($index1 >= $upperBound1) && ($index2 <= $upperBound2 )){
					while($index2 <= $upperBound2){
						$temp[$tempIndex++] = $this->references[$index2++];
					}	
				}elseif(($index1 <= $upperBound1) && ($index2 >= $upperBound2 )){
					while($index1 <= $upperBound1){
						$temp[$tempIndex++] = $this->references[$index1++];
					}
				}
				$copyTempIndex = $lowerBound1;
				foreach($temp as $sorted){
					$this->references[$copyTempIndex++] = $sorted;
				}
			}	
		}

		private function mergeSort(){
			$this->prime();
			$mergeSize = MERGE_BASE_SIZE;
			while($mergeSize < $this->size){
				$this->splitArray($mergeSize);
				$mergeSize *= 2;
			}
		}
		
		private function prime(){
			$index = 0;
			foreach($this->unsorted as $unsorted){
				$this->references[$index++] = $unsorted;	
			}
		}
		
	}
}
?>');
INSERT INTO "code_blobs" VALUES('6f7b7c73d1362876ac213630ec89469b8eb98639','php',1756,'<?php 
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
if ( !class_exists(''TagArguments'')){
   class TagArguments{
       	private $arguments;
		private $count;

    	public static function argumentFactory($functionCall){
    		$tagArg = new TagArguments();
      		$tagArg->setArguments($tagArg->obtainArguments($functionCall));
      		return $tagArg;
		}

    
    	public function getArguments(){
    		return $this->arguments;
    	}

		public function top(){
			return end($this->arguments);
		}
		
		public function pop(){
			$this->count--;
			return array_pop($this->arguments);		
		}
		
		public function finished(){
			return ($this->count > 0);
		}

		private function __construct(){
			$this->count = 0;
		}

		private function setArguments($arg){
			$this->arguments = $arg;
			$this->count = 0;
        	foreach ($this->arguments as &$argument){
      			$argument = $this->removeParenthesis($argument);
      			$this->count++;
      		}
			$this->arguments = array_reverse($this->arguments);
			     	
    	}
	  
		private function obtainArguments($functionCall){
	  		preg_match_all(FUNCTION_ARGUMENT,$functionCall,$result);
			if(!empty($result)){
	  			return $result[0];  //return only complete matches!
			}
		}

		private function removeParenthesis($key){
			$length = strlen($key) - strlen("()");
			$newKey = substr($key,1,$length);
			return $newKey;
		}
		
		public function __toString(){
			$result = "Element Count " . count($this->arguments)."<hr />";
			if(!empty($this->arguments)){
				foreach ($this->arguments as $arg){
					$result	.= $arg . "<br />";
				}
			}
			return $result;	
		}
	}
}
?>');
INSERT INTO "code_blobs" VALUES('aad39c7664beae8a9c5f9cc9456da2e5f6aa2aed','php',1750,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
if(!class_exists("Tag_Parser")){
	class Tag_Parser{		
				
		private $tag;				//Full tag example: Foo(arg1)(arg2)
 		private $tag_arguments;		//Tag arguments arg1 and arg2. Contained in an argument wrapper class.
 		private $function_name;		//Name of the tag function to load. Foo
 		private $tag_invocation;	//Raw invocation string as received (declared: no dynamic property; PHP 8.2+)
		
		
		public static function get_tag_parser($full_tag){
			$tag_parser = new Tag_Parser();
			$tag_parser->initialize($full_tag);
			return $tag_parser;
		}
	
		private function __construct(){}
	
		
		public function initialize($tag_invocation){
			$this->tag_invocation = $tag_invocation;
			$this->tag = $this->extract_tag_name($this->tag_invocation);
			if(isset($this->tag)){
				$this->function_name = $this->get_tag_identifier($this->tag);
				$this->tag_arguments = TagArguments::argumentFactory($this->tag);
			}
		}
		
				
		public function extract_tag_name($tag){
			$prefix = strlen( KEY_PREFIX );
			$length = strlen($tag) - strlen( KEY_PREFIX.KEY_SUFFIX );
			$newKey = substr($tag,$prefix,$length); 
			return $newKey;
		}
		
				
		public function get_tag_identifier($tagString){
			preg_match(GET_TAG_IDENTIFIER,$tagString,$matches);
			if(isset($matches[0])){
				return $matches[0];
			}else{
				return NULL;	
			}
		}
		
		
		public function get_full_tag(){
			return $this->tag;
		}
		
		
		public function get_tag_arguments(){
			return $this->tag_arguments;	
		}
		
		
		public function get_function_name(){
			return $this->function_name;	
		}
			
	}
}
?>
');
INSERT INTO "code_blobs" VALUES('bbbfc23dce3ddc222dbf5ea3107a9e5f6e1c220a','php',2729,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
 if(!class_exists("Tag_Wrapper")){
  	class Tag_Wrapper {
 		private $tag_parser;
 		private $children;
 		private $invocation_string;
 		private $tag; 			
 			
 		/////////////////////invocation	
 		private function __construct(){
 			$this->children = array();
 		}

		public static function create_document_tag($document){
			$document_wrapper = new Tag_Wrapper();
			$document_wrapper->tag = $document;
			return $document_wrapper;
		}
 
 		private static function get_tag_wrapper($invocation_string){
 			$tag_wrapper = new Tag_Wrapper();
 			$tag_wrapper->tag_parser =  Tag_Parser::get_tag_parser($invocation_string);
 			$tag_class = $tag_wrapper->tag_parser->get_function_name();
 			$tag_loader = PersistentObjectManager::getData("TAG_LOADER");
 			$tag_loader->loadClassByName($tag_class);
 			$tag_wrapper->tag = new $tag_class($tag_wrapper->tag_parser->get_tag_arguments());
 			return $tag_wrapper;
  		}
  		
  		///////////////////////////////////////////////////  		
  		public function __toString(){
  			return $this->tag->__toString();	
  		}		
 		
 		public function add_child($invocation_string){
 			//Create a new Tag_Wrapper and tag as well.
 			$tag_wrapper = Tag_Wrapper::get_tag_wrapper($invocation_string);
 			array_push($this->children,$tag_wrapper);
 			return $tag_wrapper;			
 		}
 		
 		public function get_invocation_string(){
 			return $this->invocation_string;	
 		}
 
 		private static function replace_tag($document_string, $replacement_string, $invocation_string ){
			return str_replace( $invocation_string, $replacement_string, $document_string);
		} 
				
		private function identify_tag($document_string){
			$tags = array();
			$matchPattern = TAG_KEY_PREFIX . FUNCTION_NAME . FUNCTION_ARGUMENTS . TAG_KEY_SUFFIX;
			preg_match_all($matchPattern,$document_string,$tags);
			$tags = $tags[0];
			return $tags;
		}
						
		public static function execute_all_tags($tag_wrapper, $depth = 0){
			$result_string = $tag_wrapper->tag->get_document(); //The tag is processed. 
			if ($depth >= 64) { return $result_string; }   // BUG-06: bound tag-render recursion (real nesting <=~6); leave nested tags literal
			$document_string = $result_string;
			$tIA = $tag_wrapper->identify_tag($document_string);
			foreach($tIA as $tag_invocation){
				$child_tag = $tag_wrapper->add_child($tag_invocation);
				$result_substring = self::execute_all_tags($child_tag, $depth + 1);
				$result_string = self::replace_tag($result_string,$result_substring,$tag_invocation);
			}
			return $result_string;
		}		
 	}
 }
?>
');
