INSERT INTO "code_blobs" VALUES('cea88c23bfc6f5cf9882c22609ce06a218ac3e8a','python',6308,'#!/usr/bin/env python3
"""crawl.py — a background web-spider for the congruency site.

BFS over every link on every page starting from the site root: follows all INTERNAL
links, records HTTP status, flags BROKEN links (a ?page=X whose X is not a real Document,
or any non-200), lists EXTERNAL links, tracks which page each link was found on, and
writes a report (human text to stdout + JSON to --report).

The site returns HTTP 200 for unknown pages (it falls back to the ''invalid'' Document), so
"broken" is decided by the page allowlist, fetched live from the REST API (?api=Documents)
— not by status code alone.

    python3 tools/crawl.py                         # crawl http://127.0.0.1:8899
    python3 tools/crawl.py --base http://127.0.0.1:8899 --report /tmp/crawl.json
    python3 tools/crawl.py --check-external        # also HEAD-check external links (needs network)
"""
import argparse, json, re, sys, time
import urllib.parse, urllib.request, urllib.error
from collections import deque, defaultdict

HREF = re.compile(r''href=[\''"]([^\''"]+)[\''"]'', re.I)


def fetch(url, timeout=10, method="GET"):
    try:
        req = urllib.request.Request(url, method=method)
        with urllib.request.urlopen(req, timeout=timeout) as r:
            body = r.read().decode("utf-8", "replace") if method == "GET" else ""
            return r.status, body, r.headers.get("Content-Type", "")
    except urllib.error.HTTPError as e:
        return e.code, "", ""
    except Exception as e:  # noqa: BLE001
        return None, "%r" % e, ""


def valid_pages(base):
    """The page allowlist, straight from the REST API."""
    st, body, _ = fetch(base + "/?api=Documents&per=500")
    ids = set()
    if st == 200:
        try:
            for row in json.loads(body).get("rows", []):
                ids.add(row.get("DocumentID"))
        except Exception:  # noqa: BLE001
            pass
    return ids


def crawl(base, check_external):
    host = urllib.parse.urlparse(base).netloc
    pages = valid_pages(base)
    seen, ext_seen = set(), {}
    refs = defaultdict(set)                    # link -> set(pages it was found on)
    result = {}                                # internal url -> {status, broken, reason, nlinks}
    broken = []
    q = deque(["/?page=catalog", "/"])

    while q:
        path = q.popleft()
        url = urllib.parse.urljoin(base + "/", path)
        pr = urllib.parse.urlparse(url)
        if pr.netloc and pr.netloc != host:                         # external
            if url not in ext_seen:
                ext_seen[url] = fetch(url, timeout=5, method="HEAD")[0] if check_external else "not-checked"
            continue
        norm = pr.path + (("?" + pr.query) if pr.query else "")
        if norm in seen:
            continue
        seen.add(norm)

        status, body, ctype = fetch(url)
        qs = urllib.parse.parse_qs(pr.query)
        page_param = qs.get("page", [None])[0]
        broken_flag, reason = False, None
        if status != 200:
            broken_flag, reason = True, "HTTP %s" % status
        elif page_param is not None and pages and page_param not in pages:
            broken_flag, reason = True, "no such page ''%s'' (falls back to invalid)" % page_param

        found = HREF.findall(body) if "html" in ctype.lower() or body.lstrip().startswith("<") else []
        result[norm] = {"status": status, "broken": broken_flag, "reason": reason, "nlinks": len(found)}
        if broken_flag:
            broken.append({"url": norm, "reason": reason, "found_on": sorted(refs.get(norm, []))})

        for href in found:
            if href.startswith(("mailto:", "javascript:", "#")):
                continue
            tgt = urllib.parse.urljoin(url, href)
            tp = urllib.parse.urlparse(tgt)
            tnorm = tp.path + (("?" + tp.query) if tp.query else "")
            if not tp.netloc or tp.netloc == host:
                refs[tnorm].add(norm)
                if tnorm not in seen:
                    q.append(tnorm)
            else:
                refs[tgt].add(norm)
                if tgt not in ext_seen:
                    q.append(tgt)

    return {
        "base": base, "valid_pages": sorted(pages),
        "internal": result, "broken": broken,
        "external": [{"url": u, "status": s, "found_on": sorted(refs.get(u, []))} for u, s in sorted(ext_seen.items())],
    }


def report(data):
    r = data["internal"]
    ok = sum(1 for v in r.values() if not v["broken"])
    bad = len(data["broken"])
    lines = []
    lines.append("=== congruency crawl report — %s ===" % data["base"])
    lines.append("crawled %d internal URLs  (ok: %d, broken: %d)  |  valid pages: %d  |  external links: %d"
                 % (len(r), ok, bad, len(data["valid_pages"]), len(data["external"])))
    lines.append("")
    lines.append("BROKEN LINKS (%d):" % bad)
    if not data["broken"]:
        lines.append("  none ✓")
    for b in data["broken"]:
        lines.append("  %-40s  %s" % (b["url"], b["reason"]))
        lines.append("      found on: %s" % ", ".join(b["found_on"]))
    lines.append("")
    lines.append("EXTERNAL LINKS (%d):" % len(data["external"]))
    for e in data["external"]:
        lines.append("  [%s] %s" % (e["status"], e["url"]))
        lines.append("      found on: %s" % ", ".join(e["found_on"]))
    lines.append("")
    lines.append("INTERNAL URLS (%d):" % len(r))
    for u in sorted(r):
        v = r[u]
        flag = "BROKEN" if v["broken"] else "ok"
        lines.append("  %-6s %-3s  links=%-3s  %s" % (flag, v["status"], v["nlinks"], u))
    return "\n".join(lines)


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--base", default="http://127.0.0.1:8899")
    ap.add_argument("--report", default="")
    ap.add_argument("--check-external", action="store_true")
    a = ap.parse_args()
    t0 = time.time()
    data = crawl(a.base.rstrip("/"), a.check_external)
    data["elapsed_sec"] = round(time.time() - t0, 2)
    print(report(data))
    print("\n(%d URLs in %.1fs)" % (len(data["internal"]), data["elapsed_sec"]))
    if a.report:
        with open(a.report, "w") as f:
            json.dump(data, f, indent=2)
        print("JSON report: %s" % a.report)
    return 1 if data["broken"] else 0


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('295afef8273c5e24d35dd8aeeb43931a835efb68','python',5107,'#!/usr/bin/env python3
"""deploy_lifecycle_check.py -- verify the production deploy lifecycle end-to-end.

Drives deploy.py (which lives on branch `main`, beside install.py) through the full
ON -> SERVE -> OFF -> REDEPLOY cycle in an ISOLATED git worktree, so the caller''s working
tree and branch are never touched. Regression gate for ticket #26.

    python3 tools/deploy_lifecycle_check.py            # latest version-* tag
    DEPLOY_TEST_VERSION=4.078 python3 tools/deploy_lifecycle_check.py

Exit 0 iff every transition verifies (>=4 checks pass). Self-contained (stdlib only).
"""
import os
import re
import shutil
import signal
import socket
import subprocess
import sys
import tempfile
import time
import urllib.request

HERE = os.path.dirname(os.path.abspath(__file__))                 # checkouts/current/tools
ROOT = os.path.abspath(os.path.join(HERE, "..", "..", ".."))     # the package/repo root
PHP = os.path.join(ROOT, "tooling", "congruencey-harness", "php", "php")


def sh(args, cwd=None):
    return subprocess.run(args, cwd=cwd or ROOT, capture_output=True, text=True)


def free_port():
    s = socket.socket(); s.bind(("127.0.0.1", 0)); p = s.getsockname()[1]; s.close(); return p


def probe(port):
    try:
        r = urllib.request.urlopen("http://127.0.0.1:%d/?page=catalog" % port, timeout=5)
        return r.status, r.read(4000).decode("utf-8", "replace")
    except Exception as e:  # noqa: BLE001
        return None, type(e).__name__


def latest_version():
    tags = sh(["git", "tag", "-l", "version-*"]).stdout.split()
    vers = [t[len("version-"):] for t in tags]

    def key(v):
        try:
            return tuple(int(x) for x in v.split("."))
        except Exception:  # noqa: BLE001
            return ()
    if not vers:
        raise SystemExit("no version-* tags found")
    return sorted(vers, key=key)[-1]


def main():
    version = os.environ.get("DEPLOY_TEST_VERSION") or latest_version()
    port = free_port()
    work = tempfile.mkdtemp(prefix="deploy_lc_")
    wt = os.path.join(work, "wt")
    target = os.path.join(work, "target")
    results = []
    served_pid = None

    def check(name, ok, detail=""):
        results.append(ok)
        print("  %s  %s%s" % ("PASS" if ok else "FAIL", name, ("  [%s]" % detail) if detail else ""))

    try:
        # isolated worktree on `main` (where deploy.py lives) -> caller''s tree untouched
        r = sh(["git", "worktree", "add", wt, "main"])
        if r.returncode != 0:
            check("worktree add main", False, r.stderr.strip()[:120]); return 1
        # symlink the provisioned php so deploy''s provision step skips the download
        os.makedirs(os.path.join(wt, "tooling", "congruencey-harness", "php"), exist_ok=True)
        link = os.path.join(wt, "tooling", "congruencey-harness", "php", "php")
        if not os.path.exists(link) and os.path.isfile(PHP):
            os.symlink(PHP, link)
        deploy = os.path.join(wt, "deploy.py")
        if not os.path.isfile(deploy):
            check("deploy.py present on main", False, "missing"); return 1

        # ON -- deploy a fresh production target and self-verify (stub up, dev content gone)
        r = sh(["python3", deploy, "--target", target, "--version", version, "--port", str(port)])
        last = (r.stdout.strip().splitlines() or [""])[-1]
        check("ON: deploy verifies (exit0 + ''deploy OK'')",
              r.returncode == 0 and "production deploy OK" in r.stdout,
              last[:80] if r.returncode else "")

        # SERVE -- detached server on the pinned config port
        r = sh(["python3", deploy, "--serve", "--target", target])
        m = re.search(r"pid (\d+)", r.stdout)
        served_pid = int(m.group(1)) if m else None
        time.sleep(2)
        s, b = probe(port)
        check("SERVE: up (200 + stub ''Welcome'')", s == 200 and "Welcome" in b, "status=%s" % s)

        # OFF -- stop the server; the port must go dead
        if served_pid:
            try:
                os.kill(served_pid, signal.SIGTERM)
            except Exception:  # noqa: BLE001
                pass
            time.sleep(1.5)
        s, _ = probe(port)
        check("OFF: server down after stop", s is None, "resp=%s" % s)
        if s is None:
            served_pid = None

        # REDEPLOY -- same target: idempotent reuse (no rebuild) + re-verify
        r = sh(["python3", deploy, "--target", target, "--version", version, "--port", str(port)])
        check("REDEPLOY: idempotent (reused + exit0)",
              r.returncode == 0 and "target reused" in r.stdout, "")
    finally:
        if served_pid:
            try:
                os.kill(served_pid, signal.SIGKILL)
            except Exception:  # noqa: BLE001
                pass
        sh(["git", "worktree", "remove", "--force", wt])
        shutil.rmtree(work, ignore_errors=True)

    npass = sum(1 for ok in results if ok)
    n = len(results)
    print("deploy lifecycle: %d/%d transitions verified (version-%s)" % (npass, n, version))
    return 0 if (npass == n and n >= 4) else 1


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('1014720bc252914cac96ac0dffe966260ec94633','python',11994,'#!/usr/bin/env python3
"""doc_watch.py -- file a "documentation may be stale" ticket when a commit changes code but no doc.

An outside-the-app observer of commits. For each commit where a SCRIPT (.php/.py) changed but NO doc
(.md/.txt) was touched in that same commit, it maps the changed code area -> the specific doc(s) likely
now stale (a dir->doc map) and opens/append a `documentation` ticket in the unified jazz tracker
(~/.jazz/congruency.sqlite). One OPEN ticket per doc (deduped by meta.doc); each commit is recorded once
(meta.commits), so the standalone tool and the post-commit hook converge without duplicates.

Registry-gated (walks up to registry.json), python-only, best-effort (never blocks a commit).

    python3 tools/doc_watch.py                 # watermark..HEAD  (HEAD only on first run)
    python3 tools/doc_watch.py --commit <sha>  # one commit (used by the post-commit hook)
    python3 tools/doc_watch.py --head          # HEAD only
    python3 tools/doc_watch.py --since <ref>   # ref..HEAD  (batch catch-up)
    python3 tools/doc_watch.py --dry-run       # classify + print, write nothing
    python3 tools/doc_watch.py --install-hook  # drop a post-commit hook that calls --head
"""
import argparse
import json
import os
import subprocess
import sys
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None   # repo root (dir of registry.json); set in main()

# code areas whose change implicates a doc (longest-prefix wins per file)
DOC_MAP = [
    ("checkouts/current/boot/",         ["DEPENDENCIES.md", "DEPLOY.md", "checkouts/current/ARCHITECTURE.md"]),
    ("checkouts/current/state/",        ["DEPLOY.md", "DEPENDENCIES.md"]),
    ("checkouts/current/invocators/",   ["checkouts/current/ARCHITECTURE.md", "checkouts/current/doc/CMS_ADDITIONS.md"]),
    ("checkouts/current/lib/",          ["checkouts/current/ARCHITECTURE.md"]),
    ("checkouts/current/bin/",          ["checkouts/current/ARCHITECTURE.md"]),
    ("checkouts/current/www/",          ["checkouts/current/ARCHITECTURE.md"]),
    ("checkouts/current/tools/",        ["checkouts/current/tools/README.md"]),   # + filename special-cases
    ("checkouts/current/versioning/",   ["checkouts/current/versioning/README.md"]),
    ("checkouts/current/fixes/",        ["checkouts/current/fixes/README.md"]),
    ("checkouts/current/tests/parser/", ["checkouts/current/tests/parser/README.md"]),
    ("tracker/",                        ["tracker/SIGNALS.md"]),
    ("tooling/coverage/",               ["tooling/coverage/README.md", "tooling/README.md"]),
    ("tooling/pwdriver/",               ["tooling/pwdriver/README.md", "tooling/README.md"]),
    ("ENTRY_POINT.py",                  ["README.md"]),
    ("registry.json",                   ["README.md"]),
    ("note-for-claude",                 ["README.md"]),
]
FALLBACK_CODE = "checkouts/current/ARCHITECTURE.md"     # code under the app tree with no better hit
GENERIC = "__generic__"                                  # anything else -> a generic "review docs" ticket
IGNORE_SUBSTR = ("tooling/congruencey/", "tooling/tournament-", "/vendor/")   # frozen / vendored snapshots
SCRIPT_EXT = (".php", ".py")
DOC_EXT = (".md", ".txt")


# ---------------------------------------------------------------- registry + jazz
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def _jazz(reg):
    """Best-effort import of the canonical ticket writer (same package predict.py/mint_crank.py use)."""
    for cand in (os.path.join(os.path.dirname(reg["__root__"]), "jazz_telemetry"),                    # .../packages/jazz_telemetry
                 os.path.join(os.path.dirname(os.path.dirname(reg["__root__"])), "jazz_telemetry")):  # predict.py''s shim path
        if os.path.isdir(cand) and cand not in sys.path:
            sys.path.insert(0, cand)
    try:
        from jazz_telemetry import open_ticket, update_ticket, tickets, get_ticket
        return {"open_ticket": open_ticket, "update_ticket": update_ticket,
                "tickets": tickets, "get_ticket": get_ticket}
    except Exception as e:  # noqa: BLE001
        sys.stderr.write("[doc_watch] jazz_telemetry unavailable: %r\n" % e)
        return None


# ---------------------------------------------------------------- git helpers
def git(*args):
    return subprocess.run(["git"] + list(args), cwd=ROOT, capture_output=True, text=True).stdout.strip()


def resolve(ref):
    return git("rev-parse", ref)


def commits_in_range(start, end="HEAD"):
    out = git("rev-list", "--reverse", "%s..%s" % (start, end))
    return out.split() if out else []


def changed_files(sha):
    out = git("diff-tree", "--no-commit-id", "--name-only", "-r", sha)
    return out.splitlines() if out else []


def subject(sha):
    return git("log", "-1", "--format=%s", sha)


# ---------------------------------------------------------------- classification
def ignored(path):
    return any(s in path for s in IGNORE_SUBSTR)


def docs_for(path):
    best = None
    for prefix, docs in DOC_MAP:
        if path.startswith(prefix) and (best is None or len(prefix) > len(best[0])):
            best = (prefix, docs)
    if best is not None:
        docs = list(best[1])
        if best[0] == "checkouts/current/tools/":
            base = os.path.basename(path)
            if base in ("provision_php.py", "predict.py"):
                docs.append("DEPENDENCIES.md")
            if base in ("crawl.py", "tagcheck.py"):
                docs.append("checkouts/current/doc/CMS_ADDITIONS.md")
        return docs
    if path.startswith("checkouts/current/") and path.endswith(SCRIPT_EXT):
        return [FALLBACK_CODE]
    return [GENERIC]


# ---------------------------------------------------------------- dedup state
def load_open_docs(jazz):
    """map implicated-doc -> {id, meta, body} for OPEN documentation tickets already filed by doc_watch."""
    out = {}
    if not jazz:
        return out
    for t in jazz["tickets"]("OPEN"):
        if t.get("component") != "documentation":
            continue
        full = jazz["get_ticket"](t["id"])
        if not full:
            continue
        meta = full.get("meta")
        if isinstance(meta, dict) and meta.get("doc"):
            out[meta["doc"]] = {"id": full["id"], "meta": meta, "body": full.get("body") or ""}
    return out


def title_for(doc):
    return "Docs may be stale: %s" % ("review documentation" if doc == GENERIC else doc)


def process_commit(sha, jazz, open_docs, write):
    files = [f for f in changed_files(sha) if not ignored(f)]
    scripts = [f for f in files if f.endswith(SCRIPT_EXT)]
    docs_touched = [f for f in files if f.endswith(DOC_EXT)]
    if not scripts or docs_touched:
        return []   # trigger only on "code changed, docs didn''t"
    implicated = {}
    for s in scripts:
        for d in docs_for(s):
            implicated.setdefault(d, set()).add(s)
    subj = subject(sha)
    actions = []
    for doc in sorted(implicated):
        scr = sorted(implicated[doc])
        line = "%s %s -- scripts: %s" % (sha[:9], subj, ", ".join(scr))
        if doc in open_docs:
            t = open_docs[doc]
            commits = list(t["meta"].get("commits", []))
            if sha in commits:
                actions.append(("skip", doc, t["id"]))
                continue
            commits.append(sha)
            body = (t["body"] + "\n" + line).strip()
            if write:
                jazz["update_ticket"](t["id"], body=body, doc=doc, commits=commits, source="doc_watch")
            t["meta"]["commits"] = commits
            t["body"] = body
            actions.append(("append", doc, t["id"]))
        else:
            tid = "(dry)"
            if write:
                tid = jazz["open_ticket"](title_for(doc), component="documentation", severity="low",
                                          body=line, doc=doc, commits=[sha], source="doc_watch")
            open_docs[doc] = {"id": tid, "meta": {"doc": doc, "commits": [sha]}, "body": line}
            actions.append(("open", doc, tid))
    return actions


# ---------------------------------------------------------------- watermark + hook
def watermark_path(reg):
    return os.path.join(reg["__root__"], "logs", "doc_watch.json")


def read_watermark(reg):
    try:
        return json.load(open(watermark_path(reg))).get("last_seen")
    except Exception:  # noqa: BLE001
        return None


def write_watermark(reg, sha):
    try:
        p = watermark_path(reg)
        os.makedirs(os.path.dirname(p), exist_ok=True)
        json.dump({"last_seen": sha, "updated": datetime.now().isoformat()}, open(p, "w"), indent=2)
    except Exception:  # noqa: BLE001
        pass


HOOK = """#!/usr/bin/env python3
# doc_watch post-commit hook (installed by `doc_watch.py --install-hook`). Best-effort; never blocks.
import subprocess, sys, os
try:
    root = subprocess.run(["git", "rev-parse", "--show-toplevel"],
                          capture_output=True, text=True, timeout=10).stdout.strip()
    tool = os.path.join(root, "checkouts", "current", "tools", "doc_watch.py")
    if root and os.path.isfile(tool):
        subprocess.run([sys.executable, tool, "--head"], timeout=30)
except Exception:
    pass
"""


def install_hook(reg):
    gitdir = git("rev-parse", "--absolute-git-dir")
    hooks = os.path.join(gitdir, "hooks")
    os.makedirs(hooks, exist_ok=True)
    path = os.path.join(hooks, "post-commit")
    with open(path, "w") as fh:
        fh.write(HOOK)
    os.chmod(path, 0o755)
    print("installed post-commit hook -> %s  (runs doc_watch.py --head after each commit)" % path)
    return 0


# ---------------------------------------------------------------- main
def main():
    global ROOT
    ap = argparse.ArgumentParser(description="file a documentation-stale ticket when code changes without a doc update")
    ap.add_argument("--commit", help="inspect a single commit")
    ap.add_argument("--head", action="store_true", help="inspect HEAD only")
    ap.add_argument("--since", help="inspect <ref>..HEAD")
    ap.add_argument("--dry-run", action="store_true", help="classify + print, write nothing")
    ap.add_argument("--install-hook", action="store_true", help="install the post-commit hook and exit")
    a = ap.parse_args()

    reg = load_registry()
    ROOT = reg["__root__"]

    if a.install_hook:
        return install_hook(reg)

    if a.head or a.commit:
        commits = [resolve(a.commit or "HEAD")]
    elif a.since:
        commits = commits_in_range(a.since)
    else:
        wm = read_watermark(reg)
        commits = commits_in_range(wm) if wm else [resolve("HEAD")]

    jazz = _jazz(reg)
    write = (not a.dry_run) and (jazz is not None)
    open_docs = load_open_docs(jazz)

    actions = []
    for sha in commits:
        actions += process_commit(sha, jazz, open_docs, write)

    for kind, doc, tid in actions:
        print("  %-7s %-45s ticket %s" % (kind, doc, tid))
    tag = " [dry-run]" if a.dry_run else ("" if write else " [no jazz_telemetry — not written]")
    print("doc_watch: %d commit(s), %d action(s)%s" % (len(commits), len(actions), tag))

    # advance the watermark only for modes that logically processed up to HEAD (not a targeted --commit)
    if write and commits and a.commit is None:
        write_watermark(reg, resolve("HEAD"))
    return 0


if __name__ == "__main__":
    try:
        sys.exit(main())
    except Exception as e:  # noqa: BLE001  -- best-effort: never crash a commit hook
        sys.stderr.write("[doc_watch] %r\n" % e)
        sys.exit(0)
');
INSERT INTO "code_blobs" VALUES('cc9e3604de6ad9477e0966330afc654cd4b32d9b','php',10994,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * formelement_roundtrip.php -- #45 gate.
 *
 * Asserts each form element''s to_array()/from_array() round-trips through JSON with its state
 * preserved (the circular $form back-reference is intentionally dropped and rewired on rebuild).
 * Extended one element per crank as the POM moves off PHP serialize() to JSON. Exit 0 iff all pass.
 *
 *     tooling/congruencey-harness/php/php checkouts/current/tools/formelement_roundtrip.php
 */
error_reporting(E_ALL & ~E_DEPRECATED);
$B = dirname(__DIR__) . ''/lib/Modules/Constructs/Form/FormElements/'';
require $B . ''Lib/FormElementInterface.php'';
require $B . ''Lib/FormElementUtils.php'';
require $B . ''Lib/AbstractFormElement.php'';
require $B . ''BasicElements/RadioSelect.php'';
require $B . ''BasicElements/TextBox.php'';
require $B . ''BasicElements/TextField.php'';
require $B . ''BasicElements/BigTextBox.php'';
require $B . ''BasicElements/DbSelect.php'';
require $B . ''BasicElements/Checkbox.php'';
require $B . ''BasicElements/FormConfigElement.php'';
require $B . ''BasicElements/NumberField.php'';
require $B . ''BasicElements/DateField.php'';
require $B . ''BasicElements/MultiSelect.php'';
require $B . ''../FormLogic/StandardForm.php'';
require $B . ''../FormInterface/FormManager.php'';

// DbSelect is DB-backed; point CONGRUENCY_SQLITE at the install DB so its options load
$__cfg = dirname(__DIR__) . ''/install.json'';
if (is_file($__cfg)) {
    $__j = json_decode(file_get_contents($__cfg), true);
    if (!empty($__j[''CONGRUENCY_SQLITE''])) { define(''CONGRUENCY_SQLITE'', $__j[''CONGRUENCY_SQLITE'']); }
}

$pass = 0; $fail = 0;
function check($name, $ok) {
    global $pass, $fail;
    echo ($ok ? "  PASS  " : "  FAIL  ") . $name . "\n";
    $ok ? $pass++ : $fail++;
}
function roundtrip($el) {
    return AbstractFormElement::from_array(json_decode(json_encode($el->to_array()), true));
}

// --- RadioSelect ---
$r = new RadioSelect();
$r->setId(''type''); $r->setSelectionComment(''Type:''); $r->setRequired(true);
$r->setOrder(1); $r->setTabIndex(1);
$r->setElementString(''<<build>><<bug>><<design>>'');
$b = roundtrip($r);
check(''RadioSelect round-trips (class/id/options/required/order)'',
      $b instanceof RadioSelect && $b->getId() === ''type''
      && $b->getOptions() == $r->getOptions() && $b->getRequired() === true
      && $b->getCompareValue() == 1);

// --- TextBox (no element-specific state; base fields only) ---
$t = new TextBox();
$t->setId(''description''); $t->setSelectionComment(''Description:''); $t->setRequired(false);
$t->setOrder(2); $t->setTabIndex(2);
$b = roundtrip($t);
check(''TextBox round-trips (class/id/comment/order via base)'',
      $b instanceof TextBox && $b->getId() === ''description'' && $b->getCompareValue() == 2);

// --- TextField (no element-specific state; base fields only) ---
$tf = new TextField();
$tf->setId(''email''); $tf->setSelectionComment(''Email:''); $tf->setRequired(true);
$tf->setOrder(3); $tf->setTabIndex(3);
$b = roundtrip($tf);
check(''TextField round-trips (class/id/required/order via base)'',
      $b instanceof TextField && $b->getId() === ''email'' && $b->getRequired() === true && $b->getCompareValue() == 3);

// --- BigTextBox (no element-specific state; base fields only) ---
$bt = new BigTextBox();
$bt->setId(''body''); $bt->setSelectionComment(''Body:''); $bt->setOrder(4); $bt->setTabIndex(4);
$b = roundtrip($bt);
check(''BigTextBox round-trips (class/id/order via base)'',
      $b instanceof BigTextBox && $b->getId() === ''body'' && $b->getCompareValue() == 4);

// --- DbSelect (DB-backed <select>; options re-derived from elementString, not serialized) ---
$ds = new DbSelect();
$ds->setId(''pageId''); $ds->setSelectionComment(''Page:''); $ds->setOrder(5); $ds->setTabIndex(5);
$ds->setElementString(''pages'');
$b = roundtrip($ds);
check(''DbSelect round-trips (class/id; options re-derived from elementString)'',
      $b instanceof DbSelect && $b->getId() === ''pageId'' && $b->getOptions() == $ds->getOptions()
      && count($ds->getOptions()) > 0);

// --- Checkbox (no element-specific state; base fields only) ---
$cb = new Checkbox();
$cb->setId(''urgent''); $cb->setSelectionComment(''Urgent?''); $cb->setOrder(6); $cb->setTabIndex(6);
$b = roundtrip($cb);
check(''Checkbox round-trips (class/id/order via base)'',
      $b instanceof Checkbox && $b->getId() === ''urgent'' && $b->getCompareValue() == 6);

// --- FormConfigElement (FCE: action/oncomplete parsed from elementString on demand; base fields only) ---
$fce = new FormConfigElement();
$fce->setId(''__fce'');
$fce->setElementString("<action=''TicketLogger''><oncomplete=''Thanks''><incomplete=''Fill it in''>");
$b = roundtrip($fce);
check(''FormConfigElement round-trips (elementString -> action/oncomplete re-parse)'',
      $b instanceof FormConfigElement
      && FormConfigElement::parseActionTag($b->getElementString()) === ''TicketLogger''
      && FormConfigElement::parseOnCompleteTag($b->getElementString()) === ''Thanks'');

// --- StandardForm (composes elements; from_array rebuilds + rewires the circular back-refs) ---
$f = new StandardForm(''demoForm'');
$r2 = new RadioSelect(); $r2->setId(''type''); $r2->setElementString(''<<build>><<bug>>''); $r2->setOrder(1);
$t2 = new TextBox(); $t2->setId(''description''); $t2->setOrder(2);
$f->addElement($r2); $f->addElement($t2);
$f->setElementResult(''type'', ''bug'');
$f->setElementResult(''description'', ''the thing broke'');
$fb = StandardForm::from_array(json_decode(json_encode($f->to_array()), true));
$rpEls = new ReflectionProperty(''StandardForm'', ''formElements''); $rpEls->setAccessible(true);
$rebuilt = $rpEls->getValue($fb);
$rpForm = new ReflectionProperty(''AbstractFormElement'', ''form''); $rpForm->setAccessible(true);
check(''StandardForm round-trips (results survive + 2 elements + back-refs rewired to new form)'',
      $fb instanceof StandardForm
      && $fb->getElementResult(''type'') === ''bug''
      && $fb->getElementResult(''description'') === ''the thing broke''
      && $fb->getResults() == array(''type'' => ''bug'', ''description'' => ''the thing broke'')
      && $fb->getId() === ''demoForm''
      && count($rebuilt) === 2
      && ($rebuilt[''type''] ?? null) instanceof RadioSelect
      && ($rebuilt[''description''] ?? null) instanceof TextBox
      && $rebuilt[''type'']->getId() === ''type''
      && $rpForm->getValue($rebuilt[''type'']) === $fb);

// --- FormManager (id-keyed StandardForms; the POM''s top-level form value) ---
$fm = new FormManager();
$innerForm = new StandardForm(''demoForm'');
$ir = new RadioSelect(); $ir->setId(''type''); $ir->setElementString(''<<build>><<bug>>'');
$innerForm->addElement($ir);
$innerForm->setElementResult(''type'', ''bug'');
$rpFA = new ReflectionProperty(''FormManager'', ''formsArray''); $rpFA->setAccessible(true);
$rpFA->setValue($fm, array(''demoForm'' => $innerForm));
$fmb = FormManager::from_array(json_decode(json_encode($fm->to_array()), true));
check(''FormManager round-trips (getResults survives through the whole form graph)'',
      $fmb instanceof FormManager && $fmb->getResults(''demoForm'') == array(''type'' => ''bug''));

// --- NumberField (#44: numeric input; min/max from elementString; range validation) ---
$nf = new NumberField();
$nf->setId(''qty''); $nf->setSelectionComment(''Quantity:''); $nf->setOrder(7); $nf->setTabIndex(7);
$nf->setElementString(''min=1;max=10'');
$nfb = roundtrip($nf);
check(''NumberField round-trips (class/id; min/max re-derived from elementString)'',
      $nfb instanceof NumberField && $nfb->getId() === ''qty''
      && $nfb->getMin() == 1 && $nfb->getMax() == 10 && $nfb->getMin() === $nf->getMin());
// validation via a StandardForm back-ref + simulated $_POST
$vForm = new StandardForm(''vt''); $vForm->addElement($nfb);
$_POST = array(''qty'' => ''5'');   $ok_in  = ($nfb->failsExtendedValidation() === false);
$_POST = array(''qty'' => ''99'');  $ok_max = ($nfb->failsExtendedValidation() === true);
$_POST = array(''qty'' => ''abc''); $ok_num = ($nfb->failsExtendedValidation() === true);
$_POST = array();
check(''NumberField validates (accepts in-range, rejects over-max + non-numeric)'', $ok_in && $ok_max && $ok_num);
$html = $nfb->getHTML();
check(''NumberField renders <input type=number> with min/max attrs'',
      strpos($html, "type=''number''") !== false && strpos($html, "min=''1''") !== false && strpos($html, "max=''10''") !== false);

// --- DateField (#44: date input; min/max ISO dates from elementString; range validation) ---
$df = new DateField();
$df->setId(''due''); $df->setSelectionComment(''Due:''); $df->setOrder(8); $df->setTabIndex(8);
$df->setElementString(''min=2024-01-01;max=2025-12-31'');
$dfb = roundtrip($df);
check(''DateField round-trips (class/id; min/max re-derived from elementString)'',
      $dfb instanceof DateField && $dfb->getId() === ''due''
      && $dfb->getMin() === ''2024-01-01'' && $dfb->getMax() === ''2025-12-31'');
$vForm2 = new StandardForm(''vt2''); $vForm2->addElement($dfb);
$_POST = array(''due'' => ''2024-06-15''); $ok_ok  = ($dfb->failsExtendedValidation() === false);
$_POST = array(''due'' => ''2026-01-01''); $ok_hi  = ($dfb->failsExtendedValidation() === true);
$_POST = array(''due'' => ''june'');       $ok_bad = ($dfb->failsExtendedValidation() === true);
$_POST = array();
check(''DateField validates (accepts in-range ISO, rejects out-of-range + non-ISO)'', $ok_ok && $ok_hi && $ok_bad);
$html = $dfb->getHTML();
check(''DateField renders <input type=date> with min/max attrs'',
      strpos($html, "type=''date''") !== false && strpos($html, "min=''2024-01-01''") !== false && strpos($html, "max=''2025-12-31''") !== false);

// --- MultiSelect (#44: array-valued checkbox group; option-set doubles as allowlist) ---
$ms = new MultiSelect();
$ms->setId(''tags''); $ms->setSelectionComment(''Tags:''); $ms->setOrder(9); $ms->setTabIndex(9);
$ms->setElementString(''<<red>><<green>><<blue>>'');
$msb = roundtrip($ms);
check(''MultiSelect round-trips (class/id; options re-derived from elementString)'',
      $msb instanceof MultiSelect && $msb->getId() === ''tags''
      && $msb->getOptions() == $ms->getOptions() && count($ms->getOptions()) === 3);
$vForm3 = new StandardForm(''vt3''); $vForm3->addElement($msb);
$_POST = array(''tags'' => array(''red'', ''green''));  $ok_a = ($msb->failsExtendedValidation() === false);
$_POST = array(''tags'' => array(''red'', ''purple'')); $ok_b = ($msb->failsExtendedValidation() === true);
$_POST = array(''tags'' => array(''green''));          $html = $msb->getHTML();
$_POST = array();
check(''MultiSelect validates (accepts subset of options, rejects a non-option value)'', $ok_a && $ok_b);
check(''MultiSelect renders checkbox group (name=tags[] + type=checkbox + all 3 options)'',
      strpos($html, "name=''tags[]''") !== false && strpos($html, "type=''checkbox''") !== false
      && strpos($html, "value=''red''") !== false && strpos($html, "value=''green''") !== false
      && strpos($html, "value=''blue''") !== false);

echo "formelement round-trip: $pass passed, $fail failed\n";
exit($fail === 0 ? 0 : 1);
');
INSERT INTO "code_blobs" VALUES('0d75b0d1349f36d58a1e895efa140c06b2bfc8c9','python',2644,'#!/usr/bin/env python3
"""gpl_stamp.py — ticket #29: keep the GPL short-notice header on every .php file.

--check (default) lists .php files missing the notice (exit non-zero if any).
--fix inserts the header right after the opening <?php of each missing file.

    python3 tools/gpl_stamp.py            # report missing
    python3 tools/gpl_stamp.py --fix      # stamp them
"""
import argparse, os, sys

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = os.path.dirname(HERE)                     # checkouts/current
MARK = "GNU GPLv2"
HEADER = ("/*\n"
          "Copyright (C) 2006 Steven Peterson\n"
          "Congruency is free software, licensed under the GNU GPLv2 or later.\n"
          "See the LICENSE file in the project root for full license terms.\n"
          "*/\n")


def php_files():
    for base, dirs, files in os.walk(ROOT):
        dirs[:] = [d for d in dirs if d not in (".git", "state", "vendor", "node_modules")]
        for fn in files:
            if fn.endswith(".php"):
                yield os.path.join(base, fn)


def stamp(path):
    # binary I/O so the file''s existing line endings (CRLF/LF) are preserved exactly
    with open(path, "rb") as f:
        data = f.read()
    i = data.find(b"<?php")
    if i < 0:
        return False                              # not a standard php open; skip
    eol = b"\r\n" if b"\r\n" in data else b"\n"
    j = data.find(b"\n", i)
    if j < 0:
        j = i + 5
    lines = [b"/*",
             b"Copyright (C) 2006 Steven Peterson",
             b"Congruency is free software, licensed under the GNU GPLv2 or later.",
             b"See the LICENSE file in the project root for full license terms.",
             b"*/", b""]
    header = eol.join(lines)
    new = data[:j + 1] + header + data[j + 1:]
    with open(path, "wb") as f:
        f.write(new)
    return True


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--fix", action="store_true")
    a = ap.parse_args()
    missing = []
    for p in php_files():
        try:
            with open(p, "r", errors="replace") as f:
                if MARK not in f.read():
                    missing.append(p)
        except OSError:
            pass
    rel = [os.path.relpath(p, ROOT) for p in missing]
    print("%d .php files missing the GPL notice%s" % (len(missing), ":" if missing else " — all stamped ✓"))
    for r in sorted(rel):
        print("  " + r)
    if a.fix and missing:
        done = sum(1 for p in missing if stamp(p))
        print("\nstamped %d file(s)" % done)
        return 0
    return 1 if missing else 0


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('ec0b6d92949598ea217805290800feb0ce735fed','python',10695,'#!/usr/bin/env python3
"""make_state.py — deterministically (re)create this crank''s state and commit it to the
`state` side-branch.

Per checkouts/note-for-claude the DB ships compressed and is installed on checkout. This is
the missing PRODUCER: it runs the committed seed generator under the provisioned php to
build a fresh congruency.sqlite, tars it (with seed.php) into database.tar.xz, and commits
that single blob to the `state` branch at its root (state:database.tar.xz) — via git PLUMBING
only (hash-object/read-tree/write-tree/commit-tree/update-ref), so the working tree never
switches. Idempotent (bug #3): re-commits only when the DB changes. With --version, tags the
state commit `state-<version>` so it''s addressable by the matching source version.

python only, registry-gated (throws if it can''t see registry.json), auto bug-report on
exception (Variant-A), best-effort jazz telemetry.

    python3 checkouts/current/tools/make_state.py [--version X] [--no-commit]
"""
import argparse
import json
import os
import shutil
import sqlite3
import subprocess
import sys
import tarfile
import tempfile
import time
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))          # checkouts/current/tools
SOURCE = os.path.dirname(HERE)                             # checkouts/current
STATE = os.path.join(SOURCE, "state")
STATE_SPEC = os.path.join(STATE, "STATE.json")


# --------------------------------------------------------------------------- #
# registry (mandated: throw if not found) + Variant-A bug report              #
# --------------------------------------------------------------------------- #
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def bug_report(reg, exc, tb, note="ratchet crank: make_state"):
    root = (reg or {}).get("__root__") or os.path.dirname(os.path.dirname(SOURCE))
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {
        "filename": os.path.basename(__file__),
        "function": last.name if last else "?",
        "time-of-occurance": datetime.now().isoformat(),
        "methods-to-reproduce": "python3 %s %s" % (os.path.relpath(__file__, root), " ".join(sys.argv[1:])),
        "possible-cause": "%s: %s" % (type(exc).__name__, exc),
        "traceback": tb.strip().splitlines()[-6:],
        "note": note,
    }
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "a") as fh:
            fh.write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def telemetry_handles(reg):
    """Best-effort jazz_telemetry (component ''ratchet''); returns (emit_handle, open_ticket)
    or (None, None). Never raises."""
    try:
        pkgs = os.path.dirname(os.path.dirname(reg["__root__"]))   # .../packages
        cand = os.path.join(pkgs, "jazz_telemetry")
        if cand not in sys.path:
            sys.path.insert(0, cand)
        from jazz_telemetry import telemetry, open_ticket           # noqa: E402
        return telemetry("ratchet"), open_ticket
    except Exception:  # noqa: BLE001
        return None, None


# --------------------------------------------------------------------------- #
# state production                                                            #
# --------------------------------------------------------------------------- #
def find_php(reg):
    env = os.environ.get("CONGRUENCEY_PHP")
    if env and os.path.isfile(env):
        return env
    rel = (reg.get("paths", {}) or {}).get("php", "tooling/congruencey-harness/php/php")
    p = os.path.join(reg["__root__"], rel)
    if not os.path.isfile(p):
        raise FileNotFoundError("php not provisioned at %s (run provision_php.py first)" % p)
    return p


def build_tarball(reg, php, tmp):
    """Re-seed deterministically into `tmp` and return (tar_path, tables)."""
    spec = json.load(open(STATE_SPEC)) if os.path.isfile(STATE_SPEC) else {}
    seed_src = os.path.join(reg["__root__"], spec.get("seed", "tooling/congruencey-harness/seed.php"))
    if not os.path.isfile(seed_src):
        raise FileNotFoundError("seed generator missing: %s" % seed_src)
    seed_tmp = os.path.join(tmp, "seed.php")
    shutil.copy2(seed_src, seed_tmp)

    r = subprocess.run([php, seed_tmp], cwd=tmp, capture_output=True, text=True, timeout=60)
    sqlite_tmp = os.path.join(tmp, "congruency.sqlite")
    if r.returncode != 0 or not os.path.isfile(sqlite_tmp):
        raise RuntimeError("seed failed (exit %s): %s" % (r.returncode, (r.stderr or r.stdout).strip()[:400]))

    con = sqlite3.connect(sqlite_tmp)
    try:
        tables = [x[0] for x in con.execute(
            "SELECT name FROM sqlite_master WHERE type=''table'' ORDER BY name")]
    finally:
        con.close()
    missing = set(spec.get("expect_tables", [])) - set(tables)
    if missing:
        raise RuntimeError("seeded DB missing expected tables: %s" % sorted(missing))

    def _norm(ti):
        # reproducible (bug #3): strip mtime/owner so identical state -> identical blob
        ti.mtime = 0
        ti.uid = ti.gid = 0
        ti.uname = ti.gname = ""
        ti.mode = 0o644
        return ti
    tar_path = os.path.join(tmp, "database.tar.xz")
    with tarfile.open(tar_path, "w:xz") as t:
        for src, arc in sorted([(sqlite_tmp, "congruency.sqlite"), (seed_tmp, "seed.php")],
                               key=lambda x: x[1]):
            t.add(src, arcname=arc, filter=_norm)   # flat, normalized members
    return tar_path, tables


def commit_to_state_branch(reg, tar_path, version, side_branch="state"):
    """Commit the tarball to <side_branch>:database.tar.xz (single file at root) via plumbing only —
    no checkout/worktree. Idempotent (bug #3): re-commit only when the blob changes. When a `version`
    is given, tag the resulting state commit `state-<version>` so it''s addressable by source version."""
    root = reg["__root__"]

    def git(args, env=None):
        return subprocess.run(["git"] + args, cwd=root, capture_output=True, text=True, env=env)

    blob = git(["hash-object", "-w", tar_path]).stdout.strip()
    if not blob:
        raise RuntimeError("git hash-object failed for %s" % tar_path)

    ref = "refs/heads/%s" % side_branch
    head = git(["rev-parse", "--verify", "-q", ref]).stdout.strip() or None
    existing = git(["rev-parse", "-q", "--verify", "%s:database.tar.xz" % side_branch]).stdout.strip()

    if existing == blob and head:
        target, note = head, "(unchanged)"                 # DB didn''t change -> no new commit
    else:
        tmpidx = tar_path + ".idx"
        env = dict(os.environ, GIT_INDEX_FILE=tmpidx,
                   GIT_AUTHOR_NAME="ratchet", GIT_AUTHOR_EMAIL="ratchet@congruency.local",
                   GIT_COMMITTER_NAME="ratchet", GIT_COMMITTER_EMAIL="ratchet@congruency.local")
        try:
            git(["read-tree", head] if head else ["read-tree", "--empty"], env=env)
            u = git(["update-index", "--add", "--cacheinfo", "100644,%s,database.tar.xz" % blob], env=env)
            if u.returncode != 0:
                raise RuntimeError("update-index: %s" % u.stderr.strip())
            tree = git(["write-tree"], env=env).stdout.strip()
            if not tree:
                raise RuntimeError("write-tree produced no tree")
            msg = "state: database.tar.xz%s" % ((" (version-%s)" % version) if version else "")
            ct = ["commit-tree", tree, "-m", msg] + (["-p", head] if head else [])
            commit = git(ct, env=env).stdout.strip()
            if not commit:
                raise RuntimeError("commit-tree failed")
            if git(["update-ref", ref, commit]).returncode != 0:
                raise RuntimeError("update-ref failed")
            target, note = commit, commit[:10]
        finally:
            try:
                os.remove(tmpidx)
            except OSError:
                pass

    state_tag = None
    if version and target:                                  # make every source version resolvable
        state_tag = "state-%s" % version
        git(["tag", "-f", state_tag, target])
    return {"branch": side_branch, "path": "database.tar.xz", "blob": blob[:10],
            "commit": note, "state_tag": state_tag, "parent": (head or "(orphan)")[:10]}


def main():
    ap = argparse.ArgumentParser(description="produce + store state on the single `state` branch")
    ap.add_argument("--version", default=None, help="source version this state matches (tags state-<version>)")
    ap.add_argument("--no-commit", action="store_true", help="build + verify the tarball but don''t commit it")
    a = ap.parse_args()

    reg = load_registry()
    php = find_php(reg)
    spec = json.load(open(STATE_SPEC)) if os.path.isfile(STATE_SPEC) else {}
    side = spec.get("side_branch", "state")

    T, _ = telemetry_handles(reg)
    t0 = time.time()
    with tempfile.TemporaryDirectory() as tmp:
        tar_path, tables = build_tarball(reg, php, tmp)
        result = {"version": a.version, "tables": tables, "artifact_bytes": os.path.getsize(tar_path)}
        if not a.no_commit:
            result.update(commit_to_state_branch(reg, tar_path, a.version, side))
    if T:
        T.emit("make_state", status="ok", ms=(time.time() - t0) * 1000.0, version=a.version)
    print(json.dumps({"ok": True, **result}, indent=2))
    return 0


if __name__ == "__main__":
    _reg = None
    try:
        _reg = load_registry()
    except Exception:  # noqa: BLE001
        pass
    try:
        sys.exit(main())
    except SystemExit:
        raise
    except Exception as exc:  # noqa: BLE001
        tb = traceback.format_exc()
        p = bug_report(_reg, exc, tb)
        T, open_ticket = telemetry_handles(_reg) if _reg else (None, None)
        if T:
            T.emit("make_state", status="fail", note=str(exc)[:200])
        if open_ticket:
            try:
                open_ticket("ratchet make_state failed", component="ratchet", severity="high", body=tb[-1500:])
            except Exception:  # noqa: BLE001
                pass
        print("EXCEPTION — bug report -> %s" % p, file=sys.stderr)
        raise
');
INSERT INTO "code_blobs" VALUES('d542be04920bd0043da518023ab4d81f9b7463fd','python',11431,'#!/usr/bin/env python3
"""mint_crank.py — mint a crank: inject one python patch, capture it as the next version.

A crank stroke = INJECT one author-supplied Python patch on the single `source` branch, RUN it
(its one change), and CAPTURE it (commit + version tag) — the captured patch IS the diff that
defines the next version. No branch-per-crank: a crank is a commit + tag IN PLACE. This formalises
the fixes/*.py "ratchet link" discipline into one operation.

    # precondition: on the `source` branch, tracked-clean, php provisioned
    python3 checkouts/current/tools/mint_crank.py --patch /path/to/turn_xyz.py [--name xyz] [-m MSG]

Steps (each records a BUG EVENT on ANY unexpected outcome — exception OR expected!=actual —
then fail-fast):
    precondition  on `source`, tracked-clean (no fork)
    inject        copy the python patch -> checkouts/current/fixes/<name>.py  (must compile)
    run           python3 <injected>                                          (exit 0)
    capture       add -A + commit + version-4.05x tag on `source` (reuses compute_next_version)
    state         make_state.py --version <ver>   (state:database.tar.xz + state-<ver> tag)
    verify        tooling/congruencey-tests/verify                            (0 failed)

Push is a SEPARATE release step (ticket #6) — the mint stays local. python only, registry-gated.
"""
import argparse
import os
import re
import shutil
import subprocess
import sys
import time
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))          # checkouts/current/tools
SOURCE = os.path.dirname(HERE)                             # checkouts/current
FIXES = os.path.join(SOURCE, "fixes")
VERSIONING = os.path.join(SOURCE, "versioning")


# --------------------------------------------------------------------------- #
# registry + Variant-A bug report + telemetry (reused pattern)                #
# --------------------------------------------------------------------------- #
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    import json
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def bug_report(reg, exc, tb, step):
    import json
    root = (reg or {}).get("__root__") or os.path.dirname(os.path.dirname(SOURCE))
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {
        "filename": os.path.basename(__file__),
        "function": last.name if last else "?",
        "time-of-occurance": datetime.now().isoformat(),
        "methods-to-reproduce": "python3 %s %s" % (os.path.relpath(__file__, root), " ".join(sys.argv[1:])),
        "possible-cause": "%s: %s" % (type(exc).__name__, exc),
        "traceback": tb.strip().splitlines()[-6:],
        "note": "ratchet mint step: %s" % step,
    }
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "a") as fh:
            fh.write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def telemetry_handles(reg):
    try:
        pkgs = os.path.dirname(os.path.dirname(reg["__root__"]))   # .../packages
        cand = os.path.join(pkgs, "jazz_telemetry")
        if cand not in sys.path:
            sys.path.insert(0, cand)
        from jazz_telemetry import telemetry, open_ticket
        return telemetry("ratchet"), open_ticket
    except Exception:  # noqa: BLE001
        return None, None


class Unexpected(RuntimeError):
    """Raised when a step''s actual outcome != expected (bug event, even without an exception)."""


# --------------------------------------------------------------------------- #
# git + subprocess helpers                                                    #
# --------------------------------------------------------------------------- #
def _root():
    return load_registry()["__root__"]


ROOT = _root()


def git(*args):
    return subprocess.run(["git", *args], cwd=ROOT, capture_output=True, text=True)


def run_py(path, *args, timeout=300):
    return subprocess.run([sys.executable, path, *args], cwd=ROOT, capture_output=True, text=True, timeout=timeout)


# --------------------------------------------------------------------------- #
# steps                                                                       #
# --------------------------------------------------------------------------- #
def step_precondition(current):
    # A crank is now a commit + tag IN PLACE on the single `source` branch (no fork).
    if current != "source":
        raise Unexpected("mint must run on the `source` branch, not %r" % current)
    if [l for l in git("status", "--porcelain").stdout.splitlines() if not l.startswith("??")]:
        raise Unexpected("tree has uncommitted tracked changes; refusing to mint")
    return current


def step_inject(patch, name):
    if not os.path.isfile(patch):
        raise Unexpected("patch not found: %s" % patch)
    base = name if name.endswith(".py") else name + ".py"
    dest = os.path.join(FIXES, base)
    if os.path.exists(dest):
        raise Unexpected("patch destination already exists: %s" % dest)
    shutil.copy2(patch, dest)
    os.chmod(dest, os.stat(dest).st_mode | 0o111)
    c = subprocess.run([sys.executable, "-m", "py_compile", dest], capture_output=True, text=True)
    if c.returncode != 0:
        raise Unexpected("injected patch does not compile: %s" % c.stderr.strip())
    return dest


def step_run(dest):
    r = run_py(dest)
    if r.returncode != 0:
        raise Unexpected("patch exited %s: %s" % (r.returncode, (r.stderr or r.stdout).strip()[-400:]))
    return {"stdout_tail": (r.stdout or "").strip().splitlines()[-3:]}


def step_capture(message):
    """Capture the patch as the next version — LEAN single-repo path.

    commit_release''s collect_modules() scans the parent for child repos (root=repo -> "no
    modules"; root=packages -> stray manifest + a landmine if a sibling ever gets git-init''d),
    so we stage/commit/tag THIS repo directly and reuse version_source.compute_next_version()
    for the python-computed version (never inferred). Single folded repo, no sibling reach."""
    if VERSIONING not in sys.path:
        sys.path.insert(0, VERSIONING)
    from gitutil import Git
    from version_source import compute_next_version

    g = Git(identity={"name": "ratchet", "email": "ratchet@congruency.local"}, echo=False)
    g.run(["add", "-A"], ROOT, write=True)
    if not (g.query(["diff", "--cached", "--name-only"], ROOT) or "").strip():
        raise Unexpected("nothing staged — the patch produced no change to capture")

    tags_before = set(git("tag", "-l", "version-*").stdout.split())
    version = compute_next_version(g, ROOT)                     # python-computed from live tags
    tag = "version-%s" % version
    before = g.query(["rev-parse", "HEAD"], ROOT)
    g.run(["commit", "-m", message], ROOT, write=True)
    after = g.query(["rev-parse", "HEAD"], ROOT)
    if after == before:
        raise Unexpected("commit did not advance HEAD")
    g.run(["tag", "-a", tag, "-m", "Release %s" % version], ROOT, write=True)
    if tag not in (set(git("tag", "-l", "version-*").stdout.split()) - tags_before):
        raise Unexpected("expected new tag %s to be created" % tag)
    return {"version": version, "tag": tag, "committed_in": ["congruencey"], "commit": after[:10]}


def step_state(version):
    r = run_py(os.path.join(HERE, "make_state.py"), "--version", version)
    if r.returncode != 0:
        raise Unexpected("make_state failed: %s" % (r.stderr or r.stdout).strip()[-400:])
    if git("cat-file", "-e", "state:database.tar.xz").returncode != 0:
        raise Unexpected("state:database.tar.xz not committed")
    return {"state_ref": "state:database.tar.xz"}


def step_verify():
    r = subprocess.run([os.path.join(ROOT, "tooling", "congruencey-tests", "verify")],
                       cwd=ROOT, capture_output=True, text=True, timeout=300)
    m = re.search(r"(\d+)\s+suites passed,\s+(\d+)\s+failed", r.stdout)
    if not m or int(m.group(2)) != 0:
        raise Unexpected("verify not clean: %s" % (r.stdout or r.stderr).strip()[-400:])
    return {"passed": int(m.group(1)), "failed": int(m.group(2))}


# --------------------------------------------------------------------------- #
# driver                                                                      #
# --------------------------------------------------------------------------- #
def main():
    ap = argparse.ArgumentParser(description="mint a crank from one python patch")
    ap.add_argument("--patch", required=True, help="path to the python patch script (the turn)")
    ap.add_argument("--name", default=None, help="injected filename under fixes/ (default: patch basename)")
    ap.add_argument("-m", "--message", default=None, help="commit/release message")
    a = ap.parse_args()

    reg = load_registry()
    T, open_ticket = telemetry_handles(reg)
    name = a.name or os.path.splitext(os.path.basename(a.patch))[0]
    message = a.message or ("crank: %s" % name)
    current = git("rev-parse", "--abbrev-ref", "HEAD").stdout.strip()

    def do(step_name, fn):
        print("\n== %s ==" % step_name)
        t0 = time.time()
        try:
            out = fn()
            ms = (time.time() - t0) * 1000.0
            if T:
                T.emit("mint", status="ok", ms=ms, step=step_name)
            print("   ok (%.0f ms) %s" % (ms, out if out else ""))
            return out
        except Exception as exc:  # noqa: BLE001 — Unexpected or any error is a bug event
            tb = traceback.format_exc()
            p = bug_report(reg, exc, tb, step_name)
            if T:
                T.emit("mint", status="fail", step=step_name, error=str(exc)[:200])
            if open_ticket:
                try:
                    open_ticket("ratchet mint failed at %s" % step_name, component="ratchet",
                                severity="high", body=tb[-1500:], step=step_name)
                except Exception:  # noqa: BLE001
                    pass
            print("   FAIL: %s\n   bug report -> %s" % (exc, p), file=sys.stderr)
            raise

    print("mint crank: on %s, patch=%s" % (current, a.patch))
    do("precondition", lambda: step_precondition(current))
    dest = do("inject", lambda: step_inject(a.patch, name))
    do("run patch", lambda: step_run(dest))
    cap = do("capture (commit + tag)", lambda: step_capture(message))
    do("state", lambda: step_state(cap["version"]))
    do("verify", lambda: step_verify())

    if T:
        T.emit("mint", status="ok", branch=current, version=cap.get("version"))
    print("\n== crank minted on %s: %s (commit + tag in place; state + verify green) ==" % (current, cap.get("tag")))
    return 0


if __name__ == "__main__":
    try:
        sys.exit(main())
    except SystemExit:
        raise
    except Exception:  # noqa: BLE001 — per-step handler already recorded the bug event
        sys.exit(1)
');
INSERT INTO "code_blobs" VALUES('d91d46feadac022055367ebde386b3f8e10cc99d','python',5937,'#!/usr/bin/env python3
"""predict.py — the prediction ledger: record PREDICTION vs ACTUAL, verdict CONFIRMED / REFUTED.

Test-first over the ratchet: state what you EXPECT before the change, run it, then resolve with the
ACTUAL. A REFUTED prediction *is* a bug (opens a jazz ticket, component=deploy). Records to
`logs/predictions.jsonl` (git-ignored) and best-effort jazz telemetry. Registry-gated; Variant-A bug
report on exception.

    from predict import predict, resolve, check
    pid = predict("deploy creates DB at cfg path", expected=True)
    #  ... run the thing ...
    resolve(pid, actual=os.path.isfile(db))                 # -> "CONFIRMED" / "REFUTED"
    check("home page returns 200", expected=200, actual=status)   # one-shot predict+resolve
"""
import json
import os
import sys
import time
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))


def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def _sink(reg):
    rel = reg.get("predictions", "logs/predictions.jsonl")
    return os.path.join(reg["__root__"], rel)


def _jazz(reg):
    try:
        pkgs = os.path.dirname(os.path.dirname(reg["__root__"]))   # .../packages
        cand = os.path.join(pkgs, "jazz_telemetry")
        if cand not in sys.path:
            sys.path.insert(0, cand)
        from jazz_telemetry import telemetry, open_ticket
        return telemetry("deploy"), open_ticket
    except Exception:  # noqa: BLE001
        return None, None


def bug_report(reg, exc, tb):
    root = (reg or {}).get("__root__") or os.path.dirname(os.path.dirname(os.path.dirname(HERE)))
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {"filename": os.path.basename(__file__), "function": last.name if last else "?",
             "time-of-occurance": datetime.now().isoformat(),
             "methods-to-reproduce": "python3 tools/predict.py",
             "possible-cause": "%s: %s" % (type(exc).__name__, exc),
             "traceback": tb.strip().splitlines()[-6:], "note": "predict.py"}
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "a") as fh:
            fh.write(json.dumps(entry) + "\n")
    except OSError:
        pass


def _read(sink):
    if not os.path.isfile(sink):
        return []
    out = []
    for ln in open(sink):
        ln = ln.strip()
        if ln:
            try:
                out.append(json.loads(ln))
            except ValueError:
                pass
    return out


def _append(sink, rec):
    os.makedirs(os.path.dirname(sink), exist_ok=True)
    with open(sink, "a") as fh:
        fh.write(json.dumps(rec) + "\n")


def predict(statement, expected, **meta):
    """Record a prediction (BEFORE the change). Returns a mechanical id."""
    try:
        reg = load_registry()
        sink = _sink(reg)
        pid = max([e.get("id", 0) for e in _read(sink) if e.get("kind") == "predict"], default=0) + 1
        _append(sink, {"kind": "predict", "id": pid, "ts": time.strftime("%Y-%m-%dT%H:%M:%S"),
                       "statement": statement, "expected": expected, "meta": meta, "verdict": "PENDING"})
        T, _ = _jazz(reg)
        if T:
            T.emit("predict", status="pending", id=pid, statement=str(statement)[:120])
        return pid
    except Exception as exc:  # noqa: BLE001
        bug_report(None, exc, traceback.format_exc())
        raise


def resolve(pid, actual, open_bug=True, **meta):
    """Resolve a prediction with the ACTUAL. Returns ''CONFIRMED''/''REFUTED''; REFUTED opens a jazz bug."""
    try:
        reg = load_registry()
        sink = _sink(reg)
        pred = next((e for e in _read(sink) if e.get("kind") == "predict" and e.get("id") == pid), None)
        if pred is None:
            raise ValueError("no prediction with id %s" % pid)
        verdict = "CONFIRMED" if actual == pred["expected"] else "REFUTED"
        _append(sink, {"kind": "resolve", "id": pid, "ts": time.strftime("%Y-%m-%dT%H:%M:%S"),
                       "statement": pred["statement"], "expected": pred["expected"],
                       "actual": actual, "verdict": verdict, "meta": meta})
        T, open_ticket = _jazz(reg)
        if T:
            T.emit("predict", status=verdict.lower(), id=pid, statement=str(pred["statement"])[:120])
        if verdict == "REFUTED" and open_bug and open_ticket:
            try:
                open_ticket("prediction REFUTED: %s" % str(pred["statement"])[:120], component="deploy",
                            severity="high", kind="bug",
                            expected=repr(pred["expected"])[:200], actual=repr(actual)[:200])
            except Exception:  # noqa: BLE001
                pass
        return verdict
    except Exception as exc:  # noqa: BLE001
        bug_report(None, exc, traceback.format_exc())
        raise


def check(statement, expected, actual, open_bug=True, **meta):
    """One-shot predict+resolve (when you already have the actual). Returns the verdict."""
    return resolve(predict(statement, expected, **meta), actual, open_bug=open_bug, **meta)


if __name__ == "__main__":
    # tiny CLI: python3 predict.py "statement" <expected> <actual>
    a = sys.argv[1:]
    if len(a) == 3:
        print(check(a[0], a[1], a[2]))
    else:
        print("usage: predict.py \"statement\" <expected> <actual>", file=sys.stderr)
        sys.exit(2)
');
INSERT INTO "code_blobs" VALUES('e0f9e147487e937dae497f0d7bedf1cf68b1ead5','python',7096,'#!/usr/bin/env python3
"""provision_php.py — new-tree reference-server recipe: provision the php runtime.

The mono ships NO binaries (they don''t belong in git); instead this python recipe places a
php binary into <mono>/<paths.php> (default tooling/congruencey-harness/php/php) from an
available source, in order:

  1. a local source path listed in registry php_provision.sources (or the legacy defaults);
  2. otherwise a NETWORK FETCH of a static php-cli build (php_provision.download.url),
     extracted in-python — no shell script.

The recipe is committed; the binary is git-ignored. It verifies the result with `php -v`.

python-only, registry-driven (throws if it can''t see registry.json), auto-bug-report on
exception.
"""
import json
import os
import shutil
import stat
import subprocess
import sys
import tarfile
import tempfile
import traceback
import urllib.request
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
DEST_REL = os.path.join("tooling", "congruencey-harness", "php", "php")
DEFAULT_SOURCES = [
    "/home/notificationsforsteven/congruencey-harness/php/php",
    "/home/notificationsforsteven/b01/tooling/congruencey-harness/php/php",
]
DEFAULT_DOWNLOAD = {
    "url": "https://dl.static-php.dev/static-php-cli/common/php-8.4.23-cli-linux-x86_64.tar.gz",
    "member": "php",
}
UA = "Mozilla/5.0 (X11; Linux x86_64) provision_php"


def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    reg["__file__"] = path
    return reg


def bug_report(reg, exc, tb):
    # Root is the registry root when known; else the mono root (HERE''s parent, since HERE is
    # file-system-repair/). Never HERE itself — that would double the default rel path.
    root = (reg or {}).get("__root__") or os.path.dirname(HERE)
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {
        "filename": os.path.basename(last.filename) if last else os.path.basename(__file__),
        "function": last.name if last else "?",
        "time-of-occurance": datetime.now().isoformat(),
        "methods-to-reproduce": "python3 %s" % os.path.basename(__file__),
        "possible-cause": "%s: %s" % (type(exc).__name__, exc),
        "traceback": tb.strip().splitlines()[-6:],
    }
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "a") as fh:
        fh.write(json.dumps(entry) + "\n")
    return path


def ensure_gitignore(mono, rel):
    gi = os.path.join(mono, ".gitignore")
    line = "/" + rel.replace(os.sep, "/")
    existing = open(gi).read().splitlines() if os.path.isfile(gi) else []
    if line not in existing:
        with open(gi, "a") as fh:
            fh.write(("" if not existing or existing[-1] == "" else "\n") + line + "\n")
    return gi


def _download(url, dest_tmp):
    """Fetch url -> dest_tmp. Try urllib with a browser UA (static-php.dev/Cloudflare 403s
    the default python UA); fall back to curl if urllib is blocked. No shell script."""
    req = urllib.request.Request(url, headers={"User-Agent": UA})
    try:
        with urllib.request.urlopen(req, timeout=240) as r, open(dest_tmp, "wb") as fh:
            shutil.copyfileobj(r, fh)
        if os.path.getsize(dest_tmp) > 0:
            return "urllib"
    except Exception:  # noqa: BLE001 — fall through to curl
        pass
    if shutil.which("curl"):
        rc = subprocess.run(["curl", "-sL", "--max-time", "240", "-o", dest_tmp, url]).returncode
        if rc == 0 and os.path.isfile(dest_tmp) and os.path.getsize(dest_tmp) > 0:
            return "curl"
    raise RuntimeError("could not download %s (urllib blocked and curl unavailable/failed)" % url)


def _provision_from_download(dl, dest):
    member = dl.get("member", "php")
    with tempfile.TemporaryDirectory() as td:
        arch = os.path.join(td, "php.tgz")
        how = _download(dl["url"], arch)
        with tarfile.open(arch) as t:
            name = next((n for n in t.getnames() if os.path.basename(n) == member), None)
            if not name:
                raise RuntimeError("no %r member in %s" % (member, dl["url"]))
            t.extract(name, td, filter="data")
            os.makedirs(os.path.dirname(dest), exist_ok=True)
            shutil.copy2(os.path.join(td, name), dest)
    return "downloaded (%s) from %s" % (how, dl["url"])


def main():
    reg = load_registry()
    root = reg["__root__"]
    mono = os.path.join(root, reg.get("paths", {}).get("mono", "."))
    dest = os.path.join(mono, reg.get("paths", {}).get("php", DEST_REL))
    os.makedirs(os.path.dirname(dest), exist_ok=True)

    # idempotent (bug #4): a WORKING php already at dest -> skip re-acquisition (the
    # network-fetch fallback below still runs on a genuinely fresh clone).
    if os.path.isfile(dest) and subprocess.run([dest, "-v"], capture_output=True).returncode == 0:
        how = "already provisioned (%s)" % os.path.relpath(dest, mono)
    else:
        cfg = reg.get("php_provision", {}) or {}
        sources = cfg.get("sources", DEFAULT_SOURCES)
        src = next((c for c in sources if os.path.isfile(c)), None)
        if src and os.path.abspath(src) != os.path.abspath(dest):
            shutil.copy2(src, dest)
            how = "copied from %s" % src
        elif src:
            how = "already in place (%s)" % src
        else:
            how = _provision_from_download(cfg.get("download", DEFAULT_DOWNLOAD), dest)
        os.chmod(dest, os.stat(dest).st_mode | stat.S_IXUSR | stat.S_IXGRP | stat.S_IXOTH)

    ver = subprocess.run([dest, "-v"], capture_output=True, text=True)
    if ver.returncode != 0:
        raise RuntimeError("provisioned php does not run: %s" % (ver.stderr or ver.stdout).strip())

    rel = os.path.relpath(dest, mono)
    ensure_gitignore(mono, rel)
    subprocess.run(["git", "add", ".gitignore", "checkouts/current/tools/provision_php.py"],
                   cwd=mono, capture_output=True, text=True)

    result = {
        "mono": mono, "php": rel, "how": how,
        "php_version": (ver.stdout or "").splitlines()[0] if ver.stdout else "?",
        "php_size_bytes": os.path.getsize(dest),
        "gitignored": "/" + rel.replace(os.sep, "/"),
    }
    print(json.dumps(result, indent=2))
    return result


if __name__ == "__main__":
    _reg = None
    try:
        _reg = load_registry()
    except Exception:  # noqa: BLE001
        pass
    try:
        main()
    except Exception as exc:  # noqa: BLE001
        p = bug_report(_reg, exc, traceback.format_exc())
        print("EXCEPTION — bug report -> %s" % p, file=sys.stderr)
        raise
');
INSERT INTO "code_blobs" VALUES('84411b3b9c8e3343c5bdcc481891959ebb5d0fe2','python',8042,'#!/usr/bin/env python3
"""serve.py — the congruency php-web reference server (ONE python script, no shell).

Reconstruction of the old ~/congruencey-harness as the source''s own tool. It boots the
CMS under PHP''s built-in web server using the relocatable new-tree bootstrap
(../boot/router.php), served from the congruency source root (checkouts/current). This
replaces the old bash `serve`/`verify` scripts, which note-for-claude forbids.

    python3 tools/serve.py                # serve on 0.0.0.0:8899   (Ctrl-C to stop)
    python3 tools/serve.py --port 9000
    python3 tools/serve.py --verify       # boot, probe pages, assert HTTP 200, exit

Design rules (note-for-claude):
  * python only, no shell;
  * registry-gated — throws if it cannot see registry.json;
  * every path derived from __file__ (relocatable — works at any clone location);
  * php located via $CONGRUENCEY_PHP, then registry paths.php, then convention;
  * auto bug-report (timestamped) on any exception.
"""
import argparse
import json
import os
import socket
import subprocess
import sys
import tarfile
import time
import traceback
import urllib.error
import urllib.request
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))          # checkouts/current/tools
SOURCE = os.path.dirname(HERE)                             # checkouts/current
ROUTER = os.path.join("boot", "router.php")               # relative to SOURCE (cwd at serve time)
STATE = os.path.join(SOURCE, "state")
SQLITE = os.path.join(STATE, "congruency.sqlite")
DB_TAR = os.path.join(STATE, "database.tar.xz")
DEFAULT_PORT = 8899
PAGES = ["?page=catalog&fresh=1", "?page=about", "?page=catalog"]
FATAL = ("Fatal error", "Parse error", "Uncaught", "PHP Fatal", "Stack trace")


# --------------------------------------------------------------------------- #
# registry (mandated: a tool that cannot see the registry must throw)         #
# --------------------------------------------------------------------------- #
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    reg["__file__"] = path
    return reg


def bug_report(reg, exc, tb):
    root = (reg or {}).get("__root__", os.path.dirname(os.path.dirname(SOURCE)))
    rel = (reg or {}).get("bug_reports", "logs/bug_reports.jsonl")
    path = os.path.join(root, rel)
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {
        "filename": os.path.basename(__file__),
        "function": last.name if last else "?",
        "time-of-occurance": datetime.now().isoformat(),
        "methods-to-reproduce": "python3 tools/serve.py %s" % " ".join(sys.argv[1:]),
        "possible-cause": "%s: %s" % (type(exc).__name__, exc),
        "traceback": tb.strip().splitlines()[-6:],
    }
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "a") as fh:
            fh.write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


# --------------------------------------------------------------------------- #
# prerequisites                                                               #
# --------------------------------------------------------------------------- #
def find_php(reg):
    env = os.environ.get("CONGRUENCEY_PHP")
    if env and os.path.isfile(env):
        return env
    rel = (reg.get("paths", {}) or {}).get("php", "tooling/congruencey-harness/php/php")
    cand = os.path.join(reg["__root__"], rel)
    if os.path.isfile(cand):
        return cand
    raise FileNotFoundError(
        "php not found (checked $CONGRUENCEY_PHP and %s). Provision it first: "
        "python3 checkouts/current/tools/provision_php.py" % cand)


def ensure_db():
    """The state sqlite ships compressed; extract on first boot (artifact is gitignored)."""
    if os.path.isfile(SQLITE):
        return "present"
    if os.path.isfile(DB_TAR):
        with tarfile.open(DB_TAR) as t:
            t.extractall(STATE)
        if os.path.isfile(SQLITE):
            return "extracted"
    raise FileNotFoundError(
        "state DB missing and no database.tar.xz at %s (run "
        "fixes/install_state_db.py)" % DB_TAR)


# --------------------------------------------------------------------------- #
# verify mode — boot, probe, assert 200                                       #
# --------------------------------------------------------------------------- #
def _free_port():
    s = socket.socket()
    s.bind(("127.0.0.1", 0))
    p = s.getsockname()[1]
    s.close()
    return p


def _probe(url):
    try:
        with urllib.request.urlopen(url, timeout=8) as r:
            return r.status, r.read(8000).decode("utf-8", "replace")
    except urllib.error.HTTPError as e:
        return e.code, e.read(8000).decode("utf-8", "replace")
    except Exception as e:  # noqa: BLE001
        return None, "%r" % e


def verify(php):
    port = _free_port()
    proc = subprocess.Popen([php, "-S", "127.0.0.1:%d" % port, ROUTER], cwd=SOURCE,
                            stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
    time.sleep(1.5)
    rows, first = [], ""
    try:
        for pg in PAGES:
            st, body = _probe("http://127.0.0.1:%d/%s" % (port, pg))
            rows.append({"page": pg, "status": st, "bytes": len(body)})
            if not first:
                first = body
    finally:
        proc.terminate()
        try:
            _o, serr = proc.communicate(timeout=5)
        except Exception:  # noqa: BLE001
            proc.kill()
            _o, serr = proc.communicate()
    ok = (all(r["status"] == 200 for r in rows)
          and not any(m in (first + (serr or "")) for m in FATAL))
    print(json.dumps({"ok": ok, "served_from": os.path.relpath(SOURCE, reg_root()),
                      "router": ROUTER, "pages": rows}, indent=2))
    if not ok:
        raise RuntimeError("verify failed (not all 200 / fatal detected): %s" % rows)
    return ok


def reg_root():
    try:
        return os.path.dirname(find_registry())
    except Exception:  # noqa: BLE001
        return SOURCE


# --------------------------------------------------------------------------- #
# serve mode — foreground php -S (php replaces this process)                   #
# --------------------------------------------------------------------------- #
def serve(php, host, port):
    print("serving congruency CMS  http://%s:%d/?page=catalog   (Ctrl-C to stop)" % (host, port))
    print("  served from %s  via %s" % (SOURCE, ROUTER))
    os.chdir(SOURCE)                          # router path is relative to the source root
    os.execv(php, [php, "-S", "%s:%d" % (host, port), ROUTER])   # never returns on success


def main():
    ap = argparse.ArgumentParser(description="congruency php-web reference server")
    ap.add_argument("--host", default="0.0.0.0")
    ap.add_argument("--port", type=int, default=DEFAULT_PORT)
    ap.add_argument("--verify", action="store_true",
                    help="boot, probe catalog/about, assert HTTP 200, then exit")
    a = ap.parse_args()

    reg = load_registry()
    php = find_php(reg)
    ensure_db()
    if a.verify:
        return 0 if verify(php) else 1
    serve(php, a.host, a.port)
    return 0


if __name__ == "__main__":
    _reg = None
    try:
        _reg = load_registry()
    except Exception:  # noqa: BLE001
        pass
    try:
        sys.exit(main())
    except SystemExit:
        raise
    except Exception as exc:  # noqa: BLE001
        p = bug_report(_reg, exc, traceback.format_exc())
        print("EXCEPTION — bug report -> %s" % p, file=sys.stderr)
        raise
');
INSERT INTO "code_blobs" VALUES('80e8213394f7df610e039da7933e8c7fd4babc46','python',2578,'#!/usr/bin/env python3
"""tagcheck.py — a render-harness for every invocator tag (first increment of #46).

Discovers the tag list from the live gallery (?page=tags), renders each tag standalone
(?page=tags&tag=NAME), and asserts HTTP 200 with no PHP error in the output. Prints a
pass/fail table + JSON, exit non-zero if any tag fails. This is the "rendered result"
half of the tag-test harness; predicted results (as `bet` tickets) come next.

    python3 tools/tagcheck.py                 # against http://127.0.0.1:8899
    python3 tools/tagcheck.py --base URL --report out.json
"""
import argparse, json, re, sys, time, urllib.request, urllib.error

ERR = ("Fatal error", "Parse error", "Uncaught", "PHP Fatal", "Stack trace",
       "error:", "cy-form-error",
       # non-fatal PHP diagnostics too (bug #108: a null-deref Warning slipped past a fatals-only check)
       "Warning:", "Deprecated:", "Notice:", "Trying to access", "array offset on null")


def get(url):
    try:
        with urllib.request.urlopen(url, timeout=15) as r:
            return r.status, r.read().decode("utf-8", "replace")
    except urllib.error.HTTPError as e:
        return e.code, e.read().decode("utf-8", "replace")
    except Exception as e:  # noqa: BLE001
        return None, "%r" % e


def tags(base):
    st, body = get(base + "/?page=tags")
    return sorted(set(re.findall(r"[?&]tag=([A-Za-z0-9_]+)", body))) if st == 200 else []


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--base", default="http://127.0.0.1:8899")
    ap.add_argument("--report", default="")
    a = ap.parse_args()
    base = a.base.rstrip("/")
    names = tags(base)
    results, fails = [], []
    for n in names:
        st, body = get("%s/?page=tags&tag=%s" % (base, n))
        hit = [m for m in ERR if m in body]
        ok = (st == 200 and not hit)
        results.append({"tag": n, "status": st, "ok": ok, "errors": hit, "bytes": len(body)})
        if not ok:
            fails.append(n)

    print("=== tagcheck — %s ===" % base)
    print("%d tags, %d pass, %d FAIL\n" % (len(results), len(results) - len(fails), len(fails)))
    for r in results:
        print("  %-5s %-3s  %-22s %s" % ("ok" if r["ok"] else "FAIL", r["status"], r["tag"],
                                         (", ".join(r["errors"]) if r["errors"] else "")))
    if a.report:
        json.dump({"base": base, "results": results, "fails": fails}, open(a.report, "w"), indent=2)
        print("\nJSON: %s" % a.report)
    return 1 if fails else 0


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('cb87643a9c45360e52859cef23ba70854ae864fc','python',2586,'#!/usr/bin/env python3
"""tostring_check.py — flush the #60 class: __toString() that can return non-string.

PHP 8 fatals with a TypeError when __toString() returns null. This scans lib/ (+ invocators/)
for __toString methods and flags any that:
  (a) have NO return statement (falls off the end -> null), or
  (b) return a bare variable/property that was initialised to NULL in the body (e.g. $x=NULL; ... return $x;).
Returns of string literals, interpolations, concatenations, casts, or `?? ''''` are safe.

    python3 tools/tostring_check.py        # report; exit non-zero if any risky __toString
"""
import os, re, sys

ROOT = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
DIRS = ["lib", "invocators"]


def bodies(src):
    """yield (start_line, body) for each __toString method via brace matching."""
    for m in re.finditer(r''function\s+__toString\s*\([^)]*\)\s*\{'', src):
        i = m.end() - 1                      # at the opening {
        depth, j = 0, i
        while j < len(src):
            if src[j] == ''{'': depth += 1
            elif src[j] == ''}'':
                depth -= 1
                if depth == 0: break
            j += 1
        yield src[:m.start()].count(''\n'') + 1, src[i + 1:j]


def risky(body):
    rets = re.findall(r''return\s+([^;]+);'', body)
    if not rets:
        return "no return statement (falls through -> null)"
    for r in rets:
        r = r.strip()
        m = re.fullmatch(r''\$([A-Za-z_]\w*)((?:->\w+)*)'', r)   # a bare $var or $this->prop
        if m:
            var = m.group(1)
            # nullable if that local var was initialised to NULL, or it''s any object property
            if re.search(r''\$%s\s*=\s*NULL\s*;'' % re.escape(var), body, re.I) or m.group(2):
                return "returns bare nullable `%s`" % r
    return None


def main():
    flagged = []
    for d in DIRS:
        for base, _, files in os.walk(os.path.join(ROOT, d)):
            for fn in files:
                if not fn.endswith(".php"):
                    continue
                p = os.path.join(base, fn)
                src = open(p, errors="replace").read()
                for line, body in bodies(src):
                    why = risky(body)
                    if why:
                        flagged.append((os.path.relpath(p, ROOT), line, why))
    print("%d risky __toString method(s)%s" % (len(flagged), ":" if flagged else " — clean ✓"))
    for rel, line, why in sorted(flagged):
        print("  %s:%d  %s" % (rel, line, why))
    return 1 if flagged else 0


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('f50ae8faa8d38135433b1d8d9f360e0a9655c130','python',5444,'#!/usr/bin/env python3
"""checkout.py — check the versioned project out into a specified folder.

Materialises every module (and its submodules) into a destination folder by cloning
from the LOCAL BUNDLES and checking out a version tag. Uses the project version
manifest to know what to lay down and how submodules are wired, then re-points each
submodule at its local bundle so the whole tree checks out offline.

INSTRUMENTED: every git operation runs live against the bundles and is logged via
gitutil.Git — nothing from memory.

Usage:
  ./checkout.py DEST [--version N] [--module NAME] [--bundles DIR]
                [--manifest FILE] [--force] [--log OUT.log]
"""
import argparse
import json
import os
import shutil
import sys

from gitutil import Git, parse_gitmodules


def bundle_for(name, bundles):
    return os.path.join(bundles, name.replace("/", "-") + ".bundle")


def checkout_module(git, m, dest_root, tag, bundles):
    name = m["name"]
    bundle = bundle_for(name, bundles)
    target = os.path.join(dest_root, os.path.basename(name))
    r = {"name": name, "target": target, "bundle": bundle, "ok": False, "errors": []}
    if not os.path.isfile(bundle):
        r["errors"].append("no bundle: %s" % bundle)
        return r

    git.run(["clone", "--quiet", bundle, target], dest_root, write=False)
    # detach at the version tag when present, else stay on the bundle''s default branch
    tags = git.query(["tag", "-l", tag], target)
    if tags:
        git.run(["checkout", "--quiet", "tags/%s" % tag], target, write=False)
    r["ref"] = tag if tags else git.query(["rev-parse", "--abbrev-ref", "HEAD"], target)
    r["commit"] = git.query(["rev-parse", "HEAD"], target)

    # wire any submodules from their local bundles so they check out offline
    declared = parse_gitmodules(target, git)
    for sub_name, cfg in declared.items():
        subpath = cfg.get("path")
        if not subpath:
            continue
        sub_bundle = bundle_for(subpath, bundles)
        sub = {"subpath": subpath, "bundle": sub_bundle, "ok": False}
        if not os.path.isfile(sub_bundle):
            sub["error"] = "no submodule bundle: %s" % sub_bundle
            r.setdefault("submodules", []).append(sub)
            r["errors"].append(sub["error"])
            continue
        git.run(["submodule", "init", "--", subpath], target, write=False)
        # override the (unreachable) upstream url with the local bundle
        git.run(["config", "submodule.%s.url" % sub_name, sub_bundle], target, write=False)
        # allow the local file:// bundle as a submodule source (blocked by default
        # since CVE-2022-39253); scoped to this one command, not global config
        git.run(["-c", "protocol.file.allow=always",
                 "submodule", "update", "--", subpath], target, write=False)
        sub["commit"] = git.query(["rev-parse", "HEAD"], os.path.join(target, subpath))
        sub["ok"] = bool(sub["commit"])
        r.setdefault("submodules", []).append(sub)

    r["ok"] = not r["errors"]
    return r


def main(argv=None):
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("dest", help="destination folder to check the project out into")
    ap.add_argument("--version", type=int, default=2)
    ap.add_argument("--module", default=None, help="only this module (default: all)")
    ap.add_argument("--bundles", default=os.path.expanduser("~/bundles"))
    ap.add_argument("--manifest", default=os.path.expanduser("~/project_versions.json"))
    ap.add_argument("--force", action="store_true", help="overwrite a non-empty dest")
    ap.add_argument("--log", default=None)
    args = ap.parse_args(argv)

    tag = "version-%d" % args.version
    if not os.path.isfile(args.manifest):
        print("manifest not found: %s (run version_source.py first)" % args.manifest)
        return 2
    manifest = json.load(open(args.manifest))

    dest = os.path.abspath(args.dest)
    if os.path.exists(dest) and os.listdir(dest):
        if not args.force:
            print("dest %s exists and is not empty (use --force)" % dest)
            return 2
        shutil.rmtree(dest)
    os.makedirs(dest, exist_ok=True)

    git = Git(logfile=args.log, echo=True)
    # top-level modules only; submodules are pulled in via their parent
    modules = [m for m in manifest["modules"] if not m.get("is_submodule")]
    if args.module:
        modules = [m for m in modules if m["name"] == args.module
                   or os.path.basename(m["name"]) == args.module]
        if not modules:
            print("no such module: %s" % args.module)
            return 2

    print("== checkout %s -> %s ==" % (tag, dest))
    results = [checkout_module(git, m, dest, tag, args.bundles) for m in modules]

    print("\n-- result --")
    ok = True
    for r in results:
        mark = "OK  " if r["ok"] else "FAIL"
        print("  [%s] %-20s %s @ %s" % (mark, os.path.basename(r["name"]),
                                        r.get("ref", "?"), (r.get("commit") or "?")[:10]))
        for s in r.get("submodules", []):
            print("        submodule %-20s @ %s" % (s["subpath"], (s.get("commit") or "?")[:10]))
        for e in r["errors"]:
            print("        - %s" % e)
            ok = False
    print("  --\n  %d module(s) into %s -> %s" % (len(results), dest, "OK" if ok else "INCOMPLETE"))
    return 0 if ok else 1


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('fcff965fe4d7ad1421d6231a6caa66a8cf6a83c7','python',5190,'"""gitutil.py — instrumented git plumbing shared by the versioning scripts.

Principle: NO GIT OPERATION IS DONE FROM MEMORY.
  * Every operation is a real `git` subprocess executed against live state — the
    scripts never assume, cache, or infer repository state.
  * Every operation is recorded (command, cwd, rc, output) to an append-only log
    and (optionally) echoed. That record IS the instrumentation.
  * Write operations REQUIRE an explicit identity passed in by the caller; git''s
    ambient/global user.* config is never trusted for authorship.
"""
import json
import os
import subprocess
import time


class GitError(Exception):
    pass


class Git:
    def __init__(self, identity=None, logfile=None, echo=True):
        # identity: {"name":..., "email":...} — mandatory for any write op.
        self.identity = identity
        self.logfile = logfile
        self.echo = echo
        self.ops = []
        if logfile:
            # truncate a fresh instrumentation log for this run
            with open(logfile, "w") as fh:
                fh.write(f"# git instrumentation log — {time.strftime(''%Y-%m-%dT%H:%M:%S'')}\n")

    def _record(self, rec):
        self.ops.append(rec)
        line = "[git] %-28s %s -> rc=%d" % (
            os.path.basename(rec["cwd"].rstrip("/")) or "/",
            " ".join(rec["argv"][1:]),
            rec["rc"],
        )
        if self.echo:
            print(line)
        if self.logfile:
            with open(self.logfile, "a") as fh:
                fh.write(json.dumps(rec) + "\n")

    def run(self, args, cwd, write=False, check=True, strip=True):
        argv = ["git"]
        env = dict(os.environ)
        if write:
            if not self.identity:
                raise GitError("refusing write op without an explicit identity "
                               "(no git operations from memory)")
            argv += ["-c", "user.name=%s" % self.identity["name"],
                     "-c", "user.email=%s" % self.identity["email"]]
            env["GIT_AUTHOR_NAME"] = env["GIT_COMMITTER_NAME"] = self.identity["name"]
            env["GIT_AUTHOR_EMAIL"] = env["GIT_COMMITTER_EMAIL"] = self.identity["email"]
        argv += list(args)
        proc = subprocess.run(argv, cwd=cwd, env=env,
                              capture_output=True, text=True)
        rec = {
            "ts": time.strftime("%Y-%m-%dT%H:%M:%S"),
            "cwd": cwd, "argv": argv, "write": write,
            "rc": proc.returncode,
            "stdout": proc.stdout.strip(),
            "stderr": proc.stderr.strip(),
        }
        self._record(rec)
        if check and proc.returncode != 0:
            raise GitError("git %s failed in %s: %s"
                           % (" ".join(args), cwd, proc.stderr.strip()))
        return proc.stdout.strip() if strip else proc.stdout.rstrip("\n")

    # read-only convenience: returns stdout or None on failure (still logged)
    def query(self, args, cwd, strip=True):
        try:
            return self.run(args, cwd, write=False, check=False, strip=strip)
        except GitError:
            return None


# ------------------------------------------------------------------ discovery --
GENERATED = {"tournament-lineage", "tournament-package"}  # excluded from versioning by default


def is_git_repo(path):
    return os.path.isdir(os.path.join(path, ".git")) or os.path.isfile(os.path.join(path, ".git"))


def repo_root_of(path, git):
    top = git.query(["rev-parse", "--show-toplevel"], path)
    return top or None


def discover_top_repos(root, git, include_generated=False):
    repos = []
    for name in sorted(os.listdir(root)):
        p = os.path.join(root, name)
        if not os.path.isdir(p) or not is_git_repo(p):
            continue
        if not include_generated and name in GENERATED:
            continue
        repos.append(p)
    return repos


def parse_gitmodules(path, git):
    """Return {name: {''path'':..., ''url'':...}} from .gitmodules, or {}."""
    gm = os.path.join(path, ".gitmodules")
    if not os.path.isfile(gm):
        return {}
    raw = git.query(["config", "-f", ".gitmodules", "--list"], path) or ""
    mods = {}
    for line in raw.splitlines():
        if "=" not in line:
            continue
        key, val = line.split("=", 1)
        # submodule.<name>.<attr>
        parts = key.split(".")
        if len(parts) >= 3 and parts[0] == "submodule":
            name = ".".join(parts[1:-1])
            attr = parts[-1]
            mods.setdefault(name, {})[attr] = val
    return mods


def submodule_status(path, git):
    """Parse `git submodule status` -> list of dicts with status char, sha, subpath."""
    raw = git.query(["submodule", "status"], path, strip=False)
    out = []
    if not raw:
        return out
    for line in raw.splitlines():
        if not line.strip():
            continue
        flag = line[0] if line[0] in " +-U" else " "
        rest = line[1:] if line[0] in " +-U" else line
        sha = rest.split(" ", 1)[0]
        tail = rest[len(sha):].strip()
        subpath = tail.split(" ")[0] if tail else ""
        out.append({"flag": flag, "sha": sha, "subpath": subpath})
    return out
');
INSERT INTO "code_blobs" VALUES('452d7b575c85e1480c1f157f236cd2fa5e5b500a','python',4724,'"""congruency versioning ops — an importable operations library.

Each operation is a submodule exposing ``run(**kwargs)``. This package wraps them with
bug-report-on-failure so a caller can drive everything from Python:

    import ops
    ops.run_op("refresh_bundles", expect_tag="version-2.0002")
    ops.run_plan([
        {"name": "commit", "op": "commit_release", "args": {"message": "..."}},
        {"name": "bundles", "op": "refresh_bundles", "args": {"expect_tag": "version-2.0002"}},
        {"name": "verify",  "op": "verify_bundles"},
    ])

Or from a shell (single launch, still the library underneath):

    PYTHONPATH=<versioning-dir> python3 -m ops PLAN.json
    PYTHONPATH=<versioning-dir> python3 -m ops --op refresh_bundles --args ''{"expect_tag": "version-2.0002"}''

On any exception the failure is appended to bug_reports.jsonl (guards against silent
context drift) and re-raised. The op submodules and the shared helpers (gitutil,
verify_git_state, version_source) live one directory up and are put on sys.path here.
"""
import importlib
import json
import os
import sys
import time
import traceback

_HERE = os.path.dirname(os.path.abspath(__file__))
_VERSIONING = os.path.dirname(_HERE)
if _VERSIONING not in sys.path:                     # make gitutil / verify_git_state / version_source importable
    sys.path.insert(0, _VERSIONING)

BUG_LOG = os.path.join(_HERE, "bug_reports.jsonl")

__all__ = ["run_op", "run_plan", "load_op", "cli", "OpError", "BUG_LOG"]


class OpError(Exception):
    pass


def _record_bug(op, kwargs, exc, tb, bugs=None):
    entry = {
        "ts": time.strftime("%Y-%m-%dT%H:%M:%S"),
        "op": op,
        "kwargs": kwargs,
        "error_type": type(exc).__name__,
        "error": str(exc),
        "traceback": tb.strip().splitlines()[-6:],
    }
    with open(bugs or BUG_LOG, "a") as fh:
        fh.write(json.dumps(entry) + "\n")
    return entry


def load_op(name):
    """Import an op submodule by name (''refresh_bundles'' or ''refresh_bundles.py'')."""
    base = os.path.basename(name)
    modname = base[:-3] if base.endswith(".py") else base
    return importlib.import_module("%s.%s" % (__name__, modname))


def run_op(name, bugs=None, **kwargs):
    """Run one op''s run(**kwargs). On failure, record a bug report and re-raise."""
    mod = load_op(name)
    if not hasattr(mod, "run"):
        raise OpError("operation %r exposes no run()" % name)
    try:
        return mod.run(**kwargs)
    except Exception as exc:  # noqa: BLE001 — record everything, then propagate
        _record_bug(name, kwargs, exc, traceback.format_exc(), bugs)
        raise


def run_plan(steps, bugs=None):
    """Run a sequence of steps [{op, args, name}] fail-fast. Returns list of results;
    raises OpError at the first failing step (after the bug is recorded)."""
    if not isinstance(steps, list) or not steps:
        raise OpError("plan must be a non-empty list of steps")
    results = []
    for i, step in enumerate(steps, 1):
        name = step.get("name", step["op"])
        try:
            result = run_op(step["op"], bugs=bugs, **step.get("args", {}))
            results.append({"step": name, "ok": True, "result": result})
        except Exception as exc:  # noqa: BLE001
            results.append({"step": name, "ok": False, "error": str(exc)})
            raise OpError("plan aborted at step %d/%d (%s): %s"
                          % (i, len(steps), name, exc))
    return results


def cli(argv=None):
    """Shared CLI used by __main__.py and the opsrun.py executable entry point.

        <entry> PLAN.json
        <entry> --op refresh_bundles --args ''{"log": "..."}''
    """
    import argparse
    ap = argparse.ArgumentParser(prog="ops")
    ap.add_argument("plan", nargs="?", help="JSON plan file (list of {op, args, name})")
    ap.add_argument("--op", help="run a single op by name")
    ap.add_argument("--args", default="{}", help="JSON kwargs for --op")
    a = ap.parse_args(argv)
    try:
        if a.op:
            result = run_op(a.op, **json.loads(a.args))
            print(json.dumps(result, default=str, indent=2))
        elif a.plan:
            with open(a.plan) as fh:
                steps = json.load(fh)
            print("== run_plan: %d step(s) ==" % len(steps))
            results = run_plan(steps)
            for r in results:
                print("  [OK] %s: %s" % (r["step"], json.dumps(r["result"], default=str)[:200]))
            print("== all %d step(s) OK ==" % len(results))
        else:
            ap.error("give a PLAN.json or --op NAME")
        return 0
    except OpError as exc:
        print("\nFAILED: %s" % exc)
        print("(bug report appended to %s)" % BUG_LOG)
        return 1
');
INSERT INTO "code_blobs" VALUES('0864fba22aa656aa7974352ffd057f76985be922','python',318,'"""CLI entry for `python3 -m ops` — delegates to the shared ops.cli().

Prefer the standalone executable `opsrun.py` (it sets its own path). This module exists
so `python3 -m ops ...` also works when the versioning dir is importable.
"""
import sys

from . import cli

if __name__ == "__main__":
    sys.exit(cli())
');
INSERT INTO "code_blobs" VALUES('7c4d5eed528e67d46512b3c39bec8c22206ef50d','python',6977,'#!/usr/bin/env python3
"""Operation: commit everything and cut a version release, in one shot.

Pipeline (all live + logged; RAISES on any deviation so the runner records a bug report):
  1. VERIFY integrity   — check every repo + submodule structurally (dirty allowed, since
                          we are about to commit); abort if any is invalid.
  2. STAGE everything   — `git add -A` in every module (respects .gitignore).
  3. no change → NO-OP  — if nothing is staged anywhere, do not commit and do not consume
                          a version number.
  4. INCREMENT version  — python-computed next checkout increment (major.NNNN) from live
                          `version-*` tags; nothing inferred by hand.
  5. COMMIT everything  — one commit per changed module; the primary repo''s commit also
                          carries the project version manifest.
  6. SMART TAG          — the project version always advances, but a module is tagged ONLY
                          if its HEAD moved past its last version tag (frozen / unchanged
                          repos keep their previous tag).
  7. RE-VERIFY          — final integrity must be VALID (clean).
"""
import json
import os
import sys

HERE = os.path.dirname(os.path.abspath(__file__))
sys.path.insert(0, os.path.dirname(HERE))          # the versioning/ dir
from gitutil import Git, is_git_repo                          # noqa: E402
from verify_git_state import check_repo                       # noqa: E402
from version_source import compute_next_version, collect_modules, build_manifest  # noqa: E402
from paths import project_root, versioning_dir  # noqa: E402


class OperationError(Exception):
    pass


def latest_version(git, repo):
    """Return (tag, commit) of the highest version-* tag on repo, or (None, None)."""
    raw = git.query(["tag", "-l", "version-*"], repo) or ""
    best, best_key = None, None
    for line in raw.splitlines():
        t = line.strip()
        if not t.startswith("version-"):
            continue
        val = t[len("version-"):]
        try:
            major = int(val.split(".")[0])
            minor = int(val.split(".")[1]) if "." in val else 0
        except (ValueError, IndexError):
            continue
        key = (major, minor)
        if best_key is None or key > best_key:
            best_key, best = key, t
    if best is None:
        return None, None
    return best, git.query(["rev-list", "-n", "1", best], repo)


def run(root=None,
        primary_name="congruency",
        message=None,
        name="tournament-versioning",
        email="versioning@congruency.local",
        major=None,
        log=None):
    if not message:
        raise OperationError("a commit message is required")
    if root is None:
        root = project_root()                          # derived, not hard-coded (BUG-V05)
    git = Git(identity={"name": name, "email": email}, logfile=log, echo=False)

    subs, parents, standalone = collect_modules(git, root, include_generated=False)
    modules = subs + parents + standalone
    if not modules:
        raise OperationError("no modules discovered under %s" % root)
    primary = next((m for m in modules
                    if os.path.basename(m["name"]) == primary_name and not m["is_submodule"]), None)
    if not primary:
        raise OperationError("primary repo %r not found under %s" % (primary_name, root))

    # 1. verify integrity (structural; dirty allowed — we are about to commit)
    for m in modules:
        rr = check_repo(git, m["path"], allow_dirty=True)
        if not rr["valid"]:
            raise OperationError("integrity invalid in %s: %s" % (m["name"], rr["errors"]))

    # 2. stage everything, per module
    staged_modules = []
    for m in modules:
        git.run(["add", "-A"], m["path"], write=True)
        if (git.query(["diff", "--cached", "--name-only"], m["path"]) or "").strip():
            staged_modules.append(m)

    # 3. no change anywhere -> no-op, no version consumed
    if not staged_modules:
        return {"status": "no-op", "detail": "nothing to commit", "version_bumped": False}

    # 4. compute the next version from live tags (python-stamped)
    version = compute_next_version(git, primary["path"], major=major)
    tag = "version-%s" % version

    # 5. write the manifest into the primary repo + canonical root, then commit each module
    manifest = build_manifest(git, version, modules)
    committed = os.path.join(versioning_dir(), "project_versions.json")
    canonical = os.path.join(root, "project_versions.json")
    for p in (committed, canonical):
        with open(p, "w") as fh:
            json.dump(manifest, fh, indent=2)
    git.run(["add", "--", os.path.relpath(committed, primary["path"])], primary["path"], write=True)
    if primary not in staged_modules:
        staged_modules.append(primary)

    committed_in = []
    for m in staged_modules:
        before = git.query(["rev-parse", "HEAD"], m["path"])
        git.run(["commit", "-m", message], m["path"], write=True)
        after = git.query(["rev-parse", "HEAD"], m["path"])
        if after == before:
            raise OperationError("commit did not advance HEAD in %s" % m["name"])
        committed_in.append(m["name"])

    # 6. SMART TAG — only modules whose HEAD advanced past their last version tag
    tagged, skipped = [], []
    for m in modules:
        _, last_commit = latest_version(git, m["path"])
        head = git.query(["rev-parse", "HEAD"], m["path"])
        if last_commit is None or head != last_commit:
            git.run(["tag", "-a", tag, "-m", "Release %s of %s" % (version, m["name"])],
                    m["path"], write=True)
            tagged.append(m["name"])
        else:
            skipped.append(m["name"])

    # 7. refresh canonical manifest with resolved tag commits, then re-verify (clean)
    for e in manifest["modules"]:
        e["tagged"] = e["name"] in tagged
        e["tag_commit"] = git.query(["rev-list", "-n", "1", tag], e["path"]) if e["tagged"] else None
    with open(canonical, "w") as fh:
        json.dump(manifest, fh, indent=2)

    for m in modules:
        rr = check_repo(git, m["path"], allow_dirty=False)
        if not rr["valid"]:
            raise OperationError("post-release integrity invalid in %s: %s" % (m["name"], rr["errors"]))

    return {"version": version, "tag": tag, "message": message,
            "committed_in": committed_in, "tagged": tagged, "skipped": skipped}


if __name__ == "__main__":
    import argparse
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("-m", "--message", required=True)
    ap.add_argument("--root", default="/home/notificationsforsteven")
    ap.add_argument("--major", type=int, default=None)
    ap.add_argument("--log", default=None)
    a = ap.parse_args()
    print(json.dumps(run(root=a.root, message=a.message, major=a.major, log=a.log),
                     indent=2, default=str))
');
INSERT INTO "code_blobs" VALUES('607928f9650153c95bb96dfda73f55cd8dbba2d4','python',8473,'#!/usr/bin/env python3
"""Operation: generate MANIFEST.md — a complete, unambiguous description of every
top-level file and folder in the repo (and of the tournament entry folder), so there is
no confusion about what gets pushed to git.

Lists each entry with its type, whether it is committed (and therefore pushed) or
gitignored (not pushed), and a curated description. RAISES if any committed top-level
entry has no description — the manifest is only trustworthy if it is exhaustive.
Instrumented via gitutil. Left on disk as a reusable tool.
"""
import os
import sys
import time

HERE = os.path.dirname(os.path.abspath(__file__))
sys.path.insert(0, os.path.dirname(HERE))          # the versioning/ dir
from gitutil import Git  # noqa: E402
from paths import entry_hash  # noqa: E402


class OperationError(Exception):
    pass


ENTRY_SUBMISSION_DESC = ("THE TOURNAMENT SUBMISSION — the commit-named entry folder. Holds "
                         "the evolved tag engine, its oracle, the zero-JS showcase, the python "
                         "versioning/ops apparatus, and a self-contained snapshot of the CMS. "
                         "See its README.md / submission_00.txt.")


ROOT_DESC = {
    ".gitignore": "Ignore rules — the generated/local files that are NOT committed or pushed (sqlite DBs, node_modules, dev caches, the pinned .oldcode/vendor).",
    "MANIFEST.md": "This file — generated inventory of every root entry and exactly what gets pushed to git.",
    "README.md": "Repository readme.",
    "ENTRANTS.txt": "Tournament entrants log — one datetime line per entry (append-only).",
    "bin": "Original congruency CMS: bootstrap/front-controller entry (Execute.php), POM init, and test harnesses.",
    "doc": "Original congruency documentation (Install / Version / Changes / License / NextVersion).",
    "etc": "Original congruency configuration (Constants.php, Privilege.php).",
    "invocators": "Original congruency tag invocators — the tag classes the parser dispatches to.",
    "lib": "Original congruency library — TagLoader/parser, DAOs, persistent-object manager, form system.",
    "www": "Original congruency web root (index.php, Constants.php).",
    "dev": "Development tooling (NOT the CMS): Playwright attack loop, the 15-bug catalogue + repros, and the old-code reference. Heavy/generated parts are gitignored.",
}

ENTRY_DESC = {
    "README.md": "Submission overview, run instructions, and the seven-goal coverage map.",
    "LINEAGE.md": "How the code lineage (original -> refactors -> submission) is assembled into one modular git repo.",
    "submission_00.txt": "Submission location relative to the main codebase + tournament protocol details.",
    "assemble_lineage.sh": "Apparatus: builds the modular lineage repo (original -> refactors -> submission), deterministic.",
    "package_tournament.sh": "Apparatus: serializes the entire tournament into one self-verifying git bundle.",
    "bundle_push.sh": "Apparatus: pushes every project repo to a local git bundle (the offline stand-in remote).",
    "serve_override.php": "auto_prepend that points the harness ABS_PATH/TAGS_DIR at this submission snapshot.",
    "showcase": "The redesigned, server-side, zero-JavaScript front-end rendered by the evolved engine (the default congruency home).",
    "tests": "The self-contained oracle and all tested data (tests/parser/: run.php + 38 datasets + the evolved engine).",
    "versioning": "The python apparatus: verify_git_state, version_source (python-computed versions), checkout, the importable `ops` package (run_op/run_plan/opsrun + commit_release/refresh_bundles/verify_bundles/propagate_version/git_commit/generate_manifest/git_push), and instrumentation logs.",
    "bin": "Snapshot of the CMS bootstrap/harness at the entry commit (so the submission evaluates in isolation).",
    "doc": "Snapshot of the CMS documentation at the entry commit.",
    "etc": "Snapshot of the CMS configuration at the entry commit.",
    "invocators": "Snapshot of the CMS tag invocators at the entry commit.",
    "lib": "Snapshot of the CMS library at the entry commit.",
    "www": "Snapshot of the CMS web root at the entry commit.",
}

KIND = {"tree": "dir", "blob": "file", "commit": "submodule"}


def _entries(git, repo, treeish):
    raw = git.query(["ls-tree", treeish], repo) or ""
    out = []
    for line in raw.splitlines():
        meta, name = line.split("\t", 1)
        _, typ, _ = meta.split()
        out.append((name, KIND.get(typ, typ)))
    return sorted(out)


def _table(entries, descs, undescribed):
    rows = ["| entry | type | pushed? | description |", "|---|---|---|---|"]
    for name, kind in entries:
        disp = name + ("/" if kind == "dir" else "")
        desc = descs.get(name, "**UNDESCRIBED**")
        if desc == "**UNDESCRIBED**":
            undescribed.append(name)
        pushed = "no (submodule ref)" if kind == "submodule" else "yes"
        rows.append("| `%s` | %s | %s | %s |" % (disp, kind, pushed, desc))
    return "\n".join(rows)


def run(repo=None, out=None, remote_url="git@github.com:dudezilla/congruency.git", log=None):
    git = Git(logfile=log, echo=False)
    if repo is None:
        repo = git.query(["rev-parse", "--show-toplevel"], HERE)
    if not repo:
        raise OperationError("cannot resolve repo toplevel")
    out = out or os.path.join(repo, "MANIFEST.md")

    eh = entry_hash()
    branch = git.query(["rev-parse", "--abbrev-ref", "HEAD"], repo)
    head = git.query(["rev-parse", "HEAD"], repo)
    root = _entries(git, repo, "HEAD")
    entry_entries = _entries(git, repo, "HEAD:%s" % eh)
    ignore = git.query(["show", "HEAD:.gitignore"], repo) or "(none)"
    has_submods = bool(git.query(["ls-tree", "HEAD", ".gitmodules"], repo))

    root_desc = dict(ROOT_DESC)
    root_desc[eh] = ENTRY_SUBMISSION_DESC              # entry-hash described dynamically (BUG-V05)
    undescribed = []
    root_tbl = _table(root, root_desc, undescribed)
    entry_tbl = _table(entry_entries, ENTRY_DESC, [])  # entry-folder descriptions are advisory

    doc = """# MANIFEST — what is in this repository (and what gets pushed)

_Generated by `versioning/ops/generate_manifest.py`. Repo `%s` @ branch `%s` (`%s`)._

This repository (`%s`) pushes to **`%s`**. Everything listed as **pushed = yes** below is
committed and travels on `git push`. Everything under *What is NOT pushed* is gitignored.

## Root entries

%s

## Inside the submission folder `%s/`

The tournament entry. Its own top-level:

%s

## What is NOT pushed (gitignore)

These patterns are generated/local and never committed:

```
%s
```

## Submodules

%s

## Pushing to GitHub (reiterated)

`origin` = `%s`. GitHub is strict about submodules: it rejects a superproject push whose
gitlink points to a commit the remote does not yet have. Push submodules first, then the
superproject, then tags:

```sh
# from a clone on a machine with network + ssh to github.com:
git -C <repo> push origin --recurse-submodules=on-demand <branch>   # or push each submodule first
git -C <repo> push origin <branch>          # e.g. from-checkout-3  (the version-2.000x line)
git -C <repo> push origin --tags            # the version-* tags
```

Use the bundled **`versioning/ops/git_push.py`** to do this robustly (retries, streams
stdout+stderr to screen and log, records exceptions) from **outside** this container.
""" % (repo, branch, (head or "")[:12], os.path.basename(repo), remote_url,
       root_tbl, eh, entry_tbl, ignore,
       ("This repo has **no submodules of its own** (no `.gitmodules`), so its own push is not "
        "submodule-gated. The pristine original source is a submodule of a *different* repo "
        "(`congruency-bugs/vendor/congruency`), pinned at the 2006 `old-code` commit."
        if not has_submods else
        "This repo HAS submodules (`.gitmodules` present) — push each submodule''s commit to its "
        "upstream BEFORE pushing this superproject, or GitHub will reject the push."),
       remote_url)

    if undescribed:
        raise OperationError("undescribed committed root entries (add to ROOT_DESC): %s" % undescribed)

    with open(out, "w") as fh:
        fh.write(doc)
    return {"manifest": out, "root_entries": len(root),
            "entry_entries": len(entry_entries), "has_submodules": has_submods,
            "branch": branch}


if __name__ == "__main__":
    import json
    print(json.dumps(run(), indent=2, default=str))
');
INSERT INTO "code_blobs" VALUES('a7f10c62f8e5be5c12eaa70184524ff0937b1001','python',1863,'#!/usr/bin/env python3
"""Operation: stage paths and commit them into a repo, with verification.

Stages each path, asserts something is actually staged (unless expect_change=False),
commits with an EXPLICIT identity, and asserts HEAD advanced. RAISES on any deviation so
the runner records a bug report — a git write op that cannot silently no-op or drift.
"""
import os
import sys

HERE = os.path.dirname(os.path.abspath(__file__))
sys.path.insert(0, os.path.dirname(HERE))          # the versioning/ dir (has gitutil.py)
from gitutil import Git, is_git_repo  # noqa: E402


class OperationError(Exception):
    pass


def run(repo, paths, message,
        name="tournament-versioning",
        email="versioning@congruency.local",
        expect_change=True,
        log=None):
    if not is_git_repo(repo):
        raise OperationError("not a git repo: %s" % repo)
    if not paths:
        raise OperationError("no paths given to commit")

    git = Git(identity={"name": name, "email": email}, logfile=log, echo=True)
    for p in paths:
        git.run(["add", "--", p], repo, write=True)

    staged = (git.query(["diff", "--cached", "--name-only"], repo) or "").strip()
    if expect_change and not staged:
        raise OperationError("nothing staged to commit (paths matched no changes)")

    before = git.query(["rev-parse", "HEAD"], repo)
    git.run(["commit", "-m", message], repo, write=True)
    after = git.query(["rev-parse", "HEAD"], repo)
    if after == before:
        raise OperationError("commit did not advance HEAD (%s)" % before)

    return {"repo": repo, "commit": after, "branch":
            git.query(["rev-parse", "--abbrev-ref", "HEAD"], repo),
            "files": staged.splitlines()}


if __name__ == "__main__":
    import json
    print(json.dumps(run(sys.argv[1], sys.argv[2:-1], sys.argv[-1]), indent=2, default=str))
');
INSERT INTO "code_blobs" VALUES('e0776811c9cf8f4cd916ba456af241637404bcd4','python',7607,'#!/usr/bin/env python3
"""git_push.py — push this repository to its GitHub origin, from OUTSIDE the container.

Run this on a machine that has network access and an ssh key authorised for
git@github.com. It is self-contained (stdlib only) so it can be copied anywhere.

Why it exists: GitHub is strict about submodules — it REJECTS a superproject push whose
gitlink points to a commit the remote does not yet have. So this script (a) pushes every
submodule first, (b) then the branches, (c) then the tags, and retries transient failures
(expect several attempts). Every git call goes through run(): it uses subprocess, streams
stdout AND stderr to the screen and to a log file, and is wrapped in try/except so any
exception is recorded rather than silently swallowed.

Usage:
    python3 git_push.py                 # push configured branches + tags to origin
    python3 git_push.py --branch main   # override branch(es), repeatable
    python3 git_push.py --dry-run       # print what it would do, push nothing
"""
import argparse
import datetime
import os
import subprocess
import sys
import time

# ---------------------------------------------------------------- configuration --
REPO = os.getcwd()                                   # set at runtime to the git toplevel
REMOTE = "origin"
DEFAULT_BRANCHES = ["from-checkout-3", "order-logging"]
MAX_ATTEMPTS = 12
RETRY_DELAY_S = 5
LOG_PATH = None                                      # set at runtime

EXCEPTIONS = []                                      # (context, error) recorded here


# --------------------------------------------------------------------- logging --
def log(msg):
    """Print to screen AND append to the console log file."""
    line = "%s  %s" % (datetime.datetime.now().isoformat(timespec="seconds"), msg)
    print(line, flush=True)
    if LOG_PATH:
        try:
            with open(LOG_PATH, "a") as fh:
                fh.write(line + "\n")
        except OSError as exc:                       # never let logging crash the push
            print("(!) could not write log: %s" % exc, flush=True)


# ---------------------------------------------- subprocess-using functions -----
def run(cmd, cwd=None, dry_run=False):
    """Run a command via subprocess; stream stdout+stderr to screen+log; try/except-guarded.
    Returns (returncode, stdout, stderr). Records any exception in EXCEPTIONS."""
    cwd = cwd or REPO
    log("$ %s   (cwd=%s)" % (" ".join(cmd), cwd))
    if dry_run:
        log("  (dry-run: not executed)")
        return 0, "", ""
    try:
        proc = subprocess.run(cmd, cwd=cwd, capture_output=True, text=True)
    except Exception as exc:                         # FileNotFoundError, OSError, etc.
        log("  !! EXCEPTION: %r" % exc)
        EXCEPTIONS.append((" ".join(cmd), repr(exc)))
        return 1, "", str(exc)
    for ln in (proc.stdout or "").splitlines():
        log("  out| %s" % ln)
    for ln in (proc.stderr or "").splitlines():
        log("  err| %s" % ln)
    log("  -> rc=%d" % proc.returncode)
    return proc.returncode, proc.stdout, proc.stderr


def resolve_toplevel():
    """Set REPO to the git worktree toplevel of this script''s location."""
    global REPO
    here = os.path.dirname(os.path.abspath(__file__))
    try:
        proc = subprocess.run(["git", "-C", here, "rev-parse", "--show-toplevel"],
                              capture_output=True, text=True)
        if proc.returncode == 0 and proc.stdout.strip():
            REPO = proc.stdout.strip()
    except Exception as exc:
        EXCEPTIONS.append(("resolve_toplevel", repr(exc)))
    return REPO


def show_remote(dry_run=False):
    rc, out, _ = run(["git", "remote", "-v"], dry_run=dry_run)
    return rc == 0


def list_submodules(dry_run=False):
    rc, out, _ = run(["git", "submodule", "status"], dry_run=dry_run)
    subs = []
    for line in (out or "").splitlines():
        parts = line.strip().lstrip("+-U ").split()
        if len(parts) >= 2:
            subs.append(parts[1])
    return subs


def retry(fn, what, attempts=MAX_ATTEMPTS, delay=RETRY_DELAY_S):
    """Run fn() up to `attempts` times until it returns True; record failures."""
    for i in range(1, attempts + 1):
        log("== attempt %d/%d: %s ==" % (i, attempts, what))
        try:
            if fn():
                log("== SUCCESS: %s (attempt %d) ==" % (what, i))
                return True
            log("   attempt %d for ''%s'' did not succeed" % (i, what))
        except Exception as exc:
            log("   !! attempt %d raised: %r" % (i, exc))
            EXCEPTIONS.append((what, repr(exc)))
        if i < attempts:
            time.sleep(delay)
    log("== GAVE UP: %s after %d attempts ==" % (what, attempts))
    return False


def push_submodules_first(dry_run=False):
    subs = list_submodules(dry_run=dry_run)
    if not subs:
        log("no submodules in this repo — nothing to push first")
        return True
    ok = True
    for sp in subs:
        sub_cwd = os.path.join(REPO, sp)
        ok = retry(lambda sp=sp, c=sub_cwd: run(["git", "push", REMOTE, "HEAD"],
                                                cwd=c, dry_run=dry_run)[0] == 0,
                   "push submodule %s" % sp) and ok
    return ok


def push_branches(branches, dry_run=False):
    ok = True
    for b in branches:
        ok = retry(lambda b=b: run(["git", "push", REMOTE, "%s:%s" % (b, b)],
                                   dry_run=dry_run)[0] == 0,
                   "push branch %s" % b) and ok
    return ok


def push_tags(dry_run=False):
    return retry(lambda: run(["git", "push", REMOTE, "--tags"], dry_run=dry_run)[0] == 0,
                 "push tags")


# ------------------------------------------------------------------------ main --
def main(argv=None):
    global LOG_PATH
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--branch", action="append", dest="branches",
                    help="branch to push (repeatable; default: %s)" % DEFAULT_BRANCHES)
    ap.add_argument("--remote", default=REMOTE)
    ap.add_argument("--no-tags", action="store_true")
    ap.add_argument("--dry-run", action="store_true")
    ap.add_argument("--log", default=None)
    a = ap.parse_args(argv)

    resolve_toplevel()
    LOG_PATH = a.log or os.path.join(REPO, "git_push.log")
    branches = a.branches or DEFAULT_BRANCHES

    log("### git_push.py — repo=%s remote=%s branches=%s dry_run=%s ###"
        % (REPO, a.remote, branches, a.dry_run))
    show_remote(dry_run=a.dry_run)

    results = {}
    for name, fn in [
        ("submodules-first", lambda: push_submodules_first(dry_run=a.dry_run)),
        ("branches", lambda: push_branches(branches, dry_run=a.dry_run)),
        ("tags", (lambda: True) if a.no_tags else (lambda: push_tags(dry_run=a.dry_run))),
    ]:
        try:
            results[name] = fn()
        except Exception as exc:                     # top-level guard per step
            log("!! step ''%s'' raised: %r" % (name, exc))
            EXCEPTIONS.append((name, repr(exc)))
            results[name] = False

    log("### SUMMARY ###")
    for name, ok in results.items():
        log("  %-16s %s" % (name, "OK" if ok else "FAILED"))
    if EXCEPTIONS:
        log("### recorded exceptions (%d) ###" % len(EXCEPTIONS))
        for ctx, err in EXCEPTIONS:
            log("  - %s :: %s" % (ctx, err))
    ok_all = all(results.values()) and not EXCEPTIONS
    log("### DONE — %s ###" % ("ALL PUSHED" if ok_all else "INCOMPLETE (see log + exceptions)"))
    return 0 if ok_all else 1


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('05f4bae70abba50c134e16ff87e7d0fdf1670443','python',664,'#!/usr/bin/env python3
"""opsrun.py — the executable entry point for the ops library.

Runs an ops PLAN (or a single op) through the bug-trap library, with EACH link passing
through the trap. Resolves its own path from __file__ — no PYTHONPATH, no `python -m`,
no shell wrapper. Run it directly:

    ./opsrun.py PLAN.json
    ./opsrun.py --op refresh_bundles --args ''{"log": "/tmp/x.log"}''
"""
import os
import sys

# python reads its OWN path here — the versioning dir (parent of this ops/ package)
sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
import ops  # noqa: E402

if __name__ == "__main__":
    sys.exit(ops.cli())
');
INSERT INTO "code_blobs" VALUES('932527b46f3f154eae3cf61b60ca1d92f489f575','python',3506,'#!/usr/bin/env python3
"""Operation: propagate a version tag (and an optional branch) from a source root''s
repos to their ORIGIN repos.

Pushes `refs/tags/<tag>` from every module in `source_root` to the matching repo under
`origin_root`, plus `refs/heads/<branch>` for the one module that carries the change.
Verifies each ref landed at the same commit; RAISES on any mismatch so the runner
records a bug report. Instrumented via gitutil (every git op logged, live).
"""
import os
import sys

HERE = os.path.dirname(os.path.abspath(__file__))
sys.path.insert(0, os.path.dirname(HERE))          # the versioning/ dir (has gitutil.py)
from gitutil import Git, is_git_repo  # noqa: E402
from paths import project_root  # noqa: E402


class OperationError(Exception):
    pass


DEFAULT_MODULES = [
    "congruency", "congruency-harness", "congruency-tests",
    "congruency-bugs", "coverage", "pwdriver",
    "congruency-bugs/vendor/congruency",
]


def run(source_root=None,
        origin_root=None,
        tag="version-2.0001",
        branch="from-checkout-3",
        branch_module="congruency",
        modules=None,
        log=None):
    if source_root is None:
        source_root = project_root()                   # derived (BUG-V05); override for cross-checkout
    if origin_root is None:
        origin_root = project_root()
    modules = modules or DEFAULT_MODULES
    git = Git(logfile=log, echo=True)
    propagated = []
    for m in modules:
        src = os.path.join(source_root, m)
        dst = os.path.join(origin_root, m)
        if not is_git_repo(src):
            raise OperationError("source is not a git repo: %s" % src)
        if not is_git_repo(dst):
            raise OperationError("origin is not a git repo: %s" % dst)

        src_tag_commit = git.query(["rev-list", "-n", "1", tag], src)
        if not src_tag_commit:
            raise OperationError("tag %s not present in source %s" % (tag, src))

        refspecs = ["refs/tags/%s:refs/tags/%s" % (tag, tag)]
        pushing_branch = bool(branch) and m == branch_module
        if pushing_branch:
            src_branch_commit = git.query(["rev-parse", "--verify", branch], src)
            if not src_branch_commit:
                raise OperationError("branch %s not present in source %s" % (branch, src))
            refspecs.insert(0, "refs/heads/%s:refs/heads/%s" % (branch, branch))

        git.run(["push", dst] + refspecs, src, write=False)   # raises on failure

        dst_tag_commit = git.query(["rev-list", "-n", "1", tag], dst)
        if dst_tag_commit != src_tag_commit:
            raise OperationError("tag %s did not propagate to %s (%s != %s)"
                                 % (tag, dst, dst_tag_commit, src_tag_commit))
        rec = {"module": m, "tag": tag, "tag_commit": dst_tag_commit}

        if pushing_branch:
            dst_branch_commit = git.query(["rev-parse", "--verify", branch], dst)
            if dst_branch_commit != src_branch_commit:
                raise OperationError("branch %s did not propagate to %s (%s != %s)"
                                     % (branch, dst, dst_branch_commit, src_branch_commit))
            rec["branch"] = branch
            rec["branch_commit"] = dst_branch_commit
        propagated.append(rec)

    return {"tag": tag, "source_root": source_root, "origin_root": origin_root,
            "count": len(propagated), "propagated": propagated}


if __name__ == "__main__":
    import json
    print(json.dumps(run(), indent=2, default=str))
');
INSERT INTO "code_blobs" VALUES('7d721481c5b7e3a47aaefc028fa3fa2225e85809','python',2739,'#!/usr/bin/env python3
"""Operation: regenerate the local git bundles from a source root''s repos.

Rebuilds `<bundles_dir>/<name>.bundle` (all refs + tags) for each repo, verifies each
bundle re-opens (by EXIT CODE — BUG-V04), and — when `expect_tag` is given — asserts
that tag is present in every bundle. RAISES on any failure so the runner records a bug
report. Instrumented via gitutil. Output paths are ABSOLUTE (avoids BUG-V03).
"""
import os
import sys

HERE = os.path.dirname(os.path.abspath(__file__))
sys.path.insert(0, os.path.dirname(HERE))          # the versioning/ dir (has gitutil.py)
from gitutil import Git, is_git_repo  # noqa: E402
from paths import project_root, bundles_dir as default_bundles_dir  # noqa: E402


class OperationError(Exception):
    pass


# (repo path relative to source_root, bundle basename) — matches existing ~/bundles names
DEFAULT_MAPPING = [
    ("congruency", "congruency"),
    ("congruency-harness", "congruency-harness"),
    ("congruency-tests", "congruency-tests"),
    ("congruency-bugs", "congruency-bugs"),
    ("coverage", "coverage"),
    ("pwdriver", "pwdriver"),
    ("congruency-bugs/vendor/congruency", "vendor-congruency"),
]


def run(source_root=None,
        bundles_dir=None,
        mapping=None,
        expect_tag=None,
        log=None):
    if source_root is None:
        source_root = project_root()                   # derived (BUG-V05)
    if bundles_dir is None:
        bundles_dir = default_bundles_dir()
    mapping = mapping or DEFAULT_MAPPING
    git = Git(logfile=log, echo=False)
    os.makedirs(bundles_dir, exist_ok=True)
    made = []
    for relpath, name in mapping:
        src = os.path.join(source_root, relpath)
        if not is_git_repo(src):
            raise OperationError("not a git repo: %s" % src)
        out = os.path.abspath(os.path.join(bundles_dir, name + ".bundle"))
        git.run(["bundle", "create", out, "--all"], src, write=False)  # raises on failure

        # `git bundle verify` reports validity via EXIT CODE (0 = ok) and prints to
        # stderr — rely on the exit code, not stdout text (BUG-V04). check=True raises.
        git.run(["bundle", "verify", out], src, write=False, check=True)
        if expect_tag:
            heads = git.query(["bundle", "list-heads", out], src) or ""
            if ("refs/tags/%s" % expect_tag) not in heads:
                raise OperationError("bundle %s is missing expected tag %s" % (out, expect_tag))
        made.append({"repo": relpath, "bundle": out})

    return {"bundles_dir": bundles_dir, "expect_tag": expect_tag,
            "count": len(made), "bundles": made}


if __name__ == "__main__":
    import json
    print(json.dumps(run(), indent=2, default=str))
');
INSERT INTO "code_blobs" VALUES('ff6decbb41f3d6b504961bfe5fe191fe38ba9c07','python',1039,'#!/usr/bin/env python3
"""release.py "<message>" — one-liner: commit everything + auto version bump.

Thin wrapper over the ops library: runs the `commit_release` operation (verify →
add -A → commit → python-computed version bump → smart tag → re-verify), with
bug-report-on-failure. Prefer:  python3 -m ops --op commit_release --args ''{"message": "..."}''
"""
import json
import os
import sys

sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))  # versioning/
import ops  # noqa: E402


def main(argv=None):
    argv = sys.argv[1:] if argv is None else argv
    if not argv or not argv[0].strip():
        print(''usage: release.py "<commit message>"'')
        return 2
    try:
        result = ops.run_op("commit_release", message=argv[0])
        print(json.dumps(result, default=str, indent=2))
        return 0
    except Exception as exc:  # noqa: BLE001
        print("FAILED — %s (bug report in %s)" % (exc, ops.BUG_LOG))
        return 1


if __name__ == "__main__":
    sys.exit(main())
