INSERT INTO "code_blobs" VALUES('58f039d8cd36253f961784972d442ab56421f674','python',3421,'#!/usr/bin/env python3
"""Operation: verify each local bundle matches its origin repo.

For every repo: assert every `version-*` tag present in the repo is also present in its
bundle, and every branch head in the repo matches the branch head recorded in the bundle.
RAISES on any missing tag or branch drift so the runner records a bug report. Read-only
with respect to the repos (only reads git + bundle metadata).
"""
import os
import sys

HERE = os.path.dirname(os.path.abspath(__file__))
sys.path.insert(0, os.path.dirname(HERE))          # the versioning/ dir
from gitutil import Git, is_git_repo  # noqa: E402
from paths import project_root, bundles_dir as default_bundles_dir  # noqa: E402


class OperationError(Exception):
    pass


DEFAULT_MAPPING = [
    ("congruency", "congruency"),
    ("congruency-harness", "congruency-harness"),
    ("congruency-tests", "congruency-tests"),
    ("congruency-bugs", "congruency-bugs"),
    ("coverage", "coverage"),
    ("pwdriver", "pwdriver"),
    ("congruency-bugs/vendor/congruency", "vendor-congruency"),
]


def _bundle_refs(git, repo, bundle):
    """Map ref-name -> object sha from `git bundle list-heads`."""
    raw = git.query(["bundle", "list-heads", bundle], repo) or ""
    refs = {}
    for line in raw.splitlines():
        parts = line.split(None, 1)
        if len(parts) == 2:
            refs[parts[1].strip()] = parts[0].strip()
    return refs


def run(root=None,
        bundles_dir=None,
        mapping=None,
        log=None):
    if root is None:
        root = project_root()                          # derived (BUG-V05)
    if bundles_dir is None:
        bundles_dir = default_bundles_dir()
    mapping = mapping or DEFAULT_MAPPING
    git = Git(logfile=log, echo=False)
    report = []
    for relpath, name in mapping:
        repo = os.path.join(root, relpath)
        bundle = os.path.join(bundles_dir, name + ".bundle")
        if not is_git_repo(repo):
            raise OperationError("not a git repo: %s" % repo)
        if not os.path.isfile(bundle):
            raise OperationError("missing bundle: %s" % bundle)

        refs = _bundle_refs(git, repo, bundle)

        # every version-* tag in the repo must be present in the bundle
        repo_tags = (git.query(["tag", "-l", "version-*"], repo) or "").split()
        missing = [t for t in repo_tags if ("refs/tags/%s" % t) not in refs]
        if missing:
            raise OperationError("bundle %s missing tags: %s" % (name, missing))

        # every branch head in the repo must match the bundle
        branch_lines = (git.query(
            ["for-each-ref", "--format=%(refname:short) %(objectname)", "refs/heads"],
            repo) or "").splitlines()
        drift = []
        for bl in branch_lines:
            bn, commit = bl.split()
            bh = refs.get("refs/heads/%s" % bn)
            if bh is None:
                drift.append("%s:absent" % bn)
            elif bh != commit:
                drift.append("%s:%s!=%s" % (bn, bh[:9], commit[:9]))
        if drift:
            raise OperationError("bundle %s branch drift: %s" % (name, drift))

        report.append({"bundle": name, "version_tags": len(repo_tags),
                       "branches": len(branch_lines)})

    return {"bundles_dir": bundles_dir, "count": len(report), "verified": report}


if __name__ == "__main__":
    import json
    print(json.dumps(run(), indent=2, default=str))
');
INSERT INTO "code_blobs" VALUES('51e309820c4e1505b403026666476f52ddae6fc6','python',1500,'"""paths.py — derive every project path RELATIVE to this file (no hard-coded absolutes).

The tools must work from a clone at any location. This module resolves the repo, the
project root, the entry-hash folder and the bundles dir from `__file__` + `git`, so ops
can default to these instead of hard-coding `/home/...` or the commit hash.

Fixes BUG-V05. (The larger redesign — all paths + args supplied via a python-loaded JSON
config — is tracked as RD-01.)
"""
import os
import subprocess

_HERE = os.path.dirname(os.path.abspath(__file__))          # the versioning/ dir


def versioning_dir():
    return _HERE


def entry_dir():
    """The commit-named entry folder (the parent of versioning/)."""
    return os.path.dirname(_HERE)


def entry_hash():
    return os.path.basename(entry_dir())


def repo_root():
    """Git toplevel of the repository the tools live in (works at any clone location)."""
    try:
        proc = subprocess.run(["git", "-C", _HERE, "rev-parse", "--show-toplevel"],
                              capture_output=True, text=True)
        if proc.returncode == 0 and proc.stdout.strip():
            return proc.stdout.strip()
    except Exception:
        pass
    return os.path.dirname(entry_dir())                     # entry -> repo (fallback)


def project_root():
    """Parent of the repo — where sibling repos and the bundles dir live."""
    return os.path.dirname(repo_root())


def bundles_dir():
    return os.path.join(project_root(), "bundles")
');
INSERT INTO "code_blobs" VALUES('d1e6973094a28fabdc415a9a17dbc00c1cc586bb','python',3305,'#!/usr/bin/env python3
"""push_branch.py — push a branch from THIS checkout to another checkout (instrumented).

Propagates a change branch between working checkouts by PATH — no network, no bundle
round-trip. Adds the target repo as a path remote and pushes the branch, then verifies
the branch head is identical on both sides.

INSTRUMENTED: every git operation runs live and is logged via gitutil.Git; nothing from
memory. Pushing a NEW branch into a detached-HEAD target is conflict-free (the target has
no checked-out branch to refuse).

Usage:
  ./push_branch.py --target REPO --branch NAME [--source REPO]
                   [--remote-name NAME] [--name N --email E] [--log OUT.log]
"""
import argparse
import os
import sys

from gitutil import Git, GitError


def main(argv=None):
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--target", required=True, help="destination repo (working checkout) path")
    ap.add_argument("--branch", required=True, help="branch to push")
    ap.add_argument("--source", default=None,
                    help="source repo (default: the repo containing this script)")
    ap.add_argument("--remote-name", default=None,
                    help="remote name to register in source (default: basename of target''s parent)")
    ap.add_argument("--name", default="checkout3")
    ap.add_argument("--email", default="checkout3@congruency.local")
    ap.add_argument("--log", default=None)
    args = ap.parse_args(argv)

    identity = {"name": args.name, "email": args.email}
    git = Git(identity=identity, logfile=args.log, echo=True)

    source = args.source or os.path.dirname(os.path.abspath(__file__))
    src = git.query(["rev-parse", "--show-toplevel"], source)
    if not src:
        print("source is not a git repo: %s" % source)
        return 2
    target = os.path.abspath(args.target)
    tgt = git.query(["rev-parse", "--show-toplevel"], target)
    if not tgt:
        print("target is not a git repo: %s" % target)
        return 2

    remote = args.remote_name or ("to-" + os.path.basename(os.path.dirname(tgt)) or "target")
    branch = args.branch

    # register the target as a path remote in the source (idempotent)
    git.run(["remote", "remove", remote], src, write=False, check=False)
    git.run(["remote", "add", remote, tgt], src, write=False)

    # confirm the branch exists in source
    src_head = git.query(["rev-parse", "--verify", branch], src)
    if not src_head:
        print("branch %s not found in source %s" % (branch, src))
        return 2

    # push it (target is detached HEAD -> pushing a new branch is safe)
    git.run(["push", remote, "%s:%s" % (branch, branch)], src, write=False)

    # verify the branch head is identical on both sides
    tgt_head = git.query(["rev-parse", "--verify", branch], tgt)
    ok = bool(tgt_head) and tgt_head == src_head
    print("\n-- push result --")
    print("  branch      : %s" % branch)
    print("  source head : %s (%s)" % ((src_head or "?")[:10], src))
    print("  target head : %s (%s)" % ((tgt_head or "?")[:10], tgt))
    print("  %s" % ("OK — branch propagated, heads match" if ok
                    else "FAIL — heads differ or push did not land"))
    return 0 if ok else 1


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('900a1cbd2b90d102c9741df6845ab7cc8c987646','python',7552,'#!/usr/bin/env python3
"""verify_git_state.py — verify the multi-repo project git state is VALID.

Checks every repository under the project root and, for each, every submodule —
ensuring submodules are instrumented correctly so the repositories cannot drift
out of sync (no pointer mismatches, no uninitialised or dirty submodules, a
consistent .gitmodules). Exits 0 only when the whole project is valid.

INSTRUMENTED: every git call is executed live and logged (see gitutil.Git); no
state is taken from memory. Emits a JSON report and a human summary.

Usage:
  ./verify_git_state.py [--root DIR] [--json OUT.json] [--log OUT.log]
                        [--allow-dirty] [--include-generated] [--quiet]
"""
import argparse
import json
import os
import sys

from gitutil import (Git, discover_top_repos, is_git_repo, parse_gitmodules,
                     submodule_status)

FLAG_MEANING = {" ": "in-sync", "+": "POINTER-MISMATCH", "-": "UNINITIALISED",
                "U": "MERGE-CONFLICT"}


def check_repo(git, path, allow_dirty):
    r = {"path": path, "name": os.path.basename(path), "checks": {}, "submodules": [],
         "errors": [], "warnings": []}
    ck = r["checks"]

    # 1. valid repo + resolvable HEAD
    top = git.query(["rev-parse", "--show-toplevel"], path)
    ck["is_repo"] = bool(top)
    if not top:
        r["errors"].append("not a git repository")
        return r
    head = git.query(["rev-parse", "HEAD"], path)
    ck["head"] = head
    if not head:
        r["errors"].append("HEAD does not resolve (unborn/detached-broken)")
    branch = git.query(["rev-parse", "--abbrev-ref", "HEAD"], path)
    ck["branch"] = branch

    # 2. clean working tree
    porcelain = git.query(["status", "--porcelain"], path) or ""
    dirty = [l for l in porcelain.splitlines() if l.strip()]
    ck["clean"] = not dirty
    ck["dirty_count"] = len(dirty)
    if dirty:
        (r["warnings"] if allow_dirty else r["errors"]).append(
            "working tree dirty (%d entries)" % len(dirty))

    # 3. filemode config (mode-only noise is a known hazard here)
    ck["core_filemode"] = git.query(["config", "--get", "core.fileMode"], path)

    # 4. submodules: correct instrumentation + no cross-repo mismatch
    declared = parse_gitmodules(path, git)
    statuses = submodule_status(path, git)
    ck["submodule_count"] = len(statuses)
    seen_paths = set()
    for st in statuses:
        sp = st["subpath"]
        seen_paths.add(sp)
        sub = {"subpath": sp, "flag": st["flag"], "state": FLAG_MEANING.get(st["flag"], "?"),
               "recorded_sha": st["sha"], "errors": []}
        subabs = os.path.join(path, sp)

        # (a) declared in .gitmodules with a url
        decl = next((v for v in declared.values() if v.get("path") == sp), None)
        sub["declared"] = bool(decl)
        sub["url"] = (decl or {}).get("url")
        if not decl:
            sub["errors"].append(".gitmodules has no entry for this path")
        elif not decl.get("url"):
            sub["errors"].append(".gitmodules entry missing url")

        # (b) initialised: url wired into the parent''s config
        cfg_url = git.query(["config", "--get",
                             "submodule.%s.url" % _module_name(declared, sp)], path)
        sub["initialised"] = bool(cfg_url)
        if st["flag"] == "-":
            sub["errors"].append("submodule not initialised (run: git submodule update --init)")

        # (c) NO POINTER MISMATCH: parent gitlink == submodule HEAD
        gitlink = _gitlink_sha(git, path, sp)
        sub["parent_gitlink"] = gitlink
        if is_git_repo(subabs):
            sub_head = git.query(["rev-parse", "HEAD"], subabs)
            sub["submodule_head"] = sub_head
            if gitlink and sub_head and gitlink != sub_head:
                sub["errors"].append("MISMATCH: parent records %s but submodule HEAD is %s"
                                     % (gitlink[:10], sub_head[:10]))
            # (d) submodule working tree clean
            sub_porc = git.query(["status", "--porcelain"], subabs) or ""
            sub_dirty = [l for l in sub_porc.splitlines() if l.strip()]
            sub["clean"] = not sub_dirty
            if sub_dirty:
                (r["warnings"] if allow_dirty else sub["errors"]).append(
                    "submodule working tree dirty (%d)" % len(sub_dirty))
        if st["flag"] == "+":
            sub["errors"].append("checked-out commit differs from recorded pointer (+)")
        if st["flag"] == "U":
            sub["errors"].append("submodule has merge conflicts (U)")

        r["submodules"].append(sub)
        r["errors"].extend("%s: %s" % (sp, e) for e in sub["errors"])

    # declared-but-absent
    for name, v in declared.items():
        if v.get("path") and v["path"] not in seen_paths:
            r["errors"].append("%s declared in .gitmodules but not present" % v["path"])

    r["valid"] = not r["errors"]
    return r


def _module_name(declared, subpath):
    for name, v in declared.items():
        if v.get("path") == subpath:
            return name
    return subpath


def _gitlink_sha(git, path, subpath):
    out = git.query(["ls-tree", "HEAD", subpath], path)
    # format: "160000 commit <sha>\t<path>"
    if out and "commit" in out:
        try:
            return out.split()[2]
        except IndexError:
            return None
    return None


def main(argv=None):
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--root", default=os.path.expanduser("~"))
    ap.add_argument("--json", default=None, help="write JSON report here")
    ap.add_argument("--log", default=None, help="instrumentation log path")
    ap.add_argument("--allow-dirty", action="store_true",
                    help="treat dirty trees as warnings, not failures")
    ap.add_argument("--include-generated", action="store_true")
    ap.add_argument("--quiet", action="store_true")
    args = ap.parse_args(argv)

    git = Git(logfile=args.log, echo=not args.quiet)
    repos = discover_top_repos(args.root, git, include_generated=args.include_generated)

    report = {"root": args.root, "repos": [], "valid": True,
              "total_repos": 0, "total_submodules": 0}
    for path in repos:
        rr = check_repo(git, path, args.allow_dirty)
        report["repos"].append(rr)
        report["total_repos"] += 1
        report["total_submodules"] += len(rr["submodules"])
        if not rr.get("valid"):
            report["valid"] = False

    # ---- human summary ----
    print("\n== git state verification ==")
    for rr in report["repos"]:
        mark = "OK  " if rr.get("valid") else "FAIL"
        subinfo = ""
        if rr["submodules"]:
            subinfo = "  submodules: " + ", ".join(
                "%s[%s]" % (s["subpath"], s["state"]) for s in rr["submodules"])
        print("  [%s] %-22s %s%s" % (
            mark, rr["name"],
            (rr["checks"].get("branch") or "-"),
            subinfo))
        for e in rr["errors"]:
            print("         - ERROR: %s" % e)
        for w in rr["warnings"]:
            print("         - warn: %s" % w)
    print("  --")
    print("  %d repos, %d submodules checked -> %s"
          % (report["total_repos"], report["total_submodules"],
             "VALID" if report["valid"] else "INVALID"))

    if args.json:
        with open(args.json, "w") as fh:
            json.dump(report, fh, indent=2)
        print("  json report: %s" % args.json)

    return 0 if report["valid"] else 1


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('8112f830faa66f6674c17d3006124a305cd9692f','python',15948,'#!/usr/bin/env python3
"""version_source.py — introduce initial versioning across the whole project.

A previously-missing feature: version ALL original source code as version 2. This
script, with an EXPLICIT git identity (instrumentation — never ambient config):

  1. verifies the project git state first (aborts if invalid, unless --force);
  2. ensures every module and every submodule BOUNDARY carries an appropriate
     README;
  3. writes a project-wide version MANIFEST;
  4. reconciles any submodule pointers it moved;
  5. tags every repository AND every submodule with an annotated version tag
     (default: version-2).

It may make multiple commits. Every git operation is executed live and logged —
nothing is done from memory. Run verify_git_state.py again afterwards to confirm.

Usage:
  ./version_source.py [--version N] [--name NAME --email EMAIL]
                      [--root DIR] [--log OUT.log] [--force] [--dry-run]
"""
import argparse
import json
import os
import sys
import time

from gitutil import (Git, discover_top_repos, is_git_repo, parse_gitmodules,
                     submodule_status)
from verify_git_state import check_repo

DESC = {
    "congruency": ("Congruency CMS — the tournament SOURCE repository. The selected "
                    "winning submission lives under the entry-hash folder: the evolved "
                    "tag engine, its self-configuring oracle, and the zero-JS showcase."),
    "congruency-harness": ("Boot & serve harness for the Congruency CMS: a static PHP "
                            "runtime, the database seeder, and the dev-server router. "
                            "`./serve` starts the winning showcase (the default home); "
                            "`./serve --legacy` starts the original CMS."),
    "congruency-tests": ("Verification apparatus (the oracle) for the tournament: the "
                          "test suites and the end-to-end verify harness."),
    "congruency-bugs": ("Catalogue of 15 defects in the original Congruency CMS, each "
                         "with a runnable reproduction. Embeds the pristine original "
                         "source as a git submodule under `vendor/congruency`."),
    "coverage": ("Tokenizer-based PHP branch-coverage tool used to measure test reach "
                 "across the tournament code."),
    "pwdriver": ("Playwright-based adversarial attack loop that probes the running CMS "
                 "for defects."),
}


def module_readme(name, version):
    body = DESC.get(name, "%s — a Congruency project module." % name)
    return ("# %s\n\n%s\n\n---\n_Versioned as **version-%s** by the project versioning "
            "apparatus._\n" % (name, body, version))


def boundary_readme(subpath, url, version):
    return ("# %s — submodule boundary\n\n"
            "`%s` is a **git submodule**: the pristine original Congruency source "
            "(the 2006 \"old-code\"), pinned by commit and intentionally frozen — do "
            "not edit it in place; move the pointer via the submodule instead.\n\n"
            "* upstream: `%s`\n"
            "* wiring:   see the parent repository''s `.gitmodules`\n\n"
            "---\n_Boundary documented for **version-%s**._\n"
            % (os.path.dirname(subpath) or subpath, subpath, url or "(see .gitmodules)", version))


class Versioner:
    def __init__(self, git, version, dry_run):
        self.git = git
        self.version = version
        self.tag = "version-%s" % version
        self.dry = dry_run
        self.commits = []
        self.tags = []

    def _write_and_commit(self, repo, relpath, content, msg):
        abspath = os.path.join(repo, relpath)
        if os.path.exists(abspath):
            return False
        print("  + create %s/%s" % (os.path.basename(repo), relpath))
        if self.dry:
            return True
        os.makedirs(os.path.dirname(abspath) or repo, exist_ok=True)
        with open(abspath, "w") as fh:
            fh.write(content)
        self.git.run(["add", "--", relpath], repo, write=True)
        self.git.run(["commit", "-m", msg], repo, write=True)
        self.commits.append((repo, msg))
        return True

    def ensure_module_readme(self, repo):
        name = os.path.basename(repo)
        return self._write_and_commit(
            repo, "README.md", module_readme(name, self.version),
            "docs: add module README (version-%s boundary)" % self.version)

    def ensure_boundary_readme(self, parent, subpath, url):
        bdir = os.path.dirname(subpath) or subpath
        rel = os.path.join(bdir, "README.md")
        return self._write_and_commit(
            parent, rel, boundary_readme(subpath, url, self.version),
            "docs: document submodule boundary %s (version-%s)" % (bdir, self.version))

    def reconcile_pointer(self, parent, subpath):
        """If the submodule HEAD moved, record the new pointer in the parent."""
        stt = submodule_status(parent, self.git)
        moved = any(s["subpath"] == subpath and s["flag"] == "+" for s in stt)
        if not moved:
            return False
        print("  ~ reconcile submodule pointer %s in %s" % (subpath, os.path.basename(parent)))
        if self.dry:
            return True
        self.git.run(["add", "--", subpath], parent, write=True)
        self.git.run(["commit", "-m",
                      "chore: update %s pointer for version-%s" % (subpath, self.version)],
                     parent, write=True)
        self.commits.append((parent, "reconcile %s" % subpath))
        return True

    def tag_module(self, repo, force):
        name = os.path.basename(repo)
        existing = self.git.query(["tag", "-l", self.tag], repo)
        if existing and not force:
            print("  ! tag %s already exists in %s (use --force to move)" % (self.tag, name))
            self.tags.append((repo, self.tag, "exists"))
            return
        head = self.git.query(["rev-parse", "HEAD"], repo)
        print("  * tag %s -> %s @ %s" % (self.tag, name, (head or "?")[:10]))
        if self.dry:
            self.tags.append((repo, self.tag, "dry"))
            return
        args = ["tag", "-a"]
        if force:
            args.append("-f")
        args += [self.tag, "-m",
                 "Version %s — initial versioning of %s" % (self.version, name)]
        self.git.run(args, repo, write=True)
        self.tags.append((repo, self.tag, head))


def build_manifest(git, version, modules):
    man = {
        "project": "congruency-tournament",
        "version": version,
        "tag": "version-%s" % version,
        "generated": time.strftime("%Y-%m-%dT%H:%M:%S"),
        "note": "Initial project-wide versioning. Every module and submodule is tagged "
                "version-%s; see each repo''s tag for the exact commit." % version,
        "modules": [],
    }
    for m in modules:
        entry = {
            "name": m["name"],
            "path": m["path"],
            "is_submodule": m["is_submodule"],
            "parent": m.get("parent"),
            "url": m.get("url"),
            "branch": git.query(["rev-parse", "--abbrev-ref", "HEAD"], m["path"]),
            "commit": git.query(["rev-parse", "HEAD"], m["path"]),
            "tag": "version-%s" % version,
        }
        man["modules"].append(entry)
    return man


def collect_modules(git, root, include_generated):
    """Ordered list: submodules first (leaves), then their parents, then standalones."""
    tops = discover_top_repos(root, git, include_generated=include_generated)
    subs, parents, standalone = [], [], []
    for path in tops:
        declared = parse_gitmodules(path, git)
        stt = submodule_status(path, git)
        if stt:
            for s in stt:
                sp = s["subpath"]
                decl = next((v for v in declared.values() if v.get("path") == sp), {})
                subs.append({"name": sp, "path": os.path.join(path, sp),
                             "is_submodule": True, "parent": os.path.basename(path),
                             "parent_path": path, "subpath": sp,
                             "url": decl.get("url")})
            parents.append({"name": os.path.basename(path), "path": path,
                            "is_submodule": False, "parent": None,
                            "submodules": [{"subpath": s["subpath"],
                                            "url": next((v for v in declared.values()
                                                         if v.get("path") == s["subpath"]), {}).get("url")}
                                           for s in stt]})
        else:
            standalone.append({"name": os.path.basename(path), "path": path,
                               "is_submodule": False, "parent": None, "submodules": []})
    return subs, parents, standalone


def compute_next_version(git, repo, major=None):
    """Compute the next version to stamp by READING existing `version-*` git tags.

    Whole numbers are majors (2, 4, ...); a checkout increment is a 4-decimal step
    of the current major (2.0001, 2.0002, ...). The number is derived from live git
    state here — never inferred or passed by hand.
    """
    raw = git.query(["tag", "-l", "version-*"], repo) or ""
    majors = {}
    for line in raw.splitlines():
        tag = line.strip()
        if not tag.startswith("version-"):
            continue
        val = tag[len("version-"):]
        if "." in val:
            mj, inc = val.split(".", 1)
            try:
                majors.setdefault(int(mj), set()).add(int(inc))
            except ValueError:
                continue
        else:
            try:
                majors.setdefault(int(val), set())
            except ValueError:
                continue
    if not majors:                       # no versions yet -> first increment of the base major
        return "%d.%03d" % (major if major is not None else 4, 50)
    if major is None:
        major = max(majors)              # current highest whole-number major
    incs = majors.get(major, set())
    nxt = (max(incs) + 1) if incs else 1
    return "%d.%03d" % (major, nxt)


def main(argv=None):
    ap = argparse.ArgumentParser(description=__doc__)
    # version selection — the stamped number is COMPUTED, never inferred:
    #   --checkout-increment : compute the next 4-decimal increment of the current major
    #   --major N            : stamp a new whole-number major (e.g. 4)
    #   --version X          : explicit override (discouraged; kept for the initial major)
    ap.add_argument("--checkout-increment", action="store_true",
                    help="stamp the next python-computed checkout increment (major.NNNN)")
    ap.add_argument("--major", type=int, default=None,
                    help="stamp this whole-number major version")
    ap.add_argument("--version", default=None,
                    help="explicit version override (string, e.g. 2 or 2.0001)")
    ap.add_argument("--name", default="tournament-versioning")
    ap.add_argument("--email", default="versioning@congruency.local")
    ap.add_argument("--root", default=os.path.expanduser("~"))
    ap.add_argument("--log", default=None)
    ap.add_argument("--force", action="store_true",
                    help="proceed even if verify fails; move existing tags")
    ap.add_argument("--dry-run", action="store_true")
    args = ap.parse_args(argv)

    identity = {"name": args.name, "email": args.email}
    git = Git(identity=identity, logfile=args.log, echo=True)

    # resolve the version to stamp — COMPUTED from git state, not inferred
    ref_repo = git.query(["rev-parse", "--show-toplevel"],
                         os.path.dirname(os.path.abspath(__file__)))
    if args.version is not None:
        version = str(args.version)
    elif args.major is not None and not args.checkout_increment:
        version = str(args.major)
    else:  # default action and --checkout-increment both compute the next increment
        version = compute_next_version(git, ref_repo, major=args.major)
        print("  computed checkout-increment version: %s (from live version-* tags)" % version)

    print("== versioning: identity=%s <%s>  version=%s  dry_run=%s =="
          % (identity["name"], identity["email"], version, args.dry_run))

    # -- 1. verify first --------------------------------------------------------
    print("\n-- pre-flight verification --")
    tops = discover_top_repos(args.root, git, include_generated=False)
    invalid = []
    for p in tops:
        rr = check_repo(git, p, allow_dirty=False)
        if not rr.get("valid"):
            invalid.append((rr["name"], rr["errors"]))
    if invalid:
        print("  invalid state in: %s" % ", ".join(n for n, _ in invalid))
        for n, errs in invalid:
            for e in errs:
                print("    %s: %s" % (n, e))
        if not args.force:
            print("ABORT — fix the above or pass --force.")
            return 2
        print("  --force: continuing despite invalid state.")
    else:
        print("  state valid.")

    subs, parents, standalone = collect_modules(git, args.root, include_generated=False)
    v = Versioner(git, version, args.dry_run)

    # -- 2. READMEs: submodules (own), boundaries, parents, standalones ---------
    print("\n-- READMEs & boundaries --")
    for m in subs:
        v.ensure_module_readme(m["path"])                 # skips if present (keeps pins pristine)
    for p in parents:
        for sm in p["submodules"]:
            v.ensure_boundary_readme(p["path"], sm["subpath"], sm.get("url"))
            v.reconcile_pointer(p["path"], sm["subpath"])
        v.ensure_module_readme(p["path"])
    for m in standalone:
        v.ensure_module_readme(m["path"])

    all_modules = subs + parents + standalone

    # -- 3. project-wide manifest ----------------------------------------------
    print("\n-- manifest --")
    manifest = build_manifest(git, version, all_modules)
    script_dir = os.path.dirname(os.path.abspath(__file__))
    committed_manifest = os.path.join(script_dir, "project_versions.json")
    canonical_manifest = os.path.join(args.root, "project_versions.json")
    if not args.dry_run:
        for path in (committed_manifest, canonical_manifest):
            with open(path, "w") as fh:
                json.dump(manifest, fh, indent=2)
        # commit the versioning dir (scripts + manifest) into its own repo
        host_repo = git.query(["rev-parse", "--show-toplevel"], script_dir)
        rel = os.path.relpath(script_dir, host_repo)
        git.run(["add", "--", rel], host_repo, write=True)
        # only commit if something is staged
        staged = git.query(["diff", "--cached", "--name-only"], host_repo)
        if staged:
            git.run(["commit", "-m",
                     "feat(versioning): project-wide version-%s manifest + apparatus"
                     % version], host_repo, write=True)
            v.commits.append((host_repo, "manifest"))
    print("  manifest -> %s (committed) and %s (canonical)"
          % (committed_manifest, canonical_manifest))

    # -- 4. tags: every module + every submodule -------------------------------
    print("\n-- version tags --")
    for m in all_modules:
        v.tag_module(m["path"], force=args.force)

    # -- 5. refresh canonical manifest with resolved tag commits ---------------
    if not args.dry_run:
        for entry in manifest["modules"]:
            entry["tag_commit"] = git.query(["rev-list", "-n", "1", manifest["tag"]],
                                            entry["path"])
        with open(canonical_manifest, "w") as fh:
            json.dump(manifest, fh, indent=2)

    print("\n== done: %d commit(s), %d tag(s) as %s =="
          % (len(v.commits), len(v.tags), v.tag))
    print("   re-run verify_git_state.py to confirm the project is still valid.")
    return 0


if __name__ == "__main__":
    sys.exit(main())
');
