INSERT INTO "code_blobs" VALUES('3bba9fa79ef5adeedea31c84aa09db1500fef5a1','python',1863,'#!/usr/bin/env python3
"""install_signals.py — #37: one-command sync of the repo signals-mcp server into ~/.MCP.

The SOURCE OF RECORD is the versioned tracker/signals-mcp/server.py; the RUNNING copy lives at
~/.MCP/signals-mcp/server.py so it can import the shared ~/.MCP/mcplib. Those two drifting was the
hazard noted in SIGNALS.md §10 — this copies the repo copy over the ~/.MCP copy so they can''t.
Run it after editing the server, then restart the gate/coupler.

    python3 tracker/install_signals.py            # sync + verify identical
    python3 tracker/install_signals.py --check     # report drift only (exit 1 if drifted)

~/.MCP is OUTSIDE this repo, so only this script (the source-of-record server) is versioned here.
"""
import argparse, filecmp, os, shutil, sys

HERE = os.path.dirname(os.path.abspath(__file__))
SRC = os.path.join(HERE, "signals-mcp", "server.py")
DST = os.path.expanduser(os.path.join("~", ".MCP", "signals-mcp", "server.py"))


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--check", action="store_true", help="report drift only; do not copy")
    a = ap.parse_args()
    if not os.path.isfile(SRC):
        print("source of record missing: %s" % SRC)
        return 2

    in_sync = os.path.isfile(DST) and filecmp.cmp(SRC, DST, shallow=False)
    if a.check:
        print("signals-mcp server: %s" % ("in sync ✓" if in_sync else "DRIFTED (run without --check to fix)"))
        return 0 if in_sync else 1

    os.makedirs(os.path.dirname(DST), exist_ok=True)
    shutil.copyfile(SRC, DST)
    ok = filecmp.cmp(SRC, DST, shallow=False)
    print("synced %s -> %s : %s" % (os.path.relpath(SRC, HERE), DST, "identical ✓" if ok else "MISMATCH!"))
    print("(restart the gate/coupler so the running daemon reloads it)")
    return 0 if ok else 1


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('2c8ed98806d33b33e87b1bf69a7d2b83df8c6fd8','python',6570,'#!/usr/bin/env python3
"""signals-mcp — the tracker''s operational safety DAEMON + DB error channel.

Two jobs in one MCP:
  1. A background WATCHDOG thread. On every tick it SYNCs the ticket ledger (tracker/tickets.jsonl)
     into the db (project.db) and runs the DEAD-MAN''s switch check — catching ANY exception into an
     ERROR signal instead of failing silently. A clean sync BEATS the dead-man''s switch; if this daemon
     dies, the reader stops beating and the switch fires on the next check (default condition is error).
  2. The DB ERROR CHANNEL as tools, so agents and humans read errors FROM the db, not the file:
     signals__due, signals__ack, signals__sync, signals__check, signals__lookup, signals__status.

Owned by the coupler (registry.json → servers.signals). Reuses the tracker''s store.py (path from
$TRACKER_DIR). Zero extra deps; shares ~/.MCP/mcplib.
"""
import importlib.util
import os
import sys
import threading
import time

HERE = os.path.dirname(os.path.abspath(__file__))
MCP_DIR = os.path.dirname(HERE)                       # ~/.MCP
sys.path.insert(0, MCP_DIR)                            # mcplib, registry.json
import mcplib  # noqa: E402

TRACKER = os.environ.get("TRACKER_DIR") or os.path.normpath(
    os.path.join(MCP_DIR, "..", "big-jazz-main", "packages", "congruencey", "tracker"))
TICK = int(os.environ.get("SIGNALS_TICK", "30"))


def _load_store():
    spec = importlib.util.spec_from_file_location("store", os.path.join(TRACKER, "store.py"))
    m = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(m)
    return m


store = _load_store()


def _daemon():
    """The watchdog loop — the functional component that HOLDS BACK the default-error dead-man''s switch."""
    while True:
        try:
            store.sync_from_ledger()      # any reader exception is caught INSIDE and becomes a signal + no beat
            store.check_deadman()          # fire error signals for components that went silent
        except Exception as exc:           # last-resort catch: the daemon itself must never die silently
            try:
                store.raise_signal("error", "signals-mcp", "DAEMON_EXCEPTION",
                                   "%s: %s" % (type(exc).__name__, exc))
            except Exception:
                pass
        time.sleep(TICK)


def _fmt(sigs):
    if not sigs:
        return "_no open signals._"
    return "\n".join("- [%s] **%s** `%s` — %s%s" % (
        s["ts"], s["level"], s["code"], s["message"], (" (ref=%s)" % s["ref"]) if s["ref"] else "")
        for s in sigs)


def tool_due(args):
    args = args or {}
    lvl = args.get("level")
    sigs = store.signals(level=lvl, status="open")
    return mcplib.text_result("## signals — %d open%s\n\n%s" % (
        len(sigs), " (level=%s)" % lvl if lvl else "", _fmt(sigs)))


def tool_ack(args):
    args = args or {}
    if args.get("id") is None:
        return mcplib.text_result("provide `id`", True)
    st = args.get("status", "resolved")
    store.ack_signal(int(args["id"]), st)
    return mcplib.text_result("signal #%s → %s" % (args["id"], st))


def tool_sync(args):
    return mcplib.text_result("sync (ledger → db): %s" % store.sync_from_ledger())


def tool_check(args):
    stale = store.check_deadman()
    return mcplib.text_result("dead-man''s switch — fired for: %s" % (stale or "none (all components beating)"))


def tool_lookup(args):
    args = args or {}
    if args.get("id") is None:
        return mcplib.text_result("provide `id`", True)
    t = store.lookup_ticket(int(args["id"]))
    return mcplib.text_result("ticket #%s: %s" % (
        args["id"], t if t else "**NOT FOUND** — a TICKET_NOT_FOUND error signal was raised"))


def tool_status(args):
    sigs = store.signals(status="open")
    errs = [s for s in sigs if s["level"] == "error"]
    return mcplib.text_result("## tracker safety status\nopen signals: **%d** (errors: **%d**) · daemon tick: %ds\n\n%s"
                              % (len(sigs), len(errs), TICK, _fmt(errs[:10])))


TOOLS = [
    {"name": "due",
     "description": "List OPEN signals from the db error channel — errors, warnings, and the reconciliation signals (TICKET_ADDED / TICKET_VANISHED / TICKET_NOT_FOUND) plus dead-man fires. Optional `level` (error|warn|info).",
     "inputSchema": {"type": "object", "properties": {"level": {"type": "string"}}, "additionalProperties": False},
     "handler": tool_due},
    {"name": "ack",
     "description": "Acknowledge/resolve an open signal by `id` (append-only status change; signals are never deleted). Optional `status` (default ''resolved'').",
     "inputSchema": {"type": "object", "properties": {"id": {"type": "integer"}, "status": {"type": "string"}}, "required": ["id"], "additionalProperties": False},
     "handler": tool_ack},
    {"name": "sync",
     "description": "Force a ledger→db sync now (migrates tickets.jsonl into the db ''no matter what'' and BEATS the dead-man''s switch). Returns counts + reconciliation.",
     "inputSchema": {"type": "object", "properties": {}, "additionalProperties": False},
     "handler": tool_sync},
    {"name": "check",
     "description": "Run the dead-man''s switch check now; fires an error signal for any component that stopped beating (default condition is error).",
     "inputSchema": {"type": "object", "properties": {}, "additionalProperties": False},
     "handler": tool_check},
    {"name": "lookup",
     "description": "Look up a ticket by `id` FROM the db; a miss itself raises a TICKET_NOT_FOUND error signal (you asked to be notified on not-found).",
     "inputSchema": {"type": "object", "properties": {"id": {"type": "integer"}}, "required": ["id"], "additionalProperties": False},
     "handler": tool_lookup},
    {"name": "status",
     "description": "Tracker safety status: open signal + error counts, the daemon tick, and the most recent errors.",
     "inputSchema": {"type": "object", "properties": {}, "additionalProperties": False},
     "handler": tool_status},
]
_BY_NAME = {t["name"]: t["handler"] for t in TOOLS}


def list_tools():
    return [{"name": t["name"], "description": t["description"], "inputSchema": t["inputSchema"]} for t in TOOLS]


def call_tool(name, args):
    handler = _BY_NAME.get(name)
    if not handler:
        return mcplib.text_result("Unknown tool: %s" % name, True)
    return handler(args or {})


if __name__ == "__main__":
    threading.Thread(target=_daemon, daemon=True).start()   # the watchdog daemon
    mcplib.Server("signals", "1.0.0", list_tools, call_tool).serve()
');
INSERT INTO "code_blobs" VALUES('d27d3195f829b5f2264cb923a257a345ac7323a9','python',13239,'#!/usr/bin/env python3
"""store.py — the project DB layer: tickets (projected from the ledger), signals, a dead-man''s switch,
and the gate''s tool-use memories.

The append-only ledger (tracker/tickets.jsonl) stays the committed source of truth. The DB is ONE
PERSISTENT, INSTALL-LEVEL file — by default ~/.MCP/project.db (override with $PROJECT_DB) — NOT a copy
inside the disposable working tree. This matters: `memories` (and, transiently, signals/heartbeat) are
NOT rebuildable from the ledger, so the db must survive a repo re-clone. Only `tickets` is a projection
that one `sync` can rebuild; everything else is durable operational state that lives with the install.

  tickets(id, type, description, status, created)          -- projection of the ledger (rebuildable)
  signals(id, ts, level, source, code, message, ref, status) -- the DB error channel; errors looked up here
  heartbeat(component, last_seen, ttl, state)              -- dead-man''s switch, DEFAULT state = ERROR
  memories(id, ts, session, tool, intent, note)            -- the gate''s tool-use log (durable, NOT rebuildable)

Safety-oriented by design:
  * `sync_from_ledger()` pushes the ledger into the DB "no matter what" — every step is wrapped so ANY
    exception becomes an ERROR signal (never a silent crash), and it reconciles: a ticket ADDED to the
    ledger externally, one that VANISHED, a PARSE error, or a NOT-FOUND ref each raise a signal.
  * The dead-man''s switch DEFAULTS to error. The functional reader must `beat()` to hold it back; if it
    stops beating (crash/hang), `check_deadman()` fires an error signal. Silence == failure.

CLI: store.py sync | signals [--level error] | beat <component> [ttl] | check | watch [seconds] | status
"""
import json
import os
import sqlite3
import sys
import time

HERE = os.path.dirname(os.path.abspath(__file__))


def _default_db():
    """The ONE unified congruency db — where telemetry, tickets, notes AND the CMS content all live
    (jazz_telemetry''s default: ~/.jazz/congruency.sqlite). This safety layer keeps its own
    signals/heartbeat/memories tables in that same file; `tickets` is owned by jazz (see SCHEMA).
    Override precedence: $PROJECT_DB > $JAZZ_DB > ~/.jazz/congruency.sqlite. (The old ~/.MCP/project.db
    was a stray fork — merged back into .jazz and retired.)"""
    env = os.environ.get("PROJECT_DB") or os.environ.get("JAZZ_DB")
    if env:
        return os.path.abspath(os.path.expanduser(env))
    return os.path.join(os.path.expanduser("~"), ".jazz", "congruency.sqlite")


DB = _default_db()
LEDGER = os.path.join(HERE, "tickets.jsonl")

SCHEMA = """
-- NB: `tickets` is intentionally NOT created here — jazz owns the tickets table in the unified db
-- (schema: id/ts/updated/component/title/severity/body/meta). This layer only owns the operational
-- tables below. Recreating a divergent `tickets` here would collide with jazz''s.
CREATE TABLE IF NOT EXISTS signals (
    id INTEGER PRIMARY KEY AUTOINCREMENT, ts TEXT, level TEXT, source TEXT,
    code TEXT, message TEXT, ref TEXT, status TEXT DEFAULT ''open'');
CREATE TABLE IF NOT EXISTS heartbeat (
    component TEXT PRIMARY KEY, last_seen TEXT, ttl INTEGER, state TEXT);
CREATE TABLE IF NOT EXISTS memories (
    id INTEGER PRIMARY KEY AUTOINCREMENT, ts TEXT, session TEXT,
    tool TEXT, intent TEXT, note TEXT);
CREATE INDEX IF NOT EXISTS idx_memories_session ON memories(session);
CREATE INDEX IF NOT EXISTS idx_memories_ts ON memories(ts);
"""


def _now():
    return time.strftime("%Y-%m-%dT%H:%M:%S")


def _con():
    con = sqlite3.connect(DB, timeout=5)
    con.row_factory = sqlite3.Row
    con.executescript(SCHEMA)
    return con


# --------------------------------------------------------------------------- #
# signals — the DB error channel                                              #
# --------------------------------------------------------------------------- #
def raise_signal(level, source, code, message="", ref=""):
    """Record a signal (level: error|warn|info). Errors are looked up FROM the db via signals()."""
    con = _con()
    con.execute("INSERT INTO signals (ts, level, source, code, message, ref, status) VALUES (?,?,?,?,?,?, ''open'')",
                (_now(), level, source, code, str(message)[:500], str(ref)))
    con.commit()
    con.close()


def signals(level=None, status="open"):
    con = _con()
    q = "SELECT * FROM signals WHERE 1=1"
    args = []
    if status:
        q += " AND status=?"; args.append(status)
    if level:
        q += " AND level=?"; args.append(level)
    rows = [dict(r) for r in con.execute(q + " ORDER BY id DESC", args)]
    con.close()
    return rows


def ack_signal(sig_id, status="resolved"):
    con = _con()
    con.execute("UPDATE signals SET status=? WHERE id=?", (status, int(sig_id)))
    con.commit()
    con.close()


# --------------------------------------------------------------------------- #
# dead-man''s switch — DEFAULT state is ERROR; the reader must beat to hold it back
# --------------------------------------------------------------------------- #
def beat(component, ttl=60):
    """The functional component asserts health. Absence of a beat within ttl == error (fail-safe)."""
    con = _con()
    con.execute("INSERT INTO heartbeat (component, last_seen, ttl, state) VALUES (?,?,?, ''ok'') "
                "ON CONFLICT(component) DO UPDATE SET last_seen=excluded.last_seen, ttl=excluded.ttl, state=''ok''",
                (component, _now(), int(ttl)))
    con.commit()
    con.close()


def check_deadman():
    """Fire an error signal for any component whose heartbeat has expired (or was never seen)."""
    con = _con()
    stale = []
    for r in con.execute("SELECT * FROM heartbeat").fetchall():
        age = time.time() - time.mktime(time.strptime(r["last_seen"], "%Y-%m-%dT%H:%M:%S"))
        if age > r["ttl"] and r["state"] != "error":
            con.execute("UPDATE heartbeat SET state=''error'' WHERE component=?", (r["component"],))
            stale.append(r["component"])
    con.commit()
    con.close()
    for c in stale:
        raise_signal("error", "deadman", "DEADMAN_EXPIRED",
                     "component ''%s'' stopped asserting health (dead-man''s switch fired)" % c, ref=c)
    return stale


# --------------------------------------------------------------------------- #
# sync — push the ledger into the db "no matter what" + reconcile -> signals   #
# --------------------------------------------------------------------------- #
def _ledger_state():
    """Project tracker/tickets.jsonl (reuse ticket.py if importable, else read directly)."""
    try:
        sys.path.insert(0, HERE)
        import ticket
        return ticket.state()
    except Exception:  # noqa: BLE001 — fall back to a direct read so sync never depends on the reader
        out = {}
        for ln in open(LEDGER):
            ln = ln.strip()
            if not ln:
                continue
            e = json.loads(ln)   # a parse error here is caught by sync_from_ledger and signalled
            if e.get("kind") == "new":
                out[e["id"]] = {"id": e["id"], "type": e["type"], "description": e["description"],
                                "created": e["ts"], "status": "open"}
            elif e.get("kind") == "status" and e.get("id") in out:
                out[e["id"]]["status"] = e["status"]
        return list(out.values())


def sync_from_ledger():
    """RETIRED as a ledger→tickets projector: jazz now owns `tickets` in the unified db, and the
    append-only tickets.jsonl ledger is kept only as a historical export (its tickets were merged into
    jazz — see ~/databases/PRESERVED and the merge). The watchdog still calls this every tick, so it now
    just HOLDS BACK the dead-man''s switch by beating; any failure still becomes a signal + no beat.
    (The full port of the tracker''s ticket semantics onto the jazz schema is jazz tickets #32/#36.)"""
    try:
        beat("ticket_reader")   # the daemon is alive → hold the default-error switch back
        return {"ok": True, "note": "ledger projection retired; jazz owns tickets"}
    except Exception as exc:  # noqa: BLE001 — never fail silently; a write failure becomes a signal (no beat)
        raise_signal("error", "signals-daemon", "READER_EXCEPTION", "%s: %s" % (type(exc).__name__, exc))
        return {"ok": False, "error": str(exc)}


def lookup_ticket(tid):
    """Look up a ticket FROM the db; a miss is itself a signal (you asked to be notified on not-found)."""
    con = _con()
    r = con.execute("SELECT * FROM tickets WHERE id=?", (int(tid),)).fetchone()
    con.close()
    if r is None:
        raise_signal("error", "lookup", "TICKET_NOT_FOUND", "ticket #%s not found in the db" % tid, ref=tid)
        return None
    return dict(r)


# --------------------------------------------------------------------------- #
# memories — the gate''s tool-use log (durable; the reason project.db is persistent)
# --------------------------------------------------------------------------- #
def record_memory(tool, intent, session=None, note=None, ts=None):
    """Append one gate memory. `ts` is the gate''s authoritative stamp (ISO-8601); `session` is the
    Claude Code session id so memories persist AS sessions, not one undifferentiated stream."""
    con = _con()
    con.execute("INSERT INTO memories (ts, session, tool, intent, note) VALUES (?,?,?,?,?)",
                (ts or _now(), session, tool, intent, note))
    con.commit()
    con.close()


def memories(session=None, contains=None, limit=50):
    """Read memories, newest first. Filter by `session` (exact) and/or `contains` (tool/intent substring)."""
    con = _con()
    q = "SELECT * FROM memories WHERE 1=1"
    args = []
    if session:
        q += " AND session=?"; args.append(session)
    if contains:
        q += " AND (intent LIKE ? OR tool LIKE ?)"; args += ["%" + contains + "%"] * 2
    rows = [dict(r) for r in con.execute(q + " ORDER BY id DESC LIMIT ?", args + [int(limit)])]
    con.close()
    return rows


def import_json_log(path):
    """One-time, idempotent backfill of the legacy gate-memories.json into the memories table.
    Dedupes on (ts, tool) so re-running is safe."""
    if not os.path.exists(path):
        return {"imported": 0, "reason": "no log at %s" % path}
    with open(path) as f:
        data = json.load(f)
    con = _con()
    have = {(r["ts"], r["tool"]) for r in con.execute("SELECT ts, tool FROM memories")}
    n = 0
    for e in data.values():
        key = (e.get("timestamp"), e.get("tool"))
        if key in have or not key[0]:
            continue
        con.execute("INSERT INTO memories (ts, session, tool, intent, note) VALUES (?,?,?,?,?)",
                    (e.get("timestamp"), e.get("session"), e.get("tool"), e.get("intent"), e.get("note")))
        have.add(key)
        n += 1
    con.commit()
    con.close()
    return {"imported": n}


def main():
    a = sys.argv[1:]
    cmd = a[0] if a else "status"
    if cmd == "sync":
        print(json.dumps(sync_from_ledger()))
    elif cmd == "signals":
        lvl = a[a.index("--level") + 1] if "--level" in a else None
        for s in signals(level=lvl):
            print("  [%s] %-8s %-18s %s%s" % (s["ts"], s["level"], s["code"], s["message"],
                                              (" (ref=%s)" % s["ref"]) if s["ref"] else ""))
    elif cmd == "beat":
        beat(a[1], int(a[2]) if len(a) > 2 else 60); print("beat %s" % a[1])
    elif cmd == "check":
        stale = check_deadman(); print("dead-man fired for: %s" % (stale or "none"))
    elif cmd == "lookup":
        print(json.dumps(lookup_ticket(a[1])))
    elif cmd == "memories":
        sess = a[a.index("--session") + 1] if "--session" in a else None
        for m in memories(session=sess):
            print("  [%s] %-10s %-22s %s" % (m["ts"], (m["session"] or "-")[:10], m["tool"], m["intent"]))
    elif cmd == "import-memories":
        src = a[1] if len(a) > 1 else os.path.expanduser("~/.MCP/gate-memories.json")
        print(json.dumps(import_json_log(src)))
    elif cmd == "watch":
        every = int(a[1]) if len(a) > 1 else 15
        print("watching: sync + dead-man every %ds (Ctrl-C to stop)" % every)
        while True:
            sync_from_ledger(); check_deadman()
            time.sleep(every)
    elif cmd == "status":
        con = _con()
        print("db: %s" % DB)
        print("tickets: %d  ·  open signals: %d (errors: %d)  ·  memories: %d  ·  components: %s" % (
            con.execute("SELECT COUNT(*) FROM tickets").fetchone()[0],
            con.execute("SELECT COUNT(*) FROM signals WHERE status=''open''").fetchone()[0],
            con.execute("SELECT COUNT(*) FROM signals WHERE status=''open'' AND level=''error''").fetchone()[0],
            con.execute("SELECT COUNT(*) FROM memories").fetchone()[0],
            [dict(r)["component"] + ":" + dict(r)["state"] for r in con.execute("SELECT * FROM heartbeat")] or "none"))
        con.close()
    else:
        print("usage: store.py sync|signals|beat|check|lookup|memories|import-memories|watch|status",
              file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('92c3a730220629e408eb8b01a5621217fbd8efe4','python',8789,'#!/usr/bin/env python3
"""ticket.py — the congruency project ticket tracker (append-only ledger; REST + CLI; human + machine).

Governance (learned the hard way):
  * IDs are AUTO-STAMPED — callers (agents included) never supply them.
  * Tickets are NEVER deleted or combined — you only ever APPEND a status change.
  * The ledger (tracker/tickets.jsonl) is append-only; the current state is a projection of it.

Fields: id (auto), type (enum), description, status (tracked via appended status events).
Types: bug, build, design, spec, bet, test, documentation, rfc-investigation.

CLI:
    ticket.py new <type> "<description>"        # mints an id, status=open
    ticket.py status <id> <status> ["note"]     # append a status change
    ticket.py list [--json]                     # current state (one row per ticket)
    ticket.py show <id>                          # one ticket + full status history
    ticket.py serve [host:port]                  # REST + human view (default 127.0.0.1:8737)

REST:
    GET  /tickets                 -> JSON list          (machine)
    GET  /tickets/<id>            -> JSON one + history
    GET  /                        -> HTML table         (human)
    POST /tickets   {type, description}   -> 201 {id}
    POST /tickets/<id>/status  {status, note}  -> 200 {ok}
"""
import http.server
import json
import os
import sys
import time

HERE = os.path.dirname(os.path.abspath(__file__))
LEDGER = os.path.join(HERE, "tickets.jsonl")
TYPES = ["bug", "build", "design", "spec", "bet", "test", "documentation", "rfc-investigation"]
STATUSES = ["open", "active", "blocked", "review", "done", "dropped"]   # suggested; any string accepted


def _now():
    return time.strftime("%Y-%m-%dT%H:%M:%S")


def _events():
    if not os.path.isfile(LEDGER):
        return []
    out = []
    for ln in open(LEDGER):
        ln = ln.strip()
        if ln:
            try:
                out.append(json.loads(ln))
            except ValueError:
                pass
    return out


def _append(ev):
    os.makedirs(os.path.dirname(LEDGER), exist_ok=True)
    with open(LEDGER, "a") as fh:
        fh.write(json.dumps(ev) + "\n")


def _next_id(events=None):
    events = _events() if events is None else events
    ids = [e["id"] for e in events if e.get("kind") == "new"]
    return (max(ids) + 1) if ids else 1


def create(type_, description):
    """Mint a new ticket. id is auto-stamped; status starts ''open''. Returns the id."""
    if type_ not in TYPES:
        raise ValueError("type must be one of %s" % TYPES)
    if not description or not str(description).strip():
        raise ValueError("description required")
    tid = _next_id()
    _append({"kind": "new", "id": tid, "type": type_, "description": str(description).strip(), "ts": _now()})
    _append({"kind": "status", "id": tid, "status": "open", "note": "filed", "ts": _now()})
    return tid


def set_status(tid, status, note=""):
    """Append a status change. Never deletes; never combines."""
    tid = int(tid)
    if not any(e.get("kind") == "new" and e.get("id") == tid for e in _events()):
        raise ValueError("no ticket #%s" % tid)
    if not status or not str(status).strip():
        raise ValueError("status required")
    _append({"kind": "status", "id": tid, "status": str(status).strip(), "note": str(note), "ts": _now()})
    return True


def state():
    """Project the append-only ledger into current ticket state (sorted by id)."""
    tickets = {}
    for e in _events():
        if e.get("kind") == "new":
            tickets[e["id"]] = {"id": e["id"], "type": e["type"], "description": e["description"],
                                "created": e["ts"], "status": None, "history": []}
    for e in _events():
        if e.get("kind") == "status" and e.get("id") in tickets:
            tickets[e["id"]]["status"] = e["status"]
            tickets[e["id"]]["history"].append({"status": e["status"], "note": e.get("note", ""), "ts": e["ts"]})
    return [tickets[k] for k in sorted(tickets)]


def get(tid):
    for t in state():
        if t["id"] == int(tid):
            return t
    return None


# --------------------------------------------------------------------------- #
# REST + human view                                                           #
# --------------------------------------------------------------------------- #
def _esc(s):
    return str(s).replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")


def _html(tickets):
    rows = "".join(
        "<tr><td>#%d</td><td>%s</td><td><b>%s</b></td><td>%s</td></tr>"
        % (t["id"], _esc(t["type"]), _esc(t["status"]), _esc(t["description"]))
        for t in tickets)
    return ("<!doctype html><html><head><meta charset=''utf-8''><title>congruency tickets</title>"
            "<style>body{font-family:Georgia,serif;max-width:860px;margin:2rem auto;color:#222;background:#f7f4ee}"
            "table{border-collapse:collapse;width:100%%}td,th{border:1px solid #ccc;padding:6px 8px;text-align:left;"
            "vertical-align:top}th{background:#eae5d8}h1{font-weight:normal}</style></head><body>"
            "<h1>Congruency &mdash; project tickets</h1>"
            "<p>%d tickets. Types: %s. Machine view: <a href=''/tickets''>/tickets</a> (JSON).</p>"
            "<table><tr><th>id</th><th>type</th><th>status</th><th>description</th></tr>%s</table>"
            "</body></html>") % (len(tickets), ", ".join(TYPES), rows)


class Handler(http.server.BaseHTTPRequestHandler):
    def _send(self, code, body, ctype="application/json"):
        b = body.encode() if isinstance(body, str) else body
        self.send_response(code)
        self.send_header("Content-Type", ctype)
        self.send_header("Content-Length", str(len(b)))
        self.end_headers()
        self.wfile.write(b)

    def do_GET(self):
        path = self.path.split("?")[0]
        if path in ("/", "/index.html"):
            self._send(200, _html(state()), "text/html; charset=utf-8")
        elif path == "/tickets":
            self._send(200, json.dumps(state(), indent=2))
        elif path.startswith("/tickets/"):
            try:
                tid = int(path.split("/")[2])
            except (ValueError, IndexError):
                return self._send(400, json.dumps({"error": "bad id"}))
            t = get(tid)
            self._send(200 if t else 404, json.dumps(t or {"error": "not found"}))
        else:
            self._send(404, json.dumps({"error": "not found"}))

    def do_POST(self):
        n = int(self.headers.get("Content-Length", 0) or 0)
        raw = self.rfile.read(n).decode() if n else ""
        try:
            data = json.loads(raw) if raw else {}
        except ValueError:
            data = {}
        path = self.path.split("?")[0]
        try:
            if path == "/tickets":
                tid = create(data.get("type"), data.get("description"))
                self._send(201, json.dumps({"id": tid}))
            elif path.startswith("/tickets/") and path.endswith("/status"):
                tid = int(path.split("/")[2])
                set_status(tid, data.get("status"), data.get("note", ""))
                self._send(200, json.dumps({"ok": True, "id": tid}))
            else:
                self._send(404, json.dumps({"error": "not found"}))
        except ValueError as e:
            self._send(400, json.dumps({"error": str(e)}))

    def log_message(self, *a):
        pass


def serve(host="127.0.0.1", port=8737):
    http.server.HTTPServer((host, port), Handler).serve_forever()


def main():
    a = sys.argv[1:]
    if not a:
        print(__doc__)
        return 0
    cmd = a[0]
    try:
        if cmd == "new":
            print(create(a[1], a[2]))
        elif cmd == "status":
            set_status(a[1], a[2], a[3] if len(a) > 3 else "")
            print("ok")
        elif cmd == "list":
            st = state()
            if "--json" in a:
                print(json.dumps(st, indent=2))
            else:
                for t in st:
                    print("#%-3d [%-16s] %-8s %s" % (t["id"], t["type"], t["status"], t["description"][:64]))
        elif cmd == "show":
            print(json.dumps(get(a[1]), indent=2))
        elif cmd == "serve":
            hp = (a[1] if len(a) > 1 else "127.0.0.1:8737").split(":")
            host = hp[0] or "127.0.0.1"
            port = int(hp[1]) if len(hp) > 1 else 8737
            print("serving tickets on http://%s:%d/  (Ctrl-C to stop)" % (host, port))
            serve(host, port)
        else:
            print("unknown command: %s" % cmd, file=sys.stderr)
            return 2
    except (IndexError, ValueError) as e:
        print("error: %s" % e, file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('cdf56f92c540e04e43b038d379c71e68e366b7a7','python',12285,'#!/usr/bin/env python3
"""deploy.py — the production release deployer (lives on `main`, beside install.py).

install.py stands up a source version for DEV/TEST against the demo DB (the ratchet). deploy.py
DEPLOYS a source version to a target folder for PRODUCTION: it exports the app, writes a JSON
install config, seeds a FRESH production STUB database, and boots config-driven — recording each
verification as a PREDICTION vs ACTUAL (a REFUTED prediction is a bug + halt).

    python3 deploy.py --target /srv/site --version 4.070 [--port N] [--keep-serving]

Flow (per the plan):
  1. checkout `version-X` (detached) to materialize the source.
  2. if <target>/install.json is ABSENT: create the target, export the app (minus the ratchet
     apparatus + dev DB), write install.json {db: <target>/state/congruency.sqlite}, and run
     prod_seed.php to build a fresh stub DB there.
  3. boot <target>/boot/router.php (config_loader reads <target>/install.json -> the prod DB) and
     probe: home is the stub intro; dev pages (?page=bugs) are gone (404 stub).
Self-contained (stdlib only): main carries no source until the checkout. Best-effort jazz telemetry.
"""
import argparse
import json
import os
import shutil
import socket
import subprocess
import sys
import time
import urllib.error
import urllib.request
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))          # repo root (main)
APP_SRC = os.path.join("checkouts", "current")             # the app within the source tree
# ratchet/dev bits NOT shipped to a production target:
EXCLUDE_DIRS = {"fixes", "versioning", "tools", "tests", "__pycache__"}
EXCLUDE_STATE = {"congruency.sqlite", "database.tar.xz", "seed.php", "STATE.json"}
PAGES = None  # set at runtime


def sh(args, **kw):
    return subprocess.run(args, cwd=HERE, capture_output=True, text=True, **kw)


def git(*a):
    return sh(["git", *a])


def run(args, what):
    r = sh(args)
    if r.returncode != 0:
        raise RuntimeError("%s failed (exit %s): %s" % (what, r.returncode, (r.stderr or r.stdout).strip()[-500:]))
    return r.stdout


# --------------------------------------------------------------------------- #
# telemetry + prediction ledger (self-contained; component=deploy)            #
# --------------------------------------------------------------------------- #
def _jazz():
    try:
        cand = os.path.join(os.path.dirname(HERE), "jazz_telemetry")
        if cand not in sys.path:
            sys.path.insert(0, cand)
        from jazz_telemetry import telemetry, open_ticket
        return telemetry("deploy"), open_ticket
    except Exception:  # noqa: BLE001
        return None, None


T, OPEN_TICKET = _jazz()


def predict(statement, expected, actual):
    """Record prediction vs actual -> verdict CONFIRMED/REFUTED (logs/predictions.jsonl + jazz)."""
    sink = os.path.join(HERE, "logs", "predictions.jsonl")
    verdict = "CONFIRMED" if actual == expected else "REFUTED"
    try:
        os.makedirs(os.path.dirname(sink), exist_ok=True)
        with open(sink, "a") as fh:
            fh.write(json.dumps({"kind": "resolve", "component": "deploy",
                                 "ts": time.strftime("%Y-%m-%dT%H:%M:%S"), "statement": statement,
                                 "expected": expected, "actual": actual, "verdict": verdict}) + "\n")
    except OSError:
        pass
    if T:
        T.emit("predict", status=verdict.lower(), statement=statement[:120])
    if verdict == "REFUTED" and OPEN_TICKET:
        try:
            OPEN_TICKET("deploy prediction REFUTED: %s" % statement[:120], component="deploy",
                        severity="high", kind="bug", expected=repr(expected)[:200], actual=repr(actual)[:200])
        except Exception:  # noqa: BLE001
            pass
    print("   %s  %s" % (verdict, statement))
    return verdict


# --------------------------------------------------------------------------- #
# steps                                                                       #
# --------------------------------------------------------------------------- #
def resolve_version(explicit):
    if explicit:
        return explicit
    tags = [t[len("version-"):] for t in git("tag", "-l", "version-*").stdout.split()]
    def key(v):
        try:
            return tuple(int(x) for x in v.split("."))
        except Exception:  # noqa: BLE001
            return ()
    if not tags:
        raise RuntimeError("no version-* tags found")
    return sorted(tags, key=key)[-1]


def checkout_version(version):
    dirty = [l for l in git("status", "--porcelain").stdout.splitlines() if not l.startswith("??")]
    if dirty:
        raise RuntimeError("tree has uncommitted tracked changes; refusing to checkout")
    tag = "version-%s" % version
    if git("rev-parse", "-q", "--verify", tag).returncode != 0:
        raise RuntimeError("no such source version tag: %s" % tag)
    run(["git", "checkout", tag], "git checkout %s" % tag)
    return tag


def provision_php():
    run(["python3", os.path.join(HERE, "checkouts", "current", "tools", "provision_php.py")], "provision_php")
    return os.path.join(HERE, "tooling", "congruencey-harness", "php", "php")


def _ignore(dirpath, names):
    drop = set(n for n in names if n in EXCLUDE_DIRS)
    if os.path.basename(dirpath) == "state":
        drop |= {n for n in names if n in EXCLUDE_STATE}
    return drop


def build_target(target, php, port, host):
    """Create the target + export app + install.json (pinned port) + fresh stub DB (if not already configured)."""
    cfg = os.path.join(target, "install.json")
    if os.path.isfile(cfg):
        return {"created": False, "config": cfg, "note": "target already configured"}
    os.makedirs(target, exist_ok=True)
    # export the app (checkouts/current/* -> target/*), minus the ratchet apparatus + dev DB
    src = os.path.join(HERE, APP_SRC)
    for name in os.listdir(src):
        if name in EXCLUDE_DIRS:
            continue
        s, d = os.path.join(src, name), os.path.join(target, name)
        if os.path.isdir(s):
            shutil.copytree(s, d, ignore=_ignore, dirs_exist_ok=True)
        else:
            shutil.copy2(s, d)
    # config -> the prod DB path (the one that matters under the sqlite shim)
    db = os.path.join(os.path.abspath(target), "state", "congruency.sqlite")
    os.makedirs(os.path.dirname(db), exist_ok=True)
    with open(cfg, "w") as fh:
        json.dump({"CONGRUENCY_SQLITE": db, "CONGRUENCY_PORT": port, "CONGRUENCY_HOST": host}, fh, indent=2)
    # seed the FRESH production stub DB
    seed = os.path.join(target, "state", "prod_seed.php")
    if not os.path.isfile(seed):
        raise RuntimeError("prod_seed.php missing in exported app (%s)" % seed)
    r = subprocess.run([php, seed], cwd=os.path.join(target, "state"), capture_output=True, text=True,
                       timeout=60, env=dict(os.environ, CONGRUENCY_SQLITE=db))
    if r.returncode != 0 or not os.path.isfile(db):
        raise RuntimeError("prod_seed failed (exit %s): %s" % (r.returncode, (r.stderr or r.stdout)[:300]))
    return {"created": True, "config": cfg, "db": db}


def _free_port():
    s = socket.socket(); s.bind(("127.0.0.1", 0)); p = s.getsockname()[1]; s.close(); return p


def _probe(url):
    try:
        with urllib.request.urlopen(url, timeout=8) as r:
            return r.status, r.read(8000).decode("utf-8", "replace")
    except urllib.error.HTTPError as e:
        return e.code, e.read(8000).decode("utf-8", "replace")
    except Exception as e:  # noqa: BLE001
        return None, "%r" % e


def boot_and_verify(target, php, port, host, keep):
    proc = subprocess.Popen([php, "-S", "%s:%d" % (host, port), "boot/router.php"], cwd=target,
                            stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
    time.sleep(1.5)
    try:
        s_home, b_home = _probe("http://127.0.0.1:%d/?page=catalog" % port)
        s_bug, b_bug = _probe("http://127.0.0.1:%d/?page=bugs" % port)
    finally:
        if not keep:
            proc.terminate()
            try:
                proc.communicate(timeout=5)
            except Exception:  # noqa: BLE001
                proc.kill()
    v1 = predict("prod home (?page=catalog) is 200 with the stub intro", True,
                 (s_home == 200 and "Welcome" in b_home and "resurrection" not in b_home))
    v2 = predict("dev pages are gone (?page=bugs -> 404 stub, no BugReport)", True,
                 ("Page not found" in b_bug and "BugReport" not in b_bug and "SQL injection" not in b_bug))
    ok = (v1 == "CONFIRMED" and v2 == "CONFIRMED")
    return ok, {"home": s_home, "bugs_len": len(b_bug), "port": port, "serving": keep and proc.pid or None}


def serve_only(target, port=None, host=None):
    """Serve an already-deployed target on its PINNED config port (no checkout/rebuild)."""
    cfg = os.path.join(target, "install.json")
    if not os.path.isfile(cfg):
        raise RuntimeError("no install.json in %s — deploy there first" % target)
    conf = json.load(open(cfg))
    port = port or int(conf.get("CONGRUENCY_PORT", 8080))
    host = host or conf.get("CONGRUENCY_HOST", "0.0.0.0")
    php = os.path.join(HERE, "tooling", "congruencey-harness", "php", "php")
    if not os.path.isfile(php):
        raise RuntimeError("php not provisioned (%s) — run a deploy/install first" % php)
    log = os.path.join(target, "serve.log")
    proc = subprocess.Popen([php, "-S", "%s:%d" % (host, port), "boot/router.php"], cwd=target,
                            stdout=open(log, "a"), stderr=subprocess.STDOUT,
                            stdin=subprocess.DEVNULL, start_new_session=True)
    if T:
        T.emit("serve", status="up", target=target, port=port, pid=proc.pid)
    print("serving %s on http://%s:%d/  (pid %d, port from install.json; log %s)" % (target, host, port, proc.pid, log))
    return 0


def main():
    ap = argparse.ArgumentParser(description="deploy a source version to a production target folder")
    ap.add_argument("--target", required=True, help="target deploy folder (created if absent)")
    ap.add_argument("--version", default=None, help="source version (default: latest version-* tag)")
    ap.add_argument("--port", type=int, default=None, help="serve port to pin into install.json (default 8080)")
    ap.add_argument("--host", default=None, help="serve host/interface to pin (default 0.0.0.0)")
    ap.add_argument("--serve", action="store_true", help="serve an existing target on its config port (no rebuild)")
    ap.add_argument("--keep-serving", action="store_true", help="leave the server running after verify")
    a = ap.parse_args()

    target = os.path.abspath(os.path.expanduser(a.target))
    if a.serve:
        return serve_only(target, a.port, a.host)

    version = resolve_version(a.version)
    port = a.port or 8080
    host = a.host or "0.0.0.0"
    print("deploy: source version-%s -> %s (port %d)" % (version, target, port))
    try:
        tag = checkout_version(version)
        php = provision_php()
        built = build_target(target, php, port, host)
        print("   target %s (%s)" % ("built" if built.get("created") else "reused", built.get("config")))
        conf = json.load(open(os.path.join(target, "install.json")))     # honor the pinned config port
        eff_port, eff_host = int(conf.get("CONGRUENCY_PORT", port)), conf.get("CONGRUENCY_HOST", host)
        ok, info = boot_and_verify(target, php, eff_port, eff_host, a.keep_serving)
        if T:
            T.emit("deploy", status="ok" if ok else "fail", version=version, target=target)
        run(["git", "checkout", "main"], "return to main")
        if not ok:
            raise RuntimeError("deploy verification REFUTED (see predictions): %s" % info)
        print("\n== production deploy OK — version-%s at %s (stub site up; dev content absent) ==" % (version, target))
        return 0
    except Exception:
        try:
            git("checkout", "main")
        except Exception:  # noqa: BLE001
            pass
        raise


if __name__ == "__main__":
    try:
        sys.exit(main())
    except SystemExit:
        raise
    except Exception as exc:  # noqa: BLE001
        print("DEPLOY FAILED: %s" % exc, file=sys.stderr)
        sys.exit(1)
');
INSERT INTO "code_blobs" VALUES('58a2da089d103ce55925014d6eb6988b847edcd9','python',9326,'#!/usr/bin/env python3
"""install.py — the ratchet installer (lives on `main`, the forward-only ratchet).

`main` carries no source tree — only this installer. Running it:
  1. checks out the `source` version tag `version-<X>` (detached — materializes source@X),
  2. provisions the php runtime,
  3. installs the matching STATE from the `state` branch (state-<X> tag, else newest <=X, else HEAD),
  4. stands the CMS up and verifies,
recording telemetry per step and catching any bug thrown (Variant-A bug-report + jazz ticket).

Self-contained (stdlib only): on `main` there is no registry or tooling until the source version
is checked out, so this script embeds its own bug-report + best-effort jazz telemetry and drives
the source''s registry-gated tools by subprocess.

    python3 install.py --version X [--no-verify] [--return-to-main]
"""
import argparse
import json
import os
import subprocess
import sys
import tarfile
import tempfile
import time
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))          # repo root (source-free on main)


def sh(args, **kw):
    return subprocess.run(args, cwd=HERE, capture_output=True, text=True, **kw)


def git(*args):
    return sh(["git", *args])


def run(args, what):
    r = sh(args)
    if r.returncode != 0:
        raise RuntimeError("%s failed (exit %s): %s" % (what, r.returncode, (r.stderr or r.stdout).strip()[-600:]))
    return r.stdout


# --------------------------------------------------------------------------- #
# self-contained telemetry + bug-report (pre-checkout: no registry yet)       #
# --------------------------------------------------------------------------- #
def telemetry_handles():
    try:
        cand = os.path.join(os.path.dirname(HERE), "jazz_telemetry")   # sibling package
        if cand not in sys.path:
            sys.path.insert(0, cand)
        from jazz_telemetry import telemetry, open_ticket
        return telemetry("ratchet"), open_ticket
    except Exception:  # noqa: BLE001
        return None, None


def bug_sink():
    rel = "logs/bug_reports.jsonl"
    reg = os.path.join(HERE, "registry.json")
    if os.path.isfile(reg):
        try:
            rel = json.load(open(reg)).get("bug_reports", rel)
        except Exception:  # noqa: BLE001
            pass
    return os.path.join(HERE, rel)


def bug_report(exc, tb, step):
    path = bug_sink()
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {
        "filename": os.path.basename(__file__),
        "function": last.name if last else "?",
        "time-of-occurance": datetime.now().isoformat(),
        "methods-to-reproduce": "python3 install.py %s" % " ".join(sys.argv[1:]),
        "possible-cause": "%s: %s" % (type(exc).__name__, exc),
        "traceback": tb.strip().splitlines()[-6:],
        "note": "ratchet install step: %s" % step,
    }
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "a") as fh:
            fh.write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


T, OPEN_TICKET = telemetry_handles()


def step(name, fn):
    """Run one install step with telemetry + bug-catching; fail-fast (re-raises)."""
    print("\n== %s ==" % name)
    t0 = time.time()
    try:
        out = fn()
        ms = (time.time() - t0) * 1000.0
        if T:
            T.emit("crank", status="ok", ms=ms, step=name)
        print("   ok (%.0f ms)" % ms)
        return out
    except Exception as exc:  # noqa: BLE001
        tb = traceback.format_exc()
        p = bug_report(exc, tb, name)
        if T:
            T.emit("crank", status="fail", step=name, error=str(exc)[:200])
        if OPEN_TICKET:
            try:
                OPEN_TICKET("ratchet install failed at %s" % name, component="ratchet",
                            severity="high", body=tb[-1500:])
            except Exception:  # noqa: BLE001
                pass
        print("   FAIL: %s\n   bug report -> %s" % (exc, p), file=sys.stderr)
        raise


# --------------------------------------------------------------------------- #
# crank resolution + steps                                                    #
# --------------------------------------------------------------------------- #
def _vkey(v):
    try:
        return tuple(int(x) for x in v.split("."))
    except Exception:  # noqa: BLE001
        return None


def do_checkout_version(version):
    # untracked (??) leftovers are fine; only tracked modifications block a checkout.
    dirty = [l for l in git("status", "--porcelain").stdout.splitlines() if not l.startswith("??")]
    if dirty:
        raise RuntimeError("tree has uncommitted tracked changes; refusing to checkout")
    tag = "version-%s" % version
    if git("rev-parse", "-q", "--verify", tag).returncode != 0:
        raise RuntimeError("no such source version tag: %s" % tag)
    run(["git", "checkout", tag], "git checkout %s" % tag)   # detached -> materializes source@version
    return tag


def do_provision_php():
    return run(["python3", os.path.join(HERE, "checkouts", "current", "tools", "provision_php.py")], "provision_php")


def _state_spec():
    p = os.path.join(HERE, "checkouts", "current", "state", "STATE.json")
    return json.load(open(p)) if os.path.isfile(p) else {}


def _resolve_state_ref(version):
    """State for a source version: state-<version> tag, else newest state-<Y<=version>, else the
    state-branch HEAD (state:database.tar.xz)."""
    side = _state_spec().get("side_branch", "state")
    if git("rev-parse", "-q", "--verify", "state-%s" % version).returncode == 0:
        return "state-%s:database.tar.xz" % version
    tgt = _vkey(version)
    cands = [(k, t) for t in git("tag", "-l", "state-*").stdout.split()
             for k in [_vkey(t[len("state-"):])] if k and tgt and k <= tgt]
    if cands:
        return "%s:database.tar.xz" % sorted(cands)[-1][1]
    if git("cat-file", "-e", "%s:database.tar.xz" % side).returncode == 0:
        return "%s:database.tar.xz" % side
    raise RuntimeError("no state found for version %s" % version)


def do_state(version):
    expect = set(_state_spec().get("expect_tables", []))
    ref = _resolve_state_ref(version)

    # Materialize state from the side-branch tarball into the gitignored artifacts only
    # (never touch tracked files -> the working tree stays clean).
    state_dir = os.path.join(HERE, "checkouts", "current", "state")
    with tempfile.NamedTemporaryFile(suffix=".tar.xz", delete=False) as tf:
        tmp = tf.name
    try:
        with open(tmp, "wb") as fh:
            r = subprocess.run(["git", "show", ref], cwd=HERE, stdout=fh)
        if r.returncode != 0:
            raise RuntimeError("git show %s failed" % ref)
        with tarfile.open(tmp, "r:xz") as t:
            t.extractall(state_dir, filter="data")
    finally:
        os.remove(tmp)

    import sqlite3
    sqlite = os.path.join(state_dir, "congruency.sqlite")
    con = sqlite3.connect(sqlite)
    try:
        tables = {x[0] for x in con.execute("SELECT name FROM sqlite_master WHERE type=''table''")}
    finally:
        con.close()
    missing = expect - tables
    if missing:
        raise RuntimeError("installed state missing tables: %s" % sorted(missing))
    return {"source": ref, "tables": sorted(tables)}


def do_standup():
    # HTTP-200 stand-up gate that writes NO tracked files (serve.py --verify) — used for the
    # --no-verify path (boot_www would modify fixes/index.json and dirty the tree).
    return run(["python3", os.path.join(HERE, "checkouts", "current", "tools", "serve.py"), "--verify"],
               "serve --verify")


def do_verify():
    return run([os.path.join(HERE, "tooling", "congruencey-tests", "verify")], "verify")


def main():
    ap = argparse.ArgumentParser(description="ratchet installer: check out a source version + stand it up")
    ap.add_argument("--version", required=True, help="source version to install, e.g. 4.059")
    ap.add_argument("--no-verify", action="store_true", help="skip the final multi-suite verify")
    ap.add_argument("--return-to-main", action="store_true", help="git checkout main when done")
    a = ap.parse_args()

    start = git("rev-parse", "--abbrev-ref", "HEAD").stdout.strip()
    version = a.version
    tag = "version-%s" % version
    print("ratchet install: %s -> source %s" % (start, tag))

    step("checkout %s" % tag, lambda: do_checkout_version(version))
    step("provision php", do_provision_php)
    step("install state", lambda: do_state(version))
    if a.no_verify:
        step("stand up", do_standup)               # serve.py --verify: HTTP 200, no tracked writes
    else:
        step("stand up + verify", do_verify)       # tooling verify: stand_up + bug_catalog + branch_cov
    if a.return_to_main:
        step("return to main", lambda: run(["git", "checkout", "main"], "git checkout main"))

    if T:
        T.emit("install", status="ok", version=version)
    print("\n== ratchet install OK — source %s stood up ==" % tag)
    return 0


if __name__ == "__main__":
    try:
        sys.exit(main())
    except SystemExit:
        raise
    except Exception:  # noqa: BLE001 — per-step handlers already recorded; exit non-zero
        sys.exit(1)
');
INSERT INTO "code_blobs" VALUES('794b9c96c936c5b9b5a6566efd0c263e929ebc76','php',7436,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * rest.php — a generic READ-ONLY REST interface over every table in the unified
 * DB (CONGRUENCY_SQLITE). Dispatched by boot/router.php when ?api is present:
 *
 *   ?api=tables              -> { "tables": [ ... ] }        (discovery)
 *   ?api=<table>             -> { table,total,page,per,pages,rows:[...] }   (paginated)
 *   ?api=<table>&p=2&per=25  -> page 2, 25 rows
 *   ?api=<table>&id=<pk>     -> a single row by primary key
 *
 * The table name is always validated against sqlite_master before use (allowlist),
 * so it can''t be used for injection. Writes (POST/PUT/DELETE) are intentionally NOT
 * implemented yet — see ticket #47.
 */
function congruency_rest_dispatch() {
    header(''Content-Type: application/json'');
    header(''Access-Control-Allow-Origin: *'');
    $out = null;
    try {
        if (!defined(''CONGRUENCY_SQLITE'')) { throw new Exception(''CONGRUENCY_SQLITE not defined''); }
        $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
        $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

        $tables = array();
        foreach ($db->query("SELECT name FROM sqlite_master WHERE type=''table'' AND name NOT LIKE ''sqlite_%'' ORDER BY name") as $r) {
            $tables[$r[''name'']] = 1;
        }
        // admin-only: keep the self-hosting source/doc archive out of the public REST surface
        foreach (array(''code_blobs'', ''code_refs'', ''doc_blobs'', ''doc_refs'') as $__deny) { unset($tables[$__deny]); }

        $api = (string)($_GET[''api''] ?? '''');
        $method = strtoupper($_SERVER[''REQUEST_METHOD''] ?? ''GET'');

        if ($method === ''POST'' && isset($tables[$api])) {
            // CREATE: insert a row from the JSON body; only real columns are used (rest ignored).
            $data = json_decode((string)file_get_contents(''php://input''), true);
            if (!is_array($data)) { http_response_code(400); echo json_encode(array(''error'' => ''body must be a JSON object'')); return true; }
            $cols = array();
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { $cols[$c[''name'']] = 1; }
            $use = array();
            foreach ($data as $k => $v) { if (isset($cols[$k])) { $use[$k] = $v; } }
            if (!$use) { http_response_code(400); echo json_encode(array(''error'' => ''no valid columns for '' . $api, ''columns'' => array_keys($cols))); return true; }
            $names = array_keys($use);
            $sql = "INSERT INTO \"$api\" (" . implode('','', array_map(function ($n) { return "\"$n\""; }, $names)) . ") "
                 . "VALUES (" . implode('','', array_map(function ($n) { return ":$n"; }, $names)) . ")";
            $st = $db->prepare($sql);
            foreach ($use as $k => $v) { $st->bindValue(":$k", $v); }
            $st->execute();
            http_response_code(201);
            echo json_encode(array(''created'' => true, ''table'' => $api, ''rowid'' => $db->lastInsertId(), ''used'' => $use),
                             JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES) . "\n";
            return true;
        }

        if (($method === ''PUT'' || $method === ''PATCH'') && isset($tables[$api])) {
            // UPDATE by primary key: ?id=<pk>, JSON body of column=>value (real columns only).
            $pk = null;
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { if ($c[''pk'']) { $pk = $c[''name'']; } }
            if ($pk === null || !isset($_GET[''id''])) { http_response_code(400); echo json_encode(array(''error'' => ''update needs a single-column pk and ?id='')); return true; }
            $data = json_decode((string)file_get_contents(''php://input''), true);
            if (!is_array($data)) { http_response_code(400); echo json_encode(array(''error'' => ''body must be a JSON object'')); return true; }
            $cols = array();
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { $cols[$c[''name'']] = 1; }
            $use = array();
            foreach ($data as $k => $v) { if (isset($cols[$k]) && $k !== $pk) { $use[$k] = $v; } }
            if (!$use) { http_response_code(400); echo json_encode(array(''error'' => ''no valid columns to update'')); return true; }
            $set = implode('', '', array_map(function ($n) { return "\"$n\" = :$n"; }, array_keys($use)));
            $st = $db->prepare("UPDATE \"$api\" SET $set WHERE \"$pk\" = :__id");
            foreach ($use as $k => $v) { $st->bindValue(":$k", $v); }
            $st->bindValue(":__id", $_GET[''id'']);
            $st->execute();
            echo json_encode(array(''updated'' => $st->rowCount(), ''table'' => $api, ''pk'' => $pk, ''id'' => $_GET[''id''], ''set'' => $use),
                             JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES) . "\n";
            return true;
        }

        if ($method === ''DELETE'' && isset($tables[$api])) {
            // DELETE a single row by primary key (?id=). No bulk deletes.
            $pk = null;
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { if ($c[''pk'']) { $pk = $c[''name'']; } }
            if ($pk === null || !isset($_GET[''id''])) { http_response_code(400); echo json_encode(array(''error'' => ''delete needs a single-column pk and ?id='')); return true; }
            $st = $db->prepare("DELETE FROM \"$api\" WHERE \"$pk\" = ?");
            $st->execute(array($_GET[''id'']));
            echo json_encode(array(''deleted'' => $st->rowCount(), ''table'' => $api, ''pk'' => $pk, ''id'' => $_GET[''id''])) . "\n";
            return true;
        }

        if ($api === '''' || $api === ''tables'') {
            $out = array(''tables'' => array_keys($tables));
        } elseif (isset($tables[$api])) {
            // primary-key column (for ?id=)
            $pk = null;
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { if ($c[''pk'']) { $pk = $c[''name'']; break; } }

            if (isset($_GET[''id'']) && $pk !== null) {
                $st = $db->prepare("SELECT * FROM \"$api\" WHERE \"$pk\" = ?");
                $st->execute(array($_GET[''id'']));
                $row = $st->fetch(PDO::FETCH_ASSOC);
                if ($row === false) { http_response_code(404); $out = array(''error'' => ''not found'', ''table'' => $api, ''id'' => $_GET[''id'']); }
                else { $out = array(''table'' => $api, ''pk'' => $pk, ''row'' => $row); }
            } else {
                $per = isset($_GET[''per'']) ? max(1, min(500, (int)$_GET[''per''])) : 50;
                $pg  = isset($_GET[''p''])   ? max(1, (int)$_GET[''p'']) : 1;
                $total = (int)$db->query("SELECT COUNT(*) FROM \"$api\"")->fetchColumn();
                $off = ($pg - 1) * $per;
                $rows = $db->query("SELECT * FROM \"$api\" LIMIT $per OFFSET $off")->fetchAll(PDO::FETCH_ASSOC);
                $out = array(''table'' => $api, ''pk'' => $pk, ''total'' => $total, ''page'' => $pg, ''per'' => $per,
                             ''pages'' => (int)ceil($total / max(1, $per)), ''rows'' => $rows);
            }
        } else {
            http_response_code(404);
            $out = array(''error'' => ''unknown table'', ''table'' => $api, ''tables'' => array_keys($tables));
        }
    } catch (\Throwable $e) {
        http_response_code(500);
        $out = array(''error'' => $e->getMessage());
    }
    echo json_encode($out, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES) . "\n";
    return true;
}
');
INSERT INTO "code_blobs" VALUES('89b953d89b8a17e9568e9acce64a2f7abc9f69af','php',6645,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * DocList — the CMS browsing its own documentation (ticket: self-hosting).
 *
 * Admin-only (UserPrivilegeSet::logged_in()). Docs are mirrored into the DB by tools/ingest_self.py,
 * content-addressed by git blob hash: doc_blobs(hash,kind,bytes,body) + doc_refs(hash,path,commit_sha,is_current).
 *   ?page=docs           -> index of the CURRENT docs (doc_refs.is_current=1)
 *   ?page=docs&doc=<hash> -> one doc rendered via a minimal, ESCAPE-FIRST markdown subset (any ''<<<Tag>>>''
 *                            example in the doc stays literal, so the tag engine never re-parses it)
 */
if (!class_exists("DocList")) {
    class DocList implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string) $s, ENT_QUOTES); }

        private static function gate() {
            if (!class_exists(''UserPrivilegeSet'') || !UserPrivilegeSet::logged_in()) {
                return "<p><strong>Administrator area.</strong> Please log in to browse the documentation.</p>\n<<<Login>>>";
            }
            return null;
        }

        public function get_document() {
            $deny = self::gate();
            if ($deny !== null) { return $deny; }
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<p>DocList: no DB.</p>"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $hash = isset($_GET[''doc'']) ? trim((string) $_GET[''doc'']) : '''';
                if ($hash !== '''') { return $this->view($db, $hash); }
                return $this->index($db);
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>DocList error: " . self::esc($e->getMessage()) . "</div>";
            }
        }

        private function index($db) {
            $rows = $db->query(
                "SELECT r.path, r.hash, b.kind, b.bytes FROM doc_refs r JOIN doc_blobs b ON b.hash=r.hash "
                . "WHERE r.is_current=1 ORDER BY r.path")->fetchAll(PDO::FETCH_ASSOC);
            $out = "<p>The CMS''s own documentation, addressed by git blob hash.</p>\n<ul class=''doclist''>\n";
            foreach ($rows as $r) {
                $out .= "<li><a href=''?page=docs&doc=" . self::esc($r[''hash'']) . "''>" . self::esc($r[''path'']) . "</a> "
                      . "<span style=''color:#888;font-size:.85em''>" . self::esc($r[''kind'']) . " &middot; " . (int) $r[''bytes''] . " B</span></li>\n";
            }
            return $out . "</ul>\n";
        }

        private function view($db, $hash) {
            $st = $db->prepare("SELECT kind, bytes, body FROM doc_blobs WHERE hash=?");
            $st->execute(array($hash));
            $blob = $st->fetch(PDO::FETCH_ASSOC);
            if (!$blob) { return "<p>No such doc blob <code>" . self::esc($hash) . "</code>. <a href=''?page=docs''>&larr; index</a></p>"; }

            $rs = $db->prepare("SELECT DISTINCT path, is_current FROM doc_refs WHERE hash=? ORDER BY path");
            $rs->execute(array($hash));
            $refs = $rs->fetchAll(PDO::FETCH_ASSOC);
            $path = $refs ? $refs[0][''path''] : '''';

            $hs = $db->prepare("SELECT hash, MAX(ts) t, MAX(is_current) cur FROM doc_refs WHERE path=? GROUP BY hash ORDER BY t DESC");
            $hs->execute(array($path));
            $hist = $hs->fetchAll(PDO::FETCH_ASSOC);

            $head = "<p><a href=''?page=docs''>&larr; index</a> &middot; <strong>" . self::esc($path) . "</strong> "
                  . "<span style=''color:#888''>(blob " . self::esc(substr($hash, 0, 12)) . ")</span></p>\n";
            $verhtml = "";
            if (count($hist) > 1) {
                $verhtml = "<p style=''font-size:.85em''>versions: ";
                foreach ($hist as $h) {
                    $lab = self::esc(substr($h[''hash''], 0, 9)) . ($h[''cur''] ? "*" : "");
                    $verhtml .= ($h[''hash''] === $hash) ? "<strong>$lab</strong> " : "<a href=''?page=docs&doc=" . self::esc($h[''hash'']) . "''>$lab</a> ";
                }
                $verhtml .= "</p>\n";
            }
            $rendered = ($blob[''kind''] === ''markdown'')
                ? self::markdown($blob[''body''])
                : "<pre style=''background:#f4f1e8;padding:.6rem;overflow:auto''>" . self::esc($blob[''body'']) . "</pre>";
            return $head . $verhtml . "<div class=''doc''>\n" . $rendered . "</div>\n";
        }

        /* Minimal markdown subset. ESCAPE FIRST (so HTML and ''<<<Tag>>>'' examples stay literal), then apply:
           #.. -> h1-h6, blank-line paragraphs, ``` / 4-space indent -> <pre><code>, `x` -> <code>, [t](u) -> <a>. */
        private static function markdown($text) {
            $esc = htmlspecialchars((string) $text, ENT_QUOTES);
            $lines = explode("\n", str_replace("\r", "", $esc));
            $out = ""; $para = array(); $inFence = false; $code = "";
            $flush = function () use (&$para, &$out) {
                if ($para) { $out .= "<p>" . implode(" ", $para) . "</p>\n"; $para = array(); }
            };
            foreach ($lines as $ln) {
                if (preg_match(''/^\s*```/'', $ln)) {
                    if (!$inFence) { $flush(); $inFence = true; $code = ""; }
                    else { $out .= "<pre><code>" . $code . "</code></pre>\n"; $inFence = false; }
                    continue;
                }
                if ($inFence) { $code .= $ln . "\n"; continue; }
                if (preg_match(''/^(#{1,6})\s+(.*)$/'', $ln, $m)) {
                    $flush(); $h = strlen($m[1]); $out .= "<h$h>" . self::inline($m[2]) . "</h$h>\n"; continue;
                }
                if (preg_match(''/^    (.*)$/'', $ln, $m)) {          // 4-space indented code line
                    $flush(); $out .= "<pre><code>" . $m[1] . "</code></pre>\n"; continue;
                }
                if (trim($ln) === "") { $flush(); continue; }
                $para[] = self::inline($ln);
            }
            $flush();
            if ($inFence) { $out .= "<pre><code>" . $code . "</code></pre>\n"; }
            return $out;
        }

        private static function inline($s) {
            $s = preg_replace(''/`([^`]+)`/'', ''<code>$1</code>'', $s);
            $s = preg_replace(''/\[([^\]]+)\]\(([^)\s]+)\)/'', ''<a href="$2">$1</a>'', $s);
            return $s;
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('e01c4347ca05bcf991bd04280d24e442992c13d6','php',2737,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * SiteMap — the "list all pages" tag, used as the site navigation.
 *
 * Implements Tag_Interface; invoked as <<<SiteMap>>>. Reads every Document
 * (page) from CONGRUENCY_SQLITE and renders an inline menu of links, so the
 * nav is generated from the pages that actually exist rather than hardcoded.
 * Terminal/internal pages (the order wizard''s tail, the 404) are blocklisted;
 * a small label map keeps the friendly names.
 */
if (!class_exists("SiteMap")) {
    class SiteMap implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<!-- SiteMap: no DB -->"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $have = array();
                foreach ($db->query("SELECT DocumentID FROM Documents")->fetchAll(PDO::FETCH_COLUMN) as $id) { $have[$id] = 1; }

                // home/about/order-wizard dropped from the nav (still reachable via Pages);
                // the nav now leads with Pages (all pages) and Tags (all tags).
                $block = array(''invalid'' => 1, ''thanks'' => 1, ''ticketDone'' => 1, ''order'' => 1,
                               ''catalog'' => 1, ''about'' => 1, ''config'' => 1);
                $label = array(''pages'' => ''Pages'', ''tags'' => ''Tags'', ''bugs'' => ''bug report'',
                               ''source'' => ''Source'', ''docs'' => ''Docs'');
                $order = array(''pages'', ''tags'', ''bugs'', ''forms'', ''tickets'', ''memories'', ''source'', ''docs'');

                $ids = array();
                foreach ($order as $id) { if (isset($have[$id]) && !isset($block[$id])) { $ids[] = $id; unset($have[$id]); } }
                foreach (array_keys($have) as $id) { if (!isset($block[$id])) { $ids[] = $id; } }  // any extras, after

                $links = array();
                foreach ($ids as $id) {
                    $text = isset($label[$id]) ? $label[$id] : $id;
                    $links[] = "<a href=''?page=" . self::esc($id) . "''>" . self::esc($text) . "</a>";
                }
                return implode(" &nbsp;&middot;&nbsp; ", $links);
            } catch (\Throwable $e) {
                return "<!-- SiteMap error: " . self::esc($e->getMessage()) . " -->";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('2a86acfada4a559c744568bd2f7de1d5e22ac453','php',6464,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * SourceList — the CMS browsing its own running source (ticket: self-hosting).
 *
 * Admin-only (UserPrivilegeSet::logged_in()). The source is mirrored into the DB by
 * tools/ingest_self.py on every crank, content-addressed by git blob hash: code_blobs(hash,...)
 * holds deduped content, code_refs(hash,path,commit_sha,is_current) is the reverse lookup.
 *   ?page=source            -> index of the RUNNING source (code_refs.is_current=1), paginated (?p=)
 *   ?page=source&file=<hash> -> one blob: escaped <pre> + line numbers, its path/commit refs, version history
 * Every value is esc()''d — output flows back through execute_all_tags, so any ''<<<...>>>'' in source
 * must stay literal.
 */
if (!class_exists("SourceList")) {
    class SourceList implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string) $s, ENT_QUOTES); }

        private static function gate() {
            if (!class_exists(''UserPrivilegeSet'') || !UserPrivilegeSet::logged_in()) {
                return "<p><strong>Administrator area.</strong> Please log in to browse the source.</p>\n<<<Login>>>";
            }
            return null;
        }

        public function get_document() {
            $deny = self::gate();
            if ($deny !== null) { return $deny; }
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<p>SourceList: no DB.</p>"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $hash = isset($_GET[''file'']) ? trim((string) $_GET[''file'']) : '''';
                if ($hash !== '''') { return $this->view($db, $hash); }
                return $this->index($db);
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>SourceList error: " . self::esc($e->getMessage()) . "</div>";
            }
        }

        private function index($db) {
            $rows = $db->query(
                "SELECT r.path, r.hash, b.lang, b.bytes FROM code_refs r JOIN code_blobs b ON b.hash=r.hash "
                . "WHERE r.is_current=1 ORDER BY r.path")->fetchAll(PDO::FETCH_ASSOC);
            $total = count($rows);
            $per = 40; $pages = max(1, (int) ceil($total / $per));
            $pg = isset($_GET[''p'']) ? (int) $_GET[''p''] : 1;
            if ($pg < 1) { $pg = 1; } if ($pg > $pages) { $pg = $pages; }
            $slice = array_slice($rows, ($pg - 1) * $per, $per);

            $pager = "<div class=''pager''>"
                   . ($pg > 1 ? "<a href=''?page=source&p=" . ($pg - 1) . "''>&larr; prev</a>" : "<span>&larr; prev</span>")
                   . " page <strong>$pg</strong> of $pages ($total files) "
                   . ($pg < $pages ? "<a href=''?page=source&p=" . ($pg + 1) . "''>next &rarr;</a>" : "<span>next &rarr;</span>")
                   . "</div>\n";

            $out = "<p>The CMS''s own running source, addressed by git blob hash.</p>\n" . $pager . "<ul class=''srclist''>\n";
            foreach ($slice as $r) {
                $out .= "<li><a href=''?page=source&file=" . self::esc($r[''hash'']) . "''>" . self::esc($r[''path'']) . "</a> "
                      . "<span style=''color:#888;font-size:.85em''>" . self::esc($r[''lang'']) . " &middot; " . (int) $r[''bytes''] . " B</span></li>\n";
            }
            return $out . "</ul>\n" . $pager;
        }

        private function view($db, $hash) {
            $st = $db->prepare("SELECT lang, bytes, body FROM code_blobs WHERE hash=?");
            $st->execute(array($hash));
            $blob = $st->fetch(PDO::FETCH_ASSOC);
            if (!$blob) { return "<p>No such source blob <code>" . self::esc($hash) . "</code>. <a href=''?page=source''>&larr; index</a></p>"; }

            // reverse lookup: which path(s)/commit(s) this blob appeared at
            $rs = $db->prepare("SELECT DISTINCT path, commit_sha, is_current FROM code_refs WHERE hash=? ORDER BY path");
            $rs->execute(array($hash));
            $refs = $rs->fetchAll(PDO::FETCH_ASSOC);
            $path = $refs ? $refs[0][''path''] : '''';

            // version history of that path (all blobs, newest ts first)
            $hs = $db->prepare("SELECT hash, MIN(commit_sha) c, MAX(ts) t, MAX(is_current) cur FROM code_refs "
                             . "WHERE path=? GROUP BY hash ORDER BY t DESC");
            $hs->execute(array($path));
            $hist = $hs->fetchAll(PDO::FETCH_ASSOC);

            $head = "<p><a href=''?page=source''>&larr; index</a> &middot; <strong>" . self::esc($path) . "</strong> "
                  . "<span style=''color:#888''>(" . self::esc($blob[''lang'']) . " &middot; " . (int) $blob[''bytes''] . " B &middot; blob " . self::esc(substr($hash, 0, 12)) . ")</span></p>\n";

            $refhtml = "<p style=''font-size:.85em;color:#666''>appears at: ";
            foreach ($refs as $r) {
                $refhtml .= self::esc($r[''path'']) . "@" . self::esc(substr($r[''commit_sha''], 0, 9)) . ($r[''is_current''] ? " <em>(current)</em>" : "") . " &nbsp; ";
            }
            $refhtml .= "</p>\n";

            $verhtml = "";
            if (count($hist) > 1) {
                $verhtml = "<p style=''font-size:.85em''>versions of this file: ";
                foreach ($hist as $h) {
                    $sel = ($h[''hash''] === $hash);
                    $lab = self::esc(substr($h[''hash''], 0, 9)) . ($h[''cur''] ? "*" : "");
                    $verhtml .= $sel ? "<strong>$lab</strong> " : "<a href=''?page=source&file=" . self::esc($h[''hash'']) . "''>$lab</a> ";
                }
                $verhtml .= "</p>\n";
            }

            $esc = self::esc($blob[''body'']);
            $lines = explode("\n", $esc);
            $code = "<pre style=''background:#f4f1e8;border:1px solid #d8d2c4;padding:.6rem;overflow:auto;font-size:.82rem;line-height:1.4''>";
            $n = 1;
            foreach ($lines as $ln) {
                $code .= "<span style=''color:#b0a890;user-select:none''>" . sprintf(''%4d'', $n++) . "</span>  " . $ln . "\n";
            }
            $code .= "</pre>\n";

            return $head . $refhtml . $verhtml . $code;
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('33a7027281f4140812b4e68c04f691f60ce51994','python',12239,'#!/usr/bin/env python3
"""doc_watch.py -- file a "documentation may be stale" ticket when a commit changes code but no doc.

An outside-the-app observer of commits. For each commit where a SCRIPT (.php/.py) changed but NO doc
(.md/.txt) was touched in that same commit, it maps the changed code area -> the specific doc(s) likely
now stale (a dir->doc map) and opens/append a `documentation` ticket in the unified jazz tracker
(~/.jazz/congruency.sqlite). One OPEN ticket per doc (deduped by meta.doc); each commit is recorded once
(meta.commits), so the standalone tool and the post-commit hook converge without duplicates.

Registry-gated (walks up to registry.json), python-only, best-effort (never blocks a commit).

    python3 tools/doc_watch.py                 # watermark..HEAD  (HEAD only on first run)
    python3 tools/doc_watch.py --commit <sha>  # one commit (used by the post-commit hook)
    python3 tools/doc_watch.py --head          # HEAD only
    python3 tools/doc_watch.py --since <ref>   # ref..HEAD  (batch catch-up)
    python3 tools/doc_watch.py --dry-run       # classify + print, write nothing
    python3 tools/doc_watch.py --install-hook  # drop a post-commit hook that calls --head
"""
import argparse
import json
import os
import subprocess
import sys
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None   # repo root (dir of registry.json); set in main()

# code areas whose change implicates a doc (longest-prefix wins per file)
DOC_MAP = [
    ("checkouts/current/boot/",         ["DEPENDENCIES.md", "DEPLOY.md", "checkouts/current/ARCHITECTURE.md"]),
    ("checkouts/current/state/",        ["DEPLOY.md", "DEPENDENCIES.md"]),
    ("checkouts/current/invocators/",   ["checkouts/current/ARCHITECTURE.md", "checkouts/current/doc/CMS_ADDITIONS.md"]),
    ("checkouts/current/lib/",          ["checkouts/current/ARCHITECTURE.md"]),
    ("checkouts/current/bin/",          ["checkouts/current/ARCHITECTURE.md"]),
    ("checkouts/current/www/",          ["checkouts/current/ARCHITECTURE.md"]),
    ("checkouts/current/tools/",        ["checkouts/current/tools/README.md"]),   # + filename special-cases
    ("checkouts/current/versioning/",   ["checkouts/current/versioning/README.md"]),
    ("checkouts/current/fixes/",        ["checkouts/current/fixes/README.md"]),
    ("checkouts/current/tests/parser/", ["checkouts/current/tests/parser/README.md"]),
    ("tracker/",                        ["tracker/SIGNALS.md"]),
    ("tooling/coverage/",               ["tooling/coverage/README.md", "tooling/README.md"]),
    ("tooling/pwdriver/",               ["tooling/pwdriver/README.md", "tooling/README.md"]),
    ("ENTRY_POINT.py",                  ["README.md"]),
    ("registry.json",                   ["README.md"]),
    ("note-for-claude",                 ["README.md"]),
]
FALLBACK_CODE = "checkouts/current/ARCHITECTURE.md"     # code under the app tree with no better hit
GENERIC = "__generic__"                                  # anything else -> a generic "review docs" ticket
IGNORE_SUBSTR = ("tooling/congruencey/", "tooling/tournament-", "/vendor/")   # frozen / vendored snapshots
SCRIPT_EXT = (".php", ".py")
DOC_EXT = (".md", ".txt")


# ---------------------------------------------------------------- registry + jazz
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def _jazz(reg):
    """Best-effort import of the canonical ticket writer (same package predict.py/mint_crank.py use)."""
    for cand in (os.path.join(os.path.dirname(reg["__root__"]), "jazz_telemetry"),                    # .../packages/jazz_telemetry
                 os.path.join(os.path.dirname(os.path.dirname(reg["__root__"])), "jazz_telemetry")):  # predict.py''s shim path
        if os.path.isdir(cand) and cand not in sys.path:
            sys.path.insert(0, cand)
    try:
        from jazz_telemetry import open_ticket, update_ticket, tickets, get_ticket
        return {"open_ticket": open_ticket, "update_ticket": update_ticket,
                "tickets": tickets, "get_ticket": get_ticket}
    except Exception as e:  # noqa: BLE001
        sys.stderr.write("[doc_watch] jazz_telemetry unavailable: %r\n" % e)
        return None


# ---------------------------------------------------------------- git helpers
def git(*args):
    return subprocess.run(["git"] + list(args), cwd=ROOT, capture_output=True, text=True).stdout.strip()


def resolve(ref):
    return git("rev-parse", ref)


def commits_in_range(start, end="HEAD"):
    out = git("rev-list", "--reverse", "%s..%s" % (start, end))
    return out.split() if out else []


def changed_files(sha):
    out = git("diff-tree", "--no-commit-id", "--name-only", "-r", sha)
    return out.splitlines() if out else []


def subject(sha):
    return git("log", "-1", "--format=%s", sha)


# ---------------------------------------------------------------- classification
def ignored(path):
    return any(s in path for s in IGNORE_SUBSTR)


def docs_for(path):
    best = None
    for prefix, docs in DOC_MAP:
        if path.startswith(prefix) and (best is None or len(prefix) > len(best[0])):
            best = (prefix, docs)
    if best is not None:
        docs = list(best[1])
        if best[0] == "checkouts/current/tools/":
            base = os.path.basename(path)
            if base in ("provision_php.py", "predict.py"):
                docs.append("DEPENDENCIES.md")
            if base in ("crawl.py", "tagcheck.py"):
                docs.append("checkouts/current/doc/CMS_ADDITIONS.md")
        return docs
    if path.startswith("checkouts/current/") and path.endswith(SCRIPT_EXT):
        return [FALLBACK_CODE]
    return [GENERIC]


# ---------------------------------------------------------------- dedup state
def load_open_docs(jazz):
    """map implicated-doc -> {id, meta, body} for OPEN documentation tickets already filed by doc_watch."""
    out = {}
    if not jazz:
        return out
    for t in jazz["tickets"]("OPEN"):
        if t.get("component") != "documentation":
            continue
        full = jazz["get_ticket"](t["id"])
        if not full:
            continue
        meta = full.get("meta")
        if isinstance(meta, dict) and meta.get("doc"):
            out[meta["doc"]] = {"id": full["id"], "meta": meta, "body": full.get("body") or ""}
    return out


def title_for(doc):
    return "Docs may be stale: %s" % ("review documentation" if doc == GENERIC else doc)


def process_commit(sha, jazz, open_docs, write):
    files = [f for f in changed_files(sha) if not ignored(f)]
    scripts = [f for f in files if f.endswith(SCRIPT_EXT)]
    docs_touched = [f for f in files if f.endswith(DOC_EXT)]
    if not scripts or docs_touched:
        return []   # trigger only on "code changed, docs didn''t"
    implicated = {}
    for s in scripts:
        for d in docs_for(s):
            implicated.setdefault(d, set()).add(s)
    subj = subject(sha)
    actions = []
    for doc in sorted(implicated):
        scr = sorted(implicated[doc])
        line = "%s %s -- scripts: %s" % (sha[:9], subj, ", ".join(scr))
        if doc in open_docs:
            t = open_docs[doc]
            commits = list(t["meta"].get("commits", []))
            if sha in commits:
                actions.append(("skip", doc, t["id"]))
                continue
            commits.append(sha)
            body = (t["body"] + "\n" + line).strip()
            if write:
                jazz["update_ticket"](t["id"], body=body, doc=doc, commits=commits, source="doc_watch")
            t["meta"]["commits"] = commits
            t["body"] = body
            actions.append(("append", doc, t["id"]))
        else:
            tid = "(dry)"
            if write:
                tid = jazz["open_ticket"](title_for(doc), component="documentation", severity="low",
                                          body=line, doc=doc, commits=[sha], source="doc_watch")
            open_docs[doc] = {"id": tid, "meta": {"doc": doc, "commits": [sha]}, "body": line}
            actions.append(("open", doc, tid))
    return actions


# ---------------------------------------------------------------- watermark + hook
def watermark_path(reg):
    return os.path.join(reg["__root__"], "logs", "doc_watch.json")


def read_watermark(reg):
    try:
        return json.load(open(watermark_path(reg))).get("last_seen")
    except Exception:  # noqa: BLE001
        return None


def write_watermark(reg, sha):
    try:
        p = watermark_path(reg)
        os.makedirs(os.path.dirname(p), exist_ok=True)
        json.dump({"last_seen": sha, "updated": datetime.now().isoformat()}, open(p, "w"), indent=2)
    except Exception:  # noqa: BLE001
        pass


HOOK = """#!/usr/bin/env python3
# post-commit hook (installed by `doc_watch.py --install-hook`). Best-effort; never blocks the commit.
# Runs the doc-stale observer AND the self-source ingestion, so on every crank the DB both flags stale
# docs and mirrors the running source (content-addressed by git blob hash).
import subprocess, sys, os
try:
    root = subprocess.run(["git", "rev-parse", "--show-toplevel"],
                          capture_output=True, text=True, timeout=10).stdout.strip()
    if root:
        for tool in ("doc_watch.py", "ingest_self.py"):
            p = os.path.join(root, "checkouts", "current", "tools", tool)
            if os.path.isfile(p):
                subprocess.run([sys.executable, p, "--head"], timeout=60)
except Exception:
    pass
"""


def install_hook(reg):
    gitdir = git("rev-parse", "--absolute-git-dir")
    hooks = os.path.join(gitdir, "hooks")
    os.makedirs(hooks, exist_ok=True)
    path = os.path.join(hooks, "post-commit")
    with open(path, "w") as fh:
        fh.write(HOOK)
    os.chmod(path, 0o755)
    print("installed post-commit hook -> %s  (runs doc_watch.py --head after each commit)" % path)
    return 0


# ---------------------------------------------------------------- main
def main():
    global ROOT
    ap = argparse.ArgumentParser(description="file a documentation-stale ticket when code changes without a doc update")
    ap.add_argument("--commit", help="inspect a single commit")
    ap.add_argument("--head", action="store_true", help="inspect HEAD only")
    ap.add_argument("--since", help="inspect <ref>..HEAD")
    ap.add_argument("--dry-run", action="store_true", help="classify + print, write nothing")
    ap.add_argument("--install-hook", action="store_true", help="install the post-commit hook and exit")
    a = ap.parse_args()

    reg = load_registry()
    ROOT = reg["__root__"]

    if a.install_hook:
        return install_hook(reg)

    if a.head or a.commit:
        commits = [resolve(a.commit or "HEAD")]
    elif a.since:
        commits = commits_in_range(a.since)
    else:
        wm = read_watermark(reg)
        commits = commits_in_range(wm) if wm else [resolve("HEAD")]

    jazz = _jazz(reg)
    write = (not a.dry_run) and (jazz is not None)
    open_docs = load_open_docs(jazz)

    actions = []
    for sha in commits:
        actions += process_commit(sha, jazz, open_docs, write)

    for kind, doc, tid in actions:
        print("  %-7s %-45s ticket %s" % (kind, doc, tid))
    tag = " [dry-run]" if a.dry_run else ("" if write else " [no jazz_telemetry — not written]")
    print("doc_watch: %d commit(s), %d action(s)%s" % (len(commits), len(actions), tag))

    # advance the watermark only for modes that logically processed up to HEAD (not a targeted --commit)
    if write and commits and a.commit is None:
        write_watermark(reg, resolve("HEAD"))
    return 0


if __name__ == "__main__":
    try:
        sys.exit(main())
    except Exception as e:  # noqa: BLE001  -- best-effort: never crash a commit hook
        sys.stderr.write("[doc_watch] %r\n" % e)
        sys.exit(0)
');
INSERT INTO "code_blobs" VALUES('1684db68c4b76ff98f5c774c279660f9e58c3303','python',12502,'#!/usr/bin/env python3
"""ingest_self.py -- mirror the running source + docs into the CMS DB, content-addressed by git blob hash.

On each crank (post-commit) this pushes the running source into the CMS DB (CONGRUENCY_SQLITE, the unified
~/.jazz/congruency.sqlite) so the CMS can render its own source and documentation. Content is deduped by
git blob hash; a reverse-lookup (path @ commit) names each blob and gives every file its version history;
`is_current=1` flags the blob for each path in the checked-out HEAD tree = the RUNNING source. Code and
docs live in separate tables.

    python3 tools/ingest_self.py             # --head (default): ingest the HEAD tree + re-flag current
    python3 tools/ingest_self.py --backfill  # walk source history into the archive, then flag current
    python3 tools/ingest_self.py --stats     # print row counts
    python3 tools/ingest_self.py --ensure-pages  # create tables + the source/docs entry Documents

Registry-gated, python-only, best-effort (never blocks a commit); Variant-A bug report on exception.
"""
import argparse
import json
import os
import sqlite3
import subprocess
import sys
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None   # repo root (dir of registry.json); set in main()

CODE_EXT = (".php", ".py")
DOC_EXT = (".md", ".txt")
IGNORE_SUBSTR = ("tooling/congruencey/", "tooling/tournament-", "/vendor/", "/node_modules/")
CODE_PREFIXES = (
    "checkouts/current/lib/", "checkouts/current/invocators/", "checkouts/current/boot/",
    "checkouts/current/www/", "checkouts/current/bin/",
    "checkouts/current/tools/", "checkouts/current/versioning/", "tracker/",
)
MAIN_EXTRAS = ("deploy.py", "install.py")            # deploy/stand-up-teardown tooling (lives on `main`)
LANG = {".php": "php", ".py": "python", ".md": "markdown", ".txt": "text"}

DDL = [
    "CREATE TABLE IF NOT EXISTS code_blobs (hash TEXT PRIMARY KEY, lang TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS code_refs  (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_code_refs ON code_refs(hash, path, commit_sha)",
    "CREATE TABLE IF NOT EXISTS doc_blobs  (hash TEXT PRIMARY KEY, kind TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS doc_refs   (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_doc_refs ON doc_refs(hash, path, commit_sha)",
]


# ------------------------------------------------------------------ registry / db
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def bug_report(reg, exc, tb, note="ingest_self"):
    root = (reg or {}).get("__root__") or ROOT or HERE
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {"filename": os.path.basename(__file__), "function": last.name if last else "?",
             "time-of-occurance": datetime.now().isoformat(),
             "methods-to-reproduce": "python3 tools/ingest_self.py " + " ".join(sys.argv[1:]),
             "possible-cause": "%s: %s" % (type(exc).__name__, exc),
             "traceback": tb.strip().splitlines()[-6:], "note": note}
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        open(path, "a").write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def db_path(reg):
    """The CMS DB the app reads: install.json''s CONGRUENCY_SQLITE, else the jazz default."""
    cfg = os.path.join(reg["__root__"], "checkouts", "current", "install.json")
    try:
        j = json.load(open(cfg))
        if j.get("CONGRUENCY_SQLITE"):
            return os.path.expanduser(j["CONGRUENCY_SQLITE"])
    except Exception:  # noqa: BLE001
        pass
    return os.path.join(os.path.expanduser("~"), ".jazz", "congruency.sqlite")


# ------------------------------------------------------------------ git
def git(*args):
    return subprocess.run(["git"] + list(args), cwd=ROOT, capture_output=True, text=True)


def resolve(ref):
    return git("rev-parse", ref).stdout.strip()


def ls_tree(ref):
    for line in git("ls-tree", "-r", ref).stdout.splitlines():
        meta, _, path = line.partition("\t")          # "<mode> blob <hash>\t<path>"
        parts = meta.split()
        if len(parts) == 3 and parts[1] == "blob":
            yield parts[2], path


def blob_body(h):
    r = git("cat-file", "blob", h)
    return r.stdout if r.returncode == 0 else ""


# ------------------------------------------------------------------ classify / write
def in_scope(path):
    if any(s in path for s in IGNORE_SUBSTR):
        return None
    ext = os.path.splitext(path)[1]
    if ext in CODE_EXT and any(path.startswith(p) for p in CODE_PREFIXES):
        return "code"
    if ext in DOC_EXT:
        return "doc"
    return None


def have_blob(db, domain, h):
    tbl = "code_blobs" if domain == "code" else "doc_blobs"
    return db.execute("SELECT 1 FROM %s WHERE hash=?" % tbl, (h,)).fetchone() is not None


def store_blob(db, domain, h, path, body):
    lang = LANG.get(os.path.splitext(path)[1], "text")
    nbytes = len(body.encode("utf-8", "replace"))
    if domain == "code":
        db.execute("INSERT OR IGNORE INTO code_blobs(hash,lang,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))
    else:
        db.execute("INSERT OR IGNORE INTO doc_blobs(hash,kind,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))


def add_ref(db, domain, h, path, commit_sha, ts):
    tbl = "code_refs" if domain == "code" else "doc_refs"
    db.execute("INSERT OR IGNORE INTO %s(hash,path,commit_sha,ts,is_current) VALUES(?,?,?,?,0)" % tbl,
               (h, path, commit_sha, ts))


def ingest_ref(db, ref, ts, main_extras=True):
    """Ingest every in-scope blob at `ref`; return [(domain, path, hash)] for current-flagging."""
    sha = resolve(ref)
    seen = []
    for h, path in ls_tree(ref):
        dom = in_scope(path)
        if not dom:
            continue
        if not have_blob(db, dom, h):
            store_blob(db, dom, h, path, blob_body(h))
        add_ref(db, dom, h, path, sha, ts)
        seen.append((dom, path, h, sha))
    if main_extras:
        main_sha = resolve("main")
        for name in MAIN_EXTRAS:
            r = git("ls-tree", "main", "--", name)
            parts = r.stdout.split()
            if r.returncode == 0 and len(parts) >= 3 and parts[1] == "blob":
                h, path = parts[2], "main:" + name
                if not have_blob(db, "code", h):
                    store_blob(db, "code", h, path, blob_body(h))
                add_ref(db, "code", h, path, main_sha, ts)
                seen.append(("code", path, h, main_sha))
    return seen


def reflag_current(db, seen):
    db.execute("UPDATE code_refs SET is_current=0")
    db.execute("UPDATE doc_refs  SET is_current=0")
    for dom, path, h, csha in seen:
        tbl = "code_refs" if dom == "code" else "doc_refs"
        db.execute("UPDATE %s SET is_current=1 WHERE hash=? AND path=? AND commit_sha=?" % tbl, (h, path, csha))


def ensure_pages(db):
    """Create the two entry-page Documents (source, docs) in the live DB if absent (idempotent)."""
    def next_tid():
        row = db.execute("SELECT COALESCE(MAX(TemplateID),0)+1 FROM Document_Templates").fetchone()
        return row[0] if row else 1
    style = "body{font-family:Georgia,serif;max-width:900px;margin:2.5rem auto;padding:0 1rem;line-height:1.5;color:#222;background:#f7f4ee}a{color:#8a5a1a}h1{font-weight:normal}code,pre{background:#eae5d8}pre{padding:.6rem;overflow:auto}"
    nav = "<nav style=''margin:0 0 1.5rem;padding-bottom:.5rem;border-bottom:1px solid #ccc''><<<SiteMap>>></nav>"
    pages = {
        "source": ("Source · Congruency", "The CMS''s own running source (admin)", "<<<SourceList>>>"),
        "docs":   ("Documentation · Congruency", "The CMS''s own documentation (admin)", "<<<DocList>>>"),
    }
    for did, (title, desc, tag) in pages.items():
        if db.execute("SELECT 1 FROM Documents WHERE DocumentID=?", (did,)).fetchone():
            continue
        tid = next_tid()
        body = "<!DOCTYPE html><html><head> <title><<<TitleTag>>></title> <style>%s</style> </head> <body> %s <h1>%s</h1> %s </body></html>" % (style, nav, title, tag)
        db.execute("INSERT INTO Document_Templates(TemplateID, Content) VALUES(?,?)", (tid, body))
        db.execute("INSERT INTO Documents(DocumentID, TemplateID, Title, Description, ContentID) VALUES(?,?,?,?,?)",
                   (did, tid, title, desc, tid))


def stats(db):
    for t in ("code_blobs", "code_refs", "doc_blobs", "doc_refs"):
        try:
            n = db.execute("SELECT COUNT(*) FROM %s" % t).fetchone()[0]
        except sqlite3.Error:
            n = "-"
        cur = ""
        if t.endswith("_refs"):
            c = db.execute("SELECT COUNT(*) FROM %s WHERE is_current=1" % t).fetchone()[0]
            cur = "  (current: %d)" % c
        print("  %-11s %s%s" % (t, n, cur))


# ------------------------------------------------------------------ main
def main():
    global ROOT
    ap = argparse.ArgumentParser(description="mirror the running source + docs into the CMS DB (content-addressed)")
    ap.add_argument("--head", action="store_true", help="ingest the HEAD tree + re-flag current (default)")
    ap.add_argument("--backfill", action="store_true", help="walk source history into the archive")
    ap.add_argument("--ensure-pages", action="store_true", help="create tables + the source/docs entry Documents")
    ap.add_argument("--stats", action="store_true", help="print row counts and exit")
    a = ap.parse_args()

    reg = load_registry()
    ROOT = reg["__root__"]
    db = sqlite3.connect(db_path(reg), timeout=15)
    try:
        for stmt in DDL:
            db.execute(stmt)

        if a.stats:
            stats(db)
            return 0

        if a.ensure_pages:
            ensure_pages(db)
            db.commit()
            print("ensure-pages: source/docs Documents ensured; tables created")
            return 0

        try:
            ensure_pages(db)   # self-healing: the source/docs entry Documents exist (idempotent)
        except Exception:  # noqa: BLE001  (a bare/fresh DB without the CMS Documents table)
            pass

        if a.backfill:
            seen_hashes_before = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0]
            for line in git("rev-list", "--timestamp", "source").stdout.splitlines():
                parts = line.split()
                if len(parts) != 2:
                    continue
                ts, sha = float(parts[0]), parts[1]
                ingest_ref(db, sha, ts, main_extras=False)
            # current main extras + flag HEAD as running source
            seen = ingest_ref(db, "HEAD", float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0), main_extras=True)
            reflag_current(db, seen)
            db.commit()
            added = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0] - seen_hashes_before
            print("backfill: walked source history (+%d new code blobs)" % added)
            stats(db)
            return 0

        # default: --head
        ts = float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0)
        seen = ingest_ref(db, "HEAD", ts, main_extras=True)
        reflag_current(db, seen)
        db.commit()
        print("ingest_self: HEAD tree mirrored (%d in-scope files); running source flagged" % len(seen))
        return 0
    finally:
        db.close()


if __name__ == "__main__":
    try:
        sys.exit(main())
    except Exception as e:  # noqa: BLE001  -- best-effort: never crash a commit hook
        try:
            reg = load_registry()
        except Exception:  # noqa: BLE001
            reg = None
        bug_report(reg, e, traceback.format_exc())
        sys.stderr.write("[ingest_self] %r\n" % e)
        sys.exit(0)
');
INSERT INTO "code_blobs" VALUES('dedaa8502b66e26a4ba48102338d812f117cef7e','php',7538,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * rest.php — a generic READ-ONLY REST interface over every table in the unified
 * DB (CONGRUENCY_SQLITE). Dispatched by boot/router.php when ?api is present:
 *
 *   ?api=tables              -> { "tables": [ ... ] }        (discovery)
 *   ?api=<table>             -> { table,total,page,per,pages,rows:[...] }   (paginated)
 *   ?api=<table>&p=2&per=25  -> page 2, 25 rows
 *   ?api=<table>&id=<pk>     -> a single row by primary key
 *
 * The table name is always validated against sqlite_master before use (allowlist),
 * so it can''t be used for injection. Writes (POST/PUT/DELETE) are intentionally NOT
 * implemented yet — see ticket #47.
 */
function congruency_rest_dispatch() {
    header(''Content-Type: application/json'');
    header(''Access-Control-Allow-Origin: *'');
    $out = null;
    try {
        if (!defined(''CONGRUENCY_SQLITE'')) { throw new Exception(''CONGRUENCY_SQLITE not defined''); }
        $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
        $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

        $tables = array();
        foreach ($db->query("SELECT name FROM sqlite_master WHERE type=''table'' AND name NOT LIKE ''sqlite_%'' ORDER BY name") as $r) {
            $tables[$r[''name'']] = 1;
        }
        // admin-only: keep the self-hosting source/doc archive + the auth tables out of the public REST surface
        foreach (array(''code_blobs'', ''code_refs'', ''doc_blobs'', ''doc_refs'',
                       ''Login_Password'', ''User_Group_Mappings'', ''Group_Privileges'') as $__deny) { unset($tables[$__deny]); }

        $api = (string)($_GET[''api''] ?? '''');
        $method = strtoupper($_SERVER[''REQUEST_METHOD''] ?? ''GET'');

        if ($method === ''POST'' && isset($tables[$api])) {
            // CREATE: insert a row from the JSON body; only real columns are used (rest ignored).
            $data = json_decode((string)file_get_contents(''php://input''), true);
            if (!is_array($data)) { http_response_code(400); echo json_encode(array(''error'' => ''body must be a JSON object'')); return true; }
            $cols = array();
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { $cols[$c[''name'']] = 1; }
            $use = array();
            foreach ($data as $k => $v) { if (isset($cols[$k])) { $use[$k] = $v; } }
            if (!$use) { http_response_code(400); echo json_encode(array(''error'' => ''no valid columns for '' . $api, ''columns'' => array_keys($cols))); return true; }
            $names = array_keys($use);
            $sql = "INSERT INTO \"$api\" (" . implode('','', array_map(function ($n) { return "\"$n\""; }, $names)) . ") "
                 . "VALUES (" . implode('','', array_map(function ($n) { return ":$n"; }, $names)) . ")";
            $st = $db->prepare($sql);
            foreach ($use as $k => $v) { $st->bindValue(":$k", $v); }
            $st->execute();
            http_response_code(201);
            echo json_encode(array(''created'' => true, ''table'' => $api, ''rowid'' => $db->lastInsertId(), ''used'' => $use),
                             JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES) . "\n";
            return true;
        }

        if (($method === ''PUT'' || $method === ''PATCH'') && isset($tables[$api])) {
            // UPDATE by primary key: ?id=<pk>, JSON body of column=>value (real columns only).
            $pk = null;
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { if ($c[''pk'']) { $pk = $c[''name'']; } }
            if ($pk === null || !isset($_GET[''id''])) { http_response_code(400); echo json_encode(array(''error'' => ''update needs a single-column pk and ?id='')); return true; }
            $data = json_decode((string)file_get_contents(''php://input''), true);
            if (!is_array($data)) { http_response_code(400); echo json_encode(array(''error'' => ''body must be a JSON object'')); return true; }
            $cols = array();
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { $cols[$c[''name'']] = 1; }
            $use = array();
            foreach ($data as $k => $v) { if (isset($cols[$k]) && $k !== $pk) { $use[$k] = $v; } }
            if (!$use) { http_response_code(400); echo json_encode(array(''error'' => ''no valid columns to update'')); return true; }
            $set = implode('', '', array_map(function ($n) { return "\"$n\" = :$n"; }, array_keys($use)));
            $st = $db->prepare("UPDATE \"$api\" SET $set WHERE \"$pk\" = :__id");
            foreach ($use as $k => $v) { $st->bindValue(":$k", $v); }
            $st->bindValue(":__id", $_GET[''id'']);
            $st->execute();
            echo json_encode(array(''updated'' => $st->rowCount(), ''table'' => $api, ''pk'' => $pk, ''id'' => $_GET[''id''], ''set'' => $use),
                             JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES) . "\n";
            return true;
        }

        if ($method === ''DELETE'' && isset($tables[$api])) {
            // DELETE a single row by primary key (?id=). No bulk deletes.
            $pk = null;
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { if ($c[''pk'']) { $pk = $c[''name'']; } }
            if ($pk === null || !isset($_GET[''id''])) { http_response_code(400); echo json_encode(array(''error'' => ''delete needs a single-column pk and ?id='')); return true; }
            $st = $db->prepare("DELETE FROM \"$api\" WHERE \"$pk\" = ?");
            $st->execute(array($_GET[''id'']));
            echo json_encode(array(''deleted'' => $st->rowCount(), ''table'' => $api, ''pk'' => $pk, ''id'' => $_GET[''id''])) . "\n";
            return true;
        }

        if ($api === '''' || $api === ''tables'') {
            $out = array(''tables'' => array_keys($tables));
        } elseif (isset($tables[$api])) {
            // primary-key column (for ?id=)
            $pk = null;
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { if ($c[''pk'']) { $pk = $c[''name'']; break; } }

            if (isset($_GET[''id'']) && $pk !== null) {
                $st = $db->prepare("SELECT * FROM \"$api\" WHERE \"$pk\" = ?");
                $st->execute(array($_GET[''id'']));
                $row = $st->fetch(PDO::FETCH_ASSOC);
                if ($row === false) { http_response_code(404); $out = array(''error'' => ''not found'', ''table'' => $api, ''id'' => $_GET[''id'']); }
                else { $out = array(''table'' => $api, ''pk'' => $pk, ''row'' => $row); }
            } else {
                $per = isset($_GET[''per'']) ? max(1, min(500, (int)$_GET[''per''])) : 50;
                $pg  = isset($_GET[''p''])   ? max(1, (int)$_GET[''p'']) : 1;
                $total = (int)$db->query("SELECT COUNT(*) FROM \"$api\"")->fetchColumn();
                $off = ($pg - 1) * $per;
                $rows = $db->query("SELECT * FROM \"$api\" LIMIT $per OFFSET $off")->fetchAll(PDO::FETCH_ASSOC);
                $out = array(''table'' => $api, ''pk'' => $pk, ''total'' => $total, ''page'' => $pg, ''per'' => $per,
                             ''pages'' => (int)ceil($total / max(1, $per)), ''rows'' => $rows);
            }
        } else {
            http_response_code(404);
            $out = array(''error'' => ''unknown table'', ''table'' => $api, ''tables'' => array_keys($tables));
        }
    } catch (\Throwable $e) {
        http_response_code(500);
        $out = array(''error'' => $e->getMessage());
    }
    echo json_encode($out, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES) . "\n";
    return true;
}
');
INSERT INTO "code_blobs" VALUES('ecb034048e56a8c4ce2c827eae5e0414467583a4','php',6672,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * SourceList — the CMS browsing its own running source (ticket: self-hosting).
 *
 * Admin-only (UserPrivilegeSet::logged_in()). The source is mirrored into the DB by
 * tools/ingest_self.py on every crank, content-addressed by git blob hash: code_blobs(hash,...)
 * holds deduped content, code_refs(hash,path,commit_sha,is_current) is the reverse lookup.
 *   ?page=source            -> index of the RUNNING source (code_refs.is_current=1), paginated (?p=)
 *   ?page=source&file=<hash> -> one blob: escaped <pre> + line numbers, its path/commit refs, version history
 * Every value is esc()''d — output flows back through execute_all_tags, so any ''<<<...>>>'' in source
 * must stay literal.
 */
if (!class_exists("SourceList")) {
    class SourceList implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string) $s, ENT_QUOTES); }

        private static function gate() {
            if (!class_exists(''UserPrivilegeSet'') || !UserPrivilegeSet::logged_in()) {
                return "<p><strong>Administrator area.</strong> Please log in to browse the source.</p>\n<<<Login>>>";
            }
            return null;
        }

        public function get_document() {
            $deny = self::gate();
            if ($deny !== null) { return $deny; }
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<p>SourceList: no DB.</p>"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $hash = isset($_GET[''file'']) ? trim((string) $_GET[''file'']) : '''';
                if ($hash !== '''') { return $this->view($db, $hash); }
                return $this->index($db);
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>SourceList error: " . self::esc($e->getMessage()) . "</div>";
            }
        }

        private function index($db) {
            $rows = $db->query(
                "SELECT r.path, r.hash, b.lang, b.bytes FROM code_refs r JOIN code_blobs b ON b.hash=r.hash "
                . "WHERE r.is_current=1 ORDER BY r.path")->fetchAll(PDO::FETCH_ASSOC);
            $total = count($rows);
            $per = 40; $pages = max(1, (int) ceil($total / $per));
            $pg = isset($_GET[''p'']) ? (int) $_GET[''p''] : 1;
            if ($pg < 1) { $pg = 1; } if ($pg > $pages) { $pg = $pages; }
            $slice = array_slice($rows, ($pg - 1) * $per, $per);

            $pager = "<div class=''pager''>"
                   . ($pg > 1 ? "<a href=''?page=source&p=" . ($pg - 1) . "''>&larr; prev</a>" : "<span>&larr; prev</span>")
                   . " page <strong>$pg</strong> of $pages ($total files) "
                   . ($pg < $pages ? "<a href=''?page=source&p=" . ($pg + 1) . "''>next &rarr;</a>" : "<span>next &rarr;</span>")
                   . "</div>\n";

            $out = "<p>The CMS''s own running source, addressed by git blob hash.</p>\n" . $pager . "<ul class=''srclist''>\n";
            foreach ($slice as $r) {
                $out .= "<li><a href=''?page=source&file=" . self::esc($r[''hash'']) . "''>" . self::esc($r[''path'']) . "</a> "
                      . "<span style=''color:#888;font-size:.85em''>" . self::esc($r[''lang'']) . " &middot; " . (int) $r[''bytes''] . " B</span></li>\n";
            }
            return $out . "</ul>\n" . $pager;
        }

        private function view($db, $hash) {
            $st = $db->prepare("SELECT lang, bytes, body FROM code_blobs WHERE hash=?");
            $st->execute(array($hash));
            $blob = $st->fetch(PDO::FETCH_ASSOC);
            if (!$blob) { return "<p>No such source blob <code>" . self::esc($hash) . "</code>. <a href=''?page=source''>&larr; index</a></p>"; }

            // reverse lookup: which path(s)/commit(s) this blob appeared at
            $rs = $db->prepare("SELECT DISTINCT path, commit_sha, is_current FROM code_refs WHERE hash=? ORDER BY path");
            $rs->execute(array($hash));
            $refs = $rs->fetchAll(PDO::FETCH_ASSOC);
            $path = $refs ? $refs[0][''path''] : '''';

            // version history of that path (all blobs, newest ts first)
            $hs = $db->prepare("SELECT hash, MIN(commit_sha) c, MAX(ts) t, MAX(is_current) cur FROM code_refs "
                             . "WHERE path=? GROUP BY hash ORDER BY t DESC");
            $hs->execute(array($path));
            $hist = $hs->fetchAll(PDO::FETCH_ASSOC);

            $head = "<p><a href=''?page=source''>&larr; index</a> &middot; <strong>" . self::esc($path) . "</strong> "
                  . "<span style=''color:#888''>(" . self::esc($blob[''lang'']) . " &middot; " . (int) $blob[''bytes''] . " B &middot; blob " . self::esc(substr($hash, 0, 12)) . ")</span></p>\n";

            $paths = array(); $isCur = false;
            foreach ($refs as $r) { $paths[$r[''path'']] = 1; if ($r[''is_current'']) { $isCur = true; } }
            $ncommits = count($db->query("SELECT commit_sha FROM code_refs WHERE hash=" . $db->quote($hash))->fetchAll());
            $refhtml = "<p style=''font-size:.85em;color:#666''>path: " . implode(", ", array_map(''self::esc'', array_keys($paths)))
                     . " &middot; in " . (int) $ncommits . " commit(s)" . ($isCur ? " &middot; <em>current</em>" : "") . "</p>\n";

            $verhtml = "";
            if (count($hist) > 1) {
                $verhtml = "<p style=''font-size:.85em''>versions of this file: ";
                foreach ($hist as $h) {
                    $sel = ($h[''hash''] === $hash);
                    $lab = self::esc(substr($h[''hash''], 0, 9)) . ($h[''cur''] ? "*" : "");
                    $verhtml .= $sel ? "<strong>$lab</strong> " : "<a href=''?page=source&file=" . self::esc($h[''hash'']) . "''>$lab</a> ";
                }
                $verhtml .= "</p>\n";
            }

            $esc = self::esc($blob[''body'']);
            $lines = explode("\n", $esc);
            $code = "<pre style=''background:#f4f1e8;border:1px solid #d8d2c4;padding:.6rem;overflow:auto;font-size:.82rem;line-height:1.4''>";
            $n = 1;
            foreach ($lines as $ln) {
                $code .= "<span style=''color:#b0a890;user-select:none''>" . sprintf(''%4d'', $n++) . "</span>  " . $ln . "\n";
            }
            $code .= "</pre>\n";

            return $head . $refhtml . $verhtml . $code;
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('24768f95ada95bb28960ea317d22360654909514','php',2753,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * SiteMap — the "list all pages" tag, used as the site navigation.
 *
 * Implements Tag_Interface; invoked as <<<SiteMap>>>. Reads every Document
 * (page) from CONGRUENCY_SQLITE and renders an inline menu of links, so the
 * nav is generated from the pages that actually exist rather than hardcoded.
 * Terminal/internal pages (the order wizard''s tail, the 404) are blocklisted;
 * a small label map keeps the friendly names.
 */
if (!class_exists("SiteMap")) {
    class SiteMap implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<!-- SiteMap: no DB -->"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $have = array();
                foreach ($db->query("SELECT DocumentID FROM Documents")->fetchAll(PDO::FETCH_COLUMN) as $id) { $have[$id] = 1; }

                // home/about/order-wizard dropped from the nav (still reachable via Pages);
                // the nav now leads with Pages (all pages) and Tags (all tags).
                $block = array(''invalid'' => 1, ''thanks'' => 1, ''ticketDone'' => 1, ''tagDone'' => 1, ''order'' => 1,
                               ''catalog'' => 1, ''about'' => 1, ''config'' => 1);
                $label = array(''pages'' => ''Pages'', ''tags'' => ''Tags'', ''bugs'' => ''bug report'',
                               ''source'' => ''Source'', ''docs'' => ''Docs'');
                $order = array(''pages'', ''tags'', ''bugs'', ''forms'', ''tickets'', ''memories'', ''source'', ''docs'');

                $ids = array();
                foreach ($order as $id) { if (isset($have[$id]) && !isset($block[$id])) { $ids[] = $id; unset($have[$id]); } }
                foreach (array_keys($have) as $id) { if (!isset($block[$id])) { $ids[] = $id; } }  // any extras, after

                $links = array();
                foreach ($ids as $id) {
                    $text = isset($label[$id]) ? $label[$id] : $id;
                    $links[] = "<a href=''?page=" . self::esc($id) . "''>" . self::esc($text) . "</a>";
                }
                return implode(" &nbsp;&middot;&nbsp; ", $links);
            } catch (\Throwable $e) {
                return "<!-- SiteMap error: " . self::esc($e->getMessage()) . " -->";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('21644e82cd29def7aa5a3afce389be90af6ce56a','php',6793,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * DocList — the CMS browsing its own documentation (ticket: self-hosting).
 *
 * Admin-only (UserPrivilegeSet::logged_in()). Docs are mirrored into the DB by tools/ingest_self.py,
 * content-addressed by git blob hash: doc_blobs(hash,kind,bytes,body) + doc_refs(hash,path,commit_sha,is_current).
 *   ?page=docs           -> index of the CURRENT docs (doc_refs.is_current=1)
 *   ?page=docs&doc=<hash> -> one doc rendered via a minimal, ESCAPE-FIRST markdown subset (any ''<<<Tag>>>''
 *                            example in the doc stays literal, so the tag engine never re-parses it)
 */
if (!class_exists("DocList")) {
    class DocList implements Tag_Interface {

        const ADMIN_GATED = false;   // TEMP: browse without login while the browser is being finished; set true to re-gate

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string) $s, ENT_QUOTES); }

        private static function gate() {
            if (self::ADMIN_GATED && (!class_exists(''UserPrivilegeSet'') || !UserPrivilegeSet::logged_in())) {
                return "<p><strong>Administrator area.</strong> Please log in to browse the documentation.</p>\n<<<Login>>>";
            }
            return null;
        }

        public function get_document() {
            $deny = self::gate();
            if ($deny !== null) { return $deny; }
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<p>DocList: no DB.</p>"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $hash = isset($_GET[''doc'']) ? trim((string) $_GET[''doc'']) : '''';
                if ($hash !== '''') { return $this->view($db, $hash); }
                return $this->index($db);
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>DocList error: " . self::esc($e->getMessage()) . "</div>";
            }
        }

        private function index($db) {
            $rows = $db->query(
                "SELECT r.path, r.hash, b.kind, b.bytes FROM doc_refs r JOIN doc_blobs b ON b.hash=r.hash "
                . "WHERE r.is_current=1 ORDER BY r.path")->fetchAll(PDO::FETCH_ASSOC);
            $out = "<p>The CMS''s own documentation, addressed by git blob hash.</p>\n<ul class=''doclist''>\n";
            foreach ($rows as $r) {
                $out .= "<li><a href=''?page=docs&doc=" . self::esc($r[''hash'']) . "''>" . self::esc($r[''path'']) . "</a> "
                      . "<span style=''color:#888;font-size:.85em''>" . self::esc($r[''kind'']) . " &middot; " . (int) $r[''bytes''] . " B</span></li>\n";
            }
            return $out . "</ul>\n";
        }

        private function view($db, $hash) {
            $st = $db->prepare("SELECT kind, bytes, body FROM doc_blobs WHERE hash=?");
            $st->execute(array($hash));
            $blob = $st->fetch(PDO::FETCH_ASSOC);
            if (!$blob) { return "<p>No such doc blob <code>" . self::esc($hash) . "</code>. <a href=''?page=docs''>&larr; index</a></p>"; }

            $rs = $db->prepare("SELECT DISTINCT path, is_current FROM doc_refs WHERE hash=? ORDER BY path");
            $rs->execute(array($hash));
            $refs = $rs->fetchAll(PDO::FETCH_ASSOC);
            $path = $refs ? $refs[0][''path''] : '''';

            $hs = $db->prepare("SELECT hash, MAX(ts) t, MAX(is_current) cur FROM doc_refs WHERE path=? GROUP BY hash ORDER BY t DESC");
            $hs->execute(array($path));
            $hist = $hs->fetchAll(PDO::FETCH_ASSOC);

            $head = "<p><a href=''?page=docs''>&larr; index</a> &middot; <strong>" . self::esc($path) . "</strong> "
                  . "<span style=''color:#888''>(blob " . self::esc(substr($hash, 0, 12)) . ")</span></p>\n";
            $verhtml = "";
            if (count($hist) > 1) {
                $verhtml = "<p style=''font-size:.85em''>versions: ";
                foreach ($hist as $h) {
                    $lab = self::esc(substr($h[''hash''], 0, 9)) . ($h[''cur''] ? "*" : "");
                    $verhtml .= ($h[''hash''] === $hash) ? "<strong>$lab</strong> " : "<a href=''?page=docs&doc=" . self::esc($h[''hash'']) . "''>$lab</a> ";
                }
                $verhtml .= "</p>\n";
            }
            $rendered = ($blob[''kind''] === ''markdown'')
                ? self::markdown($blob[''body''])
                : "<pre style=''background:#f4f1e8;padding:.6rem;overflow:auto''>" . self::esc($blob[''body'']) . "</pre>";
            return $head . $verhtml . "<div class=''doc''>\n" . $rendered . "</div>\n";
        }

        /* Minimal markdown subset. ESCAPE FIRST (so HTML and ''<<<Tag>>>'' examples stay literal), then apply:
           #.. -> h1-h6, blank-line paragraphs, ``` / 4-space indent -> <pre><code>, `x` -> <code>, [t](u) -> <a>. */
        private static function markdown($text) {
            $esc = htmlspecialchars((string) $text, ENT_QUOTES);
            $lines = explode("\n", str_replace("\r", "", $esc));
            $out = ""; $para = array(); $inFence = false; $code = "";
            $flush = function () use (&$para, &$out) {
                if ($para) { $out .= "<p>" . implode(" ", $para) . "</p>\n"; $para = array(); }
            };
            foreach ($lines as $ln) {
                if (preg_match(''/^\s*```/'', $ln)) {
                    if (!$inFence) { $flush(); $inFence = true; $code = ""; }
                    else { $out .= "<pre><code>" . $code . "</code></pre>\n"; $inFence = false; }
                    continue;
                }
                if ($inFence) { $code .= $ln . "\n"; continue; }
                if (preg_match(''/^(#{1,6})\s+(.*)$/'', $ln, $m)) {
                    $flush(); $h = strlen($m[1]); $out .= "<h$h>" . self::inline($m[2]) . "</h$h>\n"; continue;
                }
                if (preg_match(''/^    (.*)$/'', $ln, $m)) {          // 4-space indented code line
                    $flush(); $out .= "<pre><code>" . $m[1] . "</code></pre>\n"; continue;
                }
                if (trim($ln) === "") { $flush(); continue; }
                $para[] = self::inline($ln);
            }
            $flush();
            if ($inFence) { $out .= "<pre><code>" . $code . "</code></pre>\n"; }
            return $out;
        }

        private static function inline($s) {
            $s = preg_replace(''/`([^`]+)`/'', ''<code>$1</code>'', $s);
            $s = preg_replace(''/\[([^\]]+)\]\(([^)\s]+)\)/'', ''<a href="$2">$1</a>'', $s);
            return $s;
        }
    }
}
?>
');
