/*
 * SourceList — the CMS browsing its own running source (ticket: self-hosting).
 *
 * Admin-only (UserPrivilegeSet::logged_in()). The source is mirrored into the DB by
 * tools/ingest_self.py on every crank, content-addressed by git blob hash: code_blobs(hash,...)
 * holds deduped content, code_refs(hash,path,commit_sha,is_current) is the reverse lookup.
 *   ?page=source            -> index of the RUNNING source (code_refs.is_current=1), paginated (?p=)
 *   ?page=source&file=<hash> -> one blob: escaped <pre> + line numbers, its path/commit refs, version history
 * Every value is esc()''d — output flows back through execute_all_tags, so any ''<<<...>>>'' in source
 * must stay literal.
 */
if (!class_exists("SourceList")) {
    class SourceList implements Tag_Interface {

        const ADMIN_GATED = false;   // TEMP: browse without login while the browser is being finished; set true to re-gate

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string) $s, ENT_QUOTES); }

        private static function gate() {
            if (self::ADMIN_GATED && (!class_exists(''UserPrivilegeSet'') || !UserPrivilegeSet::logged_in())) {
                return "<p><strong>Administrator area.</strong> Please log in to browse the source.</p>\n<<<Login>>>";
            }
            return null;
        }

        public function get_document() {
            $deny = self::gate();
            if ($deny !== null) { return $deny; }
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<p>SourceList: no DB.</p>"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $flag = (isset($_POST[''flag'']) && isset($_POST[''flag_hash''])) ? $this->doFlag($db) : "";
                $hash = isset($_GET[''file'']) ? trim((string) $_GET[''file'']) : '''';
                if ($hash !== '''') { return $flag . $this->view($db, $hash); }
                return $flag . $this->index($db);
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>SourceList error: " . self::esc($e->getMessage()) . "</div>";
            }
        }

        /* Flag a source blob for follow-up. The abstract backing is an `annotations` row — a `tag` applied
           to an opaque `target` ref ("source:<hash>", and by the same shape "page:<id>", "doc:<hash>",
           "ticket:<id>"), so anything can be tagged with anything (see the #132 unify-tagging idea). A
           `refactor` ticket is then filed as a follow-up projection, linked back to the annotation. */
        private function doFlag($db) {
            $hash = trim((string) $_POST[''flag_hash'']);
            $path = isset($_POST[''flag_path'']) ? trim((string) $_POST[''flag_path'']) : '''';
            $note = isset($_POST[''flag_note'']) ? trim((string) $_POST[''flag_note'']) : '''';
            $now  = microtime(true);

            // 1) abstract backing: tag -> target ref
            $db->exec("CREATE TABLE IF NOT EXISTS annotations (id INTEGER PRIMARY KEY AUTOINCREMENT, tag TEXT, target TEXT, note TEXT, ts REAL, meta TEXT)");
            $an = $db->prepare("INSERT INTO annotations (tag,target,note,ts,meta) VALUES (''flag'',?,?,?,?)");
            $an->execute(array("source:" . $hash, $note, $now, json_encode(array(''path'' => $path))));
            $aid = (int) $db->lastInsertId();

            // 2) follow-up projection into the ticket backlog, linked to the annotation
            $title = "Source flag: " . $path;
            $body  = ($note !== '''' ? $note . "\n\n" : "") . "flagged source blob " . substr($hash, 0, 12) . " \u{00b7} " . $path;
            $meta  = json_encode(array(''source'' => ''source-flag'', ''annotation'' => $aid, ''target'' => "source:" . $hash, ''path'' => $path));
            $st = $db->prepare("INSERT INTO tickets (ts,updated,component,title,severity,status,body,meta) VALUES (?,?,?,?,?,''OPEN'',?,?)");
            $st->execute(array($now, $now, ''refactor'', $title, ''low'', $body, $meta));
            $id = (int) $db->lastInsertId();

            return "<div style=''border:1px solid #1a7a3a;border-left:5px solid #1a7a3a;background:#f3fbf5;padding:.5rem .8rem;margin:.5rem 0''>"
                 . "&#9873; Flagged for follow-up &mdash; annotation <code>flag &rarr; source:" . self::esc(substr($hash, 0, 12))
                 . "</code>, <strong>ticket #" . $id . "</strong> (" . self::esc($path)
                 . "). <a href=''?page=tickets''>see the backlog &rarr;</a></div>\n";
        }

        private function index($db) {
            $rows = $db->query(
                "SELECT r.path, r.hash, b.lang, b.bytes FROM code_refs r JOIN code_blobs b ON b.hash=r.hash "
                . "WHERE r.is_current=1 ORDER BY r.path")->fetchAll(PDO::FETCH_ASSOC);
            $total = count($rows);
            $per = 40; $pages = max(1, (int) ceil($total / $per));
            $pg = isset($_GET[''p'']) ? (int) $_GET[''p''] : 1;
            if ($pg < 1) { $pg = 1; } if ($pg > $pages) { $pg = $pages; }
            $slice = array_slice($rows, ($pg - 1) * $per, $per);

            $pager = "<div class=''pager''>"
                   . ($pg > 1 ? "<a href=''?page=source&p=" . ($pg - 1) . "''>&larr; prev</a>" : "<span>&larr; prev</span>")
                   . " page <strong>$pg</strong> of $pages ($total files) "
                   . ($pg < $pages ? "<a href=''?page=source&p=" . ($pg + 1) . "''>next &rarr;</a>" : "<span>next &rarr;</span>")
                   . "</div>\n";

            $out = "<p>The CMS''s own running source, addressed by git blob hash.</p>\n" . $pager . "<ul class=''srclist''>\n";
            foreach ($slice as $r) {
                $out .= "<li><a href=''?page=source&file=" . self::esc($r[''hash'']) . "''>" . self::esc($r[''path'']) . "</a> "
                      . "<span style=''color:#888;font-size:.85em''>" . self::esc($r[''lang'']) . " &middot; " . (int) $r[''bytes''] . " B</span></li>\n";
            }
            return $out . "</ul>\n" . $pager;
        }

        private function view($db, $hash) {
            $st = $db->prepare("SELECT lang, bytes, body FROM code_blobs WHERE hash=?");
            $st->execute(array($hash));
            $blob = $st->fetch(PDO::FETCH_ASSOC);
            if (!$blob) { return "<p>No such source blob <code>" . self::esc($hash) . "</code>. <a href=''?page=source''>&larr; index</a></p>"; }

            // reverse lookup: which path(s)/commit(s) this blob appeared at
            $rs = $db->prepare("SELECT DISTINCT path, commit_sha, is_current FROM code_refs WHERE hash=? ORDER BY path");
            $rs->execute(array($hash));
            $refs = $rs->fetchAll(PDO::FETCH_ASSOC);
            $path = $refs ? $refs[0][''path''] : '''';

            // version history of that path (all blobs, newest ts first)
            $hs = $db->prepare("SELECT hash, MIN(commit_sha) c, MAX(ts) t, MAX(is_current) cur FROM code_refs "
                             . "WHERE path=? GROUP BY hash ORDER BY t DESC");
            $hs->execute(array($path));
            $hist = $hs->fetchAll(PDO::FETCH_ASSOC);

            $head = "<p><a href=''?page=source''>&larr; index</a> &middot; <strong>" . self::esc($path) . "</strong> "
                  . "<span style=''color:#888''>(" . self::esc($blob[''lang'']) . " &middot; " . (int) $blob[''bytes''] . " B &middot; blob " . self::esc(substr($hash, 0, 12)) . ")</span></p>\n";

            $paths = array(); $isCur = false;
            foreach ($refs as $r) { $paths[$r[''path'']] = 1; if ($r[''is_current'']) { $isCur = true; } }
            $ncommits = count($db->query("SELECT commit_sha FROM code_refs WHERE hash=" . $db->quote($hash))->fetchAll());
            $refhtml = "<p style=''font-size:.85em;color:#666''>path: " . implode(", ", array_map(''self::esc'', array_keys($paths)))
                     . " &middot; in " . (int) $ncommits . " commit(s)" . ($isCur ? " &middot; <em>current</em>" : "") . "</p>\n";

            $verhtml = "";
            if (count($hist) > 1) {
                $verhtml = "<p style=''font-size:.85em''>versions of this file: ";
                foreach ($hist as $h) {
                    $sel = ($h[''hash''] === $hash);
                    $lab = self::esc(substr($h[''hash''], 0, 9)) . ($h[''cur''] ? "*" : "");
                    $verhtml .= $sel ? "<strong>$lab</strong> " : "<a href=''?page=source&file=" . self::esc($h[''hash'']) . "''>$lab</a> ";
                }
                $verhtml .= "</p>\n";
            }

            $esc = self::esc($blob[''body'']);
            $lines = explode("\n", $esc);
            $code = "<pre style=''background:#f4f1e8;border:1px solid #d8d2c4;padding:.6rem;overflow:auto;font-size:.82rem;line-height:1.4''>";
            $n = 1;
            foreach ($lines as $ln) {
                $code .= "<span style=''color:#b0a890;user-select:none''>" . sprintf(''%4d'', $n++) . "</span>  " . $ln . "\n";
            }
            $code .= "</pre>\n";

            $flagForm = "<form method=''POST'' style=''margin:.5rem 0;font-size:.9rem''>"
                . "<input type=''hidden'' name=''flag_hash'' value=''" . self::esc($hash) . "''>"
                . "<input type=''hidden'' name=''flag_path'' value=''" . self::esc($path) . "''>"
                . "<input type=''text'' name=''flag_note'' placeholder=''why flag this? (optional)'' style=''width:55%''> "
                . "<input type=''submit'' name=''flag'' value=''&#9873; flag for follow-up''></form>\n";

            return $head . $refhtml . $verhtml . $flagForm . $code;
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('aa3e587dab97f5b7bf91c7a830f8d4b72619854e','python',12840,'#!/usr/bin/env python3
"""ingest_self.py -- mirror the running source + docs into the CMS DB, content-addressed by git blob hash.

On each crank (post-commit) this pushes the running source into the CMS DB (CONGRUENCY_SQLITE, the unified
~/.jazz/congruency.sqlite) so the CMS can render its own source and documentation. Content is deduped by
git blob hash; a reverse-lookup (path @ commit) names each blob and gives every file its version history;
`is_current=1` flags the blob for each path in the checked-out HEAD tree = the RUNNING source. Code and
docs live in separate tables.

    python3 tools/ingest_self.py             # --head (default): ingest the HEAD tree + re-flag current
    python3 tools/ingest_self.py --backfill  # walk source history into the archive, then flag current
    python3 tools/ingest_self.py --stats     # print row counts
    python3 tools/ingest_self.py --ensure-pages  # create tables + the source/docs entry Documents

Registry-gated, python-only, best-effort (never blocks a commit); Variant-A bug report on exception.
"""
import argparse
import json
import os
import sqlite3
import subprocess
import sys
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None   # repo root (dir of registry.json); set in main()

CODE_EXT = (".php", ".py")
DOC_EXT = (".md", ".txt")
DOC_TXT_PREFIXES = ("checkouts/current/doc/",)   # .txt is a doc ONLY here (legacy 2006 CMS docs) — not stray prompts/cookie jars
IGNORE_SUBSTR = ("tooling/congruencey/", "tooling/tournament-", "/vendor/", "/node_modules/")
CODE_PREFIXES = (
    "checkouts/current/lib/", "checkouts/current/invocators/", "checkouts/current/boot/",
    "checkouts/current/www/", "checkouts/current/bin/",
    "checkouts/current/tools/", "checkouts/current/versioning/", "tracker/",
)
MAIN_EXTRAS = ("deploy.py", "install.py")            # deploy/stand-up-teardown tooling (lives on `main`)
LANG = {".php": "php", ".py": "python", ".md": "markdown", ".txt": "text"}

DDL = [
    "CREATE TABLE IF NOT EXISTS code_blobs (hash TEXT PRIMARY KEY, lang TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS code_refs  (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_code_refs ON code_refs(hash, path, commit_sha)",
    "CREATE TABLE IF NOT EXISTS doc_blobs  (hash TEXT PRIMARY KEY, kind TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS doc_refs   (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_doc_refs ON doc_refs(hash, path, commit_sha)",
]


# ------------------------------------------------------------------ registry / db
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def bug_report(reg, exc, tb, note="ingest_self"):
    root = (reg or {}).get("__root__") or ROOT or HERE
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {"filename": os.path.basename(__file__), "function": last.name if last else "?",
             "time-of-occurance": datetime.now().isoformat(),
             "methods-to-reproduce": "python3 tools/ingest_self.py " + " ".join(sys.argv[1:]),
             "possible-cause": "%s: %s" % (type(exc).__name__, exc),
             "traceback": tb.strip().splitlines()[-6:], "note": note}
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        open(path, "a").write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def db_path(reg):
    """The CMS DB the app reads: install.json''s CONGRUENCY_SQLITE, else the jazz default."""
    cfg = os.path.join(reg["__root__"], "checkouts", "current", "install.json")
    try:
        j = json.load(open(cfg))
        if j.get("CONGRUENCY_SQLITE"):
            return os.path.expanduser(j["CONGRUENCY_SQLITE"])
    except Exception:  # noqa: BLE001
        pass
    return os.path.join(os.path.expanduser("~"), ".jazz", "congruency.sqlite")


# ------------------------------------------------------------------ git
def git(*args):
    return subprocess.run(["git"] + list(args), cwd=ROOT, capture_output=True, text=True)


def resolve(ref):
    return git("rev-parse", ref).stdout.strip()


def ls_tree(ref):
    for line in git("ls-tree", "-r", ref).stdout.splitlines():
        meta, _, path = line.partition("\t")          # "<mode> blob <hash>\t<path>"
        parts = meta.split()
        if len(parts) == 3 and parts[1] == "blob":
            yield parts[2], path


def blob_body(h):
    r = git("cat-file", "blob", h)
    return r.stdout if r.returncode == 0 else ""


# ------------------------------------------------------------------ classify / write
def in_scope(path):
    if any(s in path for s in IGNORE_SUBSTR):
        return None
    ext = os.path.splitext(path)[1]
    if ext in CODE_EXT and any(path.startswith(p) for p in CODE_PREFIXES):
        return "code"
    if ext == ".md":
        return "doc"
    # .txt ONLY from the doc dir (the legacy 2006 CMS docs) — NOT stray prompts / cookie jars (e.g. wiz.txt)
    if ext == ".txt" and any(path.startswith(p) for p in DOC_TXT_PREFIXES):
        return "doc"
    return None


def have_blob(db, domain, h):
    tbl = "code_blobs" if domain == "code" else "doc_blobs"
    return db.execute("SELECT 1 FROM %s WHERE hash=?" % tbl, (h,)).fetchone() is not None


def store_blob(db, domain, h, path, body):
    lang = LANG.get(os.path.splitext(path)[1], "text")
    nbytes = len(body.encode("utf-8", "replace"))
    if domain == "code":
        db.execute("INSERT OR IGNORE INTO code_blobs(hash,lang,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))
    else:
        db.execute("INSERT OR IGNORE INTO doc_blobs(hash,kind,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))


def add_ref(db, domain, h, path, commit_sha, ts):
    tbl = "code_refs" if domain == "code" else "doc_refs"
    db.execute("INSERT OR IGNORE INTO %s(hash,path,commit_sha,ts,is_current) VALUES(?,?,?,?,0)" % tbl,
               (h, path, commit_sha, ts))


def ingest_ref(db, ref, ts, main_extras=True):
    """Ingest every in-scope blob at `ref`; return [(domain, path, hash)] for current-flagging."""
    sha = resolve(ref)
    seen = []
    for h, path in ls_tree(ref):
        dom = in_scope(path)
        if not dom:
            continue
        if not have_blob(db, dom, h):
            store_blob(db, dom, h, path, blob_body(h))
        add_ref(db, dom, h, path, sha, ts)
        seen.append((dom, path, h, sha))
    if main_extras:
        main_sha = resolve("main")
        for name in MAIN_EXTRAS:
            r = git("ls-tree", "main", "--", name)
            parts = r.stdout.split()
            if r.returncode == 0 and len(parts) >= 3 and parts[1] == "blob":
                h, path = parts[2], "main:" + name
                if not have_blob(db, "code", h):
                    store_blob(db, "code", h, path, blob_body(h))
                add_ref(db, "code", h, path, main_sha, ts)
                seen.append(("code", path, h, main_sha))
    return seen


def reflag_current(db, seen):
    db.execute("UPDATE code_refs SET is_current=0")
    db.execute("UPDATE doc_refs  SET is_current=0")
    for dom, path, h, csha in seen:
        tbl = "code_refs" if dom == "code" else "doc_refs"
        db.execute("UPDATE %s SET is_current=1 WHERE hash=? AND path=? AND commit_sha=?" % tbl, (h, path, csha))


def ensure_pages(db):
    """Create the two entry-page Documents (source, docs) in the live DB if absent (idempotent)."""
    def next_tid():
        row = db.execute("SELECT COALESCE(MAX(TemplateID),0)+1 FROM Document_Templates").fetchone()
        return row[0] if row else 1
    style = "body{font-family:Georgia,serif;max-width:900px;margin:2.5rem auto;padding:0 1rem;line-height:1.5;color:#222;background:#f7f4ee}a{color:#8a5a1a}h1{font-weight:normal}code,pre{background:#eae5d8}pre{padding:.6rem;overflow:auto}"
    nav = "<nav style=''margin:0 0 1.5rem;padding-bottom:.5rem;border-bottom:1px solid #ccc''><<<SiteMap>>></nav>"
    pages = {
        "source": ("Source · Congruency", "The CMS''s own running source (admin)", "<<<SourceList>>>"),
        "docs":   ("Documentation · Congruency", "The CMS''s own documentation (admin)", "<<<DocList>>>"),
    }
    for did, (title, desc, tag) in pages.items():
        if db.execute("SELECT 1 FROM Documents WHERE DocumentID=?", (did,)).fetchone():
            continue
        tid = next_tid()
        body = "<!DOCTYPE html><html><head> <title><<<TitleTag>>></title> <style>%s</style> </head> <body> %s <h1>%s</h1> %s </body></html>" % (style, nav, title, tag)
        db.execute("INSERT INTO Document_Templates(TemplateID, Content) VALUES(?,?)", (tid, body))
        db.execute("INSERT INTO Documents(DocumentID, TemplateID, Title, Description, ContentID) VALUES(?,?,?,?,?)",
                   (did, tid, title, desc, tid))


def stats(db):
    for t in ("code_blobs", "code_refs", "doc_blobs", "doc_refs"):
        try:
            n = db.execute("SELECT COUNT(*) FROM %s" % t).fetchone()[0]
        except sqlite3.Error:
            n = "-"
        cur = ""
        if t.endswith("_refs"):
            c = db.execute("SELECT COUNT(*) FROM %s WHERE is_current=1" % t).fetchone()[0]
            cur = "  (current: %d)" % c
        print("  %-11s %s%s" % (t, n, cur))


# ------------------------------------------------------------------ main
def main():
    global ROOT
    ap = argparse.ArgumentParser(description="mirror the running source + docs into the CMS DB (content-addressed)")
    ap.add_argument("--head", action="store_true", help="ingest the HEAD tree + re-flag current (default)")
    ap.add_argument("--backfill", action="store_true", help="walk source history into the archive")
    ap.add_argument("--ensure-pages", action="store_true", help="create tables + the source/docs entry Documents")
    ap.add_argument("--stats", action="store_true", help="print row counts and exit")
    a = ap.parse_args()

    reg = load_registry()
    ROOT = reg["__root__"]
    db = sqlite3.connect(db_path(reg), timeout=15)
    try:
        for stmt in DDL:
            db.execute(stmt)

        if a.stats:
            stats(db)
            return 0

        if a.ensure_pages:
            ensure_pages(db)
            db.commit()
            print("ensure-pages: source/docs Documents ensured; tables created")
            return 0

        try:
            ensure_pages(db)   # self-healing: the source/docs entry Documents exist (idempotent)
        except Exception:  # noqa: BLE001  (a bare/fresh DB without the CMS Documents table)
            pass

        if a.backfill:
            seen_hashes_before = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0]
            for line in git("rev-list", "--timestamp", "source").stdout.splitlines():
                parts = line.split()
                if len(parts) != 2:
                    continue
                ts, sha = float(parts[0]), parts[1]
                ingest_ref(db, sha, ts, main_extras=False)
            # current main extras + flag HEAD as running source
            seen = ingest_ref(db, "HEAD", float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0), main_extras=True)
            reflag_current(db, seen)
            db.commit()
            added = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0] - seen_hashes_before
            print("backfill: walked source history (+%d new code blobs)" % added)
            stats(db)
            return 0

        # default: --head
        ts = float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0)
        seen = ingest_ref(db, "HEAD", ts, main_extras=True)
        reflag_current(db, seen)
        db.commit()
        print("ingest_self: HEAD tree mirrored (%d in-scope files); running source flagged" % len(seen))
        return 0
    finally:
        db.close()


if __name__ == "__main__":
    try:
        sys.exit(main())
    except Exception as e:  # noqa: BLE001  -- best-effort: never crash a commit hook
        try:
            reg = load_registry()
        except Exception:  # noqa: BLE001
            reg = None
        bug_report(reg, e, traceback.format_exc())
        sys.stderr.write("[ingest_self] %r\n" % e)
        sys.exit(0)
');
INSERT INTO "code_blobs" VALUES('a9364b51f31ba28ce5d894de6ff79e7ab163d988','php',3396,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * CategoryPages — browse pages by category (the page-tagging layer).
 *
 * Invoked as <<<CategoryPages(specifications)>>>. Resolves the category name to
 * its Categories.key, then lists every Document linked to it via the
 * Page_Categories join table, as hyperlinks. With no argument it lists all
 * categories and how many pages each holds.
 */
if (!class_exists("CategoryPages")) {
    class CategoryPages implements Tag_Interface {

        private $category;
        public function __construct($arguments) {
            $this->category = (isset($arguments) && method_exists($arguments, ''top'')) ? $arguments->top() : '''';
        }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        private function db() {
            $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
            $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            return $db;
        }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<p>CategoryPages: no DB.</p>"; }
                $db = $this->db();
                // category comes from the tag argument, else the ?category= URL param (clickable index)
                $cat = trim((string)$this->category);
                if ($cat === '''' && isset($_GET[''category''])) { $cat = trim((string)$_GET[''category'']); }

                if ($cat === '''') {   // no arg -> index of all categories with page counts
                    $rows = $db->query("SELECT c.name, c.description, COUNT(a.id) AS n
                        FROM Categories c LEFT JOIN annotations a ON a.tag=c.name AND a.target LIKE ''page:%''
                        GROUP BY c.`key` ORDER BY c.name")->fetchAll(PDO::FETCH_ASSOC);
                    $out = "<ul>";
                    foreach ($rows as $r) {
                        $out .= "<li><a href=''?page=pages&category=" . self::esc($r[''name'']) . "''>" . self::esc($r[''name''])
                              . "</a> (" . (int)$r[''n''] . ")" . ($r[''description''] ? " &mdash; " . self::esc($r[''description'']) : "") . "</li>";
                    }
                    return $out . "</ul>";
                }

                $st = $db->prepare("SELECT d.DocumentID, d.Title FROM annotations a
                    JOIN Documents d ON d.DocumentID=substr(a.target, 6)
                    WHERE a.tag=? AND a.target LIKE ''page:%'' ORDER BY d.DocumentID");
                $st->execute(array($cat));
                $rows = $st->fetchAll(PDO::FETCH_ASSOC);
                if (!$rows) { return "<p>No pages tagged <code>" . self::esc($cat) . "</code> yet.</p>"; }
                $out = "<ul>";
                foreach ($rows as $r) {
                    $title = ($r[''Title''] !== null && $r[''Title''] !== '''') ? $r[''Title''] : $r[''DocumentID''];
                    $out .= "<li><a href=''?page=" . self::esc($r[''DocumentID'']) . "''>" . self::esc($title) . "</a></li>";
                }
                return $out . "</ul>";
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>CategoryPages error: " . self::esc(get_class($e) . '': '' . $e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('5c2c55224cfe70ac3d82b539b7d1dc9fd6763fe8','php',3925,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * TagPageHandler — file a page->category tag (the handler for TagPageForm).
 *
 * Modeled on TicketLogger: on ?page=tagDone it reads the completed TagPageForm
 * results (pageId, category) via FORM_MANAGER, validates both against the DB,
 * and inserts a row into Page_Categories. Idempotent (INSERT OR IGNORE) and
 * self-consuming (resets the form) so a refresh can''t double-file.
 */
if (!class_exists("TagPageHandler")) {
    class TagPageHandler implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }
        private static function back() { return "<p><a href=''?page=pages''>&larr; back to tag a page</a></p>"; }

        public function get_document() {
            try {
                $fm = PersistentObjectManager::getData(''FORM_MANAGER'');
                $res = isset($fm) ? $fm->getResults(''TagPageForm'') : null;
                $pageId   = isset($res[''pageId''])   ? trim((string)$res[''pageId''])   : '''';
                $category = isset($res[''category'']) ? trim((string)$res[''category'']) : '''';

                if ($pageId === '''' && $category === '''') {
                    return "<p>No pending page tag. <a href=''?page=pages''>Tag a page &rarr;</a></p>";
                }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

                $st = $db->prepare("SELECT 1 FROM Documents WHERE DocumentID=?");
                $st->execute(array($pageId));
                if (!$st->fetch()) { return "<p style=''color:#b00020''>No such page: <code>" . self::esc($pageId) . "</code></p>" . self::back(); }

                $st = $db->prepare("SELECT `key` FROM Categories WHERE name=?");
                $st->execute(array($category));
                if (!$st->fetch()) { return "<p style=''color:#b00020''>No such category: <code>" . self::esc($category) . "</code></p>" . self::back(); }

                // page-tagging is now an annotation: tag=<category name>, target="page:<DocumentID>"
                $target = ''page:'' . $pageId;
                $chk = $db->prepare("SELECT 1 FROM annotations WHERE tag=? AND target=?");
                $chk->execute(array($category, $target));
                $added = false;
                if (!$chk->fetch()) {
                    $ins = $db->prepare("INSERT INTO annotations (tag,target,note,ts,meta) VALUES (?,?,'''',?,?)");
                    $ins->execute(array($category, $target, microtime(true), json_encode(array(''kind'' => ''category''))));
                    $added = true;
                }

                if (isset($fm)) { $f = $fm->getCachedForm(''TagPageForm''); if (isset($f)) { $f->setResults(array()); $f->reset(); } }

                $msg = $added
                    ? "Tagged page <code>" . self::esc($pageId) . "</code> as <code>" . self::esc($category) . "</code>."
                    : "Page <code>" . self::esc($pageId) . "</code> was already tagged <code>" . self::esc($category) . "</code>.";
                return "<div style=''border:1px solid #1a7a3a;border-left:5px solid #1a7a3a;border-radius:6px;padding:.7rem .9rem;background:#f3fbf5''>"
                     . "<p style=''margin:.2rem 0''><strong>" . $msg . "</strong></p></div>\n"
                     . "<p><a href=''?page=pages&category=" . self::esc($category) . "''>&rarr; see pages in " . self::esc($category) . "</a></p>";
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>TagPageHandler error: " . self::esc(get_class($e) . '': '' . $e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('a9a807c78339cca37075ed652befbcf66339b675','python',13108,'#!/usr/bin/env python3
"""ingest_self.py -- mirror the running source + docs into the CMS DB, content-addressed by git blob hash.

On each crank (post-commit) this pushes the running source into the CMS DB (CONGRUENCY_SQLITE, the unified
~/.jazz/congruency.sqlite) so the CMS can render its own source and documentation. Content is deduped by
git blob hash; a reverse-lookup (path @ commit) names each blob and gives every file its version history;
`is_current=1` flags the blob for each path in the checked-out HEAD tree = the RUNNING source. Code and
docs live in separate tables.

    python3 tools/ingest_self.py             # --head (default): ingest the HEAD tree + re-flag current
    python3 tools/ingest_self.py --backfill  # walk source history into the archive, then flag current
    python3 tools/ingest_self.py --stats     # print row counts
    python3 tools/ingest_self.py --ensure-pages  # create tables + the source/docs entry Documents

Registry-gated, python-only, best-effort (never blocks a commit); Variant-A bug report on exception.
"""
import argparse
import json
import os
import sqlite3
import subprocess
import sys
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None   # repo root (dir of registry.json); set in main()

CODE_EXT = (".php", ".py")
DOC_EXT = (".md", ".txt")
DOC_TXT_PREFIXES = ("checkouts/current/doc/",)   # .txt is a doc ONLY here (legacy 2006 CMS docs) — not stray prompts/cookie jars
IGNORE_SUBSTR = ("tooling/congruencey/", "tooling/tournament-", "/vendor/", "/node_modules/")
CODE_PREFIXES = (
    "checkouts/current/lib/", "checkouts/current/invocators/", "checkouts/current/boot/",
    "checkouts/current/www/", "checkouts/current/bin/",
    "checkouts/current/tools/", "checkouts/current/versioning/", "tracker/",
)
MAIN_EXTRAS = ("deploy.py", "install.py")            # deploy/stand-up-teardown tooling (lives on `main`)
LANG = {".php": "php", ".py": "python", ".md": "markdown", ".txt": "text"}

DDL = [
    "CREATE TABLE IF NOT EXISTS code_blobs (hash TEXT PRIMARY KEY, lang TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS code_refs  (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_code_refs ON code_refs(hash, path, commit_sha)",
    "CREATE TABLE IF NOT EXISTS doc_blobs  (hash TEXT PRIMARY KEY, kind TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS doc_refs   (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    # abstract tagging: a `tag` applied to an opaque `target` ref ("source:<hash>" / "page:<id>" / "doc:<hash>" / "ticket:<id>")
    "CREATE TABLE IF NOT EXISTS annotations (id INTEGER PRIMARY KEY AUTOINCREMENT, tag TEXT, target TEXT, note TEXT, ts REAL, meta TEXT)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_doc_refs ON doc_refs(hash, path, commit_sha)",
]


# ------------------------------------------------------------------ registry / db
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def bug_report(reg, exc, tb, note="ingest_self"):
    root = (reg or {}).get("__root__") or ROOT or HERE
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {"filename": os.path.basename(__file__), "function": last.name if last else "?",
             "time-of-occurance": datetime.now().isoformat(),
             "methods-to-reproduce": "python3 tools/ingest_self.py " + " ".join(sys.argv[1:]),
             "possible-cause": "%s: %s" % (type(exc).__name__, exc),
             "traceback": tb.strip().splitlines()[-6:], "note": note}
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        open(path, "a").write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def db_path(reg):
    """The CMS DB the app reads: install.json''s CONGRUENCY_SQLITE, else the jazz default."""
    cfg = os.path.join(reg["__root__"], "checkouts", "current", "install.json")
    try:
        j = json.load(open(cfg))
        if j.get("CONGRUENCY_SQLITE"):
            return os.path.expanduser(j["CONGRUENCY_SQLITE"])
    except Exception:  # noqa: BLE001
        pass
    return os.path.join(os.path.expanduser("~"), ".jazz", "congruency.sqlite")


# ------------------------------------------------------------------ git
def git(*args):
    return subprocess.run(["git"] + list(args), cwd=ROOT, capture_output=True, text=True)


def resolve(ref):
    return git("rev-parse", ref).stdout.strip()


def ls_tree(ref):
    for line in git("ls-tree", "-r", ref).stdout.splitlines():
        meta, _, path = line.partition("\t")          # "<mode> blob <hash>\t<path>"
        parts = meta.split()
        if len(parts) == 3 and parts[1] == "blob":
            yield parts[2], path


def blob_body(h):
    r = git("cat-file", "blob", h)
    return r.stdout if r.returncode == 0 else ""


# ------------------------------------------------------------------ classify / write
def in_scope(path):
    if any(s in path for s in IGNORE_SUBSTR):
        return None
    ext = os.path.splitext(path)[1]
    if ext in CODE_EXT and any(path.startswith(p) for p in CODE_PREFIXES):
        return "code"
    if ext == ".md":
        return "doc"
    # .txt ONLY from the doc dir (the legacy 2006 CMS docs) — NOT stray prompts / cookie jars (e.g. wiz.txt)
    if ext == ".txt" and any(path.startswith(p) for p in DOC_TXT_PREFIXES):
        return "doc"
    return None


def have_blob(db, domain, h):
    tbl = "code_blobs" if domain == "code" else "doc_blobs"
    return db.execute("SELECT 1 FROM %s WHERE hash=?" % tbl, (h,)).fetchone() is not None


def store_blob(db, domain, h, path, body):
    lang = LANG.get(os.path.splitext(path)[1], "text")
    nbytes = len(body.encode("utf-8", "replace"))
    if domain == "code":
        db.execute("INSERT OR IGNORE INTO code_blobs(hash,lang,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))
    else:
        db.execute("INSERT OR IGNORE INTO doc_blobs(hash,kind,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))


def add_ref(db, domain, h, path, commit_sha, ts):
    tbl = "code_refs" if domain == "code" else "doc_refs"
    db.execute("INSERT OR IGNORE INTO %s(hash,path,commit_sha,ts,is_current) VALUES(?,?,?,?,0)" % tbl,
               (h, path, commit_sha, ts))


def ingest_ref(db, ref, ts, main_extras=True):
    """Ingest every in-scope blob at `ref`; return [(domain, path, hash)] for current-flagging."""
    sha = resolve(ref)
    seen = []
    for h, path in ls_tree(ref):
        dom = in_scope(path)
        if not dom:
            continue
        if not have_blob(db, dom, h):
            store_blob(db, dom, h, path, blob_body(h))
        add_ref(db, dom, h, path, sha, ts)
        seen.append((dom, path, h, sha))
    if main_extras:
        main_sha = resolve("main")
        for name in MAIN_EXTRAS:
            r = git("ls-tree", "main", "--", name)
            parts = r.stdout.split()
            if r.returncode == 0 and len(parts) >= 3 and parts[1] == "blob":
                h, path = parts[2], "main:" + name
                if not have_blob(db, "code", h):
                    store_blob(db, "code", h, path, blob_body(h))
                add_ref(db, "code", h, path, main_sha, ts)
                seen.append(("code", path, h, main_sha))
    return seen


def reflag_current(db, seen):
    db.execute("UPDATE code_refs SET is_current=0")
    db.execute("UPDATE doc_refs  SET is_current=0")
    for dom, path, h, csha in seen:
        tbl = "code_refs" if dom == "code" else "doc_refs"
        db.execute("UPDATE %s SET is_current=1 WHERE hash=? AND path=? AND commit_sha=?" % tbl, (h, path, csha))


def ensure_pages(db):
    """Create the two entry-page Documents (source, docs) in the live DB if absent (idempotent)."""
    def next_tid():
        row = db.execute("SELECT COALESCE(MAX(TemplateID),0)+1 FROM Document_Templates").fetchone()
        return row[0] if row else 1
    style = "body{font-family:Georgia,serif;max-width:900px;margin:2.5rem auto;padding:0 1rem;line-height:1.5;color:#222;background:#f7f4ee}a{color:#8a5a1a}h1{font-weight:normal}code,pre{background:#eae5d8}pre{padding:.6rem;overflow:auto}"
    nav = "<nav style=''margin:0 0 1.5rem;padding-bottom:.5rem;border-bottom:1px solid #ccc''><<<SiteMap>>></nav>"
    pages = {
        "source": ("Source · Congruency", "The CMS''s own running source (admin)", "<<<SourceList>>>"),
        "docs":   ("Documentation · Congruency", "The CMS''s own documentation (admin)", "<<<DocList>>>"),
    }
    for did, (title, desc, tag) in pages.items():
        if db.execute("SELECT 1 FROM Documents WHERE DocumentID=?", (did,)).fetchone():
            continue
        tid = next_tid()
        body = "<!DOCTYPE html><html><head> <title><<<TitleTag>>></title> <style>%s</style> </head> <body> %s <h1>%s</h1> %s </body></html>" % (style, nav, title, tag)
        db.execute("INSERT INTO Document_Templates(TemplateID, Content) VALUES(?,?)", (tid, body))
        db.execute("INSERT INTO Documents(DocumentID, TemplateID, Title, Description, ContentID) VALUES(?,?,?,?,?)",
                   (did, tid, title, desc, tid))


def stats(db):
    for t in ("code_blobs", "code_refs", "doc_blobs", "doc_refs"):
        try:
            n = db.execute("SELECT COUNT(*) FROM %s" % t).fetchone()[0]
        except sqlite3.Error:
            n = "-"
        cur = ""
        if t.endswith("_refs"):
            c = db.execute("SELECT COUNT(*) FROM %s WHERE is_current=1" % t).fetchone()[0]
            cur = "  (current: %d)" % c
        print("  %-11s %s%s" % (t, n, cur))


# ------------------------------------------------------------------ main
def main():
    global ROOT
    ap = argparse.ArgumentParser(description="mirror the running source + docs into the CMS DB (content-addressed)")
    ap.add_argument("--head", action="store_true", help="ingest the HEAD tree + re-flag current (default)")
    ap.add_argument("--backfill", action="store_true", help="walk source history into the archive")
    ap.add_argument("--ensure-pages", action="store_true", help="create tables + the source/docs entry Documents")
    ap.add_argument("--stats", action="store_true", help="print row counts and exit")
    a = ap.parse_args()

    reg = load_registry()
    ROOT = reg["__root__"]
    db = sqlite3.connect(db_path(reg), timeout=15)
    try:
        for stmt in DDL:
            db.execute(stmt)

        if a.stats:
            stats(db)
            return 0

        if a.ensure_pages:
            ensure_pages(db)
            db.commit()
            print("ensure-pages: source/docs Documents ensured; tables created")
            return 0

        try:
            ensure_pages(db)   # self-healing: the source/docs entry Documents exist (idempotent)
        except Exception:  # noqa: BLE001  (a bare/fresh DB without the CMS Documents table)
            pass

        if a.backfill:
            seen_hashes_before = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0]
            for line in git("rev-list", "--timestamp", "source").stdout.splitlines():
                parts = line.split()
                if len(parts) != 2:
                    continue
                ts, sha = float(parts[0]), parts[1]
                ingest_ref(db, sha, ts, main_extras=False)
            # current main extras + flag HEAD as running source
            seen = ingest_ref(db, "HEAD", float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0), main_extras=True)
            reflag_current(db, seen)
            db.commit()
            added = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0] - seen_hashes_before
            print("backfill: walked source history (+%d new code blobs)" % added)
            stats(db)
            return 0

        # default: --head
        ts = float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0)
        seen = ingest_ref(db, "HEAD", ts, main_extras=True)
        reflag_current(db, seen)
        db.commit()
        print("ingest_self: HEAD tree mirrored (%d in-scope files); running source flagged" % len(seen))
        return 0
    finally:
        db.close()


if __name__ == "__main__":
    try:
        sys.exit(main())
    except Exception as e:  # noqa: BLE001  -- best-effort: never crash a commit hook
        try:
            reg = load_registry()
        except Exception:  # noqa: BLE001
            reg = None
        bug_report(reg, e, traceback.format_exc())
        sys.stderr.write("[ingest_self] %r\n" % e)
        sys.exit(0)
');
INSERT INTO "code_blobs" VALUES('49cda5b1a041fd1a5b054ec196135d4aaf79bfb7','php',5477,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * Annotations — one browse view over the abstract tag->target layer.
 *
 * The `annotations` table is the unified tagging model: a `tag` applied to an opaque `target` ref
 * ("source:<hash>", "page:<DocumentID>", "doc:<hash>", "ticket:<id>"). Source `flag`s and page
 * categories both live here. This tag renders them all, with a tag/kind filter bar; each target is
 * linked back to wherever it lives.
 *   ?page=annotations             -> everything, newest first
 *   ?page=annotations&tag=flag    -> one tag
 *   ?page=annotations&kind=page   -> one target-kind (source|page|doc|ticket)
 */
if (!class_exists("Annotations")) {
    class Annotations implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string) $s, ENT_QUOTES); }

        private static function target_link($target) {
            $pos = strpos((string) $target, '':'');
            if ($pos === false) { return self::esc($target); }
            $kind = substr($target, 0, $pos);
            $id   = substr($target, $pos + 1);
            switch ($kind) {
                case ''source'': return "<a href=''?page=source&file=" . self::esc($id) . "''>source: " . self::esc(substr($id, 0, 12)) . "</a>";
                case ''doc'':    return "<a href=''?page=docs&doc=" . self::esc($id) . "''>doc: " . self::esc(substr($id, 0, 12)) . "</a>";
                case ''page'':   return "<a href=''?page=" . self::esc($id) . "''>page: " . self::esc($id) . "</a>";
                case ''ticket'': return "<a href=''?page=tickets''>ticket #" . self::esc($id) . "</a>";
                default:       return self::esc($target);
            }
        }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<p>Annotations: no DB.</p>"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                if (!$db->query("SELECT name FROM sqlite_master WHERE type=''table'' AND name=''annotations''")->fetch()) {
                    return "<p>No annotations yet. Flag a source file on <a href=''?page=source''>Source</a> or tag a page on <a href=''?page=pages''>Pages</a>.</p>";
                }

                $tag  = isset($_GET[''tag''])  ? trim((string) $_GET[''tag''])  : '''';
                $kind = isset($_GET[''kind'']) ? trim((string) $_GET[''kind'']) : '''';

                $tags = $db->query("SELECT tag, COUNT(*) n FROM annotations GROUP BY tag ORDER BY tag")->fetchAll(PDO::FETCH_ASSOC);
                $bar = "<p style=''font-size:.9rem''><strong>tag:</strong> " . ($tag === '''' ? "<strong>all</strong>" : "<a href=''?page=annotations''>all</a>") . " ";
                foreach ($tags as $t) {
                    $lab = self::esc($t[''tag'']) . " (" . (int) $t[''n''] . ")";
                    $bar .= "&middot; " . (($t[''tag''] === $tag) ? "<strong>$lab</strong>" : "<a href=''?page=annotations&tag=" . self::esc($t[''tag'']) . "''>$lab</a>") . " ";
                }
                $bar .= "<br><strong>kind:</strong> " . ($kind === '''' ? "<strong>all</strong>" : "<a href=''?page=annotations''>all</a>") . " ";
                foreach (array(''source'', ''page'', ''doc'', ''ticket'') as $k) {
                    $bar .= "&middot; " . (($k === $kind) ? "<strong>$k</strong>" : "<a href=''?page=annotations&kind=$k''>$k</a>") . " ";
                }
                $bar .= "</p>\n";

                $where = array(); $args = array();
                if ($tag !== '''')  { $where[] = "tag=?";         $args[] = $tag; }
                if ($kind !== '''') { $where[] = "target LIKE ?"; $args[] = $kind . '':%''; }
                $sql = "SELECT tag, target, note, ts FROM annotations" . ($where ? " WHERE " . implode(" AND ", $where) : "") . " ORDER BY ts DESC, id DESC";
                $st = $db->prepare($sql);
                $st->execute($args);
                $rows = $st->fetchAll(PDO::FETCH_ASSOC);
                if (!$rows) { return $bar . "<p>No annotations match that filter.</p>"; }

                $out = $bar . "<table style=''border-collapse:collapse;font-size:.9rem''>\n"
                     . "<tr><th align=''left'' style=''padding-right:1rem''>tag</th><th align=''left'' style=''padding-right:1rem''>target</th>"
                     . "<th align=''left'' style=''padding-right:1rem''>note</th><th align=''left''>when</th></tr>\n";
                foreach ($rows as $r) {
                    $when = $r[''ts''] ? date(''Y-m-d H:i'', (int) $r[''ts'']) : '''';
                    $out .= "<tr><td style=''padding:.15rem 1rem .15rem 0''><code>" . self::esc($r[''tag'']) . "</code></td>"
                          . "<td style=''padding:.15rem 1rem .15rem 0''>" . self::target_link($r[''target'']) . "</td>"
                          . "<td style=''padding:.15rem 1rem .15rem 0''>" . self::esc($r[''note'']) . "</td>"
                          . "<td style=''padding:.15rem 0;color:#888''>" . self::esc($when) . "</td></tr>\n";
                }
                return $out . "</table>\n";
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>Annotations error: " . self::esc($e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('45c7c6f48d397a0bb855b125ca958ee6829f091e','php',2800,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * SiteMap — the "list all pages" tag, used as the site navigation.
 *
 * Implements Tag_Interface; invoked as <<<SiteMap>>>. Reads every Document
 * (page) from CONGRUENCY_SQLITE and renders an inline menu of links, so the
 * nav is generated from the pages that actually exist rather than hardcoded.
 * Terminal/internal pages (the order wizard''s tail, the 404) are blocklisted;
 * a small label map keeps the friendly names.
 */
if (!class_exists("SiteMap")) {
    class SiteMap implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<!-- SiteMap: no DB -->"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $have = array();
                foreach ($db->query("SELECT DocumentID FROM Documents")->fetchAll(PDO::FETCH_COLUMN) as $id) { $have[$id] = 1; }

                // home/about/order-wizard dropped from the nav (still reachable via Pages);
                // the nav now leads with Pages (all pages) and Tags (all tags).
                $block = array(''invalid'' => 1, ''thanks'' => 1, ''ticketDone'' => 1, ''tagDone'' => 1, ''order'' => 1,
                               ''catalog'' => 1, ''about'' => 1, ''config'' => 1);
                $label = array(''pages'' => ''Pages'', ''tags'' => ''Tags'', ''bugs'' => ''bug report'',
                               ''source'' => ''Source'', ''docs'' => ''Docs'', ''annotations'' => ''Annotations'');
                $order = array(''pages'', ''tags'', ''bugs'', ''forms'', ''tickets'', ''memories'', ''source'', ''docs'', ''annotations'');

                $ids = array();
                foreach ($order as $id) { if (isset($have[$id]) && !isset($block[$id])) { $ids[] = $id; unset($have[$id]); } }
                foreach (array_keys($have) as $id) { if (!isset($block[$id])) { $ids[] = $id; } }  // any extras, after

                $links = array();
                foreach ($ids as $id) {
                    $text = isset($label[$id]) ? $label[$id] : $id;
                    $links[] = "<a href=''?page=" . self::esc($id) . "''>" . self::esc($text) . "</a>";
                }
                return implode(" &nbsp;&middot;&nbsp; ", $links);
            } catch (\Throwable $e) {
                return "<!-- SiteMap error: " . self::esc($e->getMessage()) . " -->";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('8e1869ab18cb8435d92ca017b7a25e9f1ab289a4','python',13326,'#!/usr/bin/env python3
"""ingest_self.py -- mirror the running source + docs into the CMS DB, content-addressed by git blob hash.

On each crank (post-commit) this pushes the running source into the CMS DB (CONGRUENCY_SQLITE, the unified
~/.jazz/congruency.sqlite) so the CMS can render its own source and documentation. Content is deduped by
git blob hash; a reverse-lookup (path @ commit) names each blob and gives every file its version history;
`is_current=1` flags the blob for each path in the checked-out HEAD tree = the RUNNING source. Code and
docs live in separate tables.

    python3 tools/ingest_self.py             # --head (default): ingest the HEAD tree + re-flag current
    python3 tools/ingest_self.py --backfill  # walk source history into the archive, then flag current
    python3 tools/ingest_self.py --stats     # print row counts
    python3 tools/ingest_self.py --ensure-pages  # create tables + the source/docs entry Documents

Registry-gated, python-only, best-effort (never blocks a commit); Variant-A bug report on exception.
"""
import argparse
import json
import os
import sqlite3
import subprocess
import sys
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None   # repo root (dir of registry.json); set in main()

CODE_EXT = (".php", ".py")
DOC_EXT = (".md", ".txt")
DOC_TXT_PREFIXES = ("checkouts/current/doc/",)   # .txt is a doc ONLY here (legacy 2006 CMS docs) — not stray prompts/cookie jars
IGNORE_SUBSTR = ("tooling/congruencey/", "tooling/tournament-", "/vendor/", "/node_modules/")
CODE_PREFIXES = (
    "checkouts/current/lib/", "checkouts/current/invocators/", "checkouts/current/boot/",
    "checkouts/current/www/", "checkouts/current/bin/",
    "checkouts/current/tools/", "checkouts/current/versioning/", "tracker/",
)
MAIN_EXTRAS = ("deploy.py", "install.py")            # deploy/stand-up-teardown tooling (lives on `main`)
LANG = {".php": "php", ".py": "python", ".md": "markdown", ".txt": "text"}

DDL = [
    "CREATE TABLE IF NOT EXISTS code_blobs (hash TEXT PRIMARY KEY, lang TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS code_refs  (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_code_refs ON code_refs(hash, path, commit_sha)",
    "CREATE TABLE IF NOT EXISTS doc_blobs  (hash TEXT PRIMARY KEY, kind TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS doc_refs   (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    # abstract tagging: a `tag` applied to an opaque `target` ref ("source:<hash>" / "page:<id>" / "doc:<hash>" / "ticket:<id>")
    "CREATE TABLE IF NOT EXISTS annotations (id INTEGER PRIMARY KEY AUTOINCREMENT, tag TEXT, target TEXT, note TEXT, ts REAL, meta TEXT)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_doc_refs ON doc_refs(hash, path, commit_sha)",
]


# ------------------------------------------------------------------ registry / db
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def bug_report(reg, exc, tb, note="ingest_self"):
    root = (reg or {}).get("__root__") or ROOT or HERE
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {"filename": os.path.basename(__file__), "function": last.name if last else "?",
             "time-of-occurance": datetime.now().isoformat(),
             "methods-to-reproduce": "python3 tools/ingest_self.py " + " ".join(sys.argv[1:]),
             "possible-cause": "%s: %s" % (type(exc).__name__, exc),
             "traceback": tb.strip().splitlines()[-6:], "note": note}
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        open(path, "a").write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def db_path(reg):
    """The CMS DB the app reads: install.json''s CONGRUENCY_SQLITE, else the jazz default."""
    cfg = os.path.join(reg["__root__"], "checkouts", "current", "install.json")
    try:
        j = json.load(open(cfg))
        if j.get("CONGRUENCY_SQLITE"):
            return os.path.expanduser(j["CONGRUENCY_SQLITE"])
    except Exception:  # noqa: BLE001
        pass
    return os.path.join(os.path.expanduser("~"), ".jazz", "congruency.sqlite")


# ------------------------------------------------------------------ git
def git(*args):
    return subprocess.run(["git"] + list(args), cwd=ROOT, capture_output=True, text=True)


def resolve(ref):
    return git("rev-parse", ref).stdout.strip()


def ls_tree(ref):
    for line in git("ls-tree", "-r", ref).stdout.splitlines():
        meta, _, path = line.partition("\t")          # "<mode> blob <hash>\t<path>"
        parts = meta.split()
        if len(parts) == 3 and parts[1] == "blob":
            yield parts[2], path


def blob_body(h):
    r = git("cat-file", "blob", h)
    return r.stdout if r.returncode == 0 else ""


# ------------------------------------------------------------------ classify / write
def in_scope(path):
    if any(s in path for s in IGNORE_SUBSTR):
        return None
    ext = os.path.splitext(path)[1]
    if ext in CODE_EXT and any(path.startswith(p) for p in CODE_PREFIXES):
        return "code"
    if ext == ".md":
        return "doc"
    # .txt ONLY from the doc dir (the legacy 2006 CMS docs) — NOT stray prompts / cookie jars (e.g. wiz.txt)
    if ext == ".txt" and any(path.startswith(p) for p in DOC_TXT_PREFIXES):
        return "doc"
    return None


def have_blob(db, domain, h):
    tbl = "code_blobs" if domain == "code" else "doc_blobs"
    return db.execute("SELECT 1 FROM %s WHERE hash=?" % tbl, (h,)).fetchone() is not None


def store_blob(db, domain, h, path, body):
    lang = LANG.get(os.path.splitext(path)[1], "text")
    nbytes = len(body.encode("utf-8", "replace"))
    if domain == "code":
        db.execute("INSERT OR IGNORE INTO code_blobs(hash,lang,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))
    else:
        db.execute("INSERT OR IGNORE INTO doc_blobs(hash,kind,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))


def add_ref(db, domain, h, path, commit_sha, ts):
    tbl = "code_refs" if domain == "code" else "doc_refs"
    db.execute("INSERT OR IGNORE INTO %s(hash,path,commit_sha,ts,is_current) VALUES(?,?,?,?,0)" % tbl,
               (h, path, commit_sha, ts))


def ingest_ref(db, ref, ts, main_extras=True):
    """Ingest every in-scope blob at `ref`; return [(domain, path, hash)] for current-flagging."""
    sha = resolve(ref)
    seen = []
    for h, path in ls_tree(ref):
        dom = in_scope(path)
        if not dom:
            continue
        if not have_blob(db, dom, h):
            store_blob(db, dom, h, path, blob_body(h))
        add_ref(db, dom, h, path, sha, ts)
        seen.append((dom, path, h, sha))
    if main_extras:
        main_sha = resolve("main")
        for name in MAIN_EXTRAS:
            r = git("ls-tree", "main", "--", name)
            parts = r.stdout.split()
            if r.returncode == 0 and len(parts) >= 3 and parts[1] == "blob":
                h, path = parts[2], "main:" + name
                if not have_blob(db, "code", h):
                    store_blob(db, "code", h, path, blob_body(h))
                add_ref(db, "code", h, path, main_sha, ts)
                seen.append(("code", path, h, main_sha))
    return seen


def reflag_current(db, seen):
    db.execute("UPDATE code_refs SET is_current=0")
    db.execute("UPDATE doc_refs  SET is_current=0")
    for dom, path, h, csha in seen:
        tbl = "code_refs" if dom == "code" else "doc_refs"
        db.execute("UPDATE %s SET is_current=1 WHERE hash=? AND path=? AND commit_sha=?" % tbl, (h, path, csha))


def ensure_pages(db):
    """Create the two entry-page Documents (source, docs) in the live DB if absent (idempotent)."""
    def next_tid():
        row = db.execute("SELECT COALESCE(MAX(TemplateID),0)+1 FROM Document_Templates").fetchone()
        return row[0] if row else 1
    # match the site''s standard page wrapper (seed.php page()) so these don''t load a different-looking style
    style = "body{font-family:Georgia,serif;max-width:640px;margin:3rem auto;padding:0 1rem;line-height:1.6;color:#222;background:#f7f4ee}a{color:#8a5a1a}h1{font-weight:normal}code{background:#eae5d8;padding:1px 4px}"
    nav = "<nav style=\"margin:0 0 1.5rem;padding-bottom:.75rem;border-bottom:1px solid #ccc\"><<<SiteMap>>></nav>"
    pages = {
        "source":      ("Source · Congruency", "The CMS''s own running source", "<<<SourceList>>>"),
        "docs":        ("Documentation · Congruency", "The CMS''s own documentation", "<<<DocList>>>"),
        "annotations": ("Annotations · Congruency", "The tag->target layer (flags + categories)", "<<<Annotations>>>"),
    }
    for did, (title, desc, tag) in pages.items():
        if db.execute("SELECT 1 FROM Documents WHERE DocumentID=?", (did,)).fetchone():
            continue
        tid = next_tid()
        body = "<!DOCTYPE html>\n<html>\n<head>\n<<<TitleTag>>>\n<style>%s</style>\n</head>\n<body>\n%s\n<h1>%s</h1>\n%s\n</body>\n</html>\n" % (style, nav, title, tag)
        db.execute("INSERT INTO Document_Templates(TemplateID, Content) VALUES(?,?)", (tid, body))
        db.execute("INSERT INTO Documents(DocumentID, TemplateID, Title, Description, ContentID) VALUES(?,?,?,?,?)",
                   (did, tid, title, desc, tid))


def stats(db):
    for t in ("code_blobs", "code_refs", "doc_blobs", "doc_refs"):
        try:
            n = db.execute("SELECT COUNT(*) FROM %s" % t).fetchone()[0]
        except sqlite3.Error:
            n = "-"
        cur = ""
        if t.endswith("_refs"):
            c = db.execute("SELECT COUNT(*) FROM %s WHERE is_current=1" % t).fetchone()[0]
            cur = "  (current: %d)" % c
        print("  %-11s %s%s" % (t, n, cur))


# ------------------------------------------------------------------ main
def main():
    global ROOT
    ap = argparse.ArgumentParser(description="mirror the running source + docs into the CMS DB (content-addressed)")
    ap.add_argument("--head", action="store_true", help="ingest the HEAD tree + re-flag current (default)")
    ap.add_argument("--backfill", action="store_true", help="walk source history into the archive")
    ap.add_argument("--ensure-pages", action="store_true", help="create tables + the source/docs entry Documents")
    ap.add_argument("--stats", action="store_true", help="print row counts and exit")
    a = ap.parse_args()

    reg = load_registry()
    ROOT = reg["__root__"]
    db = sqlite3.connect(db_path(reg), timeout=15)
    try:
        for stmt in DDL:
            db.execute(stmt)

        if a.stats:
            stats(db)
            return 0

        if a.ensure_pages:
            ensure_pages(db)
            db.commit()
            print("ensure-pages: source/docs/annotations Documents ensured; tables created")
            return 0

        try:
            ensure_pages(db)   # self-healing: the source/docs entry Documents exist (idempotent)
        except Exception:  # noqa: BLE001  (a bare/fresh DB without the CMS Documents table)
            pass

        if a.backfill:
            seen_hashes_before = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0]
            for line in git("rev-list", "--timestamp", "source").stdout.splitlines():
                parts = line.split()
                if len(parts) != 2:
                    continue
                ts, sha = float(parts[0]), parts[1]
                ingest_ref(db, sha, ts, main_extras=False)
            # current main extras + flag HEAD as running source
            seen = ingest_ref(db, "HEAD", float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0), main_extras=True)
            reflag_current(db, seen)
            db.commit()
            added = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0] - seen_hashes_before
            print("backfill: walked source history (+%d new code blobs)" % added)
            stats(db)
            return 0

        # default: --head
        ts = float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0)
        seen = ingest_ref(db, "HEAD", ts, main_extras=True)
        reflag_current(db, seen)
        db.commit()
        print("ingest_self: HEAD tree mirrored (%d in-scope files); running source flagged" % len(seen))
        return 0
    finally:
        db.close()


if __name__ == "__main__":
    try:
        sys.exit(main())
    except Exception as e:  # noqa: BLE001  -- best-effort: never crash a commit hook
        try:
            reg = load_registry()
        except Exception:  # noqa: BLE001
            reg = None
        bug_report(reg, e, traceback.format_exc())
        sys.stderr.write("[ingest_self] %r\n" % e)
        sys.exit(0)
');
INSERT INTO "code_blobs" VALUES('a86cc97b492028951e1144f0020467d6efd3219b','php',3914,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * AnnotateHandler — apply an annotation (the handler for AnnotateForm), on ?page=annotateDone.
 *
 * The general front door to the tag->target layer. Reads the completed form via FORM_MANAGER, validates
 * kind in {source,page,doc,ticket} plus a non-empty id and tag, inserts into annotations (tag -> target
 * "kind:id"), and resets the form. The inline source `flag` and the page-category tagger are just two
 * presets of this same write.
 */
if (!class_exists("AnnotateHandler")) {
    class AnnotateHandler implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string) $s, ENT_QUOTES); }
        private static function back() { return "<p><a href=''?page=forms''>&larr; back to the admin forms</a></p>"; }

        public function get_document() {
            try {
                $kinds = array(''source'', ''page'', ''doc'', ''ticket'');
                $fm = PersistentObjectManager::getData(''FORM_MANAGER'');
                $res = isset($fm) ? $fm->getResults(''AnnotateForm'') : null;
                $kind = isset($res[''targetKind'']) ? trim((string) $res[''targetKind'']) : '''';
                $id   = isset($res[''targetId''])   ? trim((string) $res[''targetId''])   : '''';
                $tag  = isset($res[''tag''])        ? trim((string) $res[''tag''])        : '''';
                $note = isset($res[''note''])       ? trim((string) $res[''note''])       : '''';

                if ($kind === '''' && $id === '''' && $tag === '''') {
                    return "<p>No pending annotation. <a href=''?page=forms''>Add one &rarr;</a></p>";
                }
                if (!in_array($kind, $kinds, true)) {
                    return "<p style=''color:#b00020''>Rejected: <code>" . self::esc($kind) . "</code> is not a valid target kind.</p>" . self::back();
                }
                if ($id === '''' || $tag === '''') {
                    return "<p style=''color:#b00020''>Rejected: a target id and a tag are both required.</p>" . self::back();
                }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $db->exec("CREATE TABLE IF NOT EXISTS annotations (id INTEGER PRIMARY KEY AUTOINCREMENT, tag TEXT, target TEXT, note TEXT, ts REAL, meta TEXT)");

                $target = $kind . '':'' . $id;
                $ins = $db->prepare("INSERT INTO annotations (tag,target,note,ts,meta) VALUES (?,?,?,?,?)");
                $ins->execute(array($tag, $target, $note, microtime(true), json_encode(array(''source'' => ''annotate-form''))));
                $aid = (int) $db->lastInsertId();

                if (isset($fm)) { $f = $fm->getCachedForm(''AnnotateForm''); if (isset($f)) { $f->setResults(array()); $f->reset(); } }

                return "<div style=''border:1px solid #1a7a3a;border-left:5px solid #1a7a3a;border-radius:6px;padding:.7rem .9rem;background:#f3fbf5''>"
                     . "<p style=''margin:.2rem 0''><strong>Annotation #" . self::esc($aid) . " added.</strong></p>"
                     . "<p style=''margin:.2rem 0;font-size:.9rem''><code>" . self::esc($tag) . "</code> &rarr; <code>" . self::esc($target) . "</code></p>"
                     . ($note !== '''' ? "<p style=''margin:.2rem 0;font-size:.9rem''>" . self::esc($note) . "</p>" : "")
                     . "</div>\n<p><a href=''?page=annotations''>&rarr; see it in Annotations</a></p>";
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>AnnotateHandler error: " . self::esc(get_class($e) . '': '' . $e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('55c17a1e07f4beeaef177f73ef6263ee7b56c9d6','php',3140,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * NewCategoryHandler — create a Category (the handler for NewCategoryForm), on ?page=categoryDone.
 *
 * Modeled on TicketLogger/TagPageHandler: reads the completed form via FORM_MANAGER, validates the name
 * (non-empty, not a duplicate), inserts into Categories with a MECHANICAL key (max+1), and resets the form
 * so a refresh can''t double-file. Grows the tag vocabulary the page-category annotations draw on.
 */
if (!class_exists("NewCategoryHandler")) {
    class NewCategoryHandler implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string) $s, ENT_QUOTES); }
        private static function back() { return "<p><a href=''?page=forms''>&larr; back to the admin forms</a></p>"; }

        public function get_document() {
            try {
                $fm = PersistentObjectManager::getData(''FORM_MANAGER'');
                $res = isset($fm) ? $fm->getResults(''NewCategoryForm'') : null;
                $name = isset($res[''name'']) ? trim((string) $res[''name'']) : '''';
                $desc = isset($res[''description'']) ? trim((string) $res[''description'']) : '''';

                if ($name === '''') {
                    return "<p>No pending category. <a href=''?page=forms''>Create one &rarr;</a></p>";
                }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

                $chk = $db->prepare("SELECT 1 FROM Categories WHERE name=?");
                $chk->execute(array($name));
                if ($chk->fetch()) {
                    return "<p style=''color:#b00020''>Category <code>" . self::esc($name) . "</code> already exists.</p>" . self::back();
                }
                $key = (int) $db->query("SELECT COALESCE(MAX(`key`),0)+1 FROM Categories")->fetchColumn();
                $ins = $db->prepare("INSERT INTO Categories (`key`, name, description) VALUES (?,?,?)");
                $ins->execute(array($key, $name, $desc));

                if (isset($fm)) { $f = $fm->getCachedForm(''NewCategoryForm''); if (isset($f)) { $f->setResults(array()); $f->reset(); } }

                return "<div style=''border:1px solid #1a7a3a;border-left:5px solid #1a7a3a;border-radius:6px;padding:.7rem .9rem;background:#f3fbf5''>"
                     . "<p style=''margin:.2rem 0''><strong>Category <code>" . self::esc($name) . "</code> created.</strong></p>"
                     . ($desc !== '''' ? "<p style=''margin:.2rem 0;font-size:.9rem''>" . self::esc($desc) . "</p>" : "")
                     . "</div>\n<p><a href=''?page=pages''>&rarr; tag a page with it</a></p>";
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>NewCategoryHandler error: " . self::esc(get_class($e) . '': '' . $e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('2bcaeccd159fc7960f6423b5ce58ba6f1a424141','php',2842,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * SiteMap — the "list all pages" tag, used as the site navigation.
 *
 * Implements Tag_Interface; invoked as <<<SiteMap>>>. Reads every Document
 * (page) from CONGRUENCY_SQLITE and renders an inline menu of links, so the
 * nav is generated from the pages that actually exist rather than hardcoded.
 * Terminal/internal pages (the order wizard''s tail, the 404) are blocklisted;
 * a small label map keeps the friendly names.
 */
if (!class_exists("SiteMap")) {
    class SiteMap implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<!-- SiteMap: no DB -->"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $have = array();
                foreach ($db->query("SELECT DocumentID FROM Documents")->fetchAll(PDO::FETCH_COLUMN) as $id) { $have[$id] = 1; }

                // home/about/order-wizard dropped from the nav (still reachable via Pages);
                // the nav now leads with Pages (all pages) and Tags (all tags).
                $block = array(''invalid'' => 1, ''thanks'' => 1, ''ticketDone'' => 1, ''tagDone'' => 1, ''order'' => 1,
                               ''catalog'' => 1, ''about'' => 1, ''config'' => 1, ''categoryDone'' => 1, ''annotateDone'' => 1);
                $label = array(''pages'' => ''Pages'', ''tags'' => ''Tags'', ''bugs'' => ''bug report'',
                               ''source'' => ''Source'', ''docs'' => ''Docs'', ''annotations'' => ''Annotations'');
                $order = array(''pages'', ''tags'', ''bugs'', ''forms'', ''tickets'', ''memories'', ''source'', ''docs'', ''annotations'');

                $ids = array();
                foreach ($order as $id) { if (isset($have[$id]) && !isset($block[$id])) { $ids[] = $id; unset($have[$id]); } }
                foreach (array_keys($have) as $id) { if (!isset($block[$id])) { $ids[] = $id; } }  // any extras, after

                $links = array();
                foreach ($ids as $id) {
                    $text = isset($label[$id]) ? $label[$id] : $id;
                    $links[] = "<a href=''?page=" . self::esc($id) . "''>" . self::esc($text) . "</a>";
                }
                return implode(" &nbsp;&middot;&nbsp; ", $links);
            } catch (\Throwable $e) {
                return "<!-- SiteMap error: " . self::esc($e->getMessage()) . " -->";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('c6dd6cecdc9ff55bbc5ff15e9df0a2d0dc5c4d4d','php',8391,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * rest.php — a generic REST interface over every table in the unified DB (CONGRUENCY_SQLITE), minus an
 * admin denylist (the self-hosting archive + the auth tables). Dispatched by boot/router.php when ?api is
 * present — AFTER the session/POM/ClassLoader boot, so it can check the admin login:
 *
 *   GET  ?api=tables              -> { "tables": [ ... ] }        (discovery)
 *   GET  ?api=<table>[&p=&per=]   -> { table,total,page,per,pages,rows:[...] }   (paginated)
 *   GET  ?api=<table>&id=<pk>     -> a single row by primary key
 *   POST/PUT/PATCH/DELETE ?api=   -> create / update / delete
 *
 * The table name is always validated against sqlite_master before use (allowlist), so it can''t be used for
 * injection. READS are public; WRITES (POST/PUT/PATCH/DELETE) require the admin login
 * (UserPrivilegeSet::logged_in()) — an unauthenticated write gets 401.
 */
function congruency_rest_dispatch() {
    if (ob_get_level()) { ob_clean(); }                 // drop buffered boot whitespace so JSON headers/body are clean
    header(''Content-Type: application/json'');
    header(''Access-Control-Allow-Origin: *'');
    $out = null;
    try {
        if (!defined(''CONGRUENCY_SQLITE'')) { throw new Exception(''CONGRUENCY_SQLITE not defined''); }
        $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
        $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

        $tables = array();
        foreach ($db->query("SELECT name FROM sqlite_master WHERE type=''table'' AND name NOT LIKE ''sqlite_%'' ORDER BY name") as $r) {
            $tables[$r[''name'']] = 1;
        }
        // admin-only: keep the self-hosting source/doc archive + the auth tables out of the public REST surface
        foreach (array(''code_blobs'', ''code_refs'', ''doc_blobs'', ''doc_refs'',
                       ''Login_Password'', ''User_Group_Mappings'', ''Group_Privileges'') as $__deny) { unset($tables[$__deny]); }

        $api = (string)($_GET[''api''] ?? '''');
        $method = strtoupper($_SERVER[''REQUEST_METHOD''] ?? ''GET'');

        // Writes require the admin login; reads stay public.
        if (in_array($method, array(''POST'', ''PUT'', ''PATCH'', ''DELETE''), true)
            && (!class_exists(''UserPrivilegeSet'') || !UserPrivilegeSet::logged_in())) {
            http_response_code(401);
            echo json_encode(array(''error'' => ''admin login required for writes'', ''method'' => $method,
                                   ''hint'' => ''log in (e.g. via the Login form), then retry'')) . "\n";
            return true;
        }

        if ($method === ''POST'' && isset($tables[$api])) {
            // CREATE: insert a row from the JSON body; only real columns are used (rest ignored).
            $data = json_decode((string)file_get_contents(''php://input''), true);
            if (!is_array($data)) { http_response_code(400); echo json_encode(array(''error'' => ''body must be a JSON object'')); return true; }
            $cols = array();
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { $cols[$c[''name'']] = 1; }
            $use = array();
            foreach ($data as $k => $v) { if (isset($cols[$k])) { $use[$k] = $v; } }
            if (!$use) { http_response_code(400); echo json_encode(array(''error'' => ''no valid columns for '' . $api, ''columns'' => array_keys($cols))); return true; }
            $names = array_keys($use);
            $sql = "INSERT INTO \"$api\" (" . implode('','', array_map(function ($n) { return "\"$n\""; }, $names)) . ") "
                 . "VALUES (" . implode('','', array_map(function ($n) { return ":$n"; }, $names)) . ")";
            $st = $db->prepare($sql);
            foreach ($use as $k => $v) { $st->bindValue(":$k", $v); }
            $st->execute();
            http_response_code(201);
            echo json_encode(array(''created'' => true, ''table'' => $api, ''rowid'' => $db->lastInsertId(), ''used'' => $use),
                             JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES) . "\n";
            return true;
        }

        if (($method === ''PUT'' || $method === ''PATCH'') && isset($tables[$api])) {
            // UPDATE by primary key: ?id=<pk>, JSON body of column=>value (real columns only).
            $pk = null;
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { if ($c[''pk'']) { $pk = $c[''name'']; } }
            if ($pk === null || !isset($_GET[''id''])) { http_response_code(400); echo json_encode(array(''error'' => ''update needs a single-column pk and ?id='')); return true; }
            $data = json_decode((string)file_get_contents(''php://input''), true);
            if (!is_array($data)) { http_response_code(400); echo json_encode(array(''error'' => ''body must be a JSON object'')); return true; }
            $cols = array();
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { $cols[$c[''name'']] = 1; }
            $use = array();
            foreach ($data as $k => $v) { if (isset($cols[$k]) && $k !== $pk) { $use[$k] = $v; } }
            if (!$use) { http_response_code(400); echo json_encode(array(''error'' => ''no valid columns to update'')); return true; }
            $set = implode('', '', array_map(function ($n) { return "\"$n\" = :$n"; }, array_keys($use)));
            $st = $db->prepare("UPDATE \"$api\" SET $set WHERE \"$pk\" = :__id");
            foreach ($use as $k => $v) { $st->bindValue(":$k", $v); }
            $st->bindValue(":__id", $_GET[''id'']);
            $st->execute();
            echo json_encode(array(''updated'' => $st->rowCount(), ''table'' => $api, ''pk'' => $pk, ''id'' => $_GET[''id''], ''set'' => $use),
                             JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES) . "\n";
            return true;
        }

        if ($method === ''DELETE'' && isset($tables[$api])) {
            // DELETE a single row by primary key (?id=). No bulk deletes.
            $pk = null;
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { if ($c[''pk'']) { $pk = $c[''name'']; } }
            if ($pk === null || !isset($_GET[''id''])) { http_response_code(400); echo json_encode(array(''error'' => ''delete needs a single-column pk and ?id='')); return true; }
            $st = $db->prepare("DELETE FROM \"$api\" WHERE \"$pk\" = ?");
            $st->execute(array($_GET[''id'']));
            echo json_encode(array(''deleted'' => $st->rowCount(), ''table'' => $api, ''pk'' => $pk, ''id'' => $_GET[''id''])) . "\n";
            return true;
        }

        if ($api === '''' || $api === ''tables'') {
            $out = array(''tables'' => array_keys($tables));
        } elseif (isset($tables[$api])) {
            // primary-key column (for ?id=)
            $pk = null;
            foreach ($db->query("PRAGMA table_info(\"$api\")") as $c) { if ($c[''pk'']) { $pk = $c[''name'']; break; } }

            if (isset($_GET[''id'']) && $pk !== null) {
                $st = $db->prepare("SELECT * FROM \"$api\" WHERE \"$pk\" = ?");
                $st->execute(array($_GET[''id'']));
                $row = $st->fetch(PDO::FETCH_ASSOC);
                if ($row === false) { http_response_code(404); $out = array(''error'' => ''not found'', ''table'' => $api, ''id'' => $_GET[''id'']); }
                else { $out = array(''table'' => $api, ''pk'' => $pk, ''row'' => $row); }
            } else {
                $per = isset($_GET[''per'']) ? max(1, min(500, (int)$_GET[''per''])) : 50;
                $pg  = isset($_GET[''p''])   ? max(1, (int)$_GET[''p'']) : 1;
                $total = (int)$db->query("SELECT COUNT(*) FROM \"$api\"")->fetchColumn();
                $off = ($pg - 1) * $per;
                $rows = $db->query("SELECT * FROM \"$api\" LIMIT $per OFFSET $off")->fetchAll(PDO::FETCH_ASSOC);
                $out = array(''table'' => $api, ''pk'' => $pk, ''total'' => $total, ''page'' => $pg, ''per'' => $per,
                             ''pages'' => (int)ceil($total / max(1, $per)), ''rows'' => $rows);
            }
        } else {
            http_response_code(404);
            $out = array(''error'' => ''unknown table'', ''table'' => $api, ''tables'' => array_keys($tables));
        }
    } catch (\Throwable $e) {
        http_response_code(500);
        $out = array(''error'' => $e->getMessage());
    }
    echo json_encode($out, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES) . "\n";
    return true;
}
');
INSERT INTO "code_blobs" VALUES('e9031d73ed825868ee16067327dd5ddec13f9b3e','php',2032,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/* New-tree router for `php -S`. Self-contained bootstrap for checkouts/current,
   pathed entirely off __DIR__ (relocatable). Telemetry stripped — standup only. */
$BOOT = __DIR__;                                        // checkouts/current/boot

error_reporting(E_ALL & ~E_DEPRECATED);
ini_set(''display_errors'', ''1'');
ini_set(''session.save_path'', sys_get_temp_dir());
ini_set(''sendmail_path'', ''/bin/true'');                 // Orderer::sendEmail() -> no MTA, no-op

ob_start();  // buffer output so ?api= can emit clean JSON + status headers after the POM/session boot
             // (included files trail whitespace after their closing php tag, which would otherwise send output)

require $BOOT . ''/shim.php'';                            // mysql_* -> PDO/sqlite
require $BOOT . ''/configure.php'';                       // install.json + defaults -> ALL constants

set_include_path($BOOT . PATH_SEPARATOR . get_include_path());  // shadow the app''s illegal AutoLoader.php
require(CLASS_LOADER_HEADER);
session_start();

if (isset($_GET[''fresh''])) { unset($_SESSION[''POM'']); }

$LOADER = getClassLoader();                             // PHP 8: SPL autoload, not __autoLoad()
spl_autoload_register(function ($class) use ($LOADER) { $LOADER->loadClassByName($class); });

PersistentObjectManager::getPOM();
include(BIN . "Initialize_POM.php");

// REST: ?api=... -> generic JSON over every table. Dispatched here (after the session/POM/ClassLoader boot)
// so writes can require the admin login via UserPrivilegeSet::logged_in(); reads stay public. Short-circuits
// the CMS front controller.
require $BOOT . ''/rest.php'';
if (isset($_GET[''api''])) { congruency_rest_dispatch(); exit; }

Controller::control();

try { PersistentObjectManager::pack($_SESSION[''POM'']); }
catch (\Throwable $e) { error_log("[POM pack skipped: " . $e->getMessage() . "]"); }
');
INSERT INTO "code_blobs" VALUES('c8aeca4e25b50189d9b972da277fb4a82d80b490','php',2940,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * SiteMap — the "list all pages" tag, used as the site navigation.
 *
 * Implements Tag_Interface; invoked as <<<SiteMap>>>. Reads every Document
 * (page) from CONGRUENCY_SQLITE and renders an inline menu of links, so the
 * nav is generated from the pages that actually exist rather than hardcoded.
 * Terminal/internal pages (the order wizard''s tail, the 404) are blocklisted;
 * a small label map keeps the friendly names.
 */
if (!class_exists("SiteMap")) {
    class SiteMap implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<!-- SiteMap: no DB -->"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $have = array();
                foreach ($db->query("SELECT DocumentID FROM Documents")->fetchAll(PDO::FETCH_COLUMN) as $id) { $have[$id] = 1; }

                // home/about/order-wizard dropped from the nav (still reachable via Pages);
                // the nav now leads with Pages (all pages) and Tags (all tags).
                $block = array(''invalid'' => 1, ''thanks'' => 1, ''ticketDone'' => 1, ''tagDone'' => 1, ''order'' => 1,
                               ''catalog'' => 1, ''about'' => 1, ''config'' => 1, ''categoryDone'' => 1, ''annotateDone'' => 1);
                $label = array(''pages'' => ''Pages'', ''tags'' => ''Tags'', ''bugs'' => ''bug report'',
                               ''source'' => ''Source'', ''docs'' => ''Docs'', ''annotations'' => ''Annotations'');
                $order = array(''pages'', ''tags'', ''bugs'', ''forms'', ''tickets'', ''memories'', ''source'', ''docs'', ''annotations'');

                $ids = array();
                foreach ($order as $id) { if (isset($have[$id]) && !isset($block[$id])) { $ids[] = $id; unset($have[$id]); } }
                foreach (array_keys($have) as $id) { if (!isset($block[$id])) { $ids[] = $id; } }  // any extras, after

                $links = array();
                foreach ($ids as $id) {
                    $text = isset($label[$id]) ? $label[$id] : $id;
                    $links[] = "<a href=''?page=" . self::esc($id) . "''>" . self::esc($text) . "</a>";
                }
                return "<span style=''text-transform:uppercase;letter-spacing:.04em''>"
                     . implode(" &nbsp;&middot;&nbsp; ", $links) . "</span>";
            } catch (\Throwable $e) {
                return "<!-- SiteMap error: " . self::esc($e->getMessage()) . " -->";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('aa9ac6131e332ad46402e22030cfcd0034b26224','python',13326,'#!/usr/bin/env python3
"""ingest_self.py -- mirror the running source + docs into the CMS DB, content-addressed by git blob hash.

On each crank (post-commit) this pushes the running source into the CMS DB (CONGRUENCY_SQLITE, the unified
~/.jazz/congruency.sqlite) so the CMS can render its own source and documentation. Content is deduped by
git blob hash; a reverse-lookup (path @ commit) names each blob and gives every file its version history;
`is_current=1` flags the blob for each path in the checked-out HEAD tree = the RUNNING source. Code and
docs live in separate tables.

    python3 tools/ingest_self.py             # --head (default): ingest the HEAD tree + re-flag current
    python3 tools/ingest_self.py --backfill  # walk source history into the archive, then flag current
    python3 tools/ingest_self.py --stats     # print row counts
    python3 tools/ingest_self.py --ensure-pages  # create tables + the source/docs entry Documents

Registry-gated, python-only, best-effort (never blocks a commit); Variant-A bug report on exception.
"""
import argparse
import json
import os
import sqlite3
import subprocess
import sys
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None   # repo root (dir of registry.json); set in main()

CODE_EXT = (".php", ".py")
DOC_EXT = (".md", ".txt")
DOC_TXT_PREFIXES = ("checkouts/current/doc/",)   # .txt is a doc ONLY here (legacy 2006 CMS docs) — not stray prompts/cookie jars
IGNORE_SUBSTR = ("tooling/congruencey/", "tooling/tournament-", "/vendor/", "/node_modules/")
CODE_PREFIXES = (
    "checkouts/current/lib/", "checkouts/current/invocators/", "checkouts/current/boot/",
    "checkouts/current/www/", "checkouts/current/bin/",
    "checkouts/current/tools/", "checkouts/current/versioning/", "tracker/",
)
MAIN_EXTRAS = ("deploy.py", "install.py")            # deploy/stand-up-teardown tooling (lives on `main`)
LANG = {".php": "php", ".py": "python", ".md": "markdown", ".txt": "text"}

DDL = [
    "CREATE TABLE IF NOT EXISTS code_blobs (hash TEXT PRIMARY KEY, lang TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS code_refs  (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_code_refs ON code_refs(hash, path, commit_sha)",
    "CREATE TABLE IF NOT EXISTS doc_blobs  (hash TEXT PRIMARY KEY, kind TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS doc_refs   (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    # abstract tagging: a `tag` applied to an opaque `target` ref ("source:<hash>" / "page:<id>" / "doc:<hash>" / "ticket:<id>")
    "CREATE TABLE IF NOT EXISTS annotations (id INTEGER PRIMARY KEY AUTOINCREMENT, tag TEXT, target TEXT, note TEXT, ts REAL, meta TEXT)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_doc_refs ON doc_refs(hash, path, commit_sha)",
]


# ------------------------------------------------------------------ registry / db
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def bug_report(reg, exc, tb, note="ingest_self"):
    root = (reg or {}).get("__root__") or ROOT or HERE
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {"filename": os.path.basename(__file__), "function": last.name if last else "?",
             "time-of-occurance": datetime.now().isoformat(),
             "methods-to-reproduce": "python3 tools/ingest_self.py " + " ".join(sys.argv[1:]),
             "possible-cause": "%s: %s" % (type(exc).__name__, exc),
             "traceback": tb.strip().splitlines()[-6:], "note": note}
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        open(path, "a").write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def db_path(reg):
    """The CMS DB the app reads: install.json''s CONGRUENCY_SQLITE, else the jazz default."""
    cfg = os.path.join(reg["__root__"], "checkouts", "current", "install.json")
    try:
        j = json.load(open(cfg))
        if j.get("CONGRUENCY_SQLITE"):
            return os.path.expanduser(j["CONGRUENCY_SQLITE"])
    except Exception:  # noqa: BLE001
        pass
    return os.path.join(os.path.expanduser("~"), ".jazz", "congruency.sqlite")


# ------------------------------------------------------------------ git
def git(*args):
    return subprocess.run(["git"] + list(args), cwd=ROOT, capture_output=True, text=True)


def resolve(ref):
    return git("rev-parse", ref).stdout.strip()


def ls_tree(ref):
    for line in git("ls-tree", "-r", ref).stdout.splitlines():
        meta, _, path = line.partition("\t")          # "<mode> blob <hash>\t<path>"
        parts = meta.split()
        if len(parts) == 3 and parts[1] == "blob":
            yield parts[2], path


def blob_body(h):
    r = git("cat-file", "blob", h)
    return r.stdout if r.returncode == 0 else ""


# ------------------------------------------------------------------ classify / write
def in_scope(path):
    if any(s in path for s in IGNORE_SUBSTR):
        return None
    ext = os.path.splitext(path)[1]
    if ext in CODE_EXT and any(path.startswith(p) for p in CODE_PREFIXES):
        return "code"
    if ext == ".md":
        return "doc"
    # .txt ONLY from the doc dir (the legacy 2006 CMS docs) — NOT stray prompts / cookie jars (e.g. wiz.txt)
    if ext == ".txt" and any(path.startswith(p) for p in DOC_TXT_PREFIXES):
        return "doc"
    return None


def have_blob(db, domain, h):
    tbl = "code_blobs" if domain == "code" else "doc_blobs"
    return db.execute("SELECT 1 FROM %s WHERE hash=?" % tbl, (h,)).fetchone() is not None


def store_blob(db, domain, h, path, body):
    lang = LANG.get(os.path.splitext(path)[1], "text")
    nbytes = len(body.encode("utf-8", "replace"))
    if domain == "code":
        db.execute("INSERT OR IGNORE INTO code_blobs(hash,lang,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))
    else:
        db.execute("INSERT OR IGNORE INTO doc_blobs(hash,kind,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))


def add_ref(db, domain, h, path, commit_sha, ts):
    tbl = "code_refs" if domain == "code" else "doc_refs"
    db.execute("INSERT OR IGNORE INTO %s(hash,path,commit_sha,ts,is_current) VALUES(?,?,?,?,0)" % tbl,
               (h, path, commit_sha, ts))


def ingest_ref(db, ref, ts, main_extras=True):
    """Ingest every in-scope blob at `ref`; return [(domain, path, hash)] for current-flagging."""
    sha = resolve(ref)
    seen = []
    for h, path in ls_tree(ref):
        dom = in_scope(path)
        if not dom:
            continue
        if not have_blob(db, dom, h):
            store_blob(db, dom, h, path, blob_body(h))
        add_ref(db, dom, h, path, sha, ts)
        seen.append((dom, path, h, sha))
    if main_extras:
        main_sha = resolve("main")
        for name in MAIN_EXTRAS:
            r = git("ls-tree", "main", "--", name)
            parts = r.stdout.split()
            if r.returncode == 0 and len(parts) >= 3 and parts[1] == "blob":
                h, path = parts[2], "main:" + name
                if not have_blob(db, "code", h):
                    store_blob(db, "code", h, path, blob_body(h))
                add_ref(db, "code", h, path, main_sha, ts)
                seen.append(("code", path, h, main_sha))
    return seen


def reflag_current(db, seen):
    db.execute("UPDATE code_refs SET is_current=0")
    db.execute("UPDATE doc_refs  SET is_current=0")
    for dom, path, h, csha in seen:
        tbl = "code_refs" if dom == "code" else "doc_refs"
        db.execute("UPDATE %s SET is_current=1 WHERE hash=? AND path=? AND commit_sha=?" % tbl, (h, path, csha))


def ensure_pages(db):
    """Create the two entry-page Documents (source, docs) in the live DB if absent (idempotent)."""
    def next_tid():
        row = db.execute("SELECT COALESCE(MAX(TemplateID),0)+1 FROM Document_Templates").fetchone()
        return row[0] if row else 1
    # match the site''s standard page wrapper (seed.php page()) so these don''t load a different-looking style
    style = "body{font-family:Georgia,serif;max-width:960px;margin:3rem auto;padding:0 1rem;line-height:1.6;color:#222;background:#f7f4ee}a{color:#8a5a1a}h1{font-weight:normal}code{background:#eae5d8;padding:1px 4px}"
    nav = "<nav style=\"margin:0 0 1.5rem;padding-bottom:.75rem;border-bottom:1px solid #ccc\"><<<SiteMap>>></nav>"
    pages = {
        "source":      ("Source · Congruency", "The CMS''s own running source", "<<<SourceList>>>"),
        "docs":        ("Documentation · Congruency", "The CMS''s own documentation", "<<<DocList>>>"),
        "annotations": ("Annotations · Congruency", "The tag->target layer (flags + categories)", "<<<Annotations>>>"),
    }
    for did, (title, desc, tag) in pages.items():
        if db.execute("SELECT 1 FROM Documents WHERE DocumentID=?", (did,)).fetchone():
            continue
        tid = next_tid()
        body = "<!DOCTYPE html>\n<html>\n<head>\n<<<TitleTag>>>\n<style>%s</style>\n</head>\n<body>\n%s\n<h1>%s</h1>\n%s\n</body>\n</html>\n" % (style, nav, title, tag)
        db.execute("INSERT INTO Document_Templates(TemplateID, Content) VALUES(?,?)", (tid, body))
        db.execute("INSERT INTO Documents(DocumentID, TemplateID, Title, Description, ContentID) VALUES(?,?,?,?,?)",
                   (did, tid, title, desc, tid))


def stats(db):
    for t in ("code_blobs", "code_refs", "doc_blobs", "doc_refs"):
        try:
            n = db.execute("SELECT COUNT(*) FROM %s" % t).fetchone()[0]
        except sqlite3.Error:
            n = "-"
        cur = ""
        if t.endswith("_refs"):
            c = db.execute("SELECT COUNT(*) FROM %s WHERE is_current=1" % t).fetchone()[0]
            cur = "  (current: %d)" % c
        print("  %-11s %s%s" % (t, n, cur))


# ------------------------------------------------------------------ main
def main():
    global ROOT
    ap = argparse.ArgumentParser(description="mirror the running source + docs into the CMS DB (content-addressed)")
    ap.add_argument("--head", action="store_true", help="ingest the HEAD tree + re-flag current (default)")
    ap.add_argument("--backfill", action="store_true", help="walk source history into the archive")
    ap.add_argument("--ensure-pages", action="store_true", help="create tables + the source/docs entry Documents")
    ap.add_argument("--stats", action="store_true", help="print row counts and exit")
    a = ap.parse_args()

    reg = load_registry()
    ROOT = reg["__root__"]
    db = sqlite3.connect(db_path(reg), timeout=15)
    try:
        for stmt in DDL:
            db.execute(stmt)

        if a.stats:
            stats(db)
            return 0

        if a.ensure_pages:
            ensure_pages(db)
            db.commit()
            print("ensure-pages: source/docs/annotations Documents ensured; tables created")
            return 0

        try:
            ensure_pages(db)   # self-healing: the source/docs entry Documents exist (idempotent)
        except Exception:  # noqa: BLE001  (a bare/fresh DB without the CMS Documents table)
            pass

        if a.backfill:
            seen_hashes_before = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0]
            for line in git("rev-list", "--timestamp", "source").stdout.splitlines():
                parts = line.split()
                if len(parts) != 2:
                    continue
                ts, sha = float(parts[0]), parts[1]
                ingest_ref(db, sha, ts, main_extras=False)
            # current main extras + flag HEAD as running source
            seen = ingest_ref(db, "HEAD", float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0), main_extras=True)
            reflag_current(db, seen)
            db.commit()
            added = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0] - seen_hashes_before
            print("backfill: walked source history (+%d new code blobs)" % added)
            stats(db)
            return 0

        # default: --head
        ts = float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0)
        seen = ingest_ref(db, "HEAD", ts, main_extras=True)
        reflag_current(db, seen)
        db.commit()
        print("ingest_self: HEAD tree mirrored (%d in-scope files); running source flagged" % len(seen))
        return 0
    finally:
        db.close()


if __name__ == "__main__":
    try:
        sys.exit(main())
    except Exception as e:  # noqa: BLE001  -- best-effort: never crash a commit hook
        try:
            reg = load_registry()
        except Exception:  # noqa: BLE001
            reg = None
        bug_report(reg, e, traceback.format_exc())
        sys.stderr.write("[ingest_self] %r\n" % e)
        sys.exit(0)
');
INSERT INTO "code_blobs" VALUES('77bb052203989241e17cce25845940dedf01934a','php',2897,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * SiteMap — the "list all pages" tag, used as the site navigation.
 *
 * Implements Tag_Interface; invoked as <<<SiteMap>>>. Reads every Document
 * (page) from CONGRUENCY_SQLITE and renders an inline menu of links, so the
 * nav is generated from the pages that actually exist rather than hardcoded.
 * Terminal/internal pages (the order wizard''s tail, the 404) are blocklisted;
 * a small label map keeps the friendly names.
 */
if (!class_exists("SiteMap")) {
    class SiteMap implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<!-- SiteMap: no DB -->"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $have = array();
                foreach ($db->query("SELECT DocumentID FROM Documents")->fetchAll(PDO::FETCH_COLUMN) as $id) { $have[$id] = 1; }

                // home/about/order-wizard dropped from the nav (still reachable via Pages);
                // the nav now leads with Pages (all pages) and Tags (all tags).
                $block = array(''invalid'' => 1, ''thanks'' => 1, ''ticketDone'' => 1, ''tagDone'' => 1, ''order'' => 1,
                               ''catalog'' => 1, ''about'' => 1, ''config'' => 1, ''categoryDone'' => 1, ''annotateDone'' => 1);
                $label = array(''pages'' => ''Pages'', ''tags'' => ''Tags'', ''bugs'' => ''bug report'',
                               ''source'' => ''Source'', ''docs'' => ''Docs'', ''annotations'' => ''Annotations'');
                $order = array(''pages'', ''tags'', ''bugs'', ''forms'', ''tickets'', ''memories'', ''source'', ''docs'', ''annotations'');

                $ids = array();
                foreach ($order as $id) { if (isset($have[$id]) && !isset($block[$id])) { $ids[] = $id; unset($have[$id]); } }
                foreach (array_keys($have) as $id) { if (!isset($block[$id])) { $ids[] = $id; } }  // any extras, after

                $links = array();
                foreach ($ids as $id) {
                    $text = isset($label[$id]) ? $label[$id] : $id;
                    $links[] = "<a href=''?page=" . self::esc($id) . "''>" . self::esc($text) . "</a>";
                }
                return implode(" &nbsp;&middot;&nbsp; ", $links);   // nav styling (incl. all-caps) lives in <<<Style>>>
            } catch (\Throwable $e) {
                return "<!-- SiteMap error: " . self::esc($e->getMessage()) . " -->";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('788f8ca7cd48250a97bf1ddcb7f05a1942be24e1','php',1420,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * Style — the ONE site stylesheet. Every page template embeds <<<Style>>> in its <head> (like
 * <<<TitleTag>>>), so the entire look lives in a single place: change it here, every page changes.
 * Full-width by design — no max-width, just comfortable side margins, so the content uses the whole screen.
 * The nav styling (including the all-caps top-level links) lives here too.
 */
if (!class_exists("Style")) {
    class Style implements Tag_Interface {
        public function __construct($arguments) {}
        public function get_document() {
            return "<style>"
                 . "body{font-family:Georgia,serif;margin:1.5rem 2.5rem;line-height:1.6;color:#222;background:#f7f4ee}"
                 . "a{color:#8a5a1a}"
                 . "h1,h2{font-weight:normal}"
                 . "code{background:#eae5d8;padding:1px 4px}"
                 . "pre{background:#f4f1e8;border:1px solid #d8d2c4;padding:.6rem;overflow:auto}"
                 . "nav{margin:0 0 1.5rem;padding-bottom:.75rem;border-bottom:1px solid #ccc;text-transform:uppercase;letter-spacing:.04em}"
                 . "table{border-collapse:collapse}"
                 . "th,td{text-align:left}"
                 . "</style>";
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('d07f66701cce4e4755c08979d9ca20d2bc1143b8','python',12993,'#!/usr/bin/env python3
"""ingest_self.py -- mirror the running source + docs into the CMS DB, content-addressed by git blob hash.

On each crank (post-commit) this pushes the running source into the CMS DB (CONGRUENCY_SQLITE, the unified
~/.jazz/congruency.sqlite) so the CMS can render its own source and documentation. Content is deduped by
git blob hash; a reverse-lookup (path @ commit) names each blob and gives every file its version history;
`is_current=1` flags the blob for each path in the checked-out HEAD tree = the RUNNING source. Code and
docs live in separate tables.

    python3 tools/ingest_self.py             # --head (default): ingest the HEAD tree + re-flag current
    python3 tools/ingest_self.py --backfill  # walk source history into the archive, then flag current
    python3 tools/ingest_self.py --stats     # print row counts
    python3 tools/ingest_self.py --ensure-pages  # create tables + the source/docs entry Documents

Registry-gated, python-only, best-effort (never blocks a commit); Variant-A bug report on exception.
"""
import argparse
import json
import os
import sqlite3
import subprocess
import sys
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None   # repo root (dir of registry.json); set in main()

CODE_EXT = (".php", ".py")
DOC_EXT = (".md", ".txt")
DOC_TXT_PREFIXES = ("checkouts/current/doc/",)   # .txt is a doc ONLY here (legacy 2006 CMS docs) — not stray prompts/cookie jars
IGNORE_SUBSTR = ("tooling/congruencey/", "tooling/tournament-", "/vendor/", "/node_modules/")
CODE_PREFIXES = (
    "checkouts/current/lib/", "checkouts/current/invocators/", "checkouts/current/boot/",
    "checkouts/current/www/", "checkouts/current/bin/",
    "checkouts/current/tools/", "checkouts/current/versioning/", "tracker/",
)
MAIN_EXTRAS = ("deploy.py", "install.py")            # deploy/stand-up-teardown tooling (lives on `main`)
LANG = {".php": "php", ".py": "python", ".md": "markdown", ".txt": "text"}

DDL = [
    "CREATE TABLE IF NOT EXISTS code_blobs (hash TEXT PRIMARY KEY, lang TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS code_refs  (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_code_refs ON code_refs(hash, path, commit_sha)",
    "CREATE TABLE IF NOT EXISTS doc_blobs  (hash TEXT PRIMARY KEY, kind TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS doc_refs   (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    # abstract tagging: a `tag` applied to an opaque `target` ref ("source:<hash>" / "page:<id>" / "doc:<hash>" / "ticket:<id>")
    "CREATE TABLE IF NOT EXISTS annotations (id INTEGER PRIMARY KEY AUTOINCREMENT, tag TEXT, target TEXT, note TEXT, ts REAL, meta TEXT)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_doc_refs ON doc_refs(hash, path, commit_sha)",
]


# ------------------------------------------------------------------ registry / db
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def bug_report(reg, exc, tb, note="ingest_self"):
    root = (reg or {}).get("__root__") or ROOT or HERE
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {"filename": os.path.basename(__file__), "function": last.name if last else "?",
             "time-of-occurance": datetime.now().isoformat(),
             "methods-to-reproduce": "python3 tools/ingest_self.py " + " ".join(sys.argv[1:]),
             "possible-cause": "%s: %s" % (type(exc).__name__, exc),
             "traceback": tb.strip().splitlines()[-6:], "note": note}
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        open(path, "a").write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def db_path(reg):
    """The CMS DB the app reads: install.json''s CONGRUENCY_SQLITE, else the jazz default."""
    cfg = os.path.join(reg["__root__"], "checkouts", "current", "install.json")
    try:
        j = json.load(open(cfg))
        if j.get("CONGRUENCY_SQLITE"):
            return os.path.expanduser(j["CONGRUENCY_SQLITE"])
    except Exception:  # noqa: BLE001
        pass
    return os.path.join(os.path.expanduser("~"), ".jazz", "congruency.sqlite")


# ------------------------------------------------------------------ git
def git(*args):
    return subprocess.run(["git"] + list(args), cwd=ROOT, capture_output=True, text=True)


def resolve(ref):
    return git("rev-parse", ref).stdout.strip()


def ls_tree(ref):
    for line in git("ls-tree", "-r", ref).stdout.splitlines():
        meta, _, path = line.partition("\t")          # "<mode> blob <hash>\t<path>"
        parts = meta.split()
        if len(parts) == 3 and parts[1] == "blob":
            yield parts[2], path


def blob_body(h):
    r = git("cat-file", "blob", h)
    return r.stdout if r.returncode == 0 else ""


# ------------------------------------------------------------------ classify / write
def in_scope(path):
    if any(s in path for s in IGNORE_SUBSTR):
        return None
    ext = os.path.splitext(path)[1]
    if ext in CODE_EXT and any(path.startswith(p) for p in CODE_PREFIXES):
        return "code"
    if ext == ".md":
        return "doc"
    # .txt ONLY from the doc dir (the legacy 2006 CMS docs) — NOT stray prompts / cookie jars (e.g. wiz.txt)
    if ext == ".txt" and any(path.startswith(p) for p in DOC_TXT_PREFIXES):
        return "doc"
    return None


def have_blob(db, domain, h):
    tbl = "code_blobs" if domain == "code" else "doc_blobs"
    return db.execute("SELECT 1 FROM %s WHERE hash=?" % tbl, (h,)).fetchone() is not None


def store_blob(db, domain, h, path, body):
    lang = LANG.get(os.path.splitext(path)[1], "text")
    nbytes = len(body.encode("utf-8", "replace"))
    if domain == "code":
        db.execute("INSERT OR IGNORE INTO code_blobs(hash,lang,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))
    else:
        db.execute("INSERT OR IGNORE INTO doc_blobs(hash,kind,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))


def add_ref(db, domain, h, path, commit_sha, ts):
    tbl = "code_refs" if domain == "code" else "doc_refs"
    db.execute("INSERT OR IGNORE INTO %s(hash,path,commit_sha,ts,is_current) VALUES(?,?,?,?,0)" % tbl,
               (h, path, commit_sha, ts))


def ingest_ref(db, ref, ts, main_extras=True):
    """Ingest every in-scope blob at `ref`; return [(domain, path, hash)] for current-flagging."""
    sha = resolve(ref)
    seen = []
    for h, path in ls_tree(ref):
        dom = in_scope(path)
        if not dom:
            continue
        if not have_blob(db, dom, h):
            store_blob(db, dom, h, path, blob_body(h))
        add_ref(db, dom, h, path, sha, ts)
        seen.append((dom, path, h, sha))
    if main_extras:
        main_sha = resolve("main")
        for name in MAIN_EXTRAS:
            r = git("ls-tree", "main", "--", name)
            parts = r.stdout.split()
            if r.returncode == 0 and len(parts) >= 3 and parts[1] == "blob":
                h, path = parts[2], "main:" + name
                if not have_blob(db, "code", h):
                    store_blob(db, "code", h, path, blob_body(h))
                add_ref(db, "code", h, path, main_sha, ts)
                seen.append(("code", path, h, main_sha))
    return seen


def reflag_current(db, seen):
    db.execute("UPDATE code_refs SET is_current=0")
    db.execute("UPDATE doc_refs  SET is_current=0")
    for dom, path, h, csha in seen:
        tbl = "code_refs" if dom == "code" else "doc_refs"
        db.execute("UPDATE %s SET is_current=1 WHERE hash=? AND path=? AND commit_sha=?" % tbl, (h, path, csha))


def ensure_pages(db):
    """Create the two entry-page Documents (source, docs) in the live DB if absent (idempotent)."""
    def next_tid():
        row = db.execute("SELECT COALESCE(MAX(TemplateID),0)+1 FROM Document_Templates").fetchone()
        return row[0] if row else 1
    # the site''s one stylesheet is the <<<Style>>> tag; every page just embeds it + the <<<SiteMap>>> nav
    pages = {
        "source":      ("Source · Congruency", "The CMS''s own running source", "<<<SourceList>>>"),
        "docs":        ("Documentation · Congruency", "The CMS''s own documentation", "<<<DocList>>>"),
        "annotations": ("Annotations · Congruency", "The tag->target layer (flags + categories)", "<<<Annotations>>>"),
    }
    for did, (title, desc, tag) in pages.items():
        if db.execute("SELECT 1 FROM Documents WHERE DocumentID=?", (did,)).fetchone():
            continue
        tid = next_tid()
        body = "<!DOCTYPE html>\n<html>\n<head>\n<<<TitleTag>>>\n<<<Style>>>\n</head>\n<body>\n<nav><<<SiteMap>>></nav>\n<h1>%s</h1>\n%s\n</body>\n</html>\n" % (title, tag)
        db.execute("INSERT INTO Document_Templates(TemplateID, Content) VALUES(?,?)", (tid, body))
        db.execute("INSERT INTO Documents(DocumentID, TemplateID, Title, Description, ContentID) VALUES(?,?,?,?,?)",
                   (did, tid, title, desc, tid))


def stats(db):
    for t in ("code_blobs", "code_refs", "doc_blobs", "doc_refs"):
        try:
            n = db.execute("SELECT COUNT(*) FROM %s" % t).fetchone()[0]
        except sqlite3.Error:
            n = "-"
        cur = ""
        if t.endswith("_refs"):
            c = db.execute("SELECT COUNT(*) FROM %s WHERE is_current=1" % t).fetchone()[0]
            cur = "  (current: %d)" % c
        print("  %-11s %s%s" % (t, n, cur))


# ------------------------------------------------------------------ main
def main():
    global ROOT
    ap = argparse.ArgumentParser(description="mirror the running source + docs into the CMS DB (content-addressed)")
    ap.add_argument("--head", action="store_true", help="ingest the HEAD tree + re-flag current (default)")
    ap.add_argument("--backfill", action="store_true", help="walk source history into the archive")
    ap.add_argument("--ensure-pages", action="store_true", help="create tables + the source/docs entry Documents")
    ap.add_argument("--stats", action="store_true", help="print row counts and exit")
    a = ap.parse_args()

    reg = load_registry()
    ROOT = reg["__root__"]
    db = sqlite3.connect(db_path(reg), timeout=15)
    try:
        for stmt in DDL:
            db.execute(stmt)

        if a.stats:
            stats(db)
            return 0

        if a.ensure_pages:
            ensure_pages(db)
            db.commit()
            print("ensure-pages: source/docs/annotations Documents ensured; tables created")
            return 0

        try:
            ensure_pages(db)   # self-healing: the source/docs entry Documents exist (idempotent)
        except Exception:  # noqa: BLE001  (a bare/fresh DB without the CMS Documents table)
            pass

        if a.backfill:
            seen_hashes_before = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0]
            for line in git("rev-list", "--timestamp", "source").stdout.splitlines():
                parts = line.split()
                if len(parts) != 2:
                    continue
                ts, sha = float(parts[0]), parts[1]
                ingest_ref(db, sha, ts, main_extras=False)
            # current main extras + flag HEAD as running source
            seen = ingest_ref(db, "HEAD", float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0), main_extras=True)
            reflag_current(db, seen)
            db.commit()
            added = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0] - seen_hashes_before
            print("backfill: walked source history (+%d new code blobs)" % added)
            stats(db)
            return 0

        # default: --head
        ts = float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0)
        seen = ingest_ref(db, "HEAD", ts, main_extras=True)
        reflag_current(db, seen)
        db.commit()
        print("ingest_self: HEAD tree mirrored (%d in-scope files); running source flagged" % len(seen))
        return 0
    finally:
        db.close()


if __name__ == "__main__":
    try:
        sys.exit(main())
    except Exception as e:  # noqa: BLE001  -- best-effort: never crash a commit hook
        try:
            reg = load_registry()
        except Exception:  # noqa: BLE001
            reg = None
        bug_report(reg, e, traceback.format_exc())
        sys.stderr.write("[ingest_self] %r\n" % e)
        sys.exit(0)
');
INSERT INTO "code_blobs" VALUES('45fd1279553f5b5aa5212347a1761d290e385409','php',7667,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * DocList — the CMS browsing its own documentation (ticket: self-hosting).
 *
 * Admin-only (UserPrivilegeSet::logged_in()). Docs are mirrored into the DB by tools/ingest_self.py,
 * content-addressed by git blob hash: doc_blobs(hash,kind,bytes,body) + doc_refs(hash,path,commit_sha,is_current).
 *   ?page=docs           -> index of the CURRENT docs (doc_refs.is_current=1)
 *   ?page=docs&doc=<hash> -> one doc rendered via a minimal, ESCAPE-FIRST markdown subset (any ''<<<Tag>>>''
 *                            example in the doc stays literal, so the tag engine never re-parses it)
 */
if (!class_exists("DocList")) {
    class DocList implements Tag_Interface {

        const ADMIN_GATED = false;   // TEMP: browse without login while the browser is being finished; set true to re-gate

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string) $s, ENT_QUOTES); }

        private static function gate() {
            if (self::ADMIN_GATED && (!class_exists(''UserPrivilegeSet'') || !UserPrivilegeSet::logged_in())) {
                return "<p><strong>Administrator area.</strong> Please log in to browse the documentation.</p>\n<<<Login>>>";
            }
            return null;
        }

        public function get_document() {
            $deny = self::gate();
            if ($deny !== null) { return $deny; }
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<p>DocList: no DB.</p>"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $hash = isset($_GET[''doc'']) ? trim((string) $_GET[''doc'']) : '''';
                if ($hash !== '''') { return $this->view($db, $hash); }
                return $this->index($db);
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>DocList error: " . self::esc($e->getMessage()) . "</div>";
            }
        }

        private function index($db) {
            $rows = $db->query(
                "SELECT r.path, r.hash, b.kind, b.bytes FROM doc_refs r JOIN doc_blobs b ON b.hash=r.hash "
                . "WHERE r.is_current=1 ORDER BY r.path")->fetchAll(PDO::FETCH_ASSOC);
            $out = "<p>The CMS''s own documentation, addressed by git blob hash.</p>\n<ul class=''doclist''>\n";
            foreach ($rows as $r) {
                $out .= "<li><a href=''?page=docs&doc=" . self::esc($r[''hash'']) . "''>" . self::esc($r[''path'']) . "</a> "
                      . "<span style=''color:#888;font-size:.85em''>" . self::esc($r[''kind'']) . " &middot; " . (int) $r[''bytes''] . " B</span></li>\n";
            }
            return $out . "</ul>\n";
        }

        private function view($db, $hash) {
            $st = $db->prepare("SELECT kind, bytes, body FROM doc_blobs WHERE hash=?");
            $st->execute(array($hash));
            $blob = $st->fetch(PDO::FETCH_ASSOC);
            if (!$blob) { return "<p>No such doc blob <code>" . self::esc($hash) . "</code>. <a href=''?page=docs''>&larr; index</a></p>"; }

            $rs = $db->prepare("SELECT DISTINCT path, is_current FROM doc_refs WHERE hash=? ORDER BY path");
            $rs->execute(array($hash));
            $refs = $rs->fetchAll(PDO::FETCH_ASSOC);
            $path = $refs ? $refs[0][''path''] : '''';

            $hs = $db->prepare("SELECT hash, MAX(ts) t, MAX(is_current) cur FROM doc_refs WHERE path=? GROUP BY hash ORDER BY t DESC");
            $hs->execute(array($path));
            $hist = $hs->fetchAll(PDO::FETCH_ASSOC);

            $head = "<p><a href=''?page=docs''>&larr; index</a> &middot; <strong>" . self::esc($path) . "</strong> "
                  . "<span style=''color:#888''>(blob " . self::esc(substr($hash, 0, 12)) . ")</span></p>\n";
            $verhtml = "";
            if (count($hist) > 1) {
                $verhtml = "<p style=''font-size:.85em''>versions: ";
                foreach ($hist as $h) {
                    $lab = self::esc(substr($h[''hash''], 0, 9)) . ($h[''cur''] ? "*" : "");
                    $verhtml .= ($h[''hash''] === $hash) ? "<strong>$lab</strong> " : "<a href=''?page=docs&doc=" . self::esc($h[''hash'']) . "''>$lab</a> ";
                }
                $verhtml .= "</p>\n";
            }
            $rendered = ($blob[''kind''] === ''markdown'')
                ? self::markdown($blob[''body''])
                : "<pre style=''background:#f4f1e8;padding:.6rem;overflow:auto''>" . self::esc($blob[''body'']) . "</pre>";
            return $head . $verhtml . "<div class=''doc prose''>\n" . $rendered . "</div>\n";
        }

        /* Minimal markdown subset. ESCAPE FIRST (so HTML and ''<<<Tag>>>'' examples stay literal), then apply:
           #.. -> h1-h6, blank-line paragraphs, ``` / 4-space indent -> <pre><code>, `x` -> <code>, [t](u) -> <a>. */
        private static function markdown($text) {
            $esc = htmlspecialchars((string) $text, ENT_QUOTES);
            $lines = explode("\n", str_replace("\r", "", $esc));
            $out = ""; $para = array(); $inFence = false; $code = "";
            $flush = function () use (&$para, &$out) {
                // inline() on the JOINED paragraph so bold/italic/code spanning a wrapped line still match
                if ($para) { $out .= "<p>" . self::inline(implode(" ", $para)) . "</p>\n"; $para = array(); }
            };
            foreach ($lines as $ln) {
                if (preg_match(''/^\s*```/'', $ln)) {
                    if (!$inFence) { $flush(); $inFence = true; $code = ""; }
                    else { $out .= "<pre><code>" . $code . "</code></pre>\n"; $inFence = false; }
                    continue;
                }
                if ($inFence) { $code .= $ln . "\n"; continue; }
                if (preg_match(''/^(#{1,6})\s+(.*)$/'', $ln, $m)) {
                    $flush(); $h = strlen($m[1]); $out .= "<h$h>" . self::inline($m[2]) . "</h$h>\n"; continue;
                }
                if (preg_match(''/^    (.*)$/'', $ln, $m)) {          // 4-space indented code line
                    $flush(); $out .= "<pre><code>" . $m[1] . "</code></pre>\n"; continue;
                }
                if (trim($ln) === "") { $flush(); continue; }
                $para[] = $ln;   // raw; inline() applied to the whole paragraph in $flush
            }
            $flush();
            if ($inFence) { $out .= "<pre><code>" . $code . "</code></pre>\n"; }
            return $out;
        }

        private static function inline($s) {
            // Protect inline code first: its contents may hold * (e.g. `mysql_*`) that would otherwise
            // break the bold/italic passes. Swap each span for a placeholder, transform, then restore.
            $codes = array();
            $s = preg_replace_callback(''/`([^`]+)`/'', function ($m) use (&$codes) {
                $k = "\x01" . count($codes) . "\x01";
                $codes[$k] = "<code>" . $m[1] . "</code>";
                return $k;
            }, $s);
            $s = preg_replace(''/\*\*(.+?)\*\*/'', ''<strong>$1</strong>'', $s);           // **bold** (non-greedy)
            $s = preg_replace(''/(^|[^*])\*([^*\s][^*]*)\*/'', ''$1<em>$2</em>'', $s);      // *italic*
            $s = preg_replace(''/\[([^\]]+)\]\(([^)\s]+)\)/'', ''<a href="$2">$1</a>'', $s);
            foreach ($codes as $k => $v) { $s = str_replace($k, $v, $s); }
            return $s;
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('a543e4f1c420b579c0bbc4b2e9ae0a29bdfbb7ab','php',1567,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * Style — the ONE site stylesheet. Every page template embeds <<<Style>>> in its <head> (like
 * <<<TitleTag>>>), so the entire look lives in a single place: change it here, every page changes.
 * Full-width by design — no max-width, just comfortable side margins, so the content uses the whole screen.
 * The nav styling (including the all-caps top-level links) lives here too.
 */
if (!class_exists("Style")) {
    class Style implements Tag_Interface {
        public function __construct($arguments) {}
        public function get_document() {
            return "<style>"
                 . "body{font-family:Georgia,serif;margin:1.5rem 2.5rem;line-height:1.6;color:#222;background:#f7f4ee}"
                 . "a{color:#8a5a1a}"
                 . "h1,h2{font-weight:normal}"
                 . "code{background:#eae5d8;padding:1px 4px}"
                 . "pre{background:#f4f1e8;border:1px solid #d8d2c4;padding:.6rem;overflow:auto}"
                 . "nav{margin:0 0 1.5rem;padding-bottom:.75rem;border-bottom:1px solid #ccc;text-transform:uppercase;letter-spacing:.04em}"
                 . "table{border-collapse:collapse}"
                 . "th,td{text-align:left}"
                 . ".prose{max-width:70ch}"   // reading pages opt in via class=''prose'' — a comfortable measure; data/code pages stay full-width
                 . "</style>";
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('24f1527f9347f0849cae6080d13af46a22b54e19','php',3456,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * DatabaseInfo — a self-describing view of the unified DB (?page=database): every table, its row count,
 * and a link to browse it via the REST API (?api=<table>). The DB backs the whole site — pages, tags,
 * forms, tickets, annotations, and the self-hosting source/doc archive — so this makes it inspectable
 * from inside the CMS. Denylisted (admin-only) tables are marked, not linked.
 */
if (!class_exists("DatabaseInfo")) {
    class DatabaseInfo implements Tag_Interface {

        public function __construct($arguments) {}
        private static function esc($s) { return htmlspecialchars((string) $s, ENT_QUOTES); }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<p>DatabaseInfo: no DB.</p>"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $denied = array(''code_blobs'' => 1, ''code_refs'' => 1, ''doc_blobs'' => 1, ''doc_refs'' => 1,
                                ''Login_Password'' => 1, ''User_Group_Mappings'' => 1, ''Group_Privileges'' => 1);
                $tables = $db->query("SELECT name FROM sqlite_master WHERE type=''table'' AND name NOT LIKE ''sqlite_%'' ORDER BY name")
                              ->fetchAll(PDO::FETCH_COLUMN);

                $out = "<p>The unified SQLite database (<code>CONGRUENCY_SQLITE</code>) that backs the whole site — "
                     . "every page, tag, form, ticket, and the self-hosting source/doc archive. Reads are public via "
                     . "<code>?api=&lt;table&gt;</code>; writes need the admin login. Admin-only tables (the archive + "
                     . "auth) are denylisted from REST.</p>\n";
                $out .= "<table>\n<tr><th style=''padding-right:1.5rem''>table</th><th style=''padding-right:1.5rem''>rows</th>"
                      . "<th>browse</th></tr>\n";
                $total = 0;
                foreach ($tables as $t) {
                    $n = (int) $db->query(''SELECT COUNT(*) FROM "'' . $t . ''"'')->fetchColumn();
                    $total += $n;
                    $browse = isset($denied[$t])
                        ? "<span style=''color:#999''>admin-only (not in REST)</span>"
                        : "<a href=''?api=" . self::esc($t) . "&per=25''>?api=" . self::esc($t) . "</a>";
                    $out .= "<tr><td style=''padding-right:1.5rem''><code>" . self::esc($t) . "</code></td>"
                          . "<td style=''padding-right:1.5rem''>" . number_format($n) . "</td><td>" . $browse . "</td></tr>\n";
                }
                $out .= "</table>\n";
                $out .= "<p style=''color:#888;font-size:.9rem;margin-top:1rem''>" . count($tables) . " tables, "
                     . number_format($total) . " rows total. Export a git-viewable seed with "
                     . "<code>tools/db_export.py</code> &rarr; <code>state/seed.sql</code>; rebuild with "
                     . "<code>tools/db_import.py --to &lt;path&gt;</code>.</p>\n";
                return $out;
            } catch (\Throwable $e) {
                return "<div class=''cy-form-error''>DatabaseInfo error: " . self::esc($e->getMessage()) . "</div>";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('c6788b46db91f20bb1cdfaf8dd9ba88363ee2bd8','php',2935,'<?php
/*
Copyright (C) 2006 Steven Peterson
Congruency is free software, licensed under the GNU GPLv2 or later.
See the LICENSE file in the project root for full license terms.
*/
/*
 * SiteMap — the "list all pages" tag, used as the site navigation.
 *
 * Implements Tag_Interface; invoked as <<<SiteMap>>>. Reads every Document
 * (page) from CONGRUENCY_SQLITE and renders an inline menu of links, so the
 * nav is generated from the pages that actually exist rather than hardcoded.
 * Terminal/internal pages (the order wizard''s tail, the 404) are blocklisted;
 * a small label map keeps the friendly names.
 */
if (!class_exists("SiteMap")) {
    class SiteMap implements Tag_Interface {

        private $arguments;
        public function __construct($arguments) { $this->arguments = $arguments; }
        private static function esc($s) { return htmlspecialchars((string)$s, ENT_QUOTES); }

        public function get_document() {
            try {
                if (!defined(''CONGRUENCY_SQLITE'')) { return "<!-- SiteMap: no DB -->"; }
                $db = new PDO(''sqlite:'' . CONGRUENCY_SQLITE);
                $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                $have = array();
                foreach ($db->query("SELECT DocumentID FROM Documents")->fetchAll(PDO::FETCH_COLUMN) as $id) { $have[$id] = 1; }

                // home/about/order-wizard dropped from the nav (still reachable via Pages);
                // the nav now leads with Pages (all pages) and Tags (all tags).
                $block = array(''invalid'' => 1, ''thanks'' => 1, ''ticketDone'' => 1, ''tagDone'' => 1, ''order'' => 1,
                               ''catalog'' => 1, ''about'' => 1, ''config'' => 1, ''categoryDone'' => 1, ''annotateDone'' => 1);
                $label = array(''pages'' => ''Pages'', ''tags'' => ''Tags'', ''bugs'' => ''bug report'',
                               ''source'' => ''Source'', ''docs'' => ''Docs'', ''annotations'' => ''Annotations'', ''database'' => ''Database'');
                $order = array(''pages'', ''tags'', ''bugs'', ''forms'', ''tickets'', ''memories'', ''source'', ''docs'', ''annotations'', ''database'');

                $ids = array();
                foreach ($order as $id) { if (isset($have[$id]) && !isset($block[$id])) { $ids[] = $id; unset($have[$id]); } }
                foreach (array_keys($have) as $id) { if (!isset($block[$id])) { $ids[] = $id; } }  // any extras, after

                $links = array();
                foreach ($ids as $id) {
                    $text = isset($label[$id]) ? $label[$id] : $id;
                    $links[] = "<a href=''?page=" . self::esc($id) . "''>" . self::esc($text) . "</a>";
                }
                return implode(" &nbsp;&middot;&nbsp; ", $links);   // nav styling (incl. all-caps) lives in <<<Style>>>
            } catch (\Throwable $e) {
                return "<!-- SiteMap error: " . self::esc($e->getMessage()) . " -->";
            }
        }
    }
}
?>
');
INSERT INTO "code_blobs" VALUES('4789fdb7bb652214aa70b5463d404803ada9c720','python',5271,'#!/usr/bin/env python3
"""db_export.py -- export the CMS database as a git-viewable SQL dump (+ compressed).

Dumps CONGRUENCY_SQLITE to state/seed.sql (readable CREATE TABLE + INSERT statements you can diff in git)
and state/seed.sql.xz (compressed, for a fast deploy restore). Excludes local-noise / secret tables by
default -- the `events` tracker log and the auth tables (Login_Password/User_Group_Mappings/Group_Privileges)
-- so the committed seed is a clean public showcase. The self-hosting source/doc archive (with full history)
is kept: the browsable version history is the point.

    python3 tools/db_export.py                 # -> state/seed.sql (+ .xz); events + auth excluded
    python3 tools/db_export.py --keep-events   # include the tracker event log
    python3 tools/db_export.py --all           # include everything (auth + events)

Registry-gated, python-only; Variant-A bug report on exception.
"""
import argparse
import json
import lzma
import os
import shutil
import sqlite3
import sys
import tempfile
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None
DEFAULT_EXCLUDE = ("events", "Login_Password", "User_Group_Mappings", "Group_Privileges")


def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    p = find_registry()
    reg = json.load(open(p))
    reg["__root__"] = os.path.dirname(p)
    return reg


def db_path(reg):
    """The CMS DB the app reads: install.json''s CONGRUENCY_SQLITE, else the jazz default."""
    cfg = os.path.join(reg["__root__"], "checkouts", "current", "install.json")
    try:
        j = json.load(open(cfg))
        if j.get("CONGRUENCY_SQLITE"):
            return os.path.expanduser(j["CONGRUENCY_SQLITE"])
    except Exception:  # noqa: BLE001
        pass
    return os.path.join(os.path.expanduser("~"), ".jazz", "congruency.sqlite")


def bug_report(reg, exc, tb, note="db_export"):
    root = (reg or {}).get("__root__") or ROOT or HERE
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {"filename": os.path.basename(__file__), "function": last.name if last else "?",
             "time-of-occurance": datetime.now().isoformat(),
             "methods-to-reproduce": "python3 tools/db_export.py " + " ".join(sys.argv[1:]),
             "possible-cause": "%s: %s" % (type(exc).__name__, exc),
             "traceback": tb.strip().splitlines()[-6:], "note": note}
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        open(path, "a").write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def export(reg, exclude):
    db = db_path(reg)
    if not os.path.isfile(db):
        raise FileNotFoundError("no CMS DB at %s" % db)
    state = os.path.join(reg["__root__"], "checkouts", "current", "state")
    os.makedirs(state, exist_ok=True)

    # Work on a copy so the live DB is never mutated: drop excluded tables, VACUUM, then dump.
    fd, tmp = tempfile.mkstemp(suffix=".sqlite")
    os.close(fd)
    shutil.copy(db, tmp)
    try:
        c = sqlite3.connect(tmp)
        dropped = []
        for t in exclude:
            if c.execute("SELECT 1 FROM sqlite_master WHERE type=''table'' AND name=?", (t,)).fetchone():
                c.execute(''DROP TABLE "%s"'' % t)
                dropped.append(t)
        c.commit()
        c.execute("VACUUM")
        c.commit()
        sql = "\n".join(c.iterdump()) + "\n"
        c.close()
    finally:
        os.remove(tmp)

    seed = os.path.join(state, "seed.sql")
    with open(seed, "w") as f:
        f.write(sql)
    with lzma.open(seed + ".xz", "wt", preset=9) as f:
        f.write(sql)
    return seed, len(sql.encode("utf-8")), dropped


def main():
    global ROOT
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--keep-events", action="store_true", help="include the tracker event log")
    ap.add_argument("--all", action="store_true", help="include everything (auth + events)")
    a = ap.parse_args()
    reg = None
    try:
        reg = load_registry()
        ROOT = reg["__root__"]
        if a.all:
            exclude = ()
        else:
            exclude = tuple(t for t in DEFAULT_EXCLUDE if not (a.keep_events and t == "events"))
        seed, nbytes, dropped = export(reg, exclude)
        rel = os.path.relpath(seed, reg["__root__"])
        print("db_export: wrote %s (%.2f MB text, %.2f MB xz); excluded: %s" % (
            rel, nbytes / 1024 / 1024, os.path.getsize(seed + ".xz") / 1024 / 1024,
            ", ".join(dropped) or "none"))
        return 0
    except Exception as e:  # noqa: BLE001
        tb = traceback.format_exc()
        try:
            bug_report(reg, e, tb)
        except Exception:  # noqa: BLE001
            pass
        sys.stderr.write(tb)
        return 1


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('0a7fe096c9969840d4a7ac7fb1815a58a4f3593e','python',4713,'#!/usr/bin/env python3
"""db_import.py -- rebuild a CMS database from the SQL seed (state/seed.sql).

MANUAL tool -- NOT run on any crank or hook. Builds a fresh DB from the committed seed. Refuses to clobber
an existing target without --force, and never touches the live DB unless you point --to at it explicitly.

    python3 tools/db_import.py --verify                 # build to a throwaway temp DB + print table counts
    python3 tools/db_import.py --to /tmp/new.sqlite     # build a fresh DB from state/seed.sql[.xz]
    python3 tools/db_import.py --to X --force           # overwrite X if it exists

Registry-gated, python-only.
"""
import argparse
import json
import lzma
import os
import sqlite3
import sys
import tempfile
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None


def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    p = find_registry()
    reg = json.load(open(p))
    reg["__root__"] = os.path.dirname(p)
    return reg


def bug_report(reg, exc, tb, note="db_import"):
    root = (reg or {}).get("__root__") or ROOT or HERE
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {"filename": os.path.basename(__file__), "function": last.name if last else "?",
             "time-of-occurance": datetime.now().isoformat(),
             "methods-to-reproduce": "python3 tools/db_import.py " + " ".join(sys.argv[1:]),
             "possible-cause": "%s: %s" % (type(exc).__name__, exc),
             "traceback": tb.strip().splitlines()[-6:], "note": note}
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        open(path, "a").write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def seed_sql(reg):
    state = os.path.join(reg["__root__"], "checkouts", "current", "state")
    plain = os.path.join(state, "seed.sql")
    xz = plain + ".xz"
    if os.path.isfile(plain):
        return open(plain).read()
    if os.path.isfile(xz):
        with lzma.open(xz, "rt") as f:
            return f.read()
    raise FileNotFoundError("no state/seed.sql[.xz] -- run tools/db_export.py first")


def build(sql, target):
    c = sqlite3.connect(target)
    c.executescript(sql)
    c.commit()
    counts = {t: c.execute(''SELECT COUNT(*) FROM "%s"'' % t).fetchone()[0]
              for (t,) in c.execute("SELECT name FROM sqlite_master WHERE type=''table'' AND name NOT LIKE ''sqlite_%'' ORDER BY name")}
    c.close()
    return counts


def main():
    global ROOT
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--to", help="target DB path to build")
    ap.add_argument("--force", action="store_true", help="overwrite an existing --to target")
    ap.add_argument("--verify", action="store_true", help="build to a temp DB + print counts (no writes kept)")
    a = ap.parse_args()
    reg = None
    try:
        reg = load_registry()
        ROOT = reg["__root__"]
        sql = seed_sql(reg)

        if a.verify:
            fd, tmp = tempfile.mkstemp(suffix=".sqlite")
            os.close(fd)
            os.remove(tmp)
            counts = build(sql, tmp)
            os.remove(tmp)
            print("db_import --verify: seed builds cleanly -> %d rows across %d tables" % (
                sum(counts.values()), len(counts)))
            for t, n in counts.items():
                print("  %-24s %d" % (t, n))
            return 0

        if not a.to:
            sys.stderr.write("db_import: --to <path> required (or --verify)\n")
            return 2
        target = os.path.abspath(os.path.expanduser(a.to))
        if os.path.exists(target) and not a.force:
            sys.stderr.write("db_import: %s exists; pass --force to overwrite\n" % target)
            return 2
        if os.path.exists(target):
            os.remove(target)
        counts = build(sql, target)
        print("db_import: built %s (%d rows across %d tables)" % (
            target, sum(counts.values()), len(counts)))
        return 0
    except Exception as e:  # noqa: BLE001
        tb = traceback.format_exc()
        try:
            bug_report(reg, e, tb)
        except Exception:  # noqa: BLE001
            pass
        sys.stderr.write(tb)
        return 1


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('5fab6b0e6a86c31dd060196db61bfecd71e21775','python',13140,'#!/usr/bin/env python3
"""ingest_self.py -- mirror the running source + docs into the CMS DB, content-addressed by git blob hash.

On each crank (post-commit) this pushes the running source into the CMS DB (CONGRUENCY_SQLITE, the unified
~/.jazz/congruency.sqlite) so the CMS can render its own source and documentation. Content is deduped by
git blob hash; a reverse-lookup (path @ commit) names each blob and gives every file its version history;
`is_current=1` flags the blob for each path in the checked-out HEAD tree = the RUNNING source. Code and
docs live in separate tables.

    python3 tools/ingest_self.py             # --head (default): ingest the HEAD tree + re-flag current
    python3 tools/ingest_self.py --backfill  # walk source history into the archive, then flag current
    python3 tools/ingest_self.py --stats     # print row counts
    python3 tools/ingest_self.py --ensure-pages  # create tables + the source/docs entry Documents

Registry-gated, python-only, best-effort (never blocks a commit); Variant-A bug report on exception.
"""
import argparse
import json
import os
import sqlite3
import subprocess
import sys
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None   # repo root (dir of registry.json); set in main()

CODE_EXT = (".php", ".py")
DOC_EXT = (".md", ".txt")
DOC_TXT_PREFIXES = ("checkouts/current/doc/",)   # .txt is a doc ONLY here (legacy 2006 CMS docs) — not stray prompts/cookie jars
IGNORE_SUBSTR = ("tooling/congruencey/", "tooling/tournament-", "/vendor/", "/node_modules/")
CODE_PREFIXES = (
    "checkouts/current/lib/", "checkouts/current/invocators/", "checkouts/current/boot/",
    "checkouts/current/www/", "checkouts/current/bin/",
    "checkouts/current/tools/", "checkouts/current/versioning/", "tracker/",
)
MAIN_EXTRAS = ("deploy.py", "install.py")            # deploy/stand-up-teardown tooling (lives on `main`)
LANG = {".php": "php", ".py": "python", ".md": "markdown", ".txt": "text"}

DDL = [
    "CREATE TABLE IF NOT EXISTS code_blobs (hash TEXT PRIMARY KEY, lang TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS code_refs  (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_code_refs ON code_refs(hash, path, commit_sha)",
    "CREATE TABLE IF NOT EXISTS doc_blobs  (hash TEXT PRIMARY KEY, kind TEXT, bytes INTEGER, body TEXT)",
    "CREATE TABLE IF NOT EXISTS doc_refs   (hash TEXT, path TEXT, commit_sha TEXT, ts REAL, is_current INTEGER DEFAULT 0)",
    # abstract tagging: a `tag` applied to an opaque `target` ref ("source:<hash>" / "page:<id>" / "doc:<hash>" / "ticket:<id>")
    "CREATE TABLE IF NOT EXISTS annotations (id INTEGER PRIMARY KEY AUTOINCREMENT, tag TEXT, target TEXT, note TEXT, ts REAL, meta TEXT)",
    "CREATE UNIQUE INDEX IF NOT EXISTS ix_doc_refs ON doc_refs(hash, path, commit_sha)",
]


# ------------------------------------------------------------------ registry / db
def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    path = find_registry()
    reg = json.load(open(path))
    reg["__root__"] = os.path.dirname(path)
    return reg


def bug_report(reg, exc, tb, note="ingest_self"):
    root = (reg or {}).get("__root__") or ROOT or HERE
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {"filename": os.path.basename(__file__), "function": last.name if last else "?",
             "time-of-occurance": datetime.now().isoformat(),
             "methods-to-reproduce": "python3 tools/ingest_self.py " + " ".join(sys.argv[1:]),
             "possible-cause": "%s: %s" % (type(exc).__name__, exc),
             "traceback": tb.strip().splitlines()[-6:], "note": note}
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        open(path, "a").write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def db_path(reg):
    """The CMS DB the app reads: install.json''s CONGRUENCY_SQLITE, else the jazz default."""
    cfg = os.path.join(reg["__root__"], "checkouts", "current", "install.json")
    try:
        j = json.load(open(cfg))
        if j.get("CONGRUENCY_SQLITE"):
            return os.path.expanduser(j["CONGRUENCY_SQLITE"])
    except Exception:  # noqa: BLE001
        pass
    return os.path.join(os.path.expanduser("~"), ".jazz", "congruency.sqlite")


# ------------------------------------------------------------------ git
def git(*args):
    return subprocess.run(["git"] + list(args), cwd=ROOT, capture_output=True, text=True)


def resolve(ref):
    return git("rev-parse", ref).stdout.strip()


def ls_tree(ref):
    for line in git("ls-tree", "-r", ref).stdout.splitlines():
        meta, _, path = line.partition("\t")          # "<mode> blob <hash>\t<path>"
        parts = meta.split()
        if len(parts) == 3 and parts[1] == "blob":
            yield parts[2], path


def blob_body(h):
    r = git("cat-file", "blob", h)
    return r.stdout if r.returncode == 0 else ""


# ------------------------------------------------------------------ classify / write
def in_scope(path):
    if any(s in path for s in IGNORE_SUBSTR):
        return None
    ext = os.path.splitext(path)[1]
    if ext in CODE_EXT and any(path.startswith(p) for p in CODE_PREFIXES):
        return "code"
    if ext == ".md":
        return "doc"
    # .txt ONLY from the doc dir (the legacy 2006 CMS docs) — NOT stray prompts / cookie jars (e.g. wiz.txt)
    if ext == ".txt" and any(path.startswith(p) for p in DOC_TXT_PREFIXES):
        return "doc"
    return None


def have_blob(db, domain, h):
    tbl = "code_blobs" if domain == "code" else "doc_blobs"
    return db.execute("SELECT 1 FROM %s WHERE hash=?" % tbl, (h,)).fetchone() is not None


def store_blob(db, domain, h, path, body):
    lang = LANG.get(os.path.splitext(path)[1], "text")
    nbytes = len(body.encode("utf-8", "replace"))
    if domain == "code":
        db.execute("INSERT OR IGNORE INTO code_blobs(hash,lang,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))
    else:
        db.execute("INSERT OR IGNORE INTO doc_blobs(hash,kind,bytes,body) VALUES(?,?,?,?)", (h, lang, nbytes, body))


def add_ref(db, domain, h, path, commit_sha, ts):
    tbl = "code_refs" if domain == "code" else "doc_refs"
    db.execute("INSERT OR IGNORE INTO %s(hash,path,commit_sha,ts,is_current) VALUES(?,?,?,?,0)" % tbl,
               (h, path, commit_sha, ts))


def ingest_ref(db, ref, ts, main_extras=True):
    """Ingest every in-scope blob at `ref`; return [(domain, path, hash)] for current-flagging."""
    sha = resolve(ref)
    seen = []
    for h, path in ls_tree(ref):
        dom = in_scope(path)
        if not dom:
            continue
        if not have_blob(db, dom, h):
            store_blob(db, dom, h, path, blob_body(h))
        add_ref(db, dom, h, path, sha, ts)
        seen.append((dom, path, h, sha))
    if main_extras:
        main_sha = resolve("main")
        for name in MAIN_EXTRAS:
            r = git("ls-tree", "main", "--", name)
            parts = r.stdout.split()
            if r.returncode == 0 and len(parts) >= 3 and parts[1] == "blob":
                h, path = parts[2], "main:" + name
                if not have_blob(db, "code", h):
                    store_blob(db, "code", h, path, blob_body(h))
                add_ref(db, "code", h, path, main_sha, ts)
                seen.append(("code", path, h, main_sha))
    return seen


def reflag_current(db, seen):
    db.execute("UPDATE code_refs SET is_current=0")
    db.execute("UPDATE doc_refs  SET is_current=0")
    for dom, path, h, csha in seen:
        tbl = "code_refs" if dom == "code" else "doc_refs"
        db.execute("UPDATE %s SET is_current=1 WHERE hash=? AND path=? AND commit_sha=?" % tbl, (h, path, csha))


def ensure_pages(db):
    """Create the two entry-page Documents (source, docs) in the live DB if absent (idempotent)."""
    def next_tid():
        row = db.execute("SELECT COALESCE(MAX(TemplateID),0)+1 FROM Document_Templates").fetchone()
        return row[0] if row else 1
    # the site''s one stylesheet is the <<<Style>>> tag; every page just embeds it + the <<<SiteMap>>> nav
    pages = {
        "source":      ("Source · Congruency", "The CMS''s own running source", "<<<SourceList>>>"),
        "docs":        ("Documentation · Congruency", "The CMS''s own documentation", "<<<DocList>>>"),
        "annotations": ("Annotations · Congruency", "The tag->target layer (flags + categories)", "<<<Annotations>>>"),
        "database":    ("Database · Congruency", "The unified DB — every table, row counts, browsable", "<<<DatabaseInfo>>>"),
    }
    for did, (title, desc, tag) in pages.items():
        if db.execute("SELECT 1 FROM Documents WHERE DocumentID=?", (did,)).fetchone():
            continue
        tid = next_tid()
        body = "<!DOCTYPE html>\n<html>\n<head>\n<<<TitleTag>>>\n<<<Style>>>\n</head>\n<body>\n<nav><<<SiteMap>>></nav>\n<h1>%s</h1>\n%s\n</body>\n</html>\n" % (title, tag)
        db.execute("INSERT INTO Document_Templates(TemplateID, Content) VALUES(?,?)", (tid, body))
        db.execute("INSERT INTO Documents(DocumentID, TemplateID, Title, Description, ContentID) VALUES(?,?,?,?,?)",
                   (did, tid, title, desc, tid))


def stats(db):
    for t in ("code_blobs", "code_refs", "doc_blobs", "doc_refs"):
        try:
            n = db.execute("SELECT COUNT(*) FROM %s" % t).fetchone()[0]
        except sqlite3.Error:
            n = "-"
        cur = ""
        if t.endswith("_refs"):
            c = db.execute("SELECT COUNT(*) FROM %s WHERE is_current=1" % t).fetchone()[0]
            cur = "  (current: %d)" % c
        print("  %-11s %s%s" % (t, n, cur))


# ------------------------------------------------------------------ main
def main():
    global ROOT
    ap = argparse.ArgumentParser(description="mirror the running source + docs into the CMS DB (content-addressed)")
    ap.add_argument("--head", action="store_true", help="ingest the HEAD tree + re-flag current (default)")
    ap.add_argument("--backfill", action="store_true", help="walk source history into the archive")
    ap.add_argument("--ensure-pages", action="store_true", help="create tables + the source/docs entry Documents")
    ap.add_argument("--stats", action="store_true", help="print row counts and exit")
    a = ap.parse_args()

    reg = load_registry()
    ROOT = reg["__root__"]
    db = sqlite3.connect(db_path(reg), timeout=15)
    try:
        for stmt in DDL:
            db.execute(stmt)

        if a.stats:
            stats(db)
            return 0

        if a.ensure_pages:
            ensure_pages(db)
            db.commit()
            print("ensure-pages: entry Documents ensured (source/docs/annotations/database); tables created")
            return 0

        try:
            ensure_pages(db)   # self-healing: the source/docs entry Documents exist (idempotent)
        except Exception:  # noqa: BLE001  (a bare/fresh DB without the CMS Documents table)
            pass

        if a.backfill:
            seen_hashes_before = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0]
            for line in git("rev-list", "--timestamp", "source").stdout.splitlines():
                parts = line.split()
                if len(parts) != 2:
                    continue
                ts, sha = float(parts[0]), parts[1]
                ingest_ref(db, sha, ts, main_extras=False)
            # current main extras + flag HEAD as running source
            seen = ingest_ref(db, "HEAD", float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0), main_extras=True)
            reflag_current(db, seen)
            db.commit()
            added = db.execute("SELECT COUNT(*) FROM code_blobs").fetchone()[0] - seen_hashes_before
            print("backfill: walked source history (+%d new code blobs)" % added)
            stats(db)
            return 0

        # default: --head
        ts = float(git("log", "-1", "--format=%ct", "HEAD").stdout.strip() or 0)
        seen = ingest_ref(db, "HEAD", ts, main_extras=True)
        reflag_current(db, seen)
        db.commit()
        print("ingest_self: HEAD tree mirrored (%d in-scope files); running source flagged" % len(seen))
        return 0
    finally:
        db.close()


if __name__ == "__main__":
    try:
        sys.exit(main())
    except Exception as e:  # noqa: BLE001  -- best-effort: never crash a commit hook
        try:
            reg = load_registry()
        except Exception:  # noqa: BLE001
            reg = None
        bug_report(reg, e, traceback.format_exc())
        sys.stderr.write("[ingest_self] %r\n" % e)
        sys.exit(0)
');
INSERT INTO "code_blobs" VALUES('b16520bdb9629d60ac8eb31591641640bc8a34fa','python',5662,'#!/usr/bin/env python3
"""db_export.py -- export the CMS database as a git-viewable SQL dump (+ compressed).

Dumps CONGRUENCY_SQLITE to state/seed.sql (readable CREATE TABLE + INSERT statements you can diff in git)
and state/seed.sql.xz (compressed, for a fast deploy restore). Excludes local-noise / secret tables by
default -- the `events` tracker log and the auth tables (Login_Password/User_Group_Mappings/Group_Privileges)
-- so the committed seed is a clean public showcase. The self-hosting source/doc archive (with full history)
is kept: the browsable version history is the point.

    python3 tools/db_export.py                 # -> state/seed.sql (+ .xz); events + auth excluded
    python3 tools/db_export.py --keep-auth     # keep the auth tables (bake in the demo admin), drop events
    python3 tools/db_export.py --keep-events   # include the tracker event log
    python3 tools/db_export.py --all           # include everything (auth + events)

Registry-gated, python-only; Variant-A bug report on exception.
"""
import argparse
import json
import lzma
import os
import shutil
import sqlite3
import sys
import tempfile
import traceback
from datetime import datetime

HERE = os.path.dirname(os.path.abspath(__file__))
ROOT = None
DEFAULT_EXCLUDE = ("events", "Login_Password", "User_Group_Mappings", "Group_Privileges")


def find_registry(start=HERE):
    d = os.path.abspath(start)
    while True:
        cand = os.path.join(d, "registry.json")
        if os.path.isfile(cand):
            return cand
        parent = os.path.dirname(d)
        if parent == d:
            raise FileNotFoundError("registry.json not found at/above %s" % start)
        d = parent


def load_registry():
    p = find_registry()
    reg = json.load(open(p))
    reg["__root__"] = os.path.dirname(p)
    return reg


def db_path(reg):
    """The CMS DB the app reads: install.json''s CONGRUENCY_SQLITE, else the jazz default."""
    cfg = os.path.join(reg["__root__"], "checkouts", "current", "install.json")
    try:
        j = json.load(open(cfg))
        if j.get("CONGRUENCY_SQLITE"):
            return os.path.expanduser(j["CONGRUENCY_SQLITE"])
    except Exception:  # noqa: BLE001
        pass
    return os.path.join(os.path.expanduser("~"), ".jazz", "congruency.sqlite")


def bug_report(reg, exc, tb, note="db_export"):
    root = (reg or {}).get("__root__") or ROOT or HERE
    path = os.path.join(root, (reg or {}).get("bug_reports", "logs/bug_reports.jsonl"))
    frames = traceback.extract_tb(exc.__traceback__)
    last = frames[-1] if frames else None
    entry = {"filename": os.path.basename(__file__), "function": last.name if last else "?",
             "time-of-occurance": datetime.now().isoformat(),
             "methods-to-reproduce": "python3 tools/db_export.py " + " ".join(sys.argv[1:]),
             "possible-cause": "%s: %s" % (type(exc).__name__, exc),
             "traceback": tb.strip().splitlines()[-6:], "note": note}
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        open(path, "a").write(json.dumps(entry) + "\n")
    except OSError:
        pass
    return path


def export(reg, exclude):
    db = db_path(reg)
    if not os.path.isfile(db):
        raise FileNotFoundError("no CMS DB at %s" % db)
    state = os.path.join(reg["__root__"], "checkouts", "current", "state")
    os.makedirs(state, exist_ok=True)

    # Work on a copy so the live DB is never mutated: drop excluded tables, VACUUM, then dump.
    fd, tmp = tempfile.mkstemp(suffix=".sqlite")
    os.close(fd)
    shutil.copy(db, tmp)
    try:
        c = sqlite3.connect(tmp)
        dropped = []
        for t in exclude:
            if c.execute("SELECT 1 FROM sqlite_master WHERE type=''table'' AND name=?", (t,)).fetchone():
                c.execute(''DROP TABLE "%s"'' % t)
                dropped.append(t)
        c.commit()
        c.execute("VACUUM")
        c.commit()
        sql = "\n".join(c.iterdump()) + "\n"
        c.close()
    finally:
        os.remove(tmp)

    seed = os.path.join(state, "seed.sql")
    with open(seed, "w") as f:
        f.write(sql)
    with lzma.open(seed + ".xz", "wt", preset=9) as f:
        f.write(sql)
    return seed, len(sql.encode("utf-8")), dropped


def main():
    global ROOT
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--keep-events", action="store_true", help="include the tracker event log")
    ap.add_argument("--keep-auth", action="store_true", help="include the auth tables (bakes in the demo admin)")
    ap.add_argument("--all", action="store_true", help="include everything (auth + events)")
    a = ap.parse_args()
    reg = None
    try:
        reg = load_registry()
        ROOT = reg["__root__"]
        auth = ("Login_Password", "User_Group_Mappings", "Group_Privileges")
        if a.all:
            exclude = ()
        else:
            exclude = tuple(t for t in DEFAULT_EXCLUDE
                            if not (a.keep_events and t == "events")
                            and not (a.keep_auth and t in auth))
        seed, nbytes, dropped = export(reg, exclude)
        rel = os.path.relpath(seed, reg["__root__"])
        print("db_export: wrote %s (%.2f MB text, %.2f MB xz); excluded: %s" % (
            rel, nbytes / 1024 / 1024, os.path.getsize(seed + ".xz") / 1024 / 1024,
            ", ".join(dropped) or "none"))
        return 0
    except Exception as e:  # noqa: BLE001
        tb = traceback.format_exc()
        try:
            bug_report(reg, e, tb)
        except Exception:  # noqa: BLE001
            pass
        sys.stderr.write(tb)
        return 1


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('9b0cc517037a59248944a20d7a9aea83566bd10b','python',2942,'#!/usr/bin/env python3
"""set_admin.py -- provision (or rotate) an admin login in a CMS database.

Explicit + safe: you name the DB and login; the password is either given (--password) or generated
(--generate, printed once). Creates the auth tables if missing and replaces any existing entry for that
login. Use it to inject a login at deploy time, or to rotate the demo admin -- instead of shipping a
credential in git. (Stored plaintext: the 2006 UserPrivilegeSet auth compares the password plaintext.)

    python3 tools/set_admin.py --db state/congruency.sqlite --login admin --generate
    python3 tools/set_admin.py --db /srv/site/state/congruency.sqlite --login ops --password ''s3cret''

python-only, standalone (operates on the --db you name; no registry needed).
"""
import argparse
import os
import secrets
import sqlite3
import string
import sys


def gen_password(n=16):
    alphabet = string.ascii_letters + string.digits
    return "".join(secrets.choice(alphabet) for _ in range(n))


def set_admin(db, login, password, group_id=1):
    c = sqlite3.connect(db)
    try:
        c.execute("CREATE TABLE IF NOT EXISTS Login_Password (Login TEXT, Password TEXT)")
        c.execute("CREATE TABLE IF NOT EXISTS User_Group_Mappings (Login TEXT, Group_ID INTEGER)")
        c.execute("CREATE TABLE IF NOT EXISTS Group_Privileges (Group_ID INTEGER, Module TEXT, Value TEXT)")
        c.execute("DELETE FROM Login_Password WHERE Login=?", (login,))
        c.execute("DELETE FROM User_Group_Mappings WHERE Login=?", (login,))
        c.execute("INSERT INTO Login_Password (Login, Password) VALUES (?,?)", (login, password))
        c.execute("INSERT INTO User_Group_Mappings (Login, Group_ID) VALUES (?,?)", (login, group_id))
        if not c.execute("SELECT 1 FROM Group_Privileges WHERE Group_ID=?", (group_id,)).fetchone():
            c.execute("INSERT INTO Group_Privileges (Group_ID, Module, Value) VALUES (?,''admin'',''1'')", (group_id,))
        c.commit()
    finally:
        c.close()


def main():
    ap = argparse.ArgumentParser(description=__doc__)
    ap.add_argument("--db", required=True, help="target SQLite DB")
    ap.add_argument("--login", required=True, help="admin login name")
    ap.add_argument("--password", help="admin password (plaintext)")
    ap.add_argument("--generate", action="store_true", help="generate a random password and print it once")
    a = ap.parse_args()

    if not a.password and not a.generate:
        sys.stderr.write("set_admin: pass --password <P> or --generate\n")
        return 2
    if not os.path.isfile(a.db):
        sys.stderr.write("set_admin: no DB at %s\n" % a.db)
        return 2

    pw = a.password or gen_password()
    set_admin(a.db, a.login, pw)
    print("set_admin: admin login %r set on %s" % (a.login, a.db))
    if a.generate:
        print("  password: %s   (shown once -- save it now)" % pw)
    return 0


if __name__ == "__main__":
    sys.exit(main())
');
INSERT INTO "code_blobs" VALUES('17d0fb70b954f21c40db47b740cc200283484569','python',7237,'#!/usr/bin/env python3
"""db_export.py -- export the CMS database as a git-viewable SQL dump (+ compressed).

Dumps CONGRUENCY_SQLITE to state/seed.sql (readable CREATE TABLE + INSERT statements you can diff in git)
and state/seed.sql.xz (compressed, for a fast deploy restore). Excludes local-noise / secret tables by
default -- the `events` tracker log and the auth tables (Login_Password/User_Group_Mappings/Group_Privileges)
-- so the committed seed is a clean public showcase. The self-hosting source/doc archive (with full history)
is kept: the browsable version history is the point.

    python3 tools/db_export.py                 # -> state/seed.sql (+ .xz); events + auth excluded
    python3 tools/db_export.py --keep-auth     # keep the auth tables (bake in the demo admin), drop events
    python3 tools/db_export.py --keep-events   # include the tracker event log
    python3 tools/db_export.py --all           # include everything (auth + events)
    python3 tools/db_export.py --keep-auth --last-n 25   # keep only the last 25 commits of history

Registry-gated, python-only; Variant-A bug report on exception.
"""
import argparse
import json
import lzma
import os
import shutil
import sqlite3
import sys
import tempfile
