INSERT INTO "tickets" VALUES(3,1.78329675766193938e+09,1.78329815823477172e+09,'ratchet','make_state non-deterministic: `state` branch churns a new blob every run','medium','CLOSED','Fixed in crank b04 (version-4.055): make_state normalizes tar members (mtime=0, uid/gid=0, fixed mode, sorted) + skips commit when blob unchanged. Verified: 3 re-runs -> identical blob d2ff5bd, state-commits steady, no churn.','{"kind": "bug", "area": "make_state.py / STATE.json"}');
INSERT INTO "tickets" VALUES(4,1.7832967576798644e+09,1.78329828575158405e+09,'ratchet','provision_php re-downloads PHP (~12MB) on every install; not idempotent','low','CLOSED','Fixed in crank b05 (version-4.056): provision_php skips re-acquisition when a working php is at dest (dest -v == 0). Verified: present->''already provisioned'' 620ms (no download); removed->fallback re-download 11.7s; present->skip.','{"kind": "bug", "area": "file-system-repair/provision_php.py"}');
INSERT INTO "tickets" VALUES(5,1.7832970132305653e+09,1.78329831912764501e+09,'ratchet','crank orchestrator: inject-one-script-per-crank, capture it as the patch to the next version','medium','CLOSED','Built as turn 14 (mint_crank.py) + example patch. Verified: smoke crank + two real bug-fix cranks (b04 #3, b05 #4) minted end-to-end. Capture uses the lean single-repo tag (commit_release couldn''t be scoped to one folded repo).','{"kind": "build", "area": "new tool (mint a crank)"}');
INSERT INTO "tickets" VALUES(6,1.78329701324434781e+09,1.78329869365122866e+09,'ratchet','release step must push version tags (version-4.05x are local-only, absent on PIVOT)','medium','CLOSED','Pushed version-4.050..056 tags to origin/PIVOT alongside cranks b03(turn14)/b04/b05 + state. Detents now on the remote. Future mints should push their tag as the release step.','{"kind": "build", "area": "push/release path"}');
INSERT INTO "tickets" VALUES(7,1.78329784273078417e+09,1.78329831914628195e+09,'ratchet','ratchet mint failed at fork','high','CLOSED','Dev-time transient during build: the mint''s fork guard CORRECTLY refused a dirty tree (a blanket __pycache__ rm had deleted tracked ops/*.pyc). Restored; not a shipped defect. The bug-event mechanism worked as designed.','{"step": "fork"}');
INSERT INTO "tickets" VALUES(8,1.78329786735670471e+09,1.78329831914850354e+09,'ratchet','ratchet mint failed at capture (commit_release)','high','CLOSED','Dev-time transient during build: commit_release ''no modules under repo'' — resolved by switching capture to the lean single-repo tag (version_source.compute_next_version + git tag). Not a shipped defect.','{"step": "capture (commit_release)"}');
INSERT INTO "tickets" VALUES(9,1.78329944599971747e+09,1.78330041288845014e+09,'ratchet','code anchored to file-system-repair/ (hardcoded bug-sink paths + provision_php location)','medium','CLOSED','De-anchored (phases 1-2): b06 documented fsr+mcp; b07 moved provision_php -> checkouts/current/tools/, repointed registry bug_reports -> logs/bug_reports.jsonl, de-hardcoded all fixes/*.py + tools writers, + install.py fixup on main. Verified: install b07 provisions from the new home, verify 0 failed. No LIVE code anchored to file-system-repair now.','{"kind": "bug", "area": "file-system-repair coupling"}');
INSERT INTO "tickets" VALUES(10,1.78330041289936685e+09,1.78330261950488877e+09,'ratchet','circle-back: remove file-system-repair remainder + vestigial mcp/ + reconcile duplicate DBs','low','CLOSED','Phase 3 done (crank version-4.065): removed file-system-repair/, mcp/, and the bare checkouts/state/ store; dropped the dead registry file_system_repair block; updated the root README. Duplicate DB reconciled -> one in-tree fallback (checkouts/current/state/database.tar.xz) + the authoritative `state` branch. install --version 4.065 verified. Remaining (minor, separate): the nested tooling/tournament vs tooling/tournament-package dump duplicate.','{"kind": "build", "area": "phase-3 cleanup"}');
