INSERT INTO "tickets" VALUES(25,1.78332030077263092e+09,1.78336219081704711e+09,'cms','Migrate the mysql_* connector to native PDO through the abstract DB class','high','CLOSED',NULL,'{"kind": "refactor", "detail": "Retire boot/shim.php (mysql_* -> PDO/sqlite stubs). All DB-touching classes route through the abstract connection class (lib/DatabaseDrivers/MySQL/DataConnection.php); swap its mysql_connect/mysql_query/mysql_select_db internals for native PDO (prepared statements). Verify auth/content/store/order/form DAOs still work; keep sqlite as the driver. Test-first: DAO round-trips CONFIRMED, CMS verify green."}');
INSERT INTO "tickets" VALUES(26,1.78332030078186082e+09,1.78336413256594014e+09,'deploy','Test-deploy lifecycle: on/off/redeploy verified end-to-end','medium','CLOSED',NULL,'{"kind": "test", "detail": "Run a full deployment cycle and prove start/stop/restart cleanly: deploy.py --target, server ON (pinned port, detached), server OFF, --serve restart, idempotent re-deploy. Make sure everything turns on AND off; no orphaned ports/processes. Follows the PDO migration."}');
INSERT INTO "tickets" VALUES(27,1.78332030078425025e+09,1.78334473948012089e+09,'deploy','Dev-server config can live outside the install folder + one-command start','high','CLOSED',NULL,'{"kind": "build", "detail": "Load config from an external path e.g. ~/config/congruency.json (via CONGRUENCY_CONFIG env or a --config flag), instantiate and START the server with ONE command. configure.php already honours $CONGRUENCY_CONFIG; extend deploy.py/serve to accept --config <path> and run the whole thing in one invocation."}');
INSERT INTO "tickets" VALUES(28,1.78332030078632712e+09,1.783363226829041e+09,'docs','Update README files for config-as-data + PDO + external config','low','CLOSED',NULL,'{"kind": "build", "detail": "Refresh main/source READMEs + DEPLOY.md/DEPENDENCIES.md to reflect: configure.php + constants.default.json (config is data), the PDO migration (no shim), external ~/config/congruency.json + one-command start, and the current on/off commands."}');
INSERT INTO "tickets" VALUES(29,1.78332030078841924e+09,1.78334448185385179e+09,'tooling','Auto-stamp the GPL short-notice header on NEW code','medium','CLOSED',NULL,'{"kind": "build", "detail": "The relicense sweep replaced old GPL+contact stamps, but NEW files get no stamp. Make stamping automatic: a ''stamp if missing'' mode reusing the relicense SHORT_LINES logic, wired into the crank/mint flow (or a pre-commit hook / a verify check) so every new source file is stamped without manual effort."}');
INSERT INTO "tickets" VALUES(30,1.78332030079845285e+09,1.78334587606657838e+09,'cms','Dead-code audit by EXTENDING the min-spec stub to demonstrate features','medium','CLOSED',NULL,'{"kind": "audit", "detail": "Do NOT naively delete ''dead'' code \u2014 the tag engine + features make static dead-code detection lie. Instead EXTEND the production min-spec stub to exercise the software''s real features (start simple: forms with validation; then catalog, tags, etc.). Whatever cannot be reached/demonstrated after the stub uses the features is the genuinely dead set. Turns the stub into a living feature demo."}');
