INSERT INTO "tickets" VALUES(124,1.78337403258412456e+09,1.78337403258412456e+09,'build','Self-hosting: CMS renders its own running source + docs (content-addressed, admin-gated)','medium','CLOSED','ingest_self.py mirrors running source into code_blobs/code_refs + doc_blobs/doc_refs (git-blob-hash content-addressed, reverse-lookup, is_current) on each crank via the post-commit hook; SourceList/DocList admin-gated tags render index+hash-view (escaped code / markdown-subset docs, tag examples literal) + version history; ?page=source/docs entry pages; REST denylist. Verified: 168 current code files, history (Content.php 4 versions/96 refs), self-hosting (own browser source archived), logged-out gated, gates 26/26 + crawl broken=1.','{"source":"feature"}');
